INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jZW50YXVyby5qc29u', 'centauro', 'Centauro', 'SRD', 'srd-extracted/centauro.json', '2', 2, 450, 'Grande', 'mostruosità', 'neutrale buono', '{"slug":"centauro","general":{"name":"Centauro","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"neutrale buono","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":45,"formula":"6d10 + 12"},"speed":{"walk":"15 m"}},"abilities":{"strength":18,"dexterity":14,"constitution":14,"intelligence":9,"wisdom":13,"charisma":11},"details":{"savingThrows":[],"skills":[{"name":"Atletica","bonus":6},{"name":"Percezione","bonus":3},{"name":"Sopravvivenza","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[{"name":"Elfico"},{"name":"Silvano"}],"proficiencyBonus":2},"traits":[{"name":"Carica","usage":null,"description":"Se il centauro si muove di almeno 9 metri diretto verso il bersaglio e colpisce con un attacco di picca durante lo stesso turno, il bersaglio subisce 10 (3d6) danni perforanti aggiuntivi."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il centauro effettua due attacchi: uno con la picca e uno con gli zoccoli o due con l''arco lungo."},{"name":"Picca","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 3 m, un bersaglio. Colpisce: 9 (1d10 + 4) danni perforanti."},{"name":"Zoccoli","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni contundenti."},{"name":"Arco Lungo","usage":null,"description":"Attacco con arma a Distanza: +4 a colpire, gittata 45/180 m, un bersaglio. Colpisce: 6 (1d8 + 2) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Centauro\nGrande mostruosità, neutrale buono\nFORZA 18 (+4)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 9 (-1)\nSAGGEZZA 13 (+1)\nCARISMA 11 (+0)\nClasse Armatura 12\nPunti Ferita 45 (6d10 + 12)\nVelocità 15 m\nAbilità Atletica +6, Percezione +3, Sopravvivenza +3\nSensi Percezione passiva 13\nLinguaggi Elfico, Silvano\nSfida 2 (450 PE)\nCarica. Se il centauro si muove di almeno 9 metri diretto verso il\nbersaglio e colpisce con un attacco di picca durante lo stesso\nturno, il bersaglio subisce 10 (3d6) danni perforanti aggiuntivi.\nAzioni\nMultiattacco. Il centauro effettua due attacchi: uno con la picca e\nuno con gli zoccoli o due con l''arco lungo.\nPicca. Attacco con arma da mischia: +6 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 9 (1d10 + 4) danni perforanti.\nZoccoli. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 11 (2d6 + 4) danni contundenti.\nArco Lungo. Attacco con arma a Distanza: +4 a colpire, gittata\n45/180 m, un bersaglio.\nColpisce: 6 (1d8 + 2) danni perforanti."}}', '2026-03-30T16:00:32.239Z', '2026-03-30T16:00:32.239Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jZW50b3BpZWRpLWdpZ2FudGUuanNvbg', 'centopiedi-gigante', 'Centopiedi Gigante', 'SRD', 'srd-extracted/centopiedi-gigante.json', '1/4', 0.25, 50, 'Piccola', 'bestia', 'disallineato', '{"slug":"centopiedi-gigante","general":{"name":"Centopiedi Gigante","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Piccola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":4,"formula":"1d6 + 1"},"speed":{"walk":"9 m","climb":"9 m"}},"abilities":{"strength":5,"dexterity":14,"constitution":12,"intelligence":1,"wisdom":7,"charisma":3},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"9 m"},{"name":"Percezione passiva 8"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, una creatura. Colpisce: 4 (1d4 + 2) danni perforanti e il bersaglio deve riuscire un tiro salvezza di Costituzione CD 11 o subire 10 (3d6) danni da veleno. Se il danno da veleno riduce il bersaglio a 0 punti ferita, il bersaglio è stabile ma resta avvelenato per 1 ora, anche dopo aver recuperato i punti ferita, e mentre è avvelenato in questo modo resta paralizzato."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Centopiedi Gigante\nPiccola bestia, disallineato\nFORZA 5 (-3)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 7 (-2)\nCARISMA 3 (-4)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 4 (1d6 + 1)\nVelocità 9 m, scalata 9 m\nSensi vista cieca 9 m, Percezione passiva 8\nLingue -\nSfida 1/4 (50 PE)\nAzioni\nMorso. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, una creatura.\nColpisce: 4 (1d4 + 2) danni perforanti e il bersaglio deve riuscire\nun tiro salvezza di Costituzione CD 11 o subire 10 (3d6) danni\nda veleno. Se il danno da veleno riduce il bersaglio a 0 punti\nferita, il bersaglio è stabile ma resta avvelenato per 1 ora, anche\ndopo aver recuperato i punti ferita, e mentre è avvelenato in\nquesto modo resta paralizzato."}}', '2026-03-30T16:00:32.421Z', '2026-03-30T16:00:32.421Z');
