INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jb2NrYXRyaWNlLmpzb24', 'cockatrice', 'Cockatrice', 'SRD', 'srd-extracted/cockatrice.json', '1/2', 0.5, 100, 'Piccola', 'mostruosità', 'disallineato', '{"slug":"cockatrice","general":{"name":"Cockatrice","challengeRating":{"fraction":"1/2","decimal":0.5,"display":"1/2","xp":100},"size":"Piccola","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":11,"note":""},"hitPoints":{"average":27,"formula":"6d6 + 6"},"speed":{"walk":"6 m","fly":"12 m"}},"abilities":{"strength":6,"dexterity":12,"constitution":12,"intelligence":2,"wisdom":13,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 11"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +3 a colpire, portata 1,5 m, una creatura. Colpisce: 3 (1d4 + 1) danni perforanti, e il bersaglio deve riuscire un tiro salvezza di Costituzione CD 11 per non essere magicamente pietrificato. Se fallisce il tiro salvezza, la creatura inizia a trasformarsi in pietra ed è intralciata. Al termine del turno successivo deve ripetere il tiro salvezza. Se lo riesce, l''effetto ha termine. Se lo fallisce, la creatura è pietrificata per 24 ore."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cockatrice\nPiccola mostruosità, disallineato\nFORZA 6 (-2)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 13 (+1)\nCARISMA 5 (-3)\nClasse Armatura 11\nPunti Ferita 27 (6d6 + 6)\nVelocità 6 m, volo 12 m\nSensi scurovisione 18 m, Percezione passiva 11\nLinguaggi -\nSfida 1/2 (100 PE)\nAzioni\nMorso. Attacco con arma da mischia: +3 a colpire, portata 1,5\nm, una creatura.\nColpisce: 3 (1d4 + 1) danni perforanti, e il bersaglio deve\nriuscire un tiro salvezza di Costituzione CD 11 per non essere\nmagicamente pietrificato. Se fallisce il tiro salvezza, la creatura\ninizia a trasformarsi in pietra ed è intralciata. Al termine del\nturno successivo deve ripetere il tiro salvezza. Se lo riesce,\nl''effetto ha termine. Se lo fallisce, la creatura è pietrificata per 24\nore."}}', '2026-03-30T15:54:05.282Z', '2026-03-30T16:00:32.242Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jb21iYXR0ZW50ZS10cmliYWxlLmpzb24', 'combattente-tribale', 'Combattente Tribale', 'SRD', 'srd-extracted/combattente-tribale.json', '1/8', 0.125, 25, NULL, NULL, NULL, '{"slug":"combattente-tribale","general":{"name":"Combattente Tribale","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura di pelle"},"hitPoints":{"average":11,"formula":"2d8 + 2"},"speed":{"walk":"9 m"}},"abilities":{"strength":13,"dexterity":11,"constitution":12,"intelligence":8,"wisdom":11,"charisma":8},"details":{"savingThrows":[],"skills":[{"name":"Medicina","bonus":4},{"name":"Natura","bonus":3},{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Tattiche di Branco","usage":null,"description":"Il combattente tribale ha vantaggio ai tiri di attacco contro una creatura se almeno uno degli alleati del picchiatore si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Bastone da Combattimento","usage":null,"description":"Attacco con Arma da Mischia: +2 a colpire (+4 a colpire con bastone*), portata 1,5 m o gittata 6/18 m, un bersaglio. Colpisce: 3 (1d6) danni contundenti, o 6 (1d8 + 2) danni contundenti con bastone o se impugnato con due mani."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Combattente Tribale\nSono i difensori delle tribù che vivono ai margini della\nciviltà.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 13 (+1)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 8 (-1)\nSAGGEZZA 11 (+0)\nCARISMA 8 (-1)\nClasse Armatura 12 (armatura di pelle)\nPunti Ferita 11 (2d8 + 2)\nVelocità 9 m\nSensi Percezione passiva 10\nLingue una qualsiasi lingua\nSfida 1/8 (25 PE)\nTattiche di Branco. Il combattente tribale ha vantaggio ai tiri di\nattacco contro una creatura se almeno uno degli alleati del\npicchiatore si trova entro 1,5 metri dalla creatura e quell''alleato\nnon è inabile.\nAzioni\nLancia. Attacco con Arma da Mischia o a Gittata: +3 a colpire,\nportata 1,5 m o gittata 6/18 m, un bersaglio.\nColpisce: 4 (1d6 + 1) danni perforanti, o 5 (1d8 + 1) danni\nperforanti se usata con due mani per effettuare un attacco da\nmischia.\nDruido\nI druidi proteggono il mondo naturale dai mostri e\ndall''avanzare della civiltà. Alcuni sono sciamani tribali\nche curano i malati, pregano agli spiriti animali e\nforniscono consigli spirituali.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 10 (+0)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 12 (+1)\nSAGGEZZA 15 (+2)\nCARISMA 11 (+0)\nClasse Armatura 11 (16 con pelle di corteccia*)\nPunti Ferita 27 (5d8 + 5)\nVelocità 9 m\nAbilità Medicina +4, Natura +3, Percezione +4\nSensi Percezione passiva 14\nLingue Druidico più due altre lingue\nSfida 2 (450 PE)\nIncantesimi. Il sacerdote è un incantatore di 4° livello. La sua\nabilità da incantatore è la Saggezza (CD dei tiri salvezza degli\nincantesimi 12, +4 al colpire con attacchi con incantesimo). Il\nsacerdote ha preparato i seguenti incantesimi da druido:\nTrucchetti (a volontà): arte druidica, bastone, produrre fiamma\n1° livello (4 slot): intralciare, onda tonante, parlare con gli\nanimali, passo veloce\n2° livello (3 slot): animale messaggero, pelle di corteccia\nAzioni\nBastone da Combattimento. Attacco con Arma da Mischia: +2 a\ncolpire (+4 a colpire con bastone*), portata 1,5 m o gittata 6/18\nm, un bersaglio.\nColpisce: 3 (1d6) danni contundenti, o 6 (1d8 + 2) danni\ncontundenti con bastone o se impugnato con due mani."}}', '2026-03-30T15:54:05.587Z', '2026-03-30T16:00:32.497Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jb3J2by5qc29u', 'corvo', 'Corvo', 'SRD', 'srd-extracted/corvo.json', '0', 0, 10, 'Minuscola', 'bestia', 'disallineato', '{"slug":"corvo","general":{"name":"Corvo","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":10},"size":"Minuscola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":1,"formula":"1d4 - 1"},"speed":{"walk":"3 m","fly":"15 m"}},"abilities":{"strength":2,"dexterity":14,"constitution":8,"intelligence":2,"wisdom":12,"charisma":6},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Imitazione","usage":null,"description":"Il corvo può imitare dei semplici suoni che ha udito, come il sussurro di una persona, il pianto di un bambino o il verso di un animale. Una creatura che ode il suono può identificarlo come imitazione riuscendo una prova di Saggezza (Intuizione) CD 10."}],"actions":[{"name":"Becco","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 1 danno perforante."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Corvo\nMinuscola bestia, disallineato\nFORZA 2 (-4)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 8 (-1)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 6 (-2)\nClasse Armatura 12\nPunti Ferita 1 (1d4 - 1)\nVelocità 3 m, volo 15 m\nAbilità Percezione +3\nSensi Percezione passiva 13\nLingue -\nSfida 0 (10 PE)\nImitazione. Il corvo può imitare dei semplici suoni che ha udito,\ncome il sussurro di una persona, il pianto di un bambino o il\nverso di un animale. Una creatura che ode il suono può\nidentificarlo come imitazione riuscendo una prova di Saggezza\n(Intuizione) CD 10.\nAzioni\nBecco. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 1 danno perforante."}}', '2026-03-30T15:54:05.520Z', '2026-03-30T16:00:32.427Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jb3VhdGwuanNvbg', 'couatl', 'Couatl', 'SRD', 'srd-extracted/couatl.json', '4', 4, 1100, 'Media', 'celestiale', 'legale buono', '{"slug":"couatl","general":{"name":"Couatl","challengeRating":{"fraction":"4","decimal":4,"display":"4","xp":1100},"size":"Media","creatureType":"celestiale","subtype":"","typeLabel":"celestiale","alignment":"legale buono","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":97,"formula":"13d8 + 39"},"speed":{"walk":"9 m","fly":"9 m"}},"abilities":{"strength":16,"dexterity":20,"constitution":17,"intelligence":18,"wisdom":20,"charisma":18},"details":{"savingThrows":[{"ability":"Costituzione","bonus":5},{"ability":"Saggezza","bonus":7},{"ability":"Carisma","bonus":6}],"skills":[],"damageVulnerabilities":[],"damageResistances":["radiante"],"damageImmunities":["psichico; contundente","perforante e"],"conditionImmunities":[],"senses":[{"name":"visione del vero","value":"36 m"},{"name":"Percezione passiva 15"}],"languages":[{"name":"tutte"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":2},"traits":[{"name":"Armi Magiche","usage":null,"description":"Gli attacchi con armi del couatl sono magici."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato del couatl è il Carisma (CD dei tiri salvezza degli incantesimi 14). Il couatl può lanciare questi incantesimi in maniera innata, usando solo componenti verbali: A volontà: individuazione del bene e del male, individuazione del magico, individuazione dei pensieri 3/giorno ciascuno: benedizione, creare cibo e acqua, cura ferite, protezione dai veleni, ristorare inferiore, santuario, scudo 1/giorno ciascuno: ristorare superiore, scrutare, sogno"},{"name":"Mente Protetta","usage":null,"description":"Il couatl è immune allo scrutare e qualsiasi effetto che percepisca le sue emozioni, legga i suoi pensieri o individui la sua posizione."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 1,5 m, una creatura. Colpisce: 8 (1d6 + 5) danni perforanti, e il bersaglio deve riuscire un tiro salvezza di Costituzione CD 13 o restare avvelenato per 24 ore. Fino al termine dell''avvelenamento, il bersaglio è privo di sensi. Un''altra creatura può effettuare un''azione per risvegliare il bersaglio."},{"name":"Stritolare","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 3 m, una creatura di taglia Media o inferiore. Colpisce: 10 (2d6 + 3) danni contundenti, e il bersaglio è afferrato (CD 15 per fuggire). Fino al termine dell''afferrare, il bersaglio è intralciato, e il couatl non può stritolare un altro bersaglio."},{"name":"Mutare Forma","usage":null,"description":"Il couatl può trasformarsi magicamente in un umanoide o bestia il cui grado di sfida sia pari o inferiore al proprio, o tornare alla sua vera forma. Alla morte ritorna alla sua vera forma. Qualsiasi equipaggiamento stia indossando o trasportando viene assorbito o trasportato nella nuova forma (a scelta del couatl). Nella nuova forma, il couatl mantiene le sue statistiche di gioco e la facoltà di parlare, ma la sua CA, metodi di movimento, Forza, Destrezza e altre azioni vengono rimpiazzati da quelli della nuova forma, e ottiene qualsiasi statistica o capacità (eccetto i privilegi di classe, azioni leggendarie e azioni da tana) possedute dalla sua nuova forma e non dalla sua originale. Se la nuova forma ha un attacco di morso, il couatl può usare il proprio morso nella nuova forma."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Couatl\nMedia celestiale, legale buono\nFORZA 16 (+3)\nDESTREZZA 20 (+5)\nCOSTITUZIONE 17 (+3)\nINTELLIGENZA 18 (+4)\nSAGGEZZA 20 (+5)\nCARISMA 18 (+4)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 97 (13d8 + 39)\nVelocità 9 m, volo 9 m\nTiri Salvezza Costituzione +5, Saggezza +7, Carisma +6\nResistenze al Danno radiante\nImmunità al Danno psichico; contundente, perforante e\ntagliente di attacchi non magici\nSensi visione del vero 36 m, Percezione passiva 15\nLinguaggi tutte, telepatia 36 m\nSfida 4 (1.100 PE)\nArmi Magiche. Gli attacchi con armi del couatl sono magici.\nIncantesimi Innati. La caratteristica da incantatore innato del\ncouatl è il Carisma (CD dei tiri salvezza degli incantesimi 14). Il\ncouatl può lanciare questi incantesimi in maniera innata, usando\nsolo componenti verbali:\nA volontà: individuazione del bene e del male, individuazione del\nmagico, individuazione dei pensieri\n3/giorno ciascuno: benedizione, creare cibo e acqua, cura ferite,\nprotezione dai veleni, ristorare inferiore, santuario, scudo\n1/giorno ciascuno: ristorare superiore, scrutare, sogno\nMente Protetta. Il couatl è immune allo scrutare e qualsiasi\neffetto che percepisca le sue emozioni, legga i suoi pensieri o\nindividui la sua posizione.\nAzioni\nMorso. Attacco con arma da mischia: +8 a colpire, portata 1,5\nm, una creatura.\nColpisce: 8 (1d6 + 5) danni perforanti, e il bersaglio deve\nriuscire un tiro salvezza di Costituzione CD 13 o restare\navvelenato per 24 ore. Fino al termine dell''avvelenamento, il\nbersaglio è privo di sensi. Un''altra creatura può effettuare\nun''azione per risvegliare il bersaglio.\nStritolare. Attacco con arma da mischia: +6 a colpire, portata 3\nm, una creatura di taglia Media o inferiore.\nColpisce: 10 (2d6 + 3) danni contundenti, e il bersaglio è afferrato\n(CD 15 per fuggire). Fino al termine dell''afferrare, il bersaglio è\nintralciato, e il couatl non può stritolare un altro bersaglio.\nMutare Forma. Il couatl può trasformarsi magicamente in un\numanoide o bestia il cui grado di sfida sia pari o inferiore al proprio,\no tornare alla sua vera forma. Alla morte ritorna alla sua vera forma.\nQualsiasi equipaggiamento stia indossando o trasportando viene\nassorbito o trasportato nella nuova forma (a scelta del couatl).\nNella nuova forma, il couatl mantiene le sue statistiche di gioco e la\nfacoltà di parlare, ma la sua CA, metodi di movimento, Forza,\nDestrezza e altre azioni vengono rimpiazzati da quelli della nuova\nforma, e ottiene qualsiasi statistica o capacità (eccetto i privilegi di\nclasse, azioni leggendarie e azioni da tana) possedute dalla sua nuova\nforma e non dalla sua originale. Se la nuova forma ha un attacco di\nmorso, il couatl può usare il proprio morso nella nuova forma."}}', '2026-03-30T15:54:05.283Z', '2026-03-30T16:00:32.243Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jdWJvLWdlbGF0aW5vc28uanNvbg', 'cubo-gelatinoso', 'Cubo Gelatinoso', 'SRD', 'srd-extracted/cubo-gelatinoso.json', '2', 2, 450, 'Grande', 'melma', 'disallineato', '{"slug":"cubo-gelatinoso","general":{"name":"Cubo Gelatinoso","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"melma","subtype":"","typeLabel":"melma","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":6,"note":""},"hitPoints":{"average":84,"formula":"8d10 + 40"},"speed":{"walk":"5 m"}},"abilities":{"strength":14,"dexterity":3,"constitution":20,"intelligence":1,"wisdom":6,"charisma":1},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":["accecato","affascinato","assordato"],"senses":[{"name":"vista cieca 18 m (cieca oltre questo raggio)"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[{"name":"Cubo di Melma","usage":null,"description":"Il cubo occupa il suo intero spazio. Le altre creature possono entrare nello spazio, ma rimangono vittima del"},{"name":"Sommergere del cubo e hanno svantaggio al tiro salvezza","usage":null,"description":"Le creature all''interno del cubo sono visibili ma godono di copertura totale. Una creatura entro 1,5 metri dal cubo può effettuare un''azione per tirare una creatura od oggetto fuori dal cubo. Farlo richiede la riuscita di una prova di Forza CD 12, e la creatura che effettua il tentativo subisce 10 (3d6) danni da acido. Il cubo può contenere solo una creatura Grande o un massimo di quattro creature Medie o più piccole alla volta."},{"name":"Natura di Melma","usage":null,"description":"Il cubo non necessita di dormire."},{"name":"Trasparente","usage":null,"description":"Anche quando è in piena vista, è necessario riuscire una prova di Saggezza (Percezione) CD 15 per notare un cubo che non si è mosso o non ha attaccato. Una creatura che cerchi di entrare nello spazio del cubo mentre è inconsapevole della sua presenza resta sorpresa dal cubo."}],"actions":[{"name":"Pseudopodo","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (3d6) danni da acido."},{"name":"Sommergere","usage":null,"description":"Il cubo si muove fino al massimo della sua velocità. Nel farlo, può entrare nello spazio di una creatura di taglia Grande o più piccola. Ogni volta che il cubo entra nello spazio di una creatura, la creatura deve effettuare un tiro salvezza di Destrezza CD 12. Se il tiro salvezza riesce, la creatura può scegliere di essere spinta indietro o di lato di 1,5 metri. Una creatura che decida di non farsi spingere subisce le conseguenze di un tiro salvezza fallito. Se il tiro salvezza fallisce, il cubo entra nello spazio della creatura, che subisce 10 (3d6) danni da acido ed è sommersa. La creatura sommersa non può respirare, è intralciata e subisce 21 (6d6) danni da acido all''inizio del turno del cubo. Quando il cubo si muove, la creatura sommersa si muove con esso. Una creatura sommersa può tentare di fuggire effettuando un''azione per compiere una prova di Forza CD 12. Se la riesce, la creatura sfugge e ed entra nello spazio di sua scelta entro 1,5 metri dal cubo."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cubo Gelatinoso\nGrande melma, disallineato\nFORZA 14 (+2)\nDESTREZZA 3 (-4)\nCOSTITUZIONE 20 (+5)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 6 (-2)\nCARISMA 1 (-5)\nClasse Armatura 6\nPunti Ferita 84 (8d10 + 40)\nVelocità 4,5 m\nImmunità alle Condizioni accecato, affascinato, assordato,\nprono, sfinimento, spaventato\nSensi vista cieca 18 m (cieca oltre questo raggio), Percezione\npassiva 8\nLinguaggi -\nSfida 2 (450 PE)\nCubo di Melma. Il cubo occupa il suo intero spazio. Le altre\ncreature possono entrare nello spazio, ma rimangono vittima del\nSommergere del cubo e hanno svantaggio al tiro salvezza.\nLe creature all''interno del cubo sono visibili ma godono di\ncopertura totale.\nUna creatura entro 1,5 metri dal cubo può effettuare un''azione\nper tirare una creatura od oggetto fuori dal cubo. Farlo richiede la\nriuscita di una prova di Forza CD 12, e la creatura che effettua il\ntentativo subisce 10 (3d6) danni da acido.\nIl cubo può contenere solo una creatura Grande o un massimo di\nquattro creature Medie o più piccole alla volta.\nNatura di Melma. Il cubo non necessita di dormire.\nTrasparente. Anche quando è in piena vista, è necessario riuscire\nuna prova di Saggezza (Percezione) CD 15 per notare un cubo\nche non si è mosso o non ha attaccato. Una creatura che cerchi di\nentrare nello spazio del cubo mentre è inconsapevole della sua\npresenza resta sorpresa dal cubo.\nAzioni\nPseudopodo. Attacco con arma da mischia: +4 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 10 (3d6) danni da acido.\nSommergere. Il cubo si muove fino al massimo della sua velocità.\nNel farlo, può entrare nello spazio di una creatura di taglia Grande o\npiù piccola. Ogni volta che il cubo entra nello spazio di una creatura,\nla creatura deve effettuare un tiro salvezza di Destrezza CD 12.\nSe il tiro salvezza riesce, la creatura può scegliere di essere spinta\nindietro o di lato di 1,5 metri. Una creatura che decida di non farsi\nspingere subisce le conseguenze di un tiro salvezza fallito.\nSe il tiro salvezza fallisce, il cubo entra nello spazio della creatura,\nche subisce 10 (3d6) danni da acido ed è sommersa. La creatura\nsommersa non può respirare, è intralciata e subisce 21 (6d6) danni da\nacido all''inizio del turno del cubo. Quando il cubo si muove, la\ncreatura sommersa si muove con esso.\nUna creatura sommersa può tentare di fuggire effettuando un''azione\nper compiere una prova di Forza CD 12. Se la riesce, la creatura\nsfugge e ed entra nello spazio di sua scelta entro 1,5 metri dal cubo."}}', '2026-03-30T15:54:05.416Z', '2026-03-30T16:00:32.353Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jdWx0aXN0YS5qc29u', 'cultista', 'Cultista', 'SRD', 'srd-extracted/cultista.json', '1/8', 0.125, 25, NULL, NULL, NULL, '{"slug":"cultista","general":{"name":"Cultista","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura di cuoio"},"hitPoints":{"average":9,"formula":"2d8"},"speed":{"walk":"9 m"}},"abilities":{"strength":11,"dexterity":12,"constitution":10,"intelligence":10,"wisdom":11,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Raggiro","bonus":2},{"name":"Religione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Oscura Devozione","usage":null,"description":"Il cultista ha vantaggio sui tiri salvezza contro l''essere affascinato o spaventato."}],"actions":[{"name":"Randello","usage":null,"description":"Attacco con Arma da Mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 2 (1d4) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cultista\nI cultisti giurano fedeltà ai poteri oscuri, e nelle loro\ncredenze e pratiche mostrano spesso segni di follia.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento non\nbuono\nFORZA 11 (+0)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 11 (+0)\nCARISMA 10 (+0)\nClasse Armatura 12 (armatura di cuoio)\nPunti Ferita 9 (2d8)\nVelocità 9 m\nAbilità Raggiro +2, Religione +2\nSensi Percezione passiva 10\nLingue una qualsiasi lingua (di solito il Comune)\nSfida 1/8 (25 PE)\nOscura Devozione. Il cultista ha vantaggio sui tiri salvezza\ncontro l''essere affascinato o spaventato.\nAzioni\nScimitarra. Attacco con Arma da Mischia: +3 a colpire, portata\n1,5 m, una creatura.\nColpisce: 4 (1d6 + 1) danni taglienti.\nAccolito\nGli accoliti sono membri di grado minore del clero, e di\nsolito rispondono ad un sacerdote di rango superiore.\nSvolgono diverse funzioni in un tempio e gli viene\nconferita dalla loro divinità l''abilità di eseguire\nincantesimi minori.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 10 (+0)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 14 (+2)\nCARISMA 11 (+0)\nClasse Armatura 10\nPunti Ferita 9 (2d8)\nVelocità 9 m\nAbilità Medicina +4, Religione +2\nSensi Percezione passiva 12\nLingue una qualsiasi lingua (di solito il Comune)\nSfida 1/4 (50 PE)\nIncantesimi. L''accolito è un incantatore di 1° livello. La sua\nabilità da incantatore è la Saggezza (CD dei tiri salvezza degli\nincantesimi 12, +4 al colpire con attacchi con incantesimo).\nL''accolito ha preparato i seguenti incantesimi da chierico:\nTrucchetti (a volontà): fiamma sacra, luce, taumaturgia\n1° livello (3 slot): benedizione, cura ferite, santuario\nAzioni\nRandello. Attacco con Arma da Mischia: +2 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 2 (1d4) danni contundenti."}}', '2026-03-30T15:54:05.583Z', '2026-03-30T16:00:32.494Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jdW11bG8tc3RyaXNjaWFudGUuanNvbg', 'cumulo-strisciante', 'Cumulo Strisciante', 'SRD', 'srd-extracted/cumulo-strisciante.json', '5', 5, 1800, 'Grande', 'pianta', 'disallineato', '{"slug":"cumulo-strisciante","general":{"name":"Cumulo Strisciante","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Grande","creatureType":"pianta","subtype":"","typeLabel":"pianta","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":136,"formula":"16d10 + 48"},"speed":{"walk":"6 m","swim":"6 m"}},"abilities":{"strength":18,"dexterity":8,"constitution":16,"intelligence":5,"wisdom":10,"charisma":5},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":2}],"damageVulnerabilities":[],"damageResistances":["freddo","fuoco"],"damageImmunities":["fulmine"],"conditionImmunities":["accecato","assordato","sfinimento"],"senses":[{"name":"vista cieca 18 m (cieco oltre questo raggio)"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":3},"traits":[{"name":"Assorbimento dei Fulmini","usage":null,"description":"Ogni qual volta il cumulo strisciante subisce danni da fulmine, non subisce danni e recupera un numero di punti ferita pari al danno da fulmine inferto."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il cumulo strisciante effettua due attacchi di schianto. Se entrambi gli attacchi colpiscono una creatura di taglia Media o inferiore, il bersaglio è afferrato (CD 14 per fuggire) e il cumulo strisciante usa Avvolgere su di esso."},{"name":"Schianto","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (2d8 + 4) danni contundenti."},{"name":"Avvolgere","usage":null,"description":"Il cumulo strisciante avvolge una creatura di taglia"},{"name":"Media o inferiore che ha afferrato","usage":null,"description":"Il bersaglio avvolto è accecato, intralciato e impossibilitato a respirare, e deve riuscire un tiro salvezza di Costituzione CD 14 all''inizio di ciascun turno del tumulo o subire 13 (2d8 + 4) danni contundenti. Se il cumulo si muove, il bersaglio avvolto si muove con esso. Il cumulo può avvolgere solo una creatura alla volta."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cumulo Strisciante\nGrande pianta, disallineato\nFORZA 18 (+4)\nDESTREZZA 8 (-1)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 5 (-3)\nSAGGEZZA 10 (+0)\nCARISMA 5 (-3)\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 136 (16d10 + 48)\nVelocità 6 m, nuoto 6 m\nAbilità Furtività +2\nResistenze al Danno freddo, fuoco\nImmunità al Danno fulmine\nImmunità alle Condizioni accecato, assordato, sfinimento\nSensi vista cieca 18 m (cieco oltre questo raggio), Percezione\npassiva 10\nLinguaggi -\nSfida 5 (1.800 PE)\nAssorbimento dei Fulmini. Ogni qual volta il cumulo strisciante\nsubisce danni da fulmine, non subisce danni e recupera un\nnumero di punti ferita pari al danno da fulmine inferto.\nAzioni\nMultiattacco. Il cumulo strisciante effettua due attacchi di\nschianto. Se entrambi gli attacchi colpiscono una creatura di\ntaglia Media o inferiore, il bersaglio è afferrato (CD 14 per\nfuggire) e il cumulo strisciante usa Avvolgere su di esso.\nSchianto. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 13 (2d8 + 4) danni contundenti.\nAvvolgere. Il cumulo strisciante avvolge una creatura di taglia\nMedia o inferiore che ha afferrato. Il bersaglio avvolto è\naccecato, intralciato e impossibilitato a respirare, e deve riuscire\nun tiro salvezza di Costituzione CD 14 all''inizio di ciascun turno\ndel tumulo o subire 13 (2d8 + 4) danni contundenti. Se il cumulo\nsi muove, il bersaglio avvolto si muove con esso. Il cumulo può\navvolgere solo una creatura alla volta."}}', '2026-03-30T15:54:05.284Z', '2026-03-30T16:00:32.243Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kZXN0cmllcm8tZGEtaW5jdWJvLmpzb24', 'destriero-da-incubo', 'Destriero da Incubo', 'SRD', 'srd-extracted/destriero-da-incubo.json', '3', 3, 700, 'Grande', 'immondo', 'neutrale malvagio', '{"slug":"destriero-da-incubo","general":{"name":"Destriero da Incubo","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"Grande","creatureType":"immondo","subtype":"","typeLabel":"immondo","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":68,"formula":"8d10 + 24"},"speed":{"walk":"18 m","fly":"24 m"}},"abilities":{"strength":18,"dexterity":15,"constitution":16,"intelligence":10,"wisdom":13,"charisma":15},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fuoco"],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 11"}],"languages":[{"name":"comprende Abissale"},{"name":"Comune e Infernale ma non può"}],"proficiencyBonus":2},"traits":[{"name":"Conferire Resistenza al Fuoco","usage":null,"description":"Il destriero da incubo può conferire resistenza al danno da fuoco a chiunque lo cavalchi."},{"name":"Illuminazione","usage":null,"description":"Il destriero da incubo irradia luce intensa in un raggio di 3 metri e luce fioca per ulteriori 3 metri."}],"actions":[{"name":"Zoccoli","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (2d8 + 4) danni contundenti più 7 (2d6) danni da fuoco."},{"name":"Passo Etereo","usage":null,"description":"Il destriero da incubo e fino a tre creature consenzienti entro 1,5 metri da esso possono entrare magicamente nel Piano Etereo dal Piano Materiale e viceversa."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Destriero da Incubo\nGrande immondo, neutrale malvagio\nFORZA 18 (+4)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 13 (+1)\nCARISMA 15 (+2)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 68 (8d10 + 24)\nVelocità 18 m, volo 24 m\nImmunità al Danno fuoco\nSensi Percezione passiva 11\nLinguaggi comprende Abissale, Comune e Infernale ma non può\nparlare\nSfida 3 (700 PE)\nConferire Resistenza al Fuoco. Il destriero da incubo può\nconferire resistenza al danno da fuoco a chiunque lo cavalchi.\nIlluminazione. Il destriero da incubo irradia luce intensa in un\nraggio di 3 metri e luce fioca per ulteriori 3 metri.\nAzioni\nZoccoli. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 13 (2d8 + 4) danni contundenti più 7 (2d6) danni da\nfuoco.\nPasso Etereo. Il destriero da incubo e fino a tre creature\nconsenzienti entro 1,5 metri da esso possono entrare\nmagicamente nel Piano Etereo dal Piano Materiale e viceversa."}}', '2026-03-30T15:54:05.292Z', '2026-03-30T16:00:32.250Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaWF2b2xvLWJhcmJ1dG8uanNvbg', 'diavolo-barbuto', 'Diavolo Barbuto', 'SRD', 'srd-extracted/diavolo-barbuto.json', '3', 3, 700, 'Media', 'immondo', 'legale malvagio', '{"slug":"diavolo-barbuto","general":{"name":"Diavolo Barbuto","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"Media","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":52,"formula":"8d8 + 16"},"speed":{"walk":"9 m"}},"abilities":{"strength":16,"dexterity":15,"constitution":15,"intelligence":9,"wisdom":11,"charisma":11},"details":{"savingThrows":[{"ability":"Forza","bonus":5},{"ability":"Costituzione","bonus":4},{"ability":"Saggezza","bonus":2}],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo; contundente","perforante e tagliente"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 10"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":2},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Il diavolo ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Risoluto","usage":null,"description":"Il diavolo non può essere spaventato finché riesce a vedere una creatura alleata entro 9 metri da lui."},{"name":"Vista del Diavolo","usage":null,"description":"La scurovisione del diavolo non è limitata dall''oscurità magica."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il diavolo effettua due attacchi: uno con la barba e uno con il falcione."},{"name":"Barba","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, una creatura. Colpisce: 6 (1d8 + 2) danni perforanti, e il bersaglio deve riuscire un tiro salvezza di Costituzione CD 12 o restare avvelenato per 1 minuto. Mentre è avvelenato in questo modo, il bersaglio non può recuperare punti ferita. Il bersaglio può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto se riesce il tiro salvezza."},{"name":"Falcione","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 3 m, un bersaglio. Colpisce: 8 (1d10 + 3) danni taglienti. Se il bersaglio è una creatura, ad esclusione di costrutti e non morti, deve riuscire un tiro salvezza di Costituzione CD 12 o perdere 5 (1d10) punti ferita all''inizio di ciascun suo turno a causa della ferita infernale. Ogni volta che il diavolo colpisce il bersaglio ferito con questo attacco, il danno inflitto dalla ferita aumenta di 5 (1d10). Qualsiasi creatura può effettuare un''azione per bloccare la ferita con una prova riuscita di Saggezza (Medicina) CD 12. La ferita si richiude anche nel caso in cui il bersaglio riceva della magia guaritrice."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Diavolo Barbuto\nMedia immondo (diavolo), legale malvagio\nFORZA 16 (+3)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 9 (-1)\nSAGGEZZA 11 (+0)\nCARISMA 11 (+0)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 52 (8d8 + 16)\nVelocità 9 m\nTiri Salvezza Forza +5, Costituzione +4, Saggezza +2\nResistenze al Danno freddo; contundente, perforante e tagliente\ndi attacchi non magici che non siano argentati\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 36 m, Percezione passiva 10\nLinguaggi Infernale, telepatia 36 m\nSfida 3 (700 PE)\nResistenza alla Magia. Il diavolo ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nRisoluto. Il diavolo non può essere spaventato finché riesce a\nvedere una creatura alleata entro 9 metri da lui.\nVista del Diavolo. La scurovisione del diavolo non è limitata\ndall''oscurità magica.\nAzioni\nMultiattacco. Il diavolo effettua due attacchi: uno con la barba e\nuno con il falcione.\nBarba. Attacco con arma da mischia: +5 a colpire, portata 1,5 m,\nuna creatura.\nColpisce: 6 (1d8 + 2) danni perforanti, e il bersaglio deve\nriuscire un tiro salvezza di Costituzione CD 12 o restare\navvelenato per 1 minuto. Mentre è avvelenato in questo modo, il\nbersaglio non può recuperare punti ferita. Il bersaglio può\nripetere il tiro salvezza al termine di ciascun suo turno,\nterminando l''effetto se riesce il tiro salvezza.\nFalcione. Attacco con arma da mischia: +5 a colpire, portata 3\nm, un bersaglio.\nColpisce: 8 (1d10 + 3) danni taglienti. Se il bersaglio è una\ncreatura, ad esclusione di costrutti e non morti, deve riuscire un\ntiro salvezza di Costituzione CD 12 o perdere 5 (1d10) punti\nferita all''inizio di ciascun suo turno a causa della ferita infernale.\nOgni volta che il diavolo colpisce il bersaglio ferito con questo\nattacco, il danno inflitto dalla ferita aumenta di 5 (1d10).\nQualsiasi creatura può effettuare un''azione per bloccare la ferita\ncon una prova riuscita di Saggezza (Medicina) CD 12. La ferita\nsi richiude anche nel caso in cui il bersaglio riceva della magia\nguaritrice."}}', '2026-03-30T15:54:05.293Z', '2026-03-30T16:00:32.250Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaWF2b2xvLWNvcm51dG8uanNvbg', 'diavolo-cornuto', 'Diavolo Cornuto', 'SRD', 'srd-extracted/diavolo-cornuto.json', '11', 11, 7200, 'Grande', 'immondo', 'legale malvagio', '{"slug":"diavolo-cornuto","general":{"name":"Diavolo Cornuto","challengeRating":{"fraction":"11","decimal":11,"display":"11","xp":7200},"size":"Grande","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":18,"note":"armatura naturale"},"hitPoints":{"average":178,"formula":"17d10 + 85"},"speed":{"walk":"6 m","fly":"18 m"}},"abilities":{"strength":22,"dexterity":17,"constitution":21,"intelligence":12,"wisdom":16,"charisma":17},"details":{"savingThrows":[{"ability":"Forza","bonus":10},{"ability":"Destrezza","bonus":7},{"ability":"Saggezza","bonus":7},{"ability":"Carisma","bonus":0}],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo; contundente","perforante e tagliente"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":4},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Il diavolo ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Vista del Diavolo","usage":null,"description":"La scurovisione del diavolo non è limitata dall''oscurità magica."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il diavolo effettua tre attacchi da mischia: due con il forcone e uno con la coda. Può usare Scagliare Fiamma al posto di qualsiasi attacco da mischia."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 3 m, un bersaglio. Colpisce: 10 (1d8 + 6) danni perforanti. Se il bersaglio è una creatura, ad esclusione di costrutti e non morti, deve riuscire un tiro salvezza di Costituzione CD 17 o perdere 10 (3d6) punti ferita all''inizio di ciascun suo turno a causa della ferita infernale. Ogni volta che il diavolo ferisce il bersaglio con questo attacco, il danno inflitto dalla ferita aumenta di 10 (3d6). Qualsiasi creatura può effettuare un''azione per bloccare la ferita riuscendo una prova di Saggezza (Medicina) CD 12. La ferita si richiude anche nel caso in cui il bersaglio riceva magia guaritrice."},{"name":"Forcone","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 3 m, un bersaglio. Colpisce: 15 (2d8 + 6) danni perforanti."},{"name":"Pungiglione","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 3 m, un bersaglio. Colpisce: 13 (2d8 + 4) danni perforanti più 17 (5d6) danni da veleno, e il bersaglio deve riuscire un tiro salvezza di"},{"name":"Costituzione CD 14, o restare avvelenato per 1 minuto","usage":null,"description":"Il bersaglio può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto se lo riesce."},{"name":"Scagliare Fiamma","usage":null,"description":"Attacco con incantesimo a Distanza: +7 a colpire, gittata 45 m, un bersaglio. Colpisce: 14 (4d6) danni da fuoco. Se il bersaglio è un oggetto infiammabile che non sia indossato o trasportato, prende fuoco."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Diavolo Cornuto\nGrande immondo (diavolo), legale malvagio\nFORZA 22 (+6)\nDESTREZZA 17 (+3)\nCOSTITUZIONE 21 (+5)\nINTELLIGENZA 12 (+1)\nSAGGEZZA 16 (+3)\nCARISMA 17 (+3)\nClasse Armatura 18 (armatura naturale)\nPunti Ferita 178 (17d10 + 85)\nVelocità 6 m, volo 18 m\nTiri Salvezza Forza +10, Destrezza +7, Saggezza +7, Carisma\n+7\nResistenze al Danno freddo; contundente, perforante e tagliente\ndi attacchi non magici che non siano argentati\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 36 m, Percezione passiva 13\nLinguaggi Infernale, telepatia 36 m\nSfida 11 (7.200 PE)\nResistenza alla Magia. Il diavolo ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nVista del Diavolo. La scurovisione del diavolo non è limitata\ndall''oscurità magica.\nAzioni\nMultiattacco. Il diavolo effettua tre attacchi da mischia: due con\nil forcone e uno con la coda. Può usare Scagliare Fiamma al\nposto di qualsiasi attacco da mischia.\nCoda. Attacco con arma da mischia: +10 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 10 (1d8 + 6) danni perforanti. Se il bersaglio è una\ncreatura, ad esclusione di costrutti e non morti, deve riuscire un\ntiro salvezza di Costituzione CD 17 o perdere 10 (3d6) punti\nferita all''inizio di ciascun suo turno a causa della ferita infernale.\nOgni volta che il diavolo ferisce il bersaglio con questo attacco,\nil danno inflitto dalla ferita aumenta di 10 (3d6). Qualsiasi\ncreatura può effettuare un''azione per bloccare la ferita riuscendo\nuna prova di Saggezza (Medicina) CD 12. La ferita si richiude\nanche nel caso in cui il bersaglio riceva magia guaritrice.\nForcone. Attacco con arma da mischia: +10 a colpire, portata 3\nm, un bersaglio.\nColpisce: 15 (2d8 + 6) danni perforanti.\nPungiglione. Attacco con arma da mischia: +8 a colpire, portata\n3 m, un bersaglio.\nColpisce: 13 (2d8 + 4) danni perforanti più 17 (5d6) danni da\nveleno, e il bersaglio deve riuscire un tiro salvezza di\nCostituzione CD 14, o restare avvelenato per 1 minuto. Il\nbersaglio può ripetere il tiro salvezza al termine di ciascun suo\nturno, terminando l''effetto se lo riesce.\nScagliare Fiamma. Attacco con incantesimo a Distanza: +7 a\ncolpire, gittata 45 m, un bersaglio.\nColpisce: 14 (4d6) danni da fuoco. Se il bersaglio è un oggetto\ninfiammabile che non sia indossato o trasportato, prende fuoco."}}', '2026-03-30T15:54:05.296Z', '2026-03-30T16:00:32.254Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaWF2b2xvLWQtb3NzYS5qc29u', 'diavolo-d-ossa', 'Diavolo d''Ossa', 'SRD', 'srd-extracted/diavolo-d-ossa.json', '9', 9, 5000, 'Grande', 'immondo', 'legale malvagio', '{"slug":"diavolo-d-ossa","general":{"name":"Diavolo d''Ossa","challengeRating":{"fraction":"9","decimal":9,"display":"9","xp":5000},"size":"Grande","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":142,"formula":"15d10 + 60"},"speed":{"walk":"12 m","fly":"12 m"}},"abilities":{"strength":18,"dexterity":16,"constitution":18,"intelligence":13,"wisdom":14,"charisma":16},"details":{"savingThrows":[{"ability":"Intelligenza","bonus":5},{"ability":"Saggezza","bonus":6},{"ability":"Carisma","bonus":7}],"skills":[{"name":"Inganno","bonus":7},{"name":"Intuizione","bonus":6}],"damageVulnerabilities":[],"damageResistances":["freddo; contundente","perforante e tagliente"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 12"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":4},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Il diavolo ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Vista del Diavolo","usage":null,"description":"La scurovisione del diavolo non è limitata dall''oscurità magica."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il diavolo effettua tre attacchi: due con gli artigli e uno con il pungiglione oppure uno con la sua arma inastata uncinata e uno con il pungiglione."},{"name":"Arma Inastata Uncinata","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 3 m, un bersaglio. Colpisce: 17 (2d12 + 4) danni perforanti. Se il bersaglio è una creatura di taglia Enorme o inferiore, è afferrato (CD 14 per fuggire). Fino al termine dell''afferrare, il diavolo non può usare la sua arma inastata su di un altro bersaglio."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 3 m, un bersaglio. Colpisce: 8 (1d8 + 4) danni taglienti."},{"name":"Pungiglione","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 3 m, un bersaglio. Colpisce: 13 (2d8 + 4) danni perforanti più 17 (5d6) danni da veleno, e il bersaglio deve riuscire un tiro salvezza di"},{"name":"Costituzione CD 14, o restare avvelenato per 1 minuto","usage":null,"description":"Il bersaglio può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Diavolo d''Ossa\nGrande immondo (diavolo), legale malvagio\nFORZA 18 (+4)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 13 (+1)\nSAGGEZZA 14 (+2)\nCARISMA 16 (+3)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 142 (15d10 + 60)\nVelocità 12 m, volo 12 m\nTiri Salvezza Intelligenza +5, Saggezza +6, Carisma +7\nAbilità Inganno +7, Intuizione +6\nResistenze al Danno freddo; contundente, perforante e tagliente\ndi attacchi non magici che non siano argentati\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 36 m, Percezione passiva 12\nLinguaggi Infernale, telepatia 36 m\nSfida 9 (5.000 PE)\nResistenza alla Magia. Il diavolo ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nVista del Diavolo. La scurovisione del diavolo non è limitata\ndall''oscurità magica.\nAzioni\nMultiattacco. Il diavolo effettua tre attacchi: due con gli artigli e\nuno con il pungiglione oppure uno con la sua arma inastata\nuncinata e uno con il pungiglione.\nArma Inastata Uncinata. Attacco con arma da mischia: +8 a\ncolpire, portata 3 m, un bersaglio.\nColpisce: 17 (2d12 + 4) danni perforanti. Se il bersaglio è una\ncreatura di taglia Enorme o inferiore, è afferrato (CD 14 per\nfuggire). Fino al termine dell''afferrare, il diavolo non può usare\nla sua arma inastata su di un altro bersaglio.\nArtiglio. Attacco con arma da mischia: +8 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 8 (1d8 + 4) danni taglienti.\nPungiglione. Attacco con arma da mischia: +8 a colpire, portata\n3 m, un bersaglio.\nColpisce: 13 (2d8 + 4) danni perforanti più 17 (5d6) danni da\nveleno, e il bersaglio deve riuscire un tiro salvezza di\nCostituzione CD 14, o restare avvelenato per 1 minuto. Il\nbersaglio può ripetere il tiro salvezza al termine di ciascun suo\nturno, terminando l''effetto se lo riesce."}}', '2026-03-30T15:54:05.299Z', '2026-03-30T16:00:32.256Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaWF2b2xvLWRlbC1naGlhY2Npby5qc29u', 'diavolo-del-ghiaccio', 'Diavolo del Ghiaccio', 'SRD', 'srd-extracted/diavolo-del-ghiaccio.json', '14', 14, 11500, 'Grande', 'immondo', 'legale malvagio', '{"slug":"diavolo-del-ghiaccio","general":{"name":"Diavolo del Ghiaccio","challengeRating":{"fraction":"14","decimal":14,"display":"14","xp":11500},"size":"Grande","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":18,"note":"armatura naturale"},"hitPoints":{"average":180,"formula":"19d10 + 76"},"speed":{"walk":"12 m"}},"abilities":{"strength":21,"dexterity":14,"constitution":18,"intelligence":18,"wisdom":15,"charisma":18},"details":{"savingThrows":[{"ability":"Destrezza","bonus":7},{"ability":"Costituzione","bonus":9},{"ability":"Saggezza","bonus":7}],"skills":[],"damageVulnerabilities":[],"damageResistances":["contundente","perforante e tagliente di"],"damageImmunities":["freddo","fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"vista cieca","value":"18 m"},{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 12"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":5},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Il diavolo ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Vista del Diavolo","usage":null,"description":"La scurovisione del diavolo non è limitata dall''oscurità magica."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il diavolo effettua tre attacchi: uno con il morso, uno con gli artigli e uno con la coda. In alternativa effettua due attacchi: uno con la coda e uno con lancia."},{"name":"Artigli","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d4 + 5) danni taglienti più 10 (3d6) danni da freddo."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 3 m, un bersaglio. Colpisce: 12 (2d6 + 5) danni contundenti più 10 (3d6) danni da freddo."},{"name":"Lancia di Ghiaccio","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 3 m, un bersaglio. Colpisce: 14 (2d8 + 5) danni perforanti più 10 (3d6) danni da freddo. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Costituzione CD 15, o avere per 1 minuto la velocità ridotta di 3 metri; durante ciascun suo turno può effettuare solo un''azione o un''azione bonus, ma non entrambe; non può effettuare reazioni. Il bersaglio può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto su di sé in caso di successo."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 1,5 m, un bersaglio. Colpisce: 12 (2d6 + 5) danni perforanti più 10 (3d6) danni da freddo."},{"name":"Muro di Ghiaccio","usage":"Ricarica 6","description":"Il diavolo forma magicamente un muro di ghiaccio opaco su di una superficie solida che possa vedere entro 18 metri da lui. Il muro è spesso 30 centimetri e largo fino a 9 metri per un massimo di 3 metri di altezza, oppure è una cupola semisferica di massimo 6 metri di diametro. Quando la parete appare, ogni creatura nel suo spazio viene spinta fuori da esso tramite la via più breve. La creatura sceglie su quale lato del muro finire, a meno che la creatura non sia inabile. La creatura poi effettua un tiro salvezza di Destrezza CD 17, subendo 35 (10d6) danni da freddo se lo fallisce, o la metà di questi danni se lo riesce. Il muro rimane per 1 minuto o finché il diavolo non è reso inabile o muore. Il muro può essere danneggiato e bucato; ogni sezione di 3 metri ha CA 5, 30 punti ferita, vulnerabilità al danno da fuoco, e immunità al danno da acido, freddo, necrotico, psichico e da veleno. Se una sezione viene distrutta, lascia una patina di aria gelida nello spazio che occupava prima il muro. Ogni volta che una creatura finisce per muoversi attraverso quest''aria gelida durante un turno, consenziente o meno, deve effettuare un tiro salvezza di Costituzione CD 17, subendo 17 (5d6) danni da freddo se lo fallisce, o la metà di questi danni se lo riesce. L''aria gelida si dissipa quando il resto del muro svanisce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Diavolo del Ghiaccio\nGrande immondo (diavolo), legale malvagio\nFORZA 21 (+5)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 18 (+4)\nSAGGEZZA 15 (+2)\nCARISMA 18 (+4)\nClasse Armatura 18 (armatura naturale)\nPunti Ferita 180 (19d10 + 76)\nVelocità 12 m\nTiri Salvezza Destrezza +7, Costituzione +9, Saggezza +7,\nCarisma +9\nResistenze al Danno contundente, perforante e tagliente di\nattacchi non magici che non siano argentate\nImmunità al Danno freddo, fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi vista cieca 18 m, scurovisione 36 m, Percezione passiva 12\nLinguaggi Infernale, telepatia 36 m\nSfida 14 (11.500 PE)\nResistenza alla Magia. Il diavolo ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nVista del Diavolo. La scurovisione del diavolo non è limitata\ndall''oscurità magica.\nAzioni\nMultiattacco. Il diavolo effettua tre attacchi: uno con il morso,\nuno con gli artigli e uno con la coda. In alternativa effettua due\nattacchi: uno con la coda e uno con lancia.\nArtigli. Attacco con arma da mischia: +10 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d4 + 5) danni taglienti più 10 (3d6) danni da\nfreddo.\nCoda. Attacco con arma da mischia: +10 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 12 (2d6 + 5) danni contundenti più 10 (3d6) danni da\nfreddo.\nLancia di Ghiaccio. Attacco con arma da mischia: +10 a colpire,\nportata 3 m, un bersaglio.\nColpisce: 14 (2d8 + 5) danni perforanti più 10 (3d6) danni da\nfreddo. Se il bersaglio è una creatura, deve riuscire un tiro\nsalvezza di Costituzione CD 15, o avere per 1 minuto la velocità\nridotta di 3 metri; durante ciascun suo turno può effettuare solo\nun''azione o un''azione bonus, ma non entrambe; non può\neffettuare reazioni. Il bersaglio può ripetere il tiro salvezza al\ntermine di ciascun suo turno, terminando l''effetto su di sé in caso\ndi successo.\nMorso. Attacco con arma da mischia: +10 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 12 (2d6 + 5) danni perforanti più 10 (3d6) danni da\nfreddo.\n\n-- 23 of 151 --\n\nSRD Italia 5a Edizione - Compendio dei Mostri\nMuro di Ghiaccio (Ricarica 6). Il diavolo forma magicamente\nun muro di ghiaccio opaco su di una superficie solida che possa\nvedere entro 18 metri da lui. Il muro è spesso 30 centimetri e\nlargo fino a 9 metri per un massimo di 3 metri di altezza, oppure\nè una cupola semisferica di massimo 6 metri di diametro.\nQuando la parete appare, ogni creatura nel suo spazio viene\nspinta fuori da esso tramite la via più breve. La creatura sceglie\nsu quale lato del muro finire, a meno che la creatura non sia\ninabile. La creatura poi effettua un tiro salvezza di Destrezza CD\n17, subendo 35 (10d6) danni da freddo se lo fallisce, o la metà di\nquesti danni se lo riesce.\nIl muro rimane per 1 minuto o finché il diavolo non è reso\ninabile o muore. Il muro può essere danneggiato e bucato; ogni\nsezione di 3 metri ha CA 5, 30 punti ferita, vulnerabilità al danno\nda fuoco, e immunità al danno da acido, freddo, necrotico,\npsichico e da veleno. Se una sezione viene distrutta, lascia una\npatina di aria gelida nello spazio che occupava prima il muro.\nOgni volta che una creatura finisce per muoversi attraverso\nquest''aria gelida durante un turno, consenziente o meno, deve\neffettuare un tiro salvezza di Costituzione CD 17, subendo 17\n(5d6) danni da freddo se lo fallisce, o la metà di questi danni se\nlo riesce. L''aria gelida si dissipa quando il resto del muro\nsvanisce."}}', '2026-03-30T15:54:05.297Z', '2026-03-30T16:00:32.255Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaWF2b2xvLWRlbGxhLWZvc3NhLmpzb24', 'diavolo-della-fossa', 'Diavolo della Fossa', 'SRD', 'srd-extracted/diavolo-della-fossa.json', '20', 20, 25000, 'Grande', 'immondo', 'legale malvagio', '{"slug":"diavolo-della-fossa","general":{"name":"Diavolo della Fossa","challengeRating":{"fraction":"20","decimal":20,"display":"20","xp":25000},"size":"Grande","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":300,"formula":"24d10 + 168"},"speed":{"walk":"9 m","fly":"18 m"}},"abilities":{"strength":26,"dexterity":14,"constitution":24,"intelligence":22,"wisdom":18,"charisma":24},"details":{"savingThrows":[{"ability":"Destrezza","bonus":8},{"ability":"Costituzione","bonus":13},{"ability":"Saggezza","bonus":10}],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo; contundente","perforante e tagliente"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"visione del vero","value":"36 m"},{"name":"Percezione passiva 14"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":6},"traits":[{"name":"Arma Magica","usage":null,"description":"Gli attacchi con arma del diavolo della fossa sono magici."},{"name":"Aura di Paura","usage":null,"description":"Qualsiasi creatura ostile al diavolo che inizi il suo turno entro 6 metri da esso, deve effettuare un tiro salvezza di Saggezza CD 21, a meno che il diavolo non sia inabile. Se fallisce il tiro salvezza, la creatura è spaventata fino all''inizio del suo prossimo turno. Se il tiro salvezza della creatura riesce, la creatura è immune all''Aura di Paura del diavolo per le successive 24 ore."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore diavolo della fossa è il Carisma (CD dei tiri salvezza degli incantesimi 21). Il diavolo della fossa può lanciare questi incantesimi in maniera innata, senza bisogno di componenti materiali: A volontà: individuazione del magico, palla di fuoco 3/giorno ciascuno: blocca mostri, muro di fuoco"},{"name":"Resistenza alla Magia","usage":null,"description":"Il diavolo ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il diavolo effettua quattro attacchi: uno con il morso, uno con l''artiglio, uno con la mazza e uno con la coda."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 3 m, un bersaglio. Colpisce: 17 (2d8 + 8) danni taglienti."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 3 m, un bersaglio. Colpisce: 24 (3d10 + 8) danni contundenti."},{"name":"Mazza","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 3 m, un bersaglio. Colpisce: 15 (2d6 + 8) danni contundenti più 21 (6d6) danni da fuoco."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 1,5 m, un bersaglio. Colpisce: 22 (4d6 + 8) danni perforanti. Il bersaglio deve riuscire un tiro salvezza di Costituzione CD 21 o restare avvelenato. Mentre è avvelenato in questo modo, il bersaglio non può recuperare punti ferita, e subisce 21 (6d6) danni da veleno all''inizio di ciascun suo turno. Il bersaglio avvelenato può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto su di sé."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Diavolo della Fossa\nGrande immondo (diavolo), legale malvagio\nFORZA 26 (+8)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 24 (+7)\nINTELLIGENZA 22 (+6)\nSAGGEZZA 18 (+4)\nCARISMA 24 (+7)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 300 (24d10 + 168)\nVelocità 9 m, volo 18 m\nTiri Salvezza Destrezza +8, Costituzione +13, Saggezza +10\nResistenze al Danno freddo; contundente, perforante e tagliente\ndi attacchi non magici che non siano argentati\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi visione del vero 36 m, Percezione passiva 14\nLinguaggi Infernale, telepatia 36 m\nSfida 20 (25.000 PE)\nArma Magica. Gli attacchi con arma del diavolo della fossa sono\nmagici.\nAura di Paura. Qualsiasi creatura ostile al diavolo che inizi il\nsuo turno entro 6 metri da esso, deve effettuare un tiro salvezza\ndi Saggezza CD 21, a meno che il diavolo non sia inabile. Se\nfallisce il tiro salvezza, la creatura è spaventata fino all''inizio del\nsuo prossimo turno. Se il tiro salvezza della creatura riesce, la\ncreatura è immune all''Aura di Paura del diavolo per le\nsuccessive 24 ore.\nIncantesimi Innati. La caratteristica da incantatore diavolo della\nfossa è il Carisma (CD dei tiri salvezza degli incantesimi 21). Il\ndiavolo della fossa può lanciare questi incantesimi in maniera\ninnata, senza bisogno di componenti materiali:\nA volontà: individuazione del magico, palla di fuoco\n3/giorno ciascuno: blocca mostri, muro di fuoco\nResistenza alla Magia. Il diavolo ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nMultiattacco. Il diavolo effettua quattro attacchi: uno con il\nmorso, uno con l''artiglio, uno con la mazza e uno con la coda.\nArtiglio. Attacco con arma da mischia: +14 a colpire, portata 3\nm, un bersaglio.\nColpisce: 17 (2d8 + 8) danni taglienti.\nCoda. Attacco con arma da mischia: +14 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 24 (3d10 + 8) danni contundenti.\nMazza. Attacco con arma da mischia: +14 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 15 (2d6 + 8) danni contundenti più 21 (6d6) danni da\nfuoco.\nMorso. Attacco con arma da mischia: +14 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 22 (4d6 + 8) danni perforanti. Il bersaglio deve riuscire\nun tiro salvezza di Costituzione CD 21 o restare avvelenato.\nMentre è avvelenato in questo modo, il bersaglio non può\nrecuperare punti ferita, e subisce 21 (6d6) danni da veleno\nall''inizio di ciascun suo turno. Il bersaglio avvelenato può\nripetere il tiro salvezza al termine di ciascun suo turno,\nterminando l''effetto su di sé."}}', '2026-03-30T15:54:05.297Z', '2026-03-30T16:00:32.254Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaWF2b2xvLWRlbGxlLWNhdGVuZS5qc29u', 'diavolo-delle-catene', 'Diavolo delle Catene', 'SRD', 'srd-extracted/diavolo-delle-catene.json', '8', 8, 3900, 'Media', 'immondo', 'legale malvagio', '{"slug":"diavolo-delle-catene","general":{"name":"Diavolo delle Catene","challengeRating":{"fraction":"8","decimal":8,"display":"8","xp":3900},"size":"Media","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":16,"note":"armatura naturale"},"hitPoints":{"average":85,"formula":"10d8 + 40"},"speed":{"walk":"9 m"}},"abilities":{"strength":18,"dexterity":15,"constitution":18,"intelligence":11,"wisdom":12,"charisma":14},"details":{"savingThrows":[{"ability":"Costituzione","bonus":7},{"ability":"Saggezza","bonus":4},{"ability":"Carisma","bonus":5}],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo; contundente","perforante e tagliente"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 11"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":3},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Il diavolo ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Vista del Diavolo","usage":null,"description":"La scurovisione del diavolo non è limitata dall''oscurità magica."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il diavolo effettua due attacchi con la catena."},{"name":"Catena","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 3 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni taglienti. Il bersaglio è afferrato (CD 14 per fuggire) se il diavolo non sta già afferrando un''altra creatura. Fino al termine dell''afferrare, il bersaglio è intralciato e subisce 7 (2d6) danni perforanti all''inizio di ciascun suo turno."},{"name":"Animare Catene","usage":"Ricarica dopo un Riposo Breve o Lungo","description":"Fino a quattro catene che il diavolo possa vedere e si trovano entro 18 metri da lui producono dei bordi affilati e si animano sotto il controllo del diavolo, purché quelle catene non siano né indossate né trasportate da qualcun altro. Ogni catena animata è un oggetto con CA 20, 20 punti ferita, resistenza ai danni perforanti, e immunità ai danni psichici e da tuono. Quando il diavolo usa Multiattacco durante il suo turno, può usare ciascuna catena animata per effettuare un ulteriore attacco di catena. Una catena animata può afferrare una creatura per conto proprio ma non può effettuare attacchi mentre afferra. Una catena animata ritorna al suo stato inanimato se viene ridotta a 0 punti ferita o se il diavolo è reso inabile o muore."}],"bonusActions":[],"reactions":[{"name":"Maschera Snervante","usage":null,"description":"Quando una creatura che il diavolo può vedere inizia il proprio turno entro 9 metri dal diavolo, il diavolo può creare un''illusione per assomigliare all''amore perduto o un acerrimo rivale di quella creatura. Se la creatura può vedere il diavolo, deve riuscire un tiro salvezza di Saggezza CD 14 o rimanere spaventata fino al termine del suo turno."}],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Diavolo delle Catene\nMedia immondo (diavolo), legale malvagio\nFORZA 18 (+4)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 12 (+1)\nCARISMA 14 (+2)\nClasse Armatura 16 (armatura naturale)\nPunti Ferita 85 (10d8 + 40)\nVelocità 9 m\nTiri Salvezza Costituzione +7, Saggezza +4, Carisma +5\nResistenze al Danno freddo; contundente, perforante e tagliente\ndi attacchi non magici che non siano argentati\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 36 m, Percezione passiva 11\nLinguaggi Infernale, telepatia 36 m\nSfida 8 (3.900 PE)\nResistenza alla Magia. Il diavolo ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nVista del Diavolo. La scurovisione del diavolo non è limitata\ndall''oscurità magica.\nAzioni\nMultiattacco. Il diavolo effettua due attacchi con la catena.\nCatena. Attacco con arma da mischia: +8 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 11 (2d6 + 4) danni taglienti. Il bersaglio è afferrato\n(CD 14 per fuggire) se il diavolo non sta già afferrando un''altra\ncreatura. Fino al termine dell''afferrare, il bersaglio è intralciato e\nsubisce 7 (2d6) danni perforanti all''inizio di ciascun suo turno.\nAnimare Catene (Ricarica dopo un Riposo Breve o Lungo).\nFino a quattro catene che il diavolo possa vedere e si trovano\nentro 18 metri da lui producono dei bordi affilati e si animano\nsotto il controllo del diavolo, purché quelle catene non siano né\nindossate né trasportate da qualcun altro.\nOgni catena animata è un oggetto con CA 20, 20 punti ferita,\nresistenza ai danni perforanti, e immunità ai danni psichici e da\ntuono. Quando il diavolo usa Multiattacco durante il suo turno,\npuò usare ciascuna catena animata per effettuare un ulteriore\nattacco di catena. Una catena animata può afferrare una creatura\nper conto proprio ma non può effettuare attacchi mentre afferra.\nUna catena animata ritorna al suo stato inanimato se viene ridotta\na 0 punti ferita o se il diavolo è reso inabile o muore.\nReazioni\nMaschera Snervante. Quando una creatura che il diavolo può\nvedere inizia il proprio turno entro 9 metri dal diavolo, il diavolo\npuò creare un''illusione per assomigliare all''amore perduto o un\nacerrimo rivale di quella creatura. Se la creatura può vedere il\ndiavolo, deve riuscire un tiro salvezza di Saggezza CD 14 o\nrimanere spaventata fino al termine del suo turno."}}', '2026-03-30T15:54:05.294Z', '2026-03-30T16:00:32.252Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaWF2b2xvLXNwaW5vc28uanNvbg', 'diavolo-spinoso', 'Diavolo Spinoso', 'SRD', 'srd-extracted/diavolo-spinoso.json', '2', 2, 450, 'Piccola', 'immondo', 'legale malvagio', '{"slug":"diavolo-spinoso","general":{"name":"Diavolo Spinoso","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Piccola","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":22,"formula":"5d6 + 5"},"speed":{"walk":"6 m","fly":"12 m"}},"abilities":{"strength":10,"dexterity":15,"constitution":12,"intelligence":11,"wisdom":14,"charisma":8},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo; contundente","perforante e tagliente"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 18"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":2},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Il diavolo ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Sorvolare","usage":null,"description":"Il diavolo non provoca attacchi di opportunità quando vola via dalla portata di un nemico."},{"name":"Spine Limitate","usage":null,"description":"Il diavolo possiede dodici spine caudali. Le spine usate ricrescono al termine di un riposo lungo da parte del diavolo."},{"name":"Vista del Diavolo","usage":null,"description":"La scurovisione del diavolo non è limitata dall''oscurità magica."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il diavolo effettua due attacchi: uno con il morso e uno con il suo forcone o due con le sue spine caudali."},{"name":"Forcone","usage":null,"description":"Attacco con arma da mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 3 (1d6) danni perforanti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (2d4) danni taglienti."},{"name":"Spina Caudale","usage":null,"description":"Attacco con arma a Distanza: +4 a colpire, gittata 6/24 m, un bersaglio. Colpisce: 4 (1d4 + 2) danni perforanti più 3 (1d6) danni da fuoco."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Diavolo Spinoso\nPiccola immondo (diavolo), legale malvagio\nFORZA 10 (+0)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 14 (+2)\nCARISMA 8 (-1)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 22 (5d6 + 5)\nVelocità 6 m, volo 12 m\nResistenze al Danno freddo; contundente, perforante e tagliente\ndi attacchi non magici che non siano argentati\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 36 m, Percezione passiva 18\nLinguaggi Infernale, telepatia 36 m\nSfida 2 (450 PE)\nResistenza alla Magia. Il diavolo ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nSorvolare. Il diavolo non provoca attacchi di opportunità quando\nvola via dalla portata di un nemico.\nSpine Limitate. Il diavolo possiede dodici spine caudali. Le\nspine usate ricrescono al termine di un riposo lungo da parte del\ndiavolo.\nVista del Diavolo. La scurovisione del diavolo non è limitata\ndall''oscurità magica.\nAzioni\nMultiattacco. Il diavolo effettua due attacchi: uno con il morso e\nuno con il suo forcone o due con le sue spine caudali.\nForcone. Attacco con arma da mischia: +2 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 3 (1d6) danni perforanti.\nMorso. Attacco con arma da mischia: +2 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 5 (2d4) danni taglienti.\nSpina Caudale. Attacco con arma a Distanza: +4 a colpire,\ngittata 6/24 m, un bersaglio.\nColpisce: 4 (1d4 + 2) danni perforanti più 3 (1d6) danni da\nfuoco."}}', '2026-03-30T15:54:05.300Z', '2026-03-30T16:00:32.257Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kaW5vbHVwby1tZXRhbHVwby5qc29u', 'dinolupo-metalupo', 'Dinolupo (Metalupo)', 'SRD', 'srd-extracted/dinolupo-metalupo.json', '1', 1, 200, 'Grande', 'bestia', 'disallineato', '{"slug":"dinolupo-metalupo","general":{"name":"Dinolupo (Metalupo)","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Grande","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":14,"note":"armatura naturale"},"hitPoints":{"average":37,"formula":"5d10 + 10"},"speed":{"walk":"15 m"}},"abilities":{"strength":17,"dexterity":15,"constitution":15,"intelligence":3,"wisdom":12,"charisma":7},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["freddo"],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Udito e Olfatto Affinato","usage":null,"description":"Il lupo ha vantaggio nelle prove di"},{"name":"Saggezza (Percezione) basate su udito o olfatto","usage":null,"description":""},{"name":"Tattiche di Branco","usage":null,"description":"Il lupo ha vantaggio ai tiri di attacco contro una creatura se almeno uno degli alleati del lupo si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni perforanti. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Forza CD 14 o cadere prona."},{"name":"Soffio Gelido","usage":"Ricarica 5-6","description":"Il lupo esala un''esplosione di vento gelido in un cono di 4,5 metri. Ogni creatura in quell''area deve effettuare un tiro salvezza di Destrezza CD 12, e subire 18 (4d8) danni da freddo se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Dinolupo (Metalupo)\nGrande bestia, disallineato\nFORZA 17 (+3)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 7 (-2)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 37 (5d10 + 10)\nVelocità 15 m\nAbilità Furtività +4, Percezione +3\nSensi Percezione passiva 13\nLingue -\nSfida 1 (200 PE)\nUdito e Olfatto Affinato. Il lupo ha vantaggio nelle prove di\nSaggezza (Percezione) basate su udito o olfatto.\nTattiche di Branco. Il lupo ha vantaggio ai tiri di attacco contro\nuna creatura se almeno uno degli alleati del lupo si trova entro\n1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMorso. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d6 + 3) danni perforanti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Forza CD 13 o cadere\nprona.\nLupo Invernale\nI lupi invernali abitano nelle regioni artiche e sono\ncreature malvagie e intelligenti dal manto bianco come\nla neve e gli occhi color del ghiaccio.\nGrande mostruosità, neutrale malvagio\nFORZA 18 (+4)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 7 (-2)\nSAGGEZZA 12 (+1)\nCARISMA 8 (-1)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 75 (10d10 + 20)\nVelocità 15 m\nAbilità Furtività +3, Percezione +5\nImmunità al Danno freddo\nSensi Percezione passiva 15\nLingue Comune, Gigante, Lupo Invernale\nSfida 3 (700 PE)\nCamuffamento di Neve. Il lupo ha vantaggio alle prove di\nDestrezza (Furtività) per nascondersi su terreno innevato.\nUdito e Olfatto Affinato. Il lupo ha vantaggio nelle prove di\nSaggezza (Percezione) basate su udito o olfatto.\nTattiche di Branco. Il lupo ha vantaggio ai tiri di attacco contro\nuna creatura se almeno uno degli alleati del lupo si trova entro\n1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMorso. Attacco con Arma da Mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 11 (2d6 + 4) danni perforanti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Forza CD 14 o cadere\nprona.\nSoffio Gelido (Ricarica 5-6). Il lupo esala un''esplosione di vento\ngelido in un cono di 4,5 metri. Ogni creatura in quell''area deve\neffettuare un tiro salvezza di Destrezza CD 12, e subire 18 (4d8)\ndanni da freddo se fallisce il tiro salvezza, o la metà di questi\ndanni se lo riesce."}}', '2026-03-30T15:54:05.534Z', '2026-03-30T16:00:32.446Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kamlubmkuanNvbg', 'djinni', 'Djinni', 'SRD', 'srd-extracted/djinni.json', '11', 11, 7200, 'Grande', 'elementale', 'caotico buono', '{"slug":"djinni","general":{"name":"Djinni","challengeRating":{"fraction":"11","decimal":11,"display":"11","xp":7200},"size":"Grande","creatureType":"elementale","subtype":"","typeLabel":"elementale","alignment":"caotico buono","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":161,"formula":"14d10 + 84"},"speed":{"walk":"9 m","fly":"27 m"}},"abilities":{"strength":21,"dexterity":15,"constitution":22,"intelligence":15,"wisdom":16,"charisma":20},"details":{"savingThrows":[{"ability":"Destrezza","bonus":6},{"ability":"Saggezza","bonus":7},{"ability":"Carisma","bonus":9}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fulmine","tuono"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"Auran"}],"proficiencyBonus":4},"traits":[{"name":"Decesso Elementale","usage":null,"description":"Se il djinni muore, il suo corpo si disintegra in una brezza calda, lasciando dietro di sé solo l''equipaggiamento che il djinni stava indossando o trasportando."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato del djinni è il Carisma (CD dei tiri salvezza degli incantesimi 17, +9 a colpire con attacchi da incantesimo). Può lanciare in maniera innata i seguenti incantesimi, senza bisogno di componenti materiali: A volontà: individuazione del bene e del male, individuazione del magico, onda tonante 3/giorno ciascuno: camminare nel vento, creare cibo e acqua (può creare vino al posto dell''acqua), linguaggi 1/giorno ciascuno: creazione, evoca elementali (solo elementale dell''aria), forma gassosa, immagine maggiore, invisibilità, spostamento planare"}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il djinni effettua tre attacchi di scimitarra."},{"name":"Scimitarra","usage":null,"description":"Attacco con arma da mischia: +9 a colpire, portata 1,5 m, un bersaglio. Colpisce: 12 (2d6 + 5) danni taglienti più 3 (1d6) danni da fulmine o tuono (a scelta del gin)."},{"name":"Creare Turbine","usage":null,"description":"Un cilindro d''aria turbinante di 1,5 metri di raggio e alto 9 metri si forma magicamente in un punto visibile al djinni entro 36 metri da esso. Il turbine resta finché il djinni mantiene la concentrazione (come se si stesse concentrando su di un incantesimo). Qualsiasi creatura salvo il djinni che entri nel turbine deve riuscire un tiro salvezza di Forza CD 18 o restare intralciata da esso. Il djinni può muovere il turbine di massimo 18 metri con un''azione, e le creature intralciate dal turbine si muovono con esso. Il turbine termina se il djinni lo perde di vista. Una creatura può usare la sua azione per liberare una creatura intralciata dal turbine, compresa se stessa, riuscendo una prova di"},{"name":"Forza CD 18","usage":null,"description":"Se la prova riesce, la creatura non è più intralciata e si sposta nello spazio più vicino all''esterno del turbine."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Djinni\nGrande elementale, caotico buono\nFORZA 21 (+5)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 22 (+6)\nINTELLIGENZA 15 (+2)\nSAGGEZZA 16 (+3)\nCARISMA 20 (+5)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 161 (14d10 + 84)\nVelocità 9 m, volo 27 m\nTiri Salvezza Destrezza +6, Saggezza +7, Carisma +9\nImmunità al Danno fulmine, tuono\nSensi scurovisione 36 m, Percezione passiva 13\nLinguaggi Auran\nSfida 11 (7.200 PE)\nDecesso Elementale. Se il djinni muore, il suo corpo si\ndisintegra in una brezza calda, lasciando dietro di sé solo\nl''equipaggiamento che il djinni stava indossando o trasportando.\nIncantesimi Innati. La caratteristica da incantatore innato del\ndjinni è il Carisma (CD dei tiri salvezza degli incantesimi 17, +9\na colpire con attacchi da incantesimo). Può lanciare in maniera\ninnata i seguenti incantesimi, senza bisogno di componenti\nmateriali:\nA volontà: individuazione del bene e del male, individuazione del\nmagico, onda tonante\n3/giorno ciascuno: camminare nel vento, creare cibo e acqua\n(può creare vino al posto dell''acqua), linguaggi\n1/giorno ciascuno: creazione, evoca elementali (solo elementale\ndell''aria), forma gassosa, immagine maggiore, invisibilità,\nspostamento planare\nAzioni\nMultiattacco. Il djinni effettua tre attacchi di scimitarra.\nScimitarra. Attacco con arma da mischia: +9 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 12 (2d6 + 5) danni taglienti più 3 (1d6) danni da\nfulmine o tuono (a scelta del gin).\nCreare Turbine. Un cilindro d''aria turbinante di 1,5 metri di\nraggio e alto 9 metri si forma magicamente in un punto visibile al\ndjinni entro 36 metri da esso. Il turbine resta finché il djinni\nmantiene la concentrazione (come se si stesse concentrando su di\nun incantesimo). Qualsiasi creatura salvo il djinni che entri nel\nturbine deve riuscire un tiro salvezza di Forza CD 18 o restare\nintralciata da esso. Il djinni può muovere il turbine di massimo\n18 metri con un''azione, e le creature intralciate dal turbine si\nmuovono con esso. Il turbine termina se il djinni lo perde di\nvista.\nUna creatura può usare la sua azione per liberare una creatura\nintralciata dal turbine, compresa se stessa, riuscendo una prova di\nForza CD 18. Se la prova riesce, la creatura non è più intralciata\ne si sposta nello spazio più vicino all''esterno del turbine."}}', '2026-03-30T15:55:58.105Z', '2026-03-30T16:00:32.314Z');
