INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kcmFnby1uZXJvLWdpb3ZhbmUuanNvbg', 'drago-nero-giovane', 'Drago Nero Giovane', 'SRD', 'srd-extracted/drago-nero-giovane.json', '7', 7, 2900, 'Grande', 'drago', 'caotico malvagio', '{"slug":"drago-nero-giovane","general":{"name":"Drago Nero Giovane","challengeRating":{"fraction":"7","decimal":7,"display":"7","xp":2900},"size":"Grande","creatureType":"drago","subtype":"","typeLabel":"drago","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":18,"note":"armatura naturale"},"hitPoints":{"average":127,"formula":"15d10 + 45"},"speed":{"walk":"12 m","climb":"12 m","fly":"24 m"}},"abilities":{"strength":19,"dexterity":14,"constitution":17,"intelligence":12,"wisdom":11,"charisma":15},"details":{"savingThrows":[{"ability":"Destrezza","bonus":5},{"ability":"Costituzione","bonus":6},{"ability":"Saggezza","bonus":3}],"skills":[{"name":"Furtività","bonus":5},{"name":"Percezione","bonus":6}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["acido"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"vista cieca","value":"9 m"},{"name":"Percezione passiva 16"}],"languages":[{"name":"Comune"},{"name":"Draconico"}],"proficiencyBonus":3},"traits":[{"name":"Anfibio","usage":null,"description":"Il drago può respirare aria e acqua."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il drago può effettuare tre attacchi: uno con il morso e due con gli artigli."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni taglienti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 3 m, un bersaglio. Colpisce: 11 (2d10 + 4) danni perforanti più 4 (1d8) danni da acido."},{"name":"Soffio Acido","usage":"Ricarica 5-6","description":"Il drago esala acido in una linea di 9 metri larga 1,5 metri. Ogni creatura in quell''area deve effettuare un tiro salvezza di Destrezza CD 14 e subire 49 (11d8) danni da acido se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Drago Nero Giovane\nGrande drago, caotico malvagio\nFORZA 19 (+4)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 17 (+3)\nINTELLIGENZA 12 (+1)\nSAGGEZZA 11 (+0)\nCARISMA 15 (+2)\nClasse Armatura 18 (armatura naturale)\nPunti Ferita 127 (15d10 + 45)\nVelocità 12 m, scalata 12 m, volo 24 m\nTiri Salvezza Destrezza +5, Costituzione +6, Saggezza +3,\nCarisma +5\nAbilità Furtività +5, Percezione +6\nImmunità al Danno acido\nSensi scurovisione 36 m, vista cieca 9 m, Percezione passiva 16\nLinguaggi Comune, Draconico\nSfida 7 (2.900 PE)\nAnfibio. Il drago può respirare aria e acqua.\nAzioni\nMultiattacco. Il drago può effettuare tre attacchi: uno con il\nmorso e due con gli artigli.\nArtiglio. Attacco con arma da mischia: +10 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 11 (2d6 + 4) danni taglienti.\nMorso. Attacco con arma da mischia: +7 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 11 (2d10 + 4) danni perforanti più 4 (1d8) danni da acido.\nSoffio Acido (Ricarica 5-6). Il drago esala acido in una linea di 9\nmetri larga 1,5 metri. Ogni creatura in quell''area deve effettuare un tiro\nsalvezza di Destrezza CD 14 e subire 49 (11d8) danni da acido se fallisce\nil tiro salvezza, o la metà di questi danni se lo riesce."}}', '2026-03-30T15:54:05.322Z', '2026-03-30T16:00:32.276Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kcmFnby1yb3Nzby1hZHVsdG8uanNvbg', 'drago-rosso-adulto', 'Drago Rosso Adulto', 'SRD', 'srd-extracted/drago-rosso-adulto.json', '17', 17, 18000, 'Enorme', 'drago', 'caotico malvagio', '{"slug":"drago-rosso-adulto","general":{"name":"Drago Rosso Adulto","challengeRating":{"fraction":"17","decimal":17,"display":"17","xp":18000},"size":"Enorme","creatureType":"drago","subtype":"","typeLabel":"drago","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":256,"formula":"19d12 + 133"},"speed":{"walk":"12 m","climb":"12 m","fly":"24 m"}},"abilities":{"strength":27,"dexterity":10,"constitution":25,"intelligence":16,"wisdom":13,"charisma":21},"details":{"savingThrows":[{"ability":"Destrezza","bonus":6},{"ability":"Costituzione","bonus":13},{"ability":"Saggezza","bonus":7}],"skills":[{"name":"Furtività","bonus":6},{"name":"Percezione","bonus":13}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fuoco"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"vista cieca","value":"18 m"},{"name":"Percezione passiva 23"}],"languages":[{"name":"Comune"},{"name":"Draconico"}],"proficiencyBonus":6},"traits":[{"name":"Resistenza Leggendaria","usage":"3/Giorno","description":"Se il drago fallisce un tiro salvezza, può scegliere invece di riuscire."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il drago può usare la sua Presenza Spaventosa e poi effettuare tre attacchi: uno con il morso e due con gli artigli."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 1,5 m, un bersaglio. Colpisce: 15 (2d6 + 8) danni taglienti."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 4,5 m, un bersaglio. Colpisce: 17 (2d8 + 8) danni contundenti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 3 m, un bersaglio. Colpisce: 19 (2d10 + 8) danni perforanti più 7 (2d6) danni da fuoco."},{"name":"Presenza Spaventosa","usage":null,"description":"Ogni creatura scelta dal drago, che si trovi entro 36 metri da esso e consapevole della sua presenza, deve riuscire un tiro salvezza di Saggezza CD 19 o restare spaventata per 1 minuto. Una creatura può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto se lo riesce. Se il tiro salvezza della creatura ha successo o l''effetto ha termine per essa, la creatura è immune alla Presenza Spaventosa del drago per le successive 24 ore."},{"name":"Soffio Infuocato","usage":"Ricarica 5-6","description":"Il drago esala fuoco in un cono di 18 metri. Ogni creatura in quell''area deve effettuare un tiro salvezza di Destrezza CD 21 e subire 63 (18d6) danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"Il drago può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. Il drago recupera le azioni leggendarie spese all''inizio del proprio turno.","actions":[{"name":"Attacco di Ala","description":"Il drago batte le ali. Ogni creatura entro 3 metri dal drago deve riuscire un tiro salvezza di Destrezza CD 22 o subire 15 (2d6 + 8) danni contundenti e venir gettato prono. Il drago può poi volare fino a metà della sua velocità di volo.","cost":2},{"name":"Attacco di Coda","description":"Il drago effettua un attacco di coda.","cost":1},{"name":"Individuare","description":"Il drago effettua una prova di Saggezza (Percezione).","cost":1}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Drago Rosso Adulto\nEnorme drago, caotico malvagio\nFORZA 27 (+8)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 25 (+7)\nINTELLIGENZA 16 (+3)\nSAGGEZZA 13 (+1)\nCARISMA 21 (+5)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 256 (19d12 + 133)\nVelocità 12 m, scalata 12 m, volo 24 m\nTiri Salvezza Destrezza +6, Costituzione +13, Saggezza +7,\nCarisma +11\nAbilità Furtività +6, Percezione +13\nImmunità al Danno fuoco\nSensi scurovisione 36 m, vista cieca 18 m, Percezione passiva 23\nLinguaggi Comune, Draconico\nSfida 17 (18.000 PE)\nResistenza Leggendaria (3/Giorno). Se il drago fallisce un tiro\nsalvezza, può scegliere invece di riuscire.\nAzioni\nMultiattacco. Il drago può usare la sua Presenza Spaventosa e\npoi effettuare tre attacchi: uno con il morso e due con gli artigli.\nArtiglio. Attacco con arma da mischia: +14 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 15 (2d6 + 8) danni taglienti.\nCoda. Attacco con arma da mischia: +14 a colpire, portata 4,5\nm, un bersaglio.\nColpisce: 17 (2d8 + 8) danni contundenti.\nMorso. Attacco con arma da mischia: +14 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 19 (2d10 + 8) danni perforanti più 7 (2d6) danni da\nfuoco.\nPresenza Spaventosa. Ogni creatura scelta dal drago, che si trovi\nentro 36 metri da esso e consapevole della sua presenza, deve\nriuscire un tiro salvezza di Saggezza CD 19 o restare spaventata\nper 1 minuto. Una creatura può ripetere il tiro salvezza al termine\ndi ciascun suo turno, terminando l''effetto se lo riesce. Se il tiro\nsalvezza della creatura ha successo o l''effetto ha termine per\nessa, la creatura è immune alla Presenza Spaventosa del drago\nper le successive 24 ore.\nSoffio Infuocato (Ricarica 5-6). Il drago esala fuoco in un cono\ndi 18 metri. Ogni creatura in quell''area deve effettuare un tiro\nsalvezza di Destrezza CD 21 e subire 63 (18d6) danni da fuoco\nse fallisce il tiro salvezza, o la metà di questi danni se lo riesce.\nAzioni Leggendarie\nIl drago può effettuare 3 azioni leggendarie, scelte tra le opzioni\nseguenti. Può usare solo un''opzione leggendaria alla volta e solo\nal termine del turno di un''altra creatura. Il drago recupera le\nazioni leggendarie spese all''inizio del proprio turno.\nAttacco di Ala (Costa 2 Azioni). Il drago batte le ali. Ogni\ncreatura entro 3 metri dal drago deve riuscire un tiro salvezza di\nDestrezza CD 22 o subire 15 (2d6 + 8) danni contundenti e venir\ngettato prono. Il drago può poi volare fino a metà della sua\nvelocità di volo.\nAttacco di Coda. Il drago effettua un attacco di coda.\nIndividuare. Il drago effettua una prova di Saggezza\n(Percezione)."}}', '2026-03-30T15:54:05.324Z', '2026-03-30T16:00:32.278Z');
