INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9wZXJzZWN1dG9yZS1pbnZpc2liaWxlLmpzb24', 'persecutore-invisibile', 'Persecutore Invisibile', 'SRD', 'srd-extracted/persecutore-invisibile.json', '6', 6, 2300, 'Media', 'elementale', 'neutrale', '{"slug":"persecutore-invisibile","general":{"name":"Persecutore Invisibile","challengeRating":{"fraction":"6","decimal":6,"display":"6","xp":2300},"size":"Media","creatureType":"elementale","subtype":"","typeLabel":"elementale","alignment":"neutrale","environments":[]},"combat":{"armorClass":{"value":14,"note":""},"hitPoints":{"average":104,"formula":"16d8 + 32"},"speed":{"walk":"15 m","fly":"15 m (fluttua)"}},"abilities":{"strength":16,"dexterity":19,"constitution":14,"intelligence":10,"wisdom":15,"charisma":11},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":10},{"name":"Percezione","bonus":8}],"damageVulnerabilities":[],"damageResistances":["contundente","perforante e tagliente di"],"damageImmunities":["veleno"],"conditionImmunities":["afferrato","avvelenato","intralciato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 18"}],"languages":[{"name":"Auran"},{"name":"comprende il Comune ma non lo parla"}],"proficiencyBonus":3},"traits":[{"name":"Cacciatore Infallibile","usage":null,"description":"Il convocatore assegna una preda al persecutore. Il persecutore sa la direzione e la distanza a cui si trova la preda finché entrambi si trovano sullo stesso piano di esistenza. Il persecutore conosce anche la posizione del suo convocatore."},{"name":"Invisibilità","usage":null,"description":"Il persecutore è invisibile."},{"name":"Natura Elementale","usage":null,"description":"Un persecutore invisibile non ha bisogno di aria, cibo, bevande o sonno."}],"actions":[{"name":"Multiattacco","usage":null,"description":"La persecutore effettua due attacchi di schianto."},{"name":"Schianto","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Persecutore Invisibile\nMedia elementale, neutrale\nFORZA 16 (+3)\nDESTREZZA 19 (+4)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 15 (+2)\nCARISMA 11 (+0)\nClasse Armatura 14\nPunti Ferita 104 (16d8 + 32)\nVelocità 15 m, volo 15 m (fluttua)\nAbilità Furtività +10, Percezione +8\nResistenze al Danno contundente, perforante e tagliente di\nattacchi non magici\nImmunità ai Danni veleno\nImmunità alle Condizioni afferrato, avvelenato, intralciato,\nparalizzato, pietrificato, privo di sensi, prono, sfinimento\nSensi scurovisione 18 m, Percezione passiva 18\nLinguaggi Auran, comprende il Comune ma non lo parla\nSfida 6 (2.300 PE)\nCacciatore Infallibile. Il convocatore assegna una preda al\npersecutore. Il persecutore sa la direzione e la distanza a cui si\ntrova la preda finché entrambi si trovano sullo stesso piano di\nesistenza. Il persecutore conosce anche la posizione del suo\nconvocatore.\nInvisibilità. Il persecutore è invisibile.\nNatura Elementale. Un persecutore invisibile non ha bisogno di\naria, cibo, bevande o sonno.\nAzioni\nMultiattacco. La persecutore effettua due attacchi di schianto.\nSchianto. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d6 + 3) danni contundenti."}}', '2026-03-30T15:54:05.451Z', '2026-03-30T16:00:32.373Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9waW92cmEtZ2lnYW50ZS5qc29u', 'piovra-gigante', 'Piovra Gigante', 'SRD', 'srd-extracted/piovra-gigante.json', '1', 1, 200, 'Grande', 'bestia', 'disallineato', '{"slug":"piovra-gigante","general":{"name":"Piovra Gigante","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Grande","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":11,"note":""},"hitPoints":{"average":52,"formula":"8d10 + 8"},"speed":{"walk":"3 m","swim":"18 m"}},"abilities":{"strength":17,"dexterity":13,"constitution":13,"intelligence":4,"wisdom":10,"charisma":4},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":5},{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"18 m"},{"name":"Percezione passiva 14"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Camuffamento Subacqueo","usage":null,"description":"La piovra ha vantaggio alle prove di"},{"name":"Destrezza (Furtività) effettuate sottacqua","usage":null,"description":""},{"name":"Respirare Acqua","usage":null,"description":"La piovra può respirare solo sottacqua."},{"name":"Trattenere il Fiato","usage":null,"description":"Mentre è fuori dell''acqua, la piovra può trattenere il fiato per 1 ora."}],"actions":[{"name":"Tentacoli","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 4,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni contundenti. Se il bersaglio è una creatura, è afferrata (CD 16 per fuggire). Fino al termine dell''afferrare, il bersaglio è intralciato, e la piovra non può usare i suoi tentacoli contro un altro bersaglio."},{"name":"Nube di Inchiostro","usage":"Ricarica dopo un Riposo Breve o Lungo","description":"Una nube di inchiostro del raggio di 6 metri si estende tutt''intorno alla piovra quando si trova sottacqua. L''aria è oscurata pesantemente per 1 minuto, sebbene una forte corrente possa dissolvere la nube più rapidamente. Dopo aver rilasciato l''inchiostro, la piovra può usare l''azione Scattare come azione bonus."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Piovra Gigante\nGrande bestia, disallineato\nFORZA 17 (+3)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 4 (-3)\nSAGGEZZA 10 (+0)\nCARISMA 4 (-3)\nClasse Armatura 11\nPunti Ferita 52 (8d10 + 8)\nVelocità 3 m, nuoto 18 m\nAbilità Furtività +5, Percezione +4\nSensi visione al buio 18 m, Percezione passiva 14\nLingue -\nSfida 1 (200 PE)\nCamuffamento Subacqueo. La piovra ha vantaggio alle prove di\nDestrezza (Furtività) effettuate sottacqua.\nRespirare Acqua. La piovra può respirare solo sottacqua.\nTrattenere il Fiato. Mentre è fuori dell''acqua, la piovra può\ntrattenere il fiato per 1 ora.\nAzioni\nTentacoli. Attacco con Arma da Mischia: +5 a colpire, portata\n4,5 m, un bersaglio.\nColpisce: 10 (2d6 + 3) danni contundenti. Se il bersaglio è una\ncreatura, è afferrata (CD 16 per fuggire). Fino al termine\ndell''afferrare, il bersaglio è intralciato, e la piovra non può usare\ni suoi tentacoli contro un altro bersaglio.\nNube di Inchiostro (Ricarica dopo un Riposo Breve o Lungo).\nUna nube di inchiostro del raggio di 6 metri si estende\ntutt''intorno alla piovra quando si trova sottacqua. L''aria è\noscurata pesantemente per 1 minuto, sebbene una forte corrente\npossa dissolvere la nube più rapidamente. Dopo aver rilasciato\nl''inchiostro, la piovra può usare l''azione Scattare come azione\nbonus."}}', '2026-03-30T15:54:05.544Z', '2026-03-30T16:00:32.455Z');
