INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9wb3BvbGFuby5qc29u', 'popolano', 'Popolano', 'SRD', 'srd-extracted/popolano.json', '0', 0, 10, NULL, NULL, NULL, '{"slug":"popolano","general":{"name":"Popolano","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":10},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":10,"note":""},"hitPoints":{"average":4,"formula":"1d8"},"speed":{"walk":"9 m"}},"abilities":{"strength":10,"dexterity":10,"constitution":10,"intelligence":10,"wisdom":10,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Intimidazione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"Il picchiatore effettua due attacchi da mischia."},{"name":"Mazza","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, una creatura. Colpisce: 5 (1d6 + 2) danni contundenti."},{"name":"Balestra Pesante","usage":null,"description":"Attacco con Arma a Gittata: +2 a colpire, gittata 30/120 m, un bersaglio. Colpisce: 5 (1d10) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Popolano\nI popolani comprendono contadini, servi, schiavi,\nservitori, pellegrini, mercanti, artigiani ed eremiti.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 10 (+0)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 10 (+0)\nClasse Armatura 10\nPunti Ferita 4 (1d8)\nVelocità 9 m\nSensi Percezione passiva 10\nLingue una qualsiasi lingua (di solito il Comune)\nSfida 0 (10 PE)\nAzioni\nRandello. Attacco con Arma da Mischia: +2 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 2 (1d4) danni contundenti.\n\n-- 142 of 151 --\n\nCriminali\nI criminali sono individui che vivono al margine della\nlegalità, procurandosi il pane svolgendo attività spesso\nconsiderate illecite e immorali.\nPicchiatore\nI picchiatori sono criminali spietati abili nell''intimidire e\nperpetrare atti di violenza. Lavorano per soldi e si fanno\npochi scrupoli.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento non\nbuono\nFORZA 15 (+2)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 11 (+0)\nClasse Armatura 11 (armatura di cuoio)\nPunti Ferita 32 (5d8 + 10)\nVelocità 9 m\nAbilità Intimidazione +2\nSensi Percezione passiva 10\nLingue una lingua qualsiasi (di solito il Comune)\nSfida 1/2 (100 PE)\nTattiche di Branco. Il picchiatore ha vantaggio ai tiri di attacco\ncontro una creatura se almeno uno degli alleati del picchiatore si\ntrova entro 1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMultiattacco. Il picchiatore effettua due attacchi da mischia.\nMazza. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, una creatura.\nColpisce: 5 (1d6 + 2) danni contundenti.\nBalestra Pesante. Attacco con Arma a Gittata: +2 a colpire,\ngittata 30/120 m, un bersaglio.\nColpisce: 5 (1d10) danni perforanti."}}', '2026-03-30T15:55:58.278Z', '2026-03-30T16:00:32.489Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9wcm9nZW5pZS12YW1waXJpY2EuanNvbg', 'progenie-vampirica', 'Progenie Vampirica', 'SRD', 'srd-extracted/progenie-vampirica.json', '5', 5, 1800, 'Media', 'non morto', 'neutrale malvagio', '{"slug":"progenie-vampirica","general":{"name":"Progenie Vampirica","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Media","creatureType":"non morto","subtype":"","typeLabel":"non morto","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":82,"formula":"11d8 + 33"},"speed":{"walk":"9 m"}},"abilities":{"strength":16,"dexterity":16,"constitution":16,"intelligence":11,"wisdom":10,"charisma":12},"details":{"savingThrows":[{"ability":"Destrezza","bonus":6},{"ability":"Saggezza","bonus":3}],"skills":[{"name":"Furtività","bonus":6},{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":["necrotico; contundente","perforante e"],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"le lingue che conosceva in vita"}],"proficiencyBonus":3},"traits":[{"name":"Debolezze della Progenie Vampirica","usage":null,"description":"La Progenie Vampirica ha i seguenti difetti:"},{"name":"Danneggiato dall''Acqua Corrente","usage":null,"description":"La Progenie Vampirica subisce 20 danni da acido se termina il suo turno all''interno dell''acqua corrente."},{"name":"Ipersensibilità alla Luce","usage":null,"description":"La Progenie Vampirica subisce 20 danni radianti quando inizia il suo turno alla luce del sole. Mentre è alla luce del sole, ha svantaggio ai tiri di attacco e le prove di abilità."},{"name":"Paletto nel Cuore","usage":null,"description":"La Progenie Vampirica è distrutto se un''arma perforante di legno gli viene conficcata nel cuore mentre è inabile all''interno del suo luogo di riposo."},{"name":"Proibizione","usage":null,"description":"La Progenie Vampirica non può entrare in un''abitazione senza invito da parte dei suoi occupanti."},{"name":"Natura Non Morta","usage":null,"description":"La Progenie Vampirica non ha bisogno di aria."},{"name":"Rigenerazione","usage":null,"description":"La Progenie Vampirica recupera 10 punti ferita all''inizio del suo turno se possiede almeno 1 punto ferita e non è esposto alla luce del sole o l''acqua corrente. Se la Progenie Vampirica subisce danno radiante o danno dall''acqua sacra, questo tratto non funziona all''inizio del prossimo turno del vampiro."},{"name":"Scalare come Ragno","usage":null,"description":"La Progenie Vampirica può scalare superfici difficili, compreso lo stare a testa in giù sul soffitto, senza bisogno di effettuare una prova di abilità."}],"actions":[{"name":"Multiattacco","usage":null,"description":"La progenie vampirica può effettuare due attacchi, ma solo uno di essi può essere un attacco con morso."},{"name":"Artigli","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, una creatura. Colpisce: 8 (2d4 + 3) danni taglienti. Invece di infliggere danno, il vampiro può afferrare il bersaglio (CD per fuggire 13)."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, una creatura afferrata dal vampiro, inabile o intralciata. Colpisce: 6 (1d6 + 3) danni perforanti più 7 (2d6) danni necrotici. I punti ferita massimi del bersaglio sono ridotti di un ammontare pari al danno necrotico subito, e il vampiro recupera un numero di punti ferita pari a quell''ammontare. Questa riduzione permane finché il bersaglio non termina un riposo lungo. Il bersaglio muore se questo effetto riduce i suoi punti ferita massimi a 0."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Progenie Vampirica\nMedia non morto, neutrale malvagio\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 82 (11d8 + 33)\nVelocità 9 m\nFORZA 16 (+3)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 12 (+1)\nTiri Salvezza Destrezza +6, Saggezza +3\nAbilità Furtività +6, Percezione +3\nResistenze ai Danni necrotico; contundente, perforante e\ntagliente di attacchi non magici\nSensi scurovisione 18 m, Percezione passiva 13\nLinguaggi le lingue che conosceva in vita\nSfida 5 (1.800 PE)\nDebolezze della Progenie Vampirica. La Progenie Vampirica ha\ni seguenti difetti:\nDanneggiato dall''Acqua Corrente. La Progenie Vampirica\nsubisce 20 danni da acido se termina il suo turno all''interno\ndell''acqua corrente.\nIpersensibilità alla Luce. La Progenie Vampirica subisce 20\ndanni radianti quando inizia il suo turno alla luce del sole.\nMentre è alla luce del sole, ha svantaggio ai tiri di attacco e le\nprove di abilità.\nPaletto nel Cuore. La Progenie Vampirica è distrutto se un''arma\nperforante di legno gli viene conficcata nel cuore mentre è\ninabile all''interno del suo luogo di riposo.\nProibizione. La Progenie Vampirica non può entrare in\nun''abitazione senza invito da parte dei suoi occupanti.\nNatura Non Morta. La Progenie Vampirica non ha bisogno di\naria.\nRigenerazione. La Progenie Vampirica recupera 10 punti ferita\nall''inizio del suo turno se possiede almeno 1 punto ferita e non è\nesposto alla luce del sole o l''acqua corrente. Se la Progenie\nVampirica subisce danno radiante o danno dall''acqua sacra,\nquesto tratto non funziona all''inizio del prossimo turno del\nvampiro.\nScalare come Ragno. La Progenie Vampirica può scalare\nsuperfici difficili, compreso lo stare a testa in giù sul soffitto,\nsenza bisogno di effettuare una prova di abilità.\nAzioni\nMultiattacco. La progenie vampirica può effettuare due attacchi,\nma solo uno di essi può essere un attacco con morso.\nArtigli. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, una creatura.\nColpisce: 8 (2d4 + 3) danni taglienti. Invece di infliggere danno,\nil vampiro può afferrare il bersaglio (CD per fuggire 13).\nMorso. Attacco con arma da mischia: +6 a colpire, portata 1,5 m,\nuna creatura afferrata dal vampiro, inabile o intralciata.\nColpisce: 6 (1d6 + 3) danni perforanti più 7 (2d6) danni necrotici. I\npunti ferita massimi del bersaglio sono ridotti di un ammontare pari\nal danno necrotico subito, e il vampiro recupera un numero di punti\nferita pari a quell''ammontare. Questa riduzione permane finché il\nbersaglio non termina un riposo lungo. Il bersaglio muore se questo\neffetto riduce i suoi punti ferita massimi a 0."}}', '2026-03-30T15:54:05.480Z', '2026-03-30T16:00:32.397Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9wcm90b3BsYXNtYS1uZXJvLmpzb24', 'protoplasma-nero', 'Protoplasma Nero', 'SRD', 'srd-extracted/protoplasma-nero.json', '4', 4, 1100, 'Grande', 'melma', 'disallineato', '{"slug":"protoplasma-nero","general":{"name":"Protoplasma Nero","challengeRating":{"fraction":"4","decimal":4,"display":"4","xp":1100},"size":"Grande","creatureType":"melma","subtype":"","typeLabel":"melma","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":7,"note":""},"hitPoints":{"average":85,"formula":"10d10 + 30"},"speed":{"walk":"6 m","climb":"6 m"}},"abilities":{"strength":16,"dexterity":5,"constitution":16,"intelligence":1,"wisdom":6,"charisma":1},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["acido","freddo","fulmine","tagliente"],"conditionImmunities":["accecato","affascinato","assordato"],"senses":[{"name":"vista cieca 18 m (cieco oltre questo raggio)"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[{"name":"Amorfo","usage":null,"description":"Il protoplasma nero può muoversi attraverso uno spazio fino a 2,5 centimetri di larghezza senza doversi stringere."},{"name":"Forma Corrosiva","usage":null,"description":"Una creatura che entri a contatto col protoplasma nero o lo colpisca con un attacco da mischia mentre si trova entro 1,5 metri da esso subisce 4 (1d8) danni da acido. Qualsiasi arma non magica fatta di metallo o legno che colpisca il protoplasma nero si corrode. Dopo aver inflitto il danno, l''arma subisce una penalità permanente e cumulativa di -1 ai tiri di danno. Se la penalità arriva a -5, l''arma è distrutta. Le munizioni non magiche fatte di metallo o legno che colpiscano il protoplasma nero, si distruggono dopo aver inflitto il danno. Il protoplasma nero può divorare legno o metallo non magico dello spessore di 5 centimetri in un 1 round."},{"name":"Natura di Melma","usage":null,"description":"Il protoplasma nero non necessita di dormire."},{"name":"Scalare come Ragno","usage":null,"description":"Il protoplasma nero può scalare superfici difficili, compreso lo stare a testa in giù sul soffitto, senza bisogno di effettuare una prova di abilità."}],"actions":[{"name":"Pseudopodo","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d6 + 3) danni contundenti più 18 (4d8) danni da acido. Inoltre, un''armatura non magica indossata dal bersaglio viene parzialmente dissolta e subisce una penalità permanente e cumulativa di -1 alla CA che offre. L''armatura è distrutta se la penalità riduce la sua CA a 10."}],"bonusActions":[],"reactions":[{"name":"Divisione","usage":null,"description":"Quando un protoplasma nero di taglia Media o più grande subisce danni da fulmine o taglienti, si divide in due nuovi protoplasma neri di almeno 10 punti ferita ciascuno. Ogni nuovo protoplasma nero ha un numero di punti ferita pari alla metà del protoplasma nero originale, arrotondati per difetto. I nuovi protoplasmi neri sono di una taglia più piccola di quella originale. Mezzo Drago Modello del Mezzo Drago Una bestia, umanoide, gigante o mostruosità può diventare un mezzo drago. Quando una creatura diventa un mezzo drago, mantiene tutte le sue statistiche eccetto come indicato di seguito."},{"name":"Sensi","usage":null,"description":"I mezzi draghi ottengono vista cieca con un raggio di 3 metri e scurovisione con un raggio di 18 metri."},{"name":"Resistenze","usage":null,"description":"Il mezzo drago ottiene resistenza ad un tipo di danno in base al suo colore. Colore Resistenza al Danno Bianco o argento freddo Blu o bronzo fulmine Nero o rame acido Oro, ottone o rosso fuoco Verde veleno"},{"name":"Linguaggi","usage":null,"description":"I mezzi draghi parlano Draconico oltre alle lingue che già conoscono."},{"name":"Gradi di Sfida","usage":null,"description":"Per evitare di dover ricalcolare il grado di sfida, applicare l''archetipo solo ad una creatura che soddisfi i prerequisiti opzionali della tabella Arma a"},{"name":"Soffio seguente","usage":null,"description":"Altrimenti, usare le linee guida in fondo a questo documento per ricalcolare il grado di sfida dopo aver applicato l''archetipo."},{"name":"Nuova Azione: Soffio","usage":null,"description":"Il mezzo drago possiede l''arma a soffio della sua parte draconica. La taglia del mezzo drago determina come funziona questa azione. Taglia Soffio Prerequisito Opzionale Grande o meno Come un cucciolo Sfida 2 o più Enorme Come un drago giovane Sfida 7 o più Mastodontica Come un drago adulto Sfida 8 o più"}],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Protoplasma Nero\nGrande melma, disallineato\nFORZA 16 (+3)\nDESTREZZA 5 (-3)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 6 (-2)\nCARISMA 1 (-5)\nClasse Armatura 7\nPunti Ferita 85 (10d10 + 30)\nVelocità 6 m, scalata 6 m\nImmunità al Danno acido, freddo, fulmine, tagliente\nImmunità alle Condizioni accecato, affascinato, assordato,\nprono, sfinimento, spaventato\nSensi vista cieca 18 m (cieco oltre questo raggio), Percezione\npassiva 8\nLinguaggi -\nSfida 4 (1.100 PE)\nAmorfo. Il protoplasma nero può muoversi attraverso uno spazio\nfino a 2,5 centimetri di larghezza senza doversi stringere.\nForma Corrosiva. Una creatura che entri a contatto col protoplasma\nnero o lo colpisca con un attacco da mischia mentre si trova entro 1,5\nmetri da esso subisce 4 (1d8) danni da acido. Qualsiasi arma non\nmagica fatta di metallo o legno che colpisca il protoplasma nero si\ncorrode. Dopo aver inflitto il danno, l''arma subisce una penalità\npermanente e cumulativa di -1 ai tiri di danno. Se la penalità arriva a\n-5, l''arma è distrutta. Le munizioni non magiche fatte di metallo o\nlegno che colpiscano il protoplasma nero, si distruggono dopo aver\ninflitto il danno.\nIl protoplasma nero può divorare legno o metallo non magico dello\nspessore di 5 centimetri in un 1 round.\nNatura di Melma. Il protoplasma nero non necessita di dormire.\nScalare come Ragno. Il protoplasma nero può scalare superfici\ndifficili, compreso lo stare a testa in giù sul soffitto, senza\nbisogno di effettuare una prova di abilità.\nAzioni\nPseudopodo. Attacco con arma da mischia: +5 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 6 (1d6 + 3) danni contundenti più 18 (4d8) danni da\nacido. Inoltre, un''armatura non magica indossata dal bersaglio\nviene parzialmente dissolta e subisce una penalità permanente e\ncumulativa di -1 alla CA che offre. L''armatura è distrutta se la\npenalità riduce la sua CA a 10.\nReazioni\nDivisione. Quando un protoplasma nero di taglia Media o più grande\nsubisce danni da fulmine o taglienti, si divide in due nuovi\nprotoplasma neri di almeno 10 punti ferita ciascuno. Ogni nuovo\nprotoplasma nero ha un numero di punti ferita pari alla metà del\nprotoplasma nero originale, arrotondati per difetto. I nuovi\nprotoplasmi neri sono di una taglia più piccola di quella originale.\nMezzo Drago\nModello del Mezzo Drago\nUna bestia, umanoide, gigante o mostruosità può\ndiventare un mezzo drago. Quando una creatura\ndiventa un mezzo drago, mantiene tutte le sue\nstatistiche eccetto come indicato di seguito.\nSensi. I mezzi draghi ottengono vista cieca con un\nraggio di 3 metri e scurovisione con un raggio di 18\nmetri.\nResistenze. Il mezzo drago ottiene resistenza ad un\ntipo di danno in base al suo colore.\nColore Resistenza al Danno\nBianco o argento freddo\nBlu o bronzo fulmine\nNero o rame acido\nOro, ottone o rosso fuoco\nVerde veleno\nLinguaggi. I mezzi draghi parlano Draconico oltre alle\nlingue che già conoscono.\nGradi di Sfida. Per evitare di dover ricalcolare il grado\ndi sfida, applicare l''archetipo solo ad una creatura che\nsoddisfi i prerequisiti opzionali della tabella Arma a\nSoffio seguente. Altrimenti, usare le linee guida in fondo\na questo documento per ricalcolare il grado di sfida\ndopo aver applicato l''archetipo.\nNuova Azione: Soffio. Il mezzo drago possiede l''arma\na soffio della sua parte draconica. La taglia del mezzo\ndrago determina come funziona questa azione.\nTaglia Soffio Prerequisito Opzionale\nGrande o meno Come un cucciolo Sfida 2 o più\nEnorme Come un drago giovane Sfida 7 o più\nMastodontica Come un drago adulto Sfida 8 o più"}}', '2026-03-30T15:54:05.418Z', '2026-03-30T16:00:32.355Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9wc2V1ZG9kcmFnby5qc29u', 'pseudodrago', 'Pseudodrago', 'SRD', 'srd-extracted/pseudodrago.json', '1/4', 0.25, 50, 'Minuscola', 'drago', 'neutrale buono', '{"slug":"pseudodrago","general":{"name":"Pseudodrago","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Minuscola","creatureType":"drago","subtype":"","typeLabel":"drago","alignment":"neutrale buono","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":7,"formula":"2d4 + 2"},"speed":{"walk":"5 m","fly":"18 m"}},"abilities":{"strength":6,"dexterity":15,"constitution":13,"intelligence":10,"wisdom":12,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"vista cieca","value":"3 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"comprende il Comune e il Draconico ma non parla"}],"proficiencyBonus":2},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Lo pseudodrago ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Sensi Affinati","usage":null,"description":"Lo pseudodrago ha vantaggio alle prove di"},{"name":"Saggezza (Percezione) basate su vista, udito e olfatto","usage":null,"description":""},{"name":"Telepatia Limitata","usage":null,"description":"Lo pseudodrago può comunicare semplici idee, emozioni e immagini telepaticamente con qualsiasi creatura entro 30 metri da esso che può comprendere una lingua."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d4 + 2) danni perforanti."},{"name":"Pungiglione","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, una creatura. Colpisce: 4 (1d4 + 2) danni perforanti, e il bersaglio deve riuscire un tiro salvezza di Costituzione CD 11 o restare avvelenato per 1 ora. Se il risultato del tiro salvezza è 6 o meno, il bersaglio cade privo di sensi per la stessa durata, o finché non subisce danni o un''altra creatura usa un''azione per risvegliarlo."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Pseudodrago\nMinuscola drago, neutrale buono\nFORZA 6 (-2)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 12 (+1)\nCARISMA 10 (+0)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 7 (2d4 + 2)\nVelocità 4,5 m, volo 18 m\nAbilità Furtività +4, Percezione +3\nSensi scurovisione 18 m, vista cieca 3 m, Percezione passiva 13\nLinguaggi comprende il Comune e il Draconico ma non parla\nSfida 1/4 (50 PE)\nResistenza alla Magia. Lo pseudodrago ha vantaggio ai tiri\nsalvezza contro incantesimi e altri effetti magici.\nSensi Affinati. Lo pseudodrago ha vantaggio alle prove di\nSaggezza (Percezione) basate su vista, udito e olfatto.\nTelepatia Limitata. Lo pseudodrago può comunicare semplici\nidee, emozioni e immagini telepaticamente con qualsiasi creatura\nentro 30 metri da esso che può comprendere una lingua.\nAzioni\nMorso. Attacco con arma da mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d4 + 2) danni perforanti.\nPungiglione. Attacco con arma da mischia: +4 a colpire, portata\n1,5 m, una creatura.\nColpisce: 4 (1d4 + 2) danni perforanti, e il bersaglio deve\nriuscire un tiro salvezza di Costituzione CD 11 o restare\navvelenato per 1 ora. Se il risultato del tiro salvezza è 6 o meno,\nil bersaglio cade privo di sensi per la stessa durata, o finché non\nsubisce danni o un''altra creatura usa un''azione per risvegliarlo."}}', '2026-03-30T15:54:05.452Z', '2026-03-30T16:00:32.374Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9xdWFzaXQuanNvbg', 'quasit', 'Quasit', 'SRD', 'srd-extracted/quasit.json', '1', 1, 200, 'Minuscola', 'immondo (demone', 'mutaforma), caotico malvagio', '{"slug":"quasit","general":{"name":"Quasit","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Minuscola","creatureType":"immondo (demone","subtype":"","typeLabel":"immondo (demone","alignment":"mutaforma), caotico malvagio","environments":[]},"combat":{"armorClass":{"value":13,"note":""},"hitPoints":{"average":7,"formula":"3d4"},"speed":{"walk":"12 m (3 m","fly":"12 m in forma di pipistrello; 12 m"}},"abilities":{"strength":5,"dexterity":17,"constitution":10,"intelligence":7,"wisdom":10,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":5}],"damageVulnerabilities":[],"damageResistances":["freddo","fulmine","fuoco; contundente"],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 10"}],"languages":[{"name":"Abissale"},{"name":"Comune"}],"proficiencyBonus":2},"traits":[{"name":"Mutaforma","usage":null,"description":"Il demone può usare la sua azione per trasformarsi in una forma bestiale da pipistrello, centopiedi o rospo, o per tornare alla sua vera forma. Le sue statistiche sono le stesse in tutte le forme, sebbene gli attacchi possano variare per alcune di esse. Qualsiasi equipaggiamento stia indossando o trasportando non viene trasformato. Alla morte ritorna alla sua vera forma."},{"name":"Resistenza alla Magia","usage":null,"description":"Il demone ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Artigli","usage":"Morso in Forma di Bestia","description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (1d4 + 3) danni perforanti. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Costituzione CD 10 o subire 5 (2d4) danni da veleno e restare avvelenato per 1 minuto. La creatura può ripetere il tiro salvezza al termine di ciascun suo turno, ponendo termine all''effetto se lo riesce."},{"name":"Invisibilità","usage":null,"description":"Il demone resta invisibile finché non attacca o termina la sua concentrazione. Qualsiasi cosa che il demone stia trasportando o indossando resta invisibile finché rimane in contatto con il demone."},{"name":"Spavento","usage":"1/Giorno","description":"Una creatura scelta dal demone che si trovi entro 6 metri da lui, deve riuscire un tiro salvezza di Saggezza CD 10 o restare spaventata per 1 minuto. Il bersaglio può ripetere il tiro salvezza al termine di ciascun suo turno, con svantaggio se il demone è in linea di visuale, ponendo termine all''effetto prematuramente se riesce il tiro salvezza."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Quasit\nMinuscola immondo (demone, mutaforma), caotico malvagio\nFORZA 5 (-3)\nDESTREZZA 17 (+3)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 7 (-2)\nSAGGEZZA 10 (+0)\nCARISMA 10 (+0)\nClasse Armatura 13\nPunti Ferita 7 (3d4)\nVelocità 12 m (3 m, volo 12 m in forma di pipistrello; 12 m,\nscalata 12 m in forma di centopiedi; 12 m, nuoto 12 m in forma\ndi rospo)\nAbilità Furtività +5\nResistenze al Danno freddo, fulmine, fuoco; contundente,\nperforante e tagliente di attacchi non magici\nImmunità al Danno veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 36 m, Percezione passiva 10\nLinguaggi Abissale, Comune\nSfida 1 (200 PE)\nMutaforma. Il demone può usare la sua azione per trasformarsi\nin una forma bestiale da pipistrello, centopiedi o rospo, o per\ntornare alla sua vera forma. Le sue statistiche sono le stesse in\ntutte le forme, sebbene gli attacchi possano variare per alcune di\nesse. Qualsiasi equipaggiamento stia indossando o trasportando\nnon viene trasformato. Alla morte ritorna alla sua vera forma.\nResistenza alla Magia. Il demone ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nArtigli (Morso in Forma di Bestia). Attacco con arma da\nmischia: +4 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 5 (1d4 + 3) danni perforanti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Costituzione CD 10 o\nsubire 5 (2d4) danni da veleno e restare avvelenato per 1 minuto.\nLa creatura può ripetere il tiro salvezza al termine di ciascun suo\nturno, ponendo termine all''effetto se lo riesce.\nInvisibilità. Il demone resta invisibile finché non attacca o\ntermina la sua concentrazione. Qualsiasi cosa che il demone stia\ntrasportando o indossando resta invisibile finché rimane in\ncontatto con il demone.\nSpavento (1/Giorno). Una creatura scelta dal demone che si trovi\nentro 6 metri da lui, deve riuscire un tiro salvezza di Saggezza\nCD 10 o restare spaventata per 1 minuto. Il bersaglio può ripetere\nil tiro salvezza al termine di ciascun suo turno, con svantaggio se\nil demone è in linea di visuale, ponendo termine all''effetto\nprematuramente se riesce il tiro salvezza."}}', '2026-03-30T15:54:05.291Z', '2026-03-30T16:00:32.249Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9yYWduby1naWdhbnRlLmpzb24', 'ragno-gigante', 'Ragno Gigante', 'SRD', 'srd-extracted/ragno-gigante.json', '1', 1, 200, 'Grande', 'bestia', 'disallineato', '{"slug":"ragno-gigante","general":{"name":"Ragno Gigante","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Grande","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":14,"note":"armatura naturale"},"hitPoints":{"average":26,"formula":"4d10 + 4"},"speed":{"walk":"9 m","climb":"9 m"}},"abilities":{"strength":14,"dexterity":16,"constitution":12,"intelligence":2,"wisdom":11,"charisma":4},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":7}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"3 m"},{"name":"visione al buio","value":"18 m"},{"name":"Percezione passiva"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Camminare sulla Tela","usage":null,"description":"Il ragno ignora le restrizioni al movimento provocate dalle ragnatele."},{"name":"Scalare come Ragno","usage":null,"description":"Il ragno può scalare superfici difficili, compreso lo stare a testa in giù sul soffitto, senza bisogno di effettuare una prova di abilità."},{"name":"Senso della Tela","usage":null,"description":"Mentre è in contatto con una ragnatela, il ragno sa l''esatta posizione di qualsiasi altra creatura in contatto con la stessa ragnatela."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +3 a colpire, portata 1,5 m, una creatura. Colpisce: 4 (1d6 + 1) danni perforanti e il bersaglio deve effettuare un tiro salvezza di Costituzione CD 11, e subire 7 (2d6) danni da veleno se fallisce il tiro salvezza, o la metà di questi danni se lo riesce. Se il danno da veleno riduce il bersaglio a 0 punti ferita, il bersaglio è stabile ma avvelenato per 1 ora, anche dopo aver recuperato i punti ferita, e mentre è avvelenato in questo modo resta paralizzato."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Ragno Gigante\nGrande bestia, disallineato\nFORZA 14 (+2)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 11 (+0)\nCARISMA 4 (-3)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 26 (4d10 + 4)\nVelocità 9 m, scalata 9 m\nAbilità Furtività +7\nSensi vista cieca 3 m, visione al buio 18 m, Percezione passiva\n10\nLingue -\nSfida 1 (200 PE)\nCamminare sulla Tela. Il ragno ignora le restrizioni al\nmovimento provocate dalle ragnatele.\nScalare come Ragno. Il ragno può scalare superfici difficili,\ncompreso lo stare a testa in giù sul soffitto, senza bisogno di\neffettuare una prova di abilità.\nSenso della Tela. Mentre è in contatto con una ragnatela, il\nragno sa l''esatta posizione di qualsiasi altra creatura in contatto\ncon la stessa ragnatela.\nAzioni\nMorso. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, una creatura.\nColpisce: 7 (1d8 + 3) danni perforanti e il bersaglio deve\neffettuare un tiro salvezza di Costituzione CD 11, e subire 9\n(2d8) danni da veleno se fallisce il tiro salvezza, o la metà di\nquesti danni se lo riesce. Se il danno da veleno riduce il bersaglio\na 0 punti ferita, il bersaglio è stabile ma avvelenato per 1 ora,\nanche dopo aver recuperato i punti ferita, e mentre è avvelenato\nin questo modo resta paralizzato.\nRagnatela (Ricarica 5-6). Attacco con Arma a Gittata: +5 a\ncolpire, gittata 9/18 m, una creatura.\nColpisce: Il bersaglio è intralciato dalla ragnatela. Con\nun''azione, il bersaglio intralciato può effettuare una prova di\nForza CD 12 e, in caso di successo, spezzare la tela. La ragnatela\npuò essere anche attaccata e distrutta (CA 10; pf 5; vulnerabilità\nal danno da fuoco; immunità ai danni contundenti, psichici e da\nveleno).\n\n-- 128 of 151 --\n\nRagno Lupo Gigante\nUn ragno lupo gigante caccia le prede su terreno aperto\no si nasconde in tane o fessure del terreno per tendere\nimboscate.\nMedia bestia, disallineato\nFORZA 12 (+1)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 4 (-3)\nClasse Armatura 13\nPunti Ferita 11 (2d8 + 2)\nVelocità 12 m, scalata 12 m\nAbilità Furtività +7, Percezione +3\nSensi vista cieca 3 m, visione al buio 18 m, Percezione passiva\n13\nLingue -\nSfida 1/4 (50 PE)\nCamminare sulla Tela. Il ragno ignora le restrizioni al\nmovimento provocate dalle ragnatele.\nScalare come Ragno. Il ragno può scalare superfici difficili,\ncompreso lo stare a testa in giù sul soffitto, senza bisogno di\neffettuare una prova di abilità.\nSenso della Tela. Mentre è in contatto con una ragnatela, il\nragno sa l''esatta posizione di qualsiasi altra creatura in contatto\ncon la stessa ragnatela.\nAzioni\nMorso. Attacco con Arma da Mischia: +3 a colpire, portata 1,5\nm, una creatura.\nColpisce: 4 (1d6 + 1) danni perforanti e il bersaglio deve\neffettuare un tiro salvezza di Costituzione CD 11, e subire 7\n(2d6) danni da veleno se fallisce il tiro salvezza, o la metà di\nquesti danni se lo riesce. Se il danno da veleno riduce il bersaglio\na 0 punti ferita, il bersaglio è stabile ma avvelenato per 1 ora,\nanche dopo aver recuperato i punti ferita, e mentre è avvelenato\nin questo modo resta paralizzato."}}', '2026-03-30T15:54:05.548Z', '2026-03-30T16:00:32.459Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9yYWduby5qc29u', 'ragno', 'Ragno', 'SRD', 'srd-extracted/ragno.json', '0', 0, 10, 'Minuscola', 'bestia', 'disallineato', '{"slug":"ragno","general":{"name":"Ragno","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":10},"size":"Minuscola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":1,"formula":"1d4 - 1"},"speed":{"walk":"6 m","climb":"6 m"}},"abilities":{"strength":2,"dexterity":14,"constitution":8,"intelligence":1,"wisdom":10,"charisma":2},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"9 m"},{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Camminare sulla Tela","usage":null,"description":"Il ragno ignora le restrizioni al movimento provocate dalle ragnatele."},{"name":"Scalare come Ragno","usage":null,"description":"Il ragno può scalare superfici difficili, compreso lo stare a testa in giù sul soffitto, senza bisogno di effettuare una prova di abilità."},{"name":"Senso della Tela","usage":null,"description":"Mentre è in contatto con una ragnatela, il ragno sa l''esatta posizione di qualsiasi altra creatura in contatto con la stessa ragnatela."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, una creatura. Colpisce: 7 (1d10 + 2) danni perforanti e il bersaglio deve effettuare un tiro salvezza di Costituzione CD 11, e subire 18 (4d8) danni da veleno se fallisce il tiro salvezza, o la metà di questo danno se lo riesce. Se il danno da veleno riduce il bersaglio a 0 punti ferita, il bersaglio è stabile ma avvelenato per 1 ora, anche dopo aver recuperato i punti ferita, e mentre è avvelenato in questo modo resta paralizzato."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Ragno\nMinuscola bestia, disallineato\nFORZA 2 (-5)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 8 (-1)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 10 (+0)\nCARISMA 2 (-4)\nClasse Armatura 12\nPunti Ferita 1 (1d4 - 1)\nVelocità 6 m, scalata 6 m\nAbilità Furtività +4\nSensi visione al buio 9 m, Percezione passiva 10\nLingue -\nSfida 0 (10 PE)\nCamminare sulla Tela. Il ragno ignora le restrizioni al\nmovimento provocate dalle ragnatele.\nScalare come Ragno. Il ragno può scalare superfici difficili,\ncompreso lo stare a testa in giù sul soffitto, senza bisogno di\neffettuare una prova di abilità.\nSenso della Tela. Mentre è in contatto con una ragnatela, il\nragno sa l''esatta posizione di qualsiasi altra creatura in contatto\ncon la stessa ragnatela.\nAzioni\nMorso. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, una creatura.\nColpisce: 1 danno perforante e il bersaglio deve riuscire un tiro\nsalvezza di Costituzione CD 9 o subire 2 (1d4) danni da veleno.\n\n-- 127 of 151 --\n\nSRD Italia 5a Edizione - Compendio dei Mostri\nRagno Fase\nIl ragno fase possiede l''abilità magica di entrare ed\nuscire dal Piano Etereo. Sembra apparire dal nulla e\nscompare rapidamente dopo aver attaccato.\nGrande mostruosità, disallineato\nFORZA 15 (+2)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 6 (-2)\nSAGGEZZA 10 (+0)\nCARISMA 6 (-2)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 32 (5d10 + 5)\nVelocità 9 m, scalata 9 m\nAbilità Furtività +6\nSensi visione al buio 18 m, Percezione passiva 10\nLingue -\nSfida 3 (700 PE)\nCamminare sulla Tela. Il ragno ignora le restrizioni al\nmovimento provocate dalle ragnatele.\nGita Eterea. Come azione bonus, il ragno può magicamente\nspostarsi dal Piano Materiale al Piano Etereo, o viceversa.\nScalare come Ragno. Il ragno può scalare superfici difficili,\ncompreso lo stare a testa in giù sul soffitto, senza bisogno di\neffettuare una prova di abilità.\nAzioni\nMorso. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, una creatura.\nColpisce: 7 (1d10 + 2) danni perforanti e il bersaglio deve\neffettuare un tiro salvezza di Costituzione CD 11, e subire 18\n(4d8) danni da veleno se fallisce il tiro salvezza, o la metà di\nquesto danno se lo riesce. Se il danno da veleno riduce il\nbersaglio a 0 punti ferita, il bersaglio è stabile ma avvelenato per\n1 ora, anche dopo aver recuperato i punti ferita, e mentre è\navvelenato in questo modo resta paralizzato."}}', '2026-03-30T15:54:05.547Z', '2026-03-30T16:00:32.458Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9yYWtzaGFzYS5qc29u', 'rakshasa', 'Rakshasa', 'SRD', 'srd-extracted/rakshasa.json', '13', 13, 10000, 'Media', 'immondo', 'legale malvagio', '{"slug":"rakshasa","general":{"name":"Rakshasa","challengeRating":{"fraction":"13","decimal":13,"display":"13","xp":10000},"size":"Media","creatureType":"immondo","subtype":"","typeLabel":"immondo","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":16,"note":"armatura naturale"},"hitPoints":{"average":110,"formula":"13d8 + 52"},"speed":{"walk":"12 m"}},"abilities":{"strength":14,"dexterity":17,"constitution":18,"intelligence":13,"wisdom":16,"charisma":20},"details":{"savingThrows":[],"skills":[{"name":"Inganno","bonus":10},{"name":"Intuizione","bonus":8}],"damageVulnerabilities":["perforante di armi magiche impugnate"],"damageResistances":[],"damageImmunities":["contundente","perforante e tagliente di"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"Comune"},{"name":"Infernale"}],"proficiencyBonus":5},"traits":[{"name":"Immunità alla Magia Limitata","usage":null,"description":"Il rakshasa è immune agli affetti o all''individuazione tramite incantesimi di 6° livello o più basso a meno che non desideri esserne soggetto. Ha vantaggio ai tiri salvezza contro tutti gli altri incantesimi ed effetti magici."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore del rakshasa è il Carisma (CD 18 per i tiri salvezza degli incantesimi, +10 a colpire con attacchi con incantesimi). Il rakshasa può lanciare in maniera innata i seguenti incantesimi, senza aver bisogno di componenti materiali: A volontà: camuffare sé stesso, illusione minore, individuazione dei pensieri, mano magica 3/Giorno ciascuno: charme su persone, immagine maggiore, individuazione del magico, invisibilità, suggestione 1/Giorno: dominare persone, spostamento planare, visione del vero, volare"}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il rakshasa può effettuare due attacchi di artiglio."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 9 (2d6 + 2) danni taglienti, e se il bersaglio è una creatura rimane maledetto. La maledizione magica ha effetto ogni qualvolta il bersaglio effettua un riposo breve o lungo, riempiendo i pensieri del bersaglio di immagini e sogni orribili. Il bersaglio maledetto non riceve beneficio dall''aver terminato un riposo breve o lungo. La maledizione perdura finché non viene rimossa dall''incantesimo rimuovi maledizione o simile magia."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Rakshasa\nMedia immondo, legale malvagio\nFORZA 14 (+2)\nDESTREZZA 17 (+3)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 13 (+1)\nSAGGEZZA 16 (+3)\nCARISMA 20 (+5)\nClasse Armatura 16 (armatura naturale)\nPunti Ferita 110 (13d8 + 52)\nVelocità 12 m\nAbilità Inganno +10, Intuizione +8\nVulnerabilità al Danno perforante di armi magiche impugnate\nda creatura buone\nImmunità al Danno contundente, perforante e tagliente di\nattacchi non magici\nSensi scurovisione 18 m, Percezione passiva 13\nLinguaggi Comune, Infernale\nSfida 13 (10.000 PE)\nImmunità alla Magia Limitata. Il rakshasa è immune agli affetti\no all''individuazione tramite incantesimi di 6° livello o più basso\na meno che non desideri esserne soggetto. Ha vantaggio ai tiri\nsalvezza contro tutti gli altri incantesimi ed effetti magici.\nIncantesimi Innati. La caratteristica da incantatore del rakshasa\nè il Carisma (CD 18 per i tiri salvezza degli incantesimi, +10 a\ncolpire con attacchi con incantesimi). Il rakshasa può lanciare in\nmaniera innata i seguenti incantesimi, senza aver bisogno di\ncomponenti materiali:\nA volontà: camuffare sé stesso, illusione minore, individuazione\ndei pensieri, mano magica\n3/Giorno ciascuno: charme su persone, immagine maggiore,\nindividuazione del magico, invisibilità, suggestione\n1/Giorno: dominare persone, spostamento planare, visione del\nvero, volare\nAzioni\nMultiattacco. Il rakshasa può effettuare due attacchi di artiglio.\nArtiglio. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 9 (2d6 + 2) danni taglienti, e se il bersaglio è una\ncreatura rimane maledetto. La maledizione magica ha effetto\nogni qualvolta il bersaglio effettua un riposo breve o lungo,\nriempiendo i pensieri del bersaglio di immagini e sogni orribili.\nIl bersaglio maledetto non riceve beneficio dall''aver terminato\nun riposo breve o lungo. La maledizione perdura finché non\nviene rimossa dall''incantesimo rimuovi maledizione o simile\nmagia."}}', '2026-03-30T15:54:05.453Z', '2026-03-30T16:00:32.375Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9yYW5hLWdpZ2FudGUuanNvbg', 'rana-gigante', 'Rana Gigante', 'SRD', 'srd-extracted/rana-gigante.json', '1/4', 0.25, 50, 'Media', 'bestia', 'disallineato', '{"slug":"rana-gigante","general":{"name":"Rana Gigante","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Media","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":11,"note":""},"hitPoints":{"average":18,"formula":"4d8"},"speed":{"walk":"9 m","swim":"9 m"}},"abilities":{"strength":12,"dexterity":13,"constitution":11,"intelligence":2,"wisdom":10,"charisma":3},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":3},{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"9 m"},{"name":"Percezione passiva 12"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Anfibio","usage":null,"description":"La rana può respirare aria e acqua."},{"name":"Salto da Fermo","usage":null,"description":"Una rana può saltare in lungo fino a 6 metri e in alto fino a 3 metri, con o senza la rincorsa."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d6 + 1) danni perforanti e il bersaglio è afferrato (CD 11 per fuggire). Fino al termine dell''afferrare, il bersaglio è intralciato, e la rana non può usare il morso contro un altro bersaglio."},{"name":"Inghiottire","usage":null,"description":"La rana effettua una attacco di morso contro un bersaglio di taglia Piccola o inferiore che sta afferrando. Se l''attacco colpisce, il bersaglio è inghiottito, e l''afferrare ha termine. Il bersaglio inghiottito è accecato e intralciato, ha copertura totale contro gli attacchi e altri effetti all''esterno della rana, e subisce 5 (2d4) danni da acido all''inizio di ciascun turno della rana. La rana può inghiottire solo un bersaglio alla volta. Se la rana muore, una creatura inghiottita non è più intralciata da essa e può uscire dal cadavere utilizzando 1,5 metri di movimento, uscendo prona."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Rana Gigante\nMedia bestia, disallineato\nFORZA 12 (+1)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 10 (+0)\nCARISMA 3 (-4)\nClasse Armatura 11\nPunti Ferita 18 (4d8)\nVelocità 9 m, nuoto 9 m\nAbilità Furtività +3, Percezione +2\nSensi visione al buio 9 m, Percezione passiva 12\nLingue -\nSfida 1/4 (50 PE)\nAnfibio. La rana può respirare aria e acqua.\nSalto da Fermo. Una rana può saltare in lungo fino a 6 metri e in\nalto fino a 3 metri, con o senza la rincorsa.\nAzioni\nMorso. Attacco con Arma da Mischia: +3 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d6 + 1) danni perforanti e il bersaglio è afferrato\n(CD 11 per fuggire). Fino al termine dell''afferrare, il bersaglio è\nintralciato, e la rana non può usare il morso contro un altro\nbersaglio.\nInghiottire. La rana effettua una attacco di morso contro un\nbersaglio di taglia Piccola o inferiore che sta afferrando. Se\nl''attacco colpisce, il bersaglio è inghiottito, e l''afferrare ha\ntermine. Il bersaglio inghiottito è accecato e intralciato, ha\ncopertura totale contro gli attacchi e altri effetti all''esterno della\nrana, e subisce 5 (2d4) danni da acido all''inizio di ciascun turno\ndella rana. La rana può inghiottire solo un bersaglio alla volta.\nSe la rana muore, una creatura inghiottita non è più intralciata da\nessa e può uscire dal cadavere utilizzando 1,5 metri di\nmovimento, uscendo prona."}}', '2026-03-30T15:54:05.550Z', '2026-03-30T16:00:32.460Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9yYW5hLmpzb24', 'rana', 'Rana', 'SRD', 'srd-extracted/rana.json', '0', 0, 0, 'Minuscola', 'bestia', 'disallineato', '{"slug":"rana","general":{"name":"Rana","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":0},"size":"Minuscola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":11,"note":""},"hitPoints":{"average":1,"formula":"1d4 - 1"},"speed":{"walk":"6 m","swim":"6 m"}},"abilities":{"strength":1,"dexterity":13,"constitution":8,"intelligence":1,"wisdom":8,"charisma":3},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":3},{"name":"Percezione","bonus":1}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"9 m"},{"name":"Percezione passiva 11"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Anfibio","usage":null,"description":"La rana può respirare aria e acqua."},{"name":"Salto da Fermo","usage":null,"description":"Una rana può saltare in lungo fino a 3 metri e in alto fino a 1,5 metri, con o senza la rincorsa."},{"name":"Una rana è sprovvista di attacchi","usage":null,"description":"Si nutre di piccoli insetti e di solito vive in prossimità di acquitrini, dentro gli alberi o sottoterra."}],"actions":[],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Rana\nMinuscola bestia, disallineato\nFORZA 1 (-5)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 8 (-1)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 8 (-1)\nCARISMA 3 (-4)\nClasse Armatura 11\nPunti Ferita 1 (1d4 - 1)\nVelocità 6 m, nuoto 6 m\nAbilità Furtività +3, Percezione +1\nSensi visione al buio 9 m, Percezione passiva 11\nLingue -\nSfida 0 (0 PE)\nAnfibio. La rana può respirare aria e acqua.\nSalto da Fermo. Una rana può saltare in lungo fino a 3 metri e in\nalto fino a 1,5 metri, con o senza la rincorsa.\nUna rana è sprovvista di attacchi. Si nutre di piccoli\ninsetti e di solito vive in prossimità di acquitrini, dentro\ngli alberi o sottoterra."}}', '2026-03-30T15:54:05.549Z', '2026-03-30T16:00:32.460Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9yYXR0by1naWdhbnRlLmpzb24', 'ratto-gigante', 'Ratto Gigante', 'SRD', 'srd-extracted/ratto-gigante.json', '1/8', 0.125, 25, 'Piccola', 'bestia', 'disallineato', '{"slug":"ratto-gigante","general":{"name":"Ratto Gigante","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"Piccola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":7,"formula":"2d6"},"speed":{"walk":"9 m"}},"abilities":{"strength":7,"dexterity":15,"constitution":11,"intelligence":2,"wisdom":10,"charisma":4},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"18 m"},{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Olfatto Affinato","usage":null,"description":"Il ratto ha vantaggio alle prove di Saggezza (Percezione) basate sull''olfatto."},{"name":"Tattiche di Branco","usage":null,"description":"Il ratto ha vantaggio al tiro di attacco contro una creatura se almeno uno degli alleati del ratto si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d4 + 2) danni perforanti. VARIANTE: RATTO GIGANTE AMMALATO Alcuni ratti giganti recano una terribile malattia che diffondono tramite il morso. Un ratto gigante ammalato ha grado di sfida 1/8 (25 PE) e la seguente azione invece del suo normale attacco di morso."},{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d4 + 2) danni perforanti. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Costituzione CD 10 o contrarre una malattia. Fino a che la malattia non viene curata, il bersaglio non può recuperare punti ferita eccetto tramite metodi magici, e i punti ferita massimi del bersaglio diminuiscono di 3 (1d6) ogni 24 ore. Se i punti ferita massimi del bersaglio scendono a 0 come risultato della malattia, il bersaglio muore."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Ratto Gigante\nPiccola bestia, disallineato\nFORZA 7 (-2)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 10 (+0)\nCARISMA 4 (-3)\nClasse Armatura 12\nPunti Ferita 7 (2d6)\nVelocità 9 m\nSensi visione al buio 18 m, Percezione passiva 10\nLingue -\nSfida 1/8 (25 PE)\nOlfatto Affinato. Il ratto ha vantaggio alle prove di Saggezza\n(Percezione) basate sull''olfatto.\nTattiche di Branco. Il ratto ha vantaggio al tiro di attacco contro\nuna creatura se almeno uno degli alleati del ratto si trova entro\n1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMorso. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d4 + 2) danni perforanti.\nVARIANTE: RATTO GIGANTE AMMALATO\nAlcuni ratti giganti recano una terribile malattia che diffondono\ntramite il morso. Un ratto gigante ammalato ha grado di sfida 1/8\n(25 PE) e la seguente azione invece del suo normale attacco di\nmorso.\nMorso. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d4 + 2) danni perforanti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Costituzione CD 10 o\ncontrarre una malattia. Fino a che la malattia non viene curata, il\nbersaglio non può recuperare punti ferita eccetto tramite metodi\nmagici, e i punti ferita massimi del bersaglio diminuiscono di 3\n(1d6) ogni 24 ore. Se i punti ferita massimi del bersaglio\nscendono a 0 come risultato della malattia, il bersaglio muore."}}', '2026-03-30T15:54:05.551Z', '2026-03-30T16:00:32.462Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9yYXR0by1tYW5uYXJvLmpzb24', 'ratto-mannaro', 'Ratto Mannaro', 'SRD', 'srd-extracted/ratto-mannaro.json', '2', 2, 450, 'Media', 'umanoide (umano', 'mutaforma), legale malvagio', '{"slug":"ratto-mannaro","general":{"name":"Ratto Mannaro","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Media","creatureType":"umanoide (umano","subtype":"","typeLabel":"umanoide (umano","alignment":"mutaforma), legale malvagio","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":33,"formula":"6d8 + 6"},"speed":{"walk":"9 m"}},"abilities":{"strength":10,"dexterity":15,"constitution":12,"intelligence":11,"wisdom":10,"charisma":8},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["contundente","perforante e tagliente di"],"conditionImmunities":[],"senses":[{"name":"scurovisione 18 m (solo in forma di ratto)"},{"name":"Percezione"}],"languages":[{"name":"Comune (non può parlare in forma di ratto)"}],"proficiencyBonus":2},"traits":[{"name":"Mutaforma","usage":null,"description":"Il ratto mannaro può usare la sua azione per trasformarsi in un ibrido ratto-umanoide o in un ratto, o per tornare alla sua vera forma, che è umanoide. Le sue statistiche, a parte la CA, sono le stesse in tutte le forme. Qualsiasi equipaggiamento stia indossando o trasportando non viene trasformato. Alla morte ritorna alla sua vera forma."},{"name":"Olfatto Affinato","usage":null,"description":"Il ratto mannaro ha vantaggio nelle prove di"},{"name":"Saggezza (Percezione) basate sull''olfatto","usage":null,"description":""}],"actions":[{"name":"Multiattacco","usage":"Solo in Forma Umanoide o Ibrida","description":"Il ratto mannaro effettua due attacchi, di cui solo uno può essere con il morso."},{"name":"Spada Corta","usage":"Soltanto in Forma Umanoide o Ibrida","description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (1d6 + 2) danni perforanti."},{"name":"Balestra a mano","usage":"Soltanto in Forma Umanoide o Ibrida","description":"Attacco con arma a Distanza: +4 a colpire, gittata 9/36 m, un bersaglio. Colpisce: 5 (1d6 + 2) danni perforanti."},{"name":"Morso","usage":"Soltanto in Forma di Ratto o Ibrida","description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d4 + 2) danni perforanti. Se il bersaglio è un umanoide, deve riuscire un tiro salvezza di Costituzione CD 11 o venir maledetto dalla licantropia del ratto mannaro."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Ratto Mannaro\nMedia umanoide (umano, mutaforma), legale malvagio\nFORZA 10 (+0)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 8 (-1)\nClasse Armatura 12\nPunti Ferita 33 (6d8 + 6)\nVelocità 9 m\nAbilità Furtività +4, Percezione +2\nImmunità al Danno contundente, perforante e tagliente di\nattacchi non magici che non siano argentati\nSensi scurovisione 18 m (solo in forma di ratto), Percezione\npassiva 12\nLinguaggi Comune (non può parlare in forma di ratto)\nSfida 2 (450 PE)\nMutaforma. Il ratto mannaro può usare la sua azione per\ntrasformarsi in un ibrido ratto-umanoide o in un ratto, o per\ntornare alla sua vera forma, che è umanoide. Le sue statistiche, a\nparte la CA, sono le stesse in tutte le forme. Qualsiasi\nequipaggiamento stia indossando o trasportando non viene\ntrasformato. Alla morte ritorna alla sua vera forma.\nOlfatto Affinato. Il ratto mannaro ha vantaggio nelle prove di\nSaggezza (Percezione) basate sull''olfatto.\nAzioni\nMultiattacco (Solo in Forma Umanoide o Ibrida). Il ratto\nmannaro effettua due attacchi, di cui solo uno può essere con il\nmorso.\nSpada Corta (Soltanto in Forma Umanoide o Ibrida). Attacco\ncon arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 5 (1d6 + 2) danni perforanti.\nBalestra a mano (Soltanto in Forma Umanoide o Ibrida).\nAttacco con arma a Distanza: +4 a colpire, gittata 9/36 m, un\nbersaglio.\nColpisce: 5 (1d6 + 2) danni perforanti.\nMorso (Soltanto in Forma di Ratto o Ibrida). Attacco con arma\nda mischia: +4 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 4 (1d4 + 2) danni perforanti. Se il bersaglio è un\numanoide, deve riuscire un tiro salvezza di Costituzione CD 11 o\nvenir maledetto dalla licantropia del ratto mannaro."}}', '2026-03-30T15:54:05.400Z', '2026-03-30T16:00:32.341Z');
