INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zY2hlbGV0cm8tZGktbWlub3RhdXJvLmpzb24', 'scheletro-di-minotauro', 'Scheletro di Minotauro', 'SRD', 'srd-extracted/scheletro-di-minotauro.json', '2', 2, 450, 'Grande', 'non morto', 'legale malvagio', '{"slug":"scheletro-di-minotauro","general":{"name":"Scheletro di Minotauro","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"non morto","subtype":"","typeLabel":"non morto","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura naturale"},"hitPoints":{"average":67,"formula":"9d10 + 18"},"speed":{"walk":"12 m"}},"abilities":{"strength":18,"dexterity":11,"constitution":15,"intelligence":6,"wisdom":8,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":["contundente"],"damageResistances":[],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato","sfinimento"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 9"}],"languages":[{"name":"comprende l''Abissale ma non può parlare"}],"proficiencyBonus":2},"traits":[{"name":"Carica","usage":null,"description":"Se lo scheletro di minotauro si muove di almeno 3 metri in linea retta verso il bersaglio e poi lo colpisce con un attacco di incornata durante lo stesso turno, il bersaglio subisce 9 (2d8) danni perforanti aggiuntivi. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Forza CD 14 o venire spinto di 3 metri indietro e cadere prono."},{"name":"Natura Non Morta","usage":null,"description":"Lo scheletro non necessita aria, cibo, bevande o sonno."}],"actions":[{"name":"Ascia Bipenne","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 17 (2d12 + 4) danni tag