INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zY29ycGlvbmUtZ2lnYW50ZS5qc29u', 'scorpione-gigante', 'Scorpione Gigante', 'SRD', 'srd-extracted/scorpione-gigante.json', '3', 3, 700, 'Grande', 'bestia', 'disallineato', '{"slug":"scorpione-gigante","general":{"name":"Scorpione Gigante","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"Grande","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":52,"formula":"7d10 + 14"},"speed":{"walk":"12 m"}},"abilities":{"strength":15,"dexterity":13,"constitution":15,"intelligence":1,"wisdom":9,"charisma":3},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"18 m"},{"name":"Percezione passiva 9"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"Lo scorpione effettua tre attacchi: due con gli artigli e uno con il pungiglione."},{"name":"Artiglio","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d8 + 2) danni contundenti e il bersaglio è afferrato (CD 12 per fuggire). Lo scorpione ha due artigli, ciascuno dei quali può afferrare solo un bersaglio."},{"name":"Pungiglione","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, una creatura. Colpisce: 7 (1d10 + 2) danni perforanti e il bersaglio deve effettuare un tiro salvezza di Costituzione CD 12, e subire 22 (4d10) danni da veleno se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Scorpione Gigante\nGrande bestia, disallineato\nFORZA 15 (+2)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 9 (-1)\nCARISMA 3 (-4)\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 52 (7d10 + 14)\nVelocità 12 m\nSensi vista cieca 18 m, Percezione passiva 9\nLingue -\nSfida 3 (700 PE)\nAzioni\nMultiattacco. Lo scorpione effettua tre attacchi: due con gli\nartigli e uno con il pungiglione.\nArtiglio. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (1d8 + 2) danni contundenti e il bersaglio è afferrato\n(CD 12 per fuggire). Lo scorpione ha due artigli, ciascuno dei\nquali può afferrare solo un bersaglio.\nPungiglione. Attacco con Arma da Mischia: +4 a colpire, portata\n1,5 m, una creatura.\nColpisce: 7 (1d10 + 2) danni perforanti e il bersaglio deve\neffettuare un tiro salvezza di Costituzione CD 12, e subire 22\n(4d10) danni da veleno se fallisce il tiro salvezza, o la metà di\nquesti danni se lo riesce."}}', '2026-03-30T15:54:05.559Z', '2026-03-30T16:00:32.476Z');
