INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zZWd1Z2lvLWluZmVybmFsZS5qc29u', 'segugio-infernale', 'Segugio Infernale', 'SRD', 'srd-extracted/segugio-infernale.json', '3', 3, 700, 'Media', 'immondo', 'legale malvagio', '{"slug":"segugio-infernale","general":{"name":"Segugio Infernale","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"Media","creatureType":"immondo","subtype":"","typeLabel":"immondo","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":45,"formula":"7d8 + 14"},"speed":{"walk":"15 m"}},"abilities":{"strength":17,"dexterity":12,"constitution":14,"intelligence":6,"wisdom":13,"charisma":6},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":5}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fuoco"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 15"}],"languages":[{"name":"comprende l''Infernale ma non può parlare"}],"proficiencyBonus":2},"traits":[{"name":"Udito e Olfatto Affinato","usage":null,"description":"Il segugio ha vantaggio nelle prove di"},{"name":"Saggezza (Percezione) basate su udito od olfatto","usage":null,"description":""},{"name":"Tattiche di Branco","usage":null,"description":"Il segugio ha vantaggio ai tiri per colpire contro una creatura se almeno uno degli alleati del segugio si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (1d6 + 3) danni perforanti più 7 (2d6) danni da fuoco."},{"name":"Soffio Infuocato","usage":"Ricarica 5-6","description":"Il segugio esala fuoco in un cono di 4,5 metri. Ogni creatura in quell''area deve effettuare un tiro salvezza di Destrezza CD 12, e subire 21 (6d6) danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Segugio Infernale\nMedia immondo, legale malvagio\nFORZA 17 (+3)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 6 (-2)\nSAGGEZZA 13 (+1)\nCARISMA 6 (-2)\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 45 (7d8 + 14)\nVelocità 15 m\nAbilità Percezione +5\nImmunità al Danno fuoco\nSensi scurovisione 18 m, Percezione passiva 15\nLinguaggi comprende l''Infernale ma non può parlare\nSfida 3 (700 PE)\nUdito e Olfatto Affinato. Il segugio ha vantaggio nelle prove di\nSaggezza (Percezione) basate su udito od olfatto.\nTattiche di Branco. Il segugio ha vantaggio ai tiri per colpire\ncontro una creatura se almeno uno degli alleati del segugio si\ntrova entro 1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMorso. Attacco con arma da mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 7 (1d6 + 3) danni perforanti più 7 (2d6) danni da\nfuoco.\nSoffio Infuocato (Ricarica 5-6). Il segugio esala fuoco in un\ncono di 4,5 metri. Ogni creatura in quell''area deve effettuare un\ntiro salvezza di Destrezza CD 12, e subire 21 (6d6) danni da\nfuoco se fallisce il tiro salvezza, o la metà di questi danni se lo\nriesce."}}', '2026-03-30T15:54:05.463Z', '2026-03-30T16:00:32.382Z');
