rom":"srd05_13_bestiario.pdf","rawText":"Triceratopo\nEnorme bestia, disallineato\nFORZA 22 (+6)\nDESTREZZA 9 (-1)\nCOSTITUZIONE 17 (+3)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 11 (+0)\nCARISMA 5 (-3)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 95 (10d12 + 30)\nVelocità 15 m\nSensi Percezione passiva 10\nLinguaggi -\nSfida 5 (1.800 PE)\nCarica Travolgente. Se il triceratopo si muove di almeno 6 metri\ndiretto verso una creatura e la colpisce con un attacco di\nincornata durante lo stesso turno, il bersaglio deve riuscire un\ntiro salvezza di Forza CD 13 o cadere prono. Se il bersaglio è\nprono, il triceratopo può effettuare un attacco di pestone contro\ndi lui come azione bonus.\nAzioni\nIncornata. Attacco con arma da mischia: +9 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 24 (3d10 + 6) danni perforanti.\nPestone. Attacco con arma da mischia: +9 a colpire, portata 1,5\nm, una creatura prona.\nColpisce: 22 (3d10 + 6) danni contundenti."}}', '2026-03-30T15:54:05.307Z', '2026-03-30T16:00:32.261Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90cm9sbC5qc29u', 'troll', 'Troll', 'SRD', 'srd-extracted/troll.json', '5', 5, 1800, 'Grande', 'gigante', 'caotico malvagio', '{"slug":"troll","general":{"name":"Troll","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Grande","creatureType":"gigante","subtype":"","typeLabel":"gigante","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":84,"formula":"8d10 + 40"},"speed":{"walk":"9 m"}},"abilities":{"strength":18,"dexterity":13,"constitution":20,"intelligence":7,"wisdom":9,"charisma":7},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 12"}],"languages":[{"name":"Gigante"}],"proficiencyBonus":3},"traits":[{"name":"Olfatto Affinato","usage":null,"description":"Il troll ha vantaggio alle prove di Saggezza (Percezione) basate sull''olfatto."},{"name":"Rigenerazione","usage":null,"description":"Il troll recupera 10 punti ferita all''inizio del suo turno. Se il troll subisce danno da acido o da fuoco, questo tratto non funziona all''inizio del prossimo turno del troll. Il troll muore solo se inizia il suo turno a 0 punti ferita e non può rigenerarsi."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il troll può effettuare tre attacchi: uno con il morso e due con gli artigli."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni taglienti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (1d6 + 4) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Troll\nGrande gigante, caotico malvagio\nFORZA 18 (+4)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 20 (+5)\nINTELLIGENZA 7 (-2)\nSAGGEZZA 9 (-1)\nCARISMA 7 (-2)\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 84 (8d10 + 40)\nVelocità 9 m\nAbilità Percezione +2\nSensi scurovisione 18 m, Percezione passiva 12\nLinguaggi Gigante\nSfida 5 (1.800 PE)\nOlfatto Affinato. Il troll ha vantaggio alle prove di Saggezza\n(Percezione) basate sull''olfatto.\nRigenerazione. Il troll recupera 10 punti ferita all''inizio del suo\nturno. Se il troll subisce danno da acido o da fuoco, questo tratto\nnon funziona all''inizio del prossimo turno del troll. Il troll muore\nsolo se inizia il suo turno a 0 punti ferita e non può rigenerarsi.\nAzioni\nMultiattacco. Il troll può effettuare tre attacchi: uno con il morso\ne due con gli artigli.\nArtiglio. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 11 (2d6 + 4) danni taglienti.\nMorso. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 7 (1d6 + 4) danni perforanti."}}', '2026-03-30T15:54:05.473Z', '2026-03-30T16:00:32.390Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC91bmljb3Juby5qc29u', 'unicorno', 'Unicorno', 'SRD', 'srd-extracted/unicorno.json', '5', 5, 1800, 'Grande', 'celestiale', 'legale buono', '{"slug":"unicorno","general":{"name":"Unicorno","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Grande","creatureType":"celestiale","subtype":"","typeLabel":"celestiale","alignment":"legale buono","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":67,"formula":"9d10 + 18"},"speed":{"walk":"15 m"}},"abilities":{"strength":18,"dexterity":14,"constitution":15,"intelligence":11,"wisdom":17,"charisma":16},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["veleno"],"conditionImmunities":["affascinato","avvelenato","paralizzato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"Celestiale"},{"name":"Elfico"},{"name":"Silvano"},{"name":"telepatia","value":"18 m"}],"proficiencyBonus":3},"traits":[{"name":"Armi Magiche","usage":null,"description":"Gli attacchi con armi dell''unicorno sono magici."},{"name":"Carica","usage":null,"description":"Se l''unicorno si muove di almeno 6 metri in linea retta verso il bersaglio e lo colpisce con un attacco di corno durante lo stesso turno, il bersaglio subisce 9 (2d8) danni perforanti aggiuntivi. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Forza CD 15 o cadere prono."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato dell''unicorno è il Carisma (CD 14 per i tiri salvezza degli incantesimi). L''unicorno può lanciare in maniera innata i seguenti incantesimi, senza bisogno di componenti: A volontà: arte del druido, individuazione del bene e male, passare senza tracce 1/giorno ciascuno: calmare emozioni, dissolvi il bene e il male, intralciare"},{"name":"Resistenza alla Magia","usage":null,"description":"L''unicorno ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''unicorno effettua due attacchi: uno con gli zoccoli e uno con il corno."},{"name":"Corno","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 8 (1d8 + 4) danni perforanti."},{"name":"Zoccoli","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni contundenti."},{"name":"Telestraporto","usage":"1/Giorno","description":"L''unicorno può teletrasportare magicamente sé stesso e fino a tre altre creature consenzienti visibili entro 1,5 metri da esso, insieme a tutto l''equipaggiamento che stanno indossando o trasportando, in un luogo familiare all''unicorno, che si trova ad un massimo di 1,5 chilometri di distanza."},{"name":"Tocco Guaritore","usage":"3/Giorno","description":"L''unicorno entra a contatto tramite il corno con un''altra creatura. Il bersaglio recupera magicamente 11 (2d8 + 2) punti ferita. Inoltre, il contatto rimuove tutte le malattie e neutralizza tutti i veleni che affliggono il bersaglio."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"L''unicorno può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. L''unicorno recupera le azioni leggendarie spese all''inizio del proprio turno.","actions":[{"name":"Autoguarigione","description":"L''unicorno recupera magicamente 11 (2d8 + 2) punti ferita.","cost":3},{"name":"Scudo Scintillante","description":"L''unicorno crea un campo magico scintillante che circonda lui o un''altra creatura visibile a lui entro 18 metri. Il bersaglio ottiene un bonus di +2 alla CA fino al termine del prossimo turno dell''unicorno.","cost":2},{"name":"Zoccoli","description":"L''unicorno effettua un attacco con gli zoccoli.","cost":1}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Unicorno\nGrande celestiale, legale buono\nFORZA 18 (+4)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 17 (+3)\nCARISMA 16 (+3)\nClasse Armatura 12\nPunti Ferita 67 (9d10 + 18)\nVelocità 15 m\nImmunità al Danno veleno\nImmunità alle Condizioni affascinato, avvelenato, paralizzato\nSensi scurovisione 18 m, Percezione passiva 13\nLinguaggi Celestiale, Elfico, Silvano, telepatia 18 m\nSfida 5 (1.800 PE)\nArmi Magiche. Gli attacchi con armi dell''unicorno sono magici.\nCarica. Se l''unicorno si muove di almeno 6 metri in linea retta\nverso il bersaglio e lo colpisce con un attacco di corno durante lo\nstesso turno, il bersaglio subisce 9 (2d8) danni perforanti\naggiuntivi. Se il bersaglio è una creatura, deve riuscire un tiro\nsalvezza di Forza CD 15 o cadere prono.\nIncantesimi Innati. La caratteristica da incantatore innato\ndell''unicorno è il Carisma (CD 14 per i tiri salvezza degli\nincantesimi). L''unicorno può lanciare in maniera innata i\nseguenti incantesimi, senza bisogno di componenti:\nA volontà: arte del druido, individuazione del bene e male,\npassare senza tracce\n1/giorno ciascuno: calmare emozioni, dissolvi il bene e il male,\nintralciare\nResistenza alla Magia. L''unicorno ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nMultiattacco. L''unicorno effettua due attacchi: uno con gli\nzoccoli e uno con il corno.\nCorno. Attacco con arma da mischia: +7 a colpire, portata 1,5 m,\nun bersaglio.\nColpisce: 8 (1d8 + 4) danni perforanti.\nZoccoli. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 11 (2d6 + 4) danni contundenti.\nTelestraporto (1/Giorno). L''unicorno può teletrasportare\nmagicamente sé stesso e fino a tre altre creature consenzienti\nvisibili entro 1,5 metri da esso, insieme a tutto\nl''equipaggiamento che stanno indossando o trasportando, in un\nluogo familiare all''unicorno, che si trova ad un massimo di 1,5\nchilometri di distanza.\nTocco Guaritore (3/Giorno). L''unicorno entra a contatto tramite\nil corno con un''altra creatura. Il bersaglio recupera magicamente\n11 (2d8 + 2) punti ferita. Inoltre, il contatto rimuove tutte le\nmalattie e neutralizza tutti i veleni che affliggono il bersaglio.\n\n-- 106 of 151 --\n\nAzioni Leggendarie\nL''unicorno può effettuare 3 azioni leggendarie, scelte tra le\nopzioni seguenti. Può usare solo un''opzione leggendaria alla\nvolta e solo al termine del turno di un''altra creatura. L''unicorno\nrecupera le azioni leggendarie spese all''inizio del proprio turno.\nAutoguarigione (Costa 3 Azioni). L''unicorno recupera\nmagicamente 11 (2d8 + 2) punti ferita.\nScudo Scintillante (Costa 2 Azioni). L''unicorno crea un campo\nmagico scintillante che circonda lui o un''altra creatura visibile a lui\nentro 18 metri. Il bersaglio ottiene un bonus di +2 alla CA fino al\ntermine del prossimo turno dell''unicorno.\nZoccoli. L''unicorno effettua un attacco con gli zoccoli."}}', '2026-03-30T15:54:05.477Z', '2026-03-30T16:00:32.393Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC91b21vLWFjcXVhdGljby5qc29u', 'uomo-acquatico', 'Uomo Acquatico', 'SRD', 'srd-extracted/uomo-acquatico.json', '1/8', 0.125, 25, 'Media', 'umanoide', 'neutrale', '{"slug":"uomo-acquatico","general":{"name":"Uomo Acquatico","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"Media","creatureType":"umanoide","subtype":"uomo acquatico","typeLabel":"umanoide (uomo acquatico)","alignment":"neutrale","environments":[]},"combat":{"armorClass":{"value":11,"note":""},"hitPoints":{"average":11,"formula":"2d8 + 2"},"speed":{"walk":"3 m","swim":"12 m"}},"abilities":{"strength":10,"dexterity":13,"constitution":12,"intelligence":11,"wisdom":11,"charisma":12},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 12"}],"languages":[{"name":"Aquan"},{"name":"Comune"}],"proficiencyBonus":2},"traits":[{"name":"Anfibio","usage":null,"description":"L''uomo acquatico può respirare aria e acqua."}],"actions":[{"name":"Lancia","usage":null,"description":"Attacco con arma da mischia o a Distanza: +2 a colpire, portata 1,5 m o gittata 6/18 m, un bersaglio. Colpisce: 3 (1d6) danni perforanti, o 4 (1d8) danni perforanti se usata con due mani per effettuare un attacco da mischia."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Uomo Acquatico\nMedia umanoide (uomo acquatico), neutrale\nFORZA 10 (+0)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 11 (+0)\nCARISMA 12 (+1)\nClasse Armatura 11\nPunti Ferita 11 (2d8 + 2)\nVelocità 3 m, nuoto 12 m\nAbilità Percezione +2\nSensi Percezione passiva 12\nLinguaggi Aquan, Comune\nSfida 1/8 (25 PE)\nAnfibio. L''uomo acquatico può respirare aria e acqua.\nAzioni\nLancia. Attacco con arma da mischia o a Distanza: +2 a colpire,\nportata 1,5 m o gittata 6/18 m, un bersaglio.\nColpisce: 3 (1d6) danni perforanti, o 4 (1d8) danni perforanti se\nusata con due mani per effettuare un attacco da mischia."}}', '2026-03-30T15:54:05.474Z', '2026-03-30T16:00:32.391Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC91b21vLWFsYmVyby10cmVhbnQuanNvbg', 'uomo-albero-treant', 'Uomo Albero (Treant)', 'SRD', 'srd-extracted/uomo-albero-treant.json', '9', 9, 5000, 'Enorme', 'pianta', 'caotico buono', '{"slug":"uomo-albero-treant","general":{"name":"Uomo Albero (Treant)","challengeRating":{"fraction":"9","decimal":9,"display":"9","xp":5000},"size":"Enorme","creatureType":"pianta","subtype":"","typeLabel":"pianta","alignment":"caotico buono","environments":[]},"combat":{"armorClass":{"value":16,"note":"armatura naturale"},"hitPoints":{"average":138,"formula":"12d12 + 60"},"speed":{"walk":"9 m"}},"abilities":{"strength":23,"dexterity":8,"constitution":21,"intelligence":12,"wisdom":16,"charisma":12},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":["fuoco"],"damageResistances":["contundente","perforante"],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[{"name":"Comune"},{"name":"Druidico"},{"name":"Elfico"},{"name":"Silvano"}],"proficiencyBonus":4},"traits":[{"name":"Falso Aspetto","usage":null,"description":"Mentre l''uomo albero rimane immobile, è indistinguibile da un normale albero."},{"name":"Mostro d''Assedio","usage":null,"description":"L''uomo albero infligge danni doppi agli oggetti e le strutture."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''uomo albero effettua due attacchi di schianto."},{"name":"Schianto","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 1,5 m, un bersaglio. Colpisce: 16 (3d6 + 6) danni contundenti."},{"name":"Sasso","usage":null,"description":"Attacco con arma a Distanza: +10 a colpire, gittata 18/54 m, un bersaglio. Colpisce: 28 (4d10 + 6) danni contundenti."},{"name":"Animare Alberi","usage":"1/Giorno","description":"L''uomo albero anima magicamente uno o due alberi visibili entro 18 metri da lui. Questi albeti hanno le stesse statistiche dell''ent, eccetto che hanno punteggio di Intelligenza e Carisma 1 (-5), non possono parlare, e hanno solo l''opzione di attacco Schianto. Un albero animato agisce come alleato dell''uomo albero. L''albero resta per 1 giorno o finché muore; finché l''uomo albero muore o si trova più di 36 metri lontano dall''albero, o finché l''uomo albero non effettua un''azione bonus per ritrasformarlo in un albero inanimato. Poi l''albero prenderà radici, se possibile."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Uomo Albero (Treant)\nEnorme pianta, caotico buono\nFORZA 23 (+6)\nDESTREZZA 8 (-1)\nCOSTITUZIONE 21 (+5)\nINTELLIGENZA 12 (+1)\nSAGGEZZA 16 (+3)\nCARISMA 12 (+1)\nClasse Armatura 16 (armatura naturale)\nPunti Ferita 138 (12d12 + 60)\nVelocità 9 m\nResistenze al Danno contundente, perforante\nVulnerabilità al Danno fuoco\nSensi Percezione passiva 13\nLinguaggi Comune, Druidico, Elfico, Silvano\nSfida 9 (5.000 PE)\nFalso Aspetto. Mentre l''uomo albero rimane immobile, è\nindistinguibile da un normale albero.\nMostro d''Assedio. L''uomo albero infligge danni doppi agli\noggetti e le strutture.\nAzioni\nMultiattacco. L''uomo albero effettua due attacchi di schianto.\nSchianto. Attacco con arma da mischia: +10 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 16 (3d6 + 6) danni contundenti.\nSasso. Attacco con arma a Distanza: +10 a colpire, gittata 18/54\nm, un bersaglio.\nColpisce: 28 (4d10 + 6) danni contundenti.\nAnimare Alberi (1/Giorno). L''uomo albero anima magicamente\nuno o due alberi visibili entro 18 metri da lui. Questi albeti hanno\nle stesse statistiche dell''ent, eccetto che hanno punteggio di\nIntelligenza e Carisma 1 (-5), non possono parlare, e hanno solo\nl''opzione di attacco Schianto. Un albero animato agisce come\nalleato dell''uomo albero. L''albero resta per 1 giorno o finché\nmuore; finché l''uomo albero muore o si trova più di 36 metri\nlontano dall''albero, o finché l''uomo albero non effettua\nun''azione bonus per ritrasformarlo in un albero inanimato. Poi\nl''albero prenderà radici, se possibile."}}', '2026-03-30T15:54:05.475Z', '2026-03-30T16:00:32.392Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC91b21vLW1hZ21hLW1hZ21pbi5qc29u', 'uomo-magma-magmin', 'Uomo Magma (Magmin)', 'SRD', 'srd-extracted/uomo-magma-magmin.json', '1/2', 0.5, 100, NULL, NULL, NULL, '{"slug":"uomo-magma-magmin","general":{"name":"Uomo Magma (Magmin)","challengeRating":{"fraction":"1/2","decimal":0.5,"display":"1/2","xp":100},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":14,"note":"armatura naturale"},"hitPoints":{"average":9,"formula":"2d6 + 2"},"speed":{"walk":"9 m"}},"abilities":{"strength":7,"dexterity":15,"constitution":12,"intelligence":8,"wisdom":11,"charisma":10},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":["contundente","perforante e tagliente di"],"damageImmunities":["fuoco"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 10"}],"languages":[{"name":"Ignan"}],"proficiencyBonus":2},"traits":[{"name":"Illuminazione Incendiaria","usage":null,"description":"Come azione bonus, l''uomo magma può accendere o spegnere le sue fiamme. Mentre la fiamma è accesa, l''uomo magma irradia luce intensa in un raggio di 3 metri e luce fioca per ulteriori 3 metri."},{"name":"Scoppio Mortale","usage":null,"description":"Quando l''uomo magma muore, esplode in uno scoppio di fuoco e magma. Ogni creatura entro 3 metri da esso deve effettuare un tiro salvezza di Destrezza CD 11, subendo 7 (2d6) danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo riesce. Gli oggetti infiammabili che non siano indossati o trasportati e che si trovino nell''area, prendono fuoco."}],"actions":[{"name":"Tocco","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (2d6) danni da fuoco. Se il bersaglio è una creatura o un oggetto infiammabile, questi prende fuoco. Fino a che una creatura effettua un''azione per estinguere la fiamma, la creatura subisce 3 (1d6) danni da fuoco al termine di ciascun suo turno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Uomo Magma\n(Magmin)\nPiccola elementale, caotico neutrale\nFORZA 7 (-2)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 8 (-1)\nSAGGEZZA 11 (+0)\nCARISMA 10 (+0)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 9 (2d6 + 2)\nVelocità 9 m\nResistenze al Danno contundente, perforante e tagliente di\nattacchi non magici\nImmunità ai Danni fuoco\nSensi scurovisione 18 m, Percezione passiva 10\nLinguaggi Ignan\nSfida 1/2 (100 PE)\nIlluminazione Incendiaria. Come azione bonus, l''uomo magma\npuò accendere o spegnere le sue fiamme. Mentre la fiamma è\naccesa, l''uomo magma irradia luce intensa in un raggio di 3\nmetri e luce fioca per ulteriori 3 metri.\nScoppio Mortale. Quando l''uomo magma muore, esplode in uno\nscoppio di fuoco e magma. Ogni creatura entro 3 metri da esso\ndeve effettuare un tiro salvezza di Destrezza CD 11, subendo 7\n(2d6) danni da fuoco se fallisce il tiro salvezza, o la metà di\nquesti danni se lo riesce. Gli oggetti infiammabili che non siano\nindossati o trasportati e che si trovino nell''area, prendono fuoco.\nAzioni\nTocco. Attacco con arma da mischia: +4 a colpire, portata 1,5 m,\nun bersaglio.\nColpisce: 7 (2d6) danni da fuoco. Se il bersaglio è una creatura o\nun oggetto infiammabile, questi prende fuoco. Fino a che una\ncreatura effettua un''azione per estinguere la fiamma, la creatura\nsubisce 3 (1d6) danni da fuoco al termine di ciascun suo turno."}}', '2026-03-30T15:54:05.476Z', '2026-03-30T16:00:32.392Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC92YW1waXJvLmpzb24', 'vampiro', 'Vampiro', 'SRD', 'srd-extracted/vampiro.json', '13', 13, 10000, 'Media', 'non morto', 'legale malvagio', '{"slug":"vampiro","general":{"name":"Vampiro","challengeRating":{"fraction":"13","decimal":13,"display":"13","xp":10000},"size":"Media","creatureType":"non morto","subtype":"mutaforma","typeLabel":"non morto (mutaforma)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":16,"note":"armatura naturale"},"hitPoints":{"average":144,"formula":"17d8 + 68"},"speed":{"walk":"9 m"}},"abilities":{"strength":18,"dexterity":18,"constitution":18,"intelligence":17,"wisdom":15,"charisma":18},"details":{"savingThrows":[{"ability":"Destrezza","bonus":9},{"ability":"Saggezza","bonus":7},{"ability":"Carisma","bonus":9}],"skills":[{"name":"Furtività","bonus":9},{"name":"Percezione","bonus":17}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["necrotico; contundente","perforante e"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 17"}],"languages":[{"name":"le lingue che conosceva in vita"}],"proficiencyBonus":5},"traits":[{"name":"Mutaforma","usage":null,"description":"Se il vampiro non è sotto la luce del sole o immerso in acqua corrente, può usare la sua azione per trasformarsi in un Minuscolo pipistrello, una nube di foschia Media, o per tornare alla sua vera forma. Mentre è in forma di pipistrello, il vampiro non può parlare, la sua velocità di passeggio è 1,5 metri e ha velocità di volo 9 metri. Le sue statistiche, a parte la taglia e la velocità, sono immutate. Qualsiasi equipaggiamento stia indossando si trasforma con esso, ma quello che stava trasportando viene fatto cadere a terra. Alla morte ritorna alla sua vera forma. Mentre è in forma di foschia, il vampiro non può effettuare azioni, parlare o manipolare oggetti. È privo di peso, ha velocità di volo 6 metri, può fluttuare, e può entrare nello spazio di una creatura ostile e fermarsi lì. Inoltre, se in uno spazio vi passa dell''aria, la foschia può fare altrettanto senza stringersi, ma non può attraversare l''acqua. Ha vantaggio ai tiri salvezza di Forza, Destrezza e Costituzione, ed è immune a tutti i danni non magici, eccetto i danni subiti dalla luce del sole."},{"name":"Debolezze del Vampiro","usage":null,"description":"Il vampiro ha i seguenti difetti:"},{"name":"Danneggiato dall''Acqua Corrente","usage":null,"description":"Il vampiro subisce 20 danni da acido se termina il suo turno all''interno dell''acqua corrente."},{"name":"Ipersensibilità alla Luce","usage":null,"description":"Il vampiro subisce 20 danni radianti quando inizia il suo turno alla luce del sole. Mentre è alla luce del sole, ha svantaggio ai tiri di attacco e le prove di abilità."},{"name":"Paletto nel Cuore","usage":null,"description":"Se un''arma perforante fatta di legno viene conficcata nel cuore del vampiro mentre il vampiro è inabile nel suo luogo di riposo, il vampiro resta paralizzato finché il paletto non viene rimosso."},{"name":"Proibizione","usage":null,"description":"Il vampiro non può entrare in un''abitazione senza invito da parte dei suoi occupanti."},{"name":"Fuga nella Foschia","usage":null,"description":"Quando scende a 0 punti ferita al di fuori del suo luogo di riposo, il vampiro si trasforma in una nube di foschia (come per il tratto Mutaforma) invece di cadere privo di sensi, purché non sia esposto alla luce del sole o all''acqua corrente. Se non può trasformarsi, viene distrutto. Mentre si trova a 0 punti ferita in questa forma, non può tornare alla sua forma di vampiro, e deve raggiungere il suo luogo di riposo entro 2 ore o venire distrutto. Una volta raggiunto il suo luogo di riposo, ritorna alla sua forma di vampiro. Resterà quindi paralizzato finché non avrà recuperato almeno 1 punto ferita. Dopo aver trascorso almeno 1 ora nel suo luogo di riposo a 0 punti ferita, il vampiro recupererà 1 punto ferita."},{"name":"Natura Non Morta","usage":null,"description":"Il vampiro non ha bisogno di aria."},{"name":"Resistenza Leggendaria","usage":"3/Giorno","description":"Se il vampiro fallisce un tiro salvezza, può scegliere invece di riuscire."},{"name":"Rigenerazione","usage":null,"description":"Il vampiro recupera 20 punti ferita all''inizio del suo turno se possiede almeno 1 punto ferita e non è esposto alla luce del sole o l''acqua corrente. Se il vampiro subisce danno radiante o danno dall''acqua sacra, questo tratto non funziona all''inizio del prossimo turno del vampiro."},{"name":"Scalare come Ragno","usage":null,"description":"Il vampiro può scalare superfici difficili, compreso lo stare a testa in giù sul soffitto, senza bisogno di effettuare una prova di abilità."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il vampiro può effettuare due attacchi, ma solo uno di essi può essere un attacco con morso."},{"name":"Colpo Disarmato","usage":"Solo in Forma di Vampiro","description":"Attacco con arma da mischia: +9 a colpire, portata 1,5 m, una creatura. Colpisce: 8 (1d8 + 4) danni contundenti. Invece di infliggere danno, il vampiro può afferrare il bersaglio (CD per fuggire 18)."},{"name":"Morso","usage":"Solo in Forma di Pipistrello o Vampiro","description":"Attacco con arma da mischia: +9 a colpire, portata 1,5 m, una creatura consenziente o una creatura afferrata dal vampiro, inabile o intralciata. Colpisce: 7 (1d6 + 4) danni perforanti più 10 (3d6) danni necrotici. I punti ferita massimi del bersaglio sono ridotti di un ammontare pari al danno necrotico subito, e il vampiro recupera un numero di punti ferita pari a quell''ammontare. Questa riduzione permane finché il bersaglio non termina un riposo lungo. Il bersaglio muore se questo effetto riduce i suoi punti ferita massimi a 0. Un umanoide ucciso in questo modo e poi sepolto nel terreno si rianima la notte seguente come progenie vampirica sotto il controllo del vampiro."},{"name":"Affascinare","usage":null,"description":"Il vampiro prende a bersaglio un umanoide entro 9 metri che può vedere. Se il bersaglio può vedere il vampiro, deve effettuare un tiro salvezza di Saggezza CD 17 contro questa magia o esserne affascinato. Il bersaglio affascinato considera il vampiro un amico fidato da ascoltare e proteggere. Sebbene il bersaglio non sia sotto il controllo del vampiro, prende le richieste e le azioni del vampiro nel modo più favorevole possibile, ed è un bersaglio consenziente dell''attacco con morso del vampiro. Ogni volta che il vampiro o i compagni del vampiro fanno qualcosa di nocivo al bersaglio, questi può ripetere il tiro salvezza, terminando l''effetto su di sé in caso di successo. Altrimenti, l''effetto persiste 24 ore o finché il vampiro non viene distrutto, si trova su di un piano di esistenza diverso dal bersaglio, o effettua un''azione bonus per terminare l''effetto."},{"name":"Figli della Notte","usage":"1/Giorno","description":"Il vampiro richiama magicamente 2d4 sciami di pipistrelli o ratti, purché il sole non sia sorto."},{"name":"Mentre è all''esterno, il vampiro può richiamare invece 3d6 lupi","usage":null,"description":"Le creature richiamate arrivano in 1d4 round, agendo da alleati del vampiro e obbedendo ai suoi comandi. Le bestie restano per 1 ora, finché il vampiro non muore, o finché non le congeda con un''azione bonus."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"Il vampiro può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. Il vampiro recupera all''inizio del proprio turno le azioni leggendarie che ha speso.","actions":[{"name":"Colpo Disarmato","description":"Il vampiro effettua un colpo disarmato.","cost":1},{"name":"Morso","description":"Il vampiro effettua un attacco con morso.","cost":2},{"name":"Muoversi","description":"Il vampiro si muove della sua velocità senza provocare attacchi di opportunità.","cost":1}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Vampiro\nMedia non morto (mutaforma), legale malvagio\nFORZA 18 (+4)\nDESTREZZA 18 (+4)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 17 (+3)\nSAGGEZZA 15 (+2)\nCARISMA 18 (+4)\nClasse Armatura 16 (armatura naturale)\nPunti Ferita 144 (17d8 + 68)\nVelocità 9 m\nTiri Salvezza Destrezza +9, Saggezza +7, Carisma +9\nAbilità Furtività +9, Percezione +17\nImmunità al Danno necrotico; contundente, perforante e\ntagliente di attacchi non magici\nSensi scurovisione 36 m, Percezione passiva 17\nLinguaggi le lingue che conosceva in vita\nSfida 13 (10.000 PE)\nMutaforma. Se il vampiro non è sotto la luce del sole o immerso\nin acqua corrente, può usare la sua azione per trasformarsi in un\nMinuscolo pipistrello, una nube di foschia Media, o per tornare\nalla sua vera forma.\nMentre è in forma di pipistrello, il vampiro non può parlare, la\nsua velocità di passeggio è 1,5 metri e ha velocità di volo 9\nmetri. Le sue statistiche, a parte la taglia e la velocità, sono\nimmutate. Qualsiasi equipaggiamento stia indossando si\ntrasforma con esso, ma quello che stava trasportando viene fatto\ncadere a terra. Alla morte ritorna alla sua vera forma.\nMentre è in forma di foschia, il vampiro non può effettuare\nazioni, parlare o manipolare oggetti. È privo di peso, ha velocità\ndi volo 6 metri, può fluttuare, e può entrare nello spazio di una\ncreatura ostile e fermarsi lì. Inoltre, se in uno spazio vi passa\ndell''aria, la foschia può fare altrettanto senza stringersi, ma non\npuò attraversare l''acqua. Ha vantaggio ai tiri salvezza di Forza,\nDestrezza e Costituzione, ed è immune a tutti i danni non magici,\neccetto i danni subiti dalla luce del sole.\nDebolezze del Vampiro. Il vampiro ha i seguenti difetti:\nDanneggiato dall''Acqua Corrente. Il vampiro subisce 20 danni\nda acido se termina il suo turno all''interno dell''acqua corrente.\nIpersensibilità alla Luce. Il vampiro subisce 20 danni radianti\nquando inizia il suo turno alla luce del sole. Mentre è alla luce\ndel sole, ha svantaggio ai tiri di attacco e le prove di abilità.\nPaletto nel Cuore. Se un''arma perforante fatta di legno viene\nconficcata nel cuore del vampiro mentre il vampiro è inabile nel\nsuo luogo di riposo, il vampiro resta paralizzato finché il paletto\nnon viene rimosso.\nProibizione. Il vampiro non può entrare in un''abitazione senza\ninvito da parte dei suoi occupanti.\nFuga nella Foschia. Quando scende a 0 punti ferita al di fuori\ndel suo luogo di riposo, il vampiro si trasforma in una nube di\nfoschia (come per il tratto Mutaforma) invece di cadere privo di\nsensi, purché non sia esposto alla luce del sole o all''acqua\ncorrente. Se non può trasformarsi, viene distrutto.\nMentre si trova a 0 punti ferita in questa forma, non può tornare\nalla sua forma di vampiro, e deve raggiungere il suo luogo di\nriposo entro 2 ore o venire distrutto. Una volta raggiunto il suo\nluogo di riposo, ritorna alla sua forma di vampiro. Resterà quindi\nparalizzato finché non avrà recuperato almeno 1 punto ferita.\nDopo aver trascorso almeno 1 ora nel suo luogo di riposo a 0\npunti ferita, il vampiro recupererà 1 punto ferita.\nNatura Non Morta. Il vampiro non ha bisogno di aria.\nResistenza Leggendaria (3/Giorno). Se il vampiro fallisce un\ntiro salvezza, può scegliere invece di riuscire.\n\n-- 107 of 151 --\n\nSRD Italia 5a Edizione - Compendio dei Mostri\nRigenerazione. Il vampiro recupera 20 punti ferita all''inizio del\nsuo turno se possiede almeno 1 punto ferita e non è esposto alla\nluce del sole o l''acqua corrente. Se il vampiro subisce danno\nradiante o danno dall''acqua sacra, questo tratto non funziona\nall''inizio del prossimo turno del vampiro.\nScalare come Ragno. Il vampiro può scalare superfici difficili,\ncompreso lo stare a testa in giù sul soffitto, senza bisogno di\neffettuare una prova di abilità.\nAzioni\nMultiattacco. Il vampiro può effettuare due attacchi, ma solo uno\ndi essi può essere un attacco con morso.\nColpo Disarmato (Solo in Forma di Vampiro). Attacco con\narma da mischia: +9 a colpire, portata 1,5 m, una creatura.\nColpisce: 8 (1d8 + 4) danni contundenti. Invece di infliggere\ndanno, il vampiro può afferrare il bersaglio (CD per fuggire 18).\nMorso (Solo in Forma di Pipistrello o Vampiro). Attacco con\narma da mischia: +9 a colpire, portata 1,5 m, una creatura\nconsenziente o una creatura afferrata dal vampiro, inabile o\nintralciata.\nColpisce: 7 (1d6 + 4) danni perforanti più 10 (3d6) danni\nnecrotici. I punti ferita massimi del bersaglio sono ridotti di un\nammontare pari al danno necrotico subito, e il vampiro recupera\nun numero di punti ferita pari a quell''ammontare. Questa\nriduzione permane finché il bersaglio non termina un riposo\nlungo. Il bersaglio muore se questo effetto riduce i suoi punti\nferita massimi a 0. Un umanoide ucciso in questo modo e poi\nsepolto nel terreno si rianima la notte seguente come progenie\nvampirica sotto il controllo del vampiro.\nAffascinare. Il vampiro prende a bersaglio un umanoide entro 9\nmetri che può vedere. Se il bersaglio può vedere il vampiro, deve\neffettuare un tiro salvezza di Saggezza CD 17 contro questa\nmagia o esserne affascinato. Il bersaglio affascinato considera il\nvampiro un amico fidato da ascoltare e proteggere. Sebbene il\nbersaglio non sia sotto il controllo del vampiro, prende le\nrichieste e le azioni del vampiro nel modo più favorevole\npossibile, ed è un bersaglio consenziente dell''attacco con morso\ndel vampiro.\nOgni volta che il vampiro o i compagni del vampiro fanno\nqualcosa di nocivo al bersaglio, questi può ripetere il tiro\nsalvezza, terminando l''effetto su di sé in caso di successo.\nAltrimenti, l''effetto persiste 24 ore o finché il vampiro non viene\ndistrutto, si trova su di un piano di esistenza diverso dal\nbersaglio, o effettua un''azione bonus per terminare l''effetto.\nFigli della Notte (1/Giorno). Il vampiro richiama magicamente\n2d4 sciami di pipistrelli o ratti, purché il sole non sia sorto.\nMentre è all''esterno, il vampiro può richiamare invece 3d6 lupi.\nLe creature richiamate arrivano in 1d4 round, agendo da alleati\ndel vampiro e obbedendo ai suoi comandi. Le bestie restano per\n1 ora, finché il vampiro non muore, o finché non le congeda con\nun''azione bonus.\nAzioni Leggendarie\nIl vampiro può effettuare 3 azioni leggendarie, scelte tra le\nopzioni seguenti. Può usare solo un''opzione leggendaria alla\nvolta e solo al termine del turno di un''altra creatura. Il vampiro\nrecupera all''inizio del proprio turno le azioni leggendarie che ha\nspeso.\nColpo Disarmato. Il vampiro effettua un colpo disarmato.\nMorso (Costa 2 Azioni). Il vampiro effettua un attacco con\nmorso.\nMuoversi. Il vampiro si muove della sua velocità senza\nprovocare attacchi di opportunità."}}', '2026-03-30T15:55:58.200Z', '2026-03-30T16:00:32.396Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC92ZXJtZS1wdXJwdXJlby5qc29u', 'verme-purpureo', 'Verme Purpureo', 'SRD', 'srd-extracted/verme-purpureo.json', '15', 15, 13000, 'Mastodontica', 'mostruosità', 'disallineato', '{"slug":"verme-purpureo","general":{"name":"Verme Purpureo","challengeRating":{"fraction":"15","decimal":15,"display":"15","xp":13000},"size":"Mastodontica","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":18,"note":"armatura naturale"},"hitPoints":{"average":247,"formula":"15d20 + 90"},"speed":{"walk":"15 m","burrow":"9 m"}},"abilities":{"strength":28,"dexterity":7,"constitution":22,"intelligence":1,"wisdom":8,"charisma":4},"details":{"savingThrows":[{"ability":"Costituzione","bonus":11},{"ability":"Saggezza","bonus":4}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"9 m"},{"name":"senso tellurico","value":"18 m"},{"name":"Percezione passiva 9"}],"languages":[{"name":"-"}],"proficiencyBonus":5},"traits":[{"name":"Scavatore di Tunnel","usage":null,"description":"Il verme può scavare attraverso la roccia solida a metà della velocità di scavare e lascia un tunnel di 3 metri di diametro dietro di sè."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il verme effettua due attacchi: uno con il morso e uno con il pungiglione."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +9 a colpire, portata 3 m, un bersaglio. Colpisce: 22 (3d8 + 9) danni perforanti. Se il bersaglio è una creatura di taglia Grande, deve riuscire un tiro salvezza di"},{"name":"Destrezza CD 19 o venire inghiottita dal verme","usage":null,"description":"Mentre è inghiottita, la creatura è accecata e intralciata, ha copertura totale contro gli attacchi e altri effetti provenienti dall''esterno del verme, e subisce 21 (6d6) danni da acido all''inizio di ciascun turno del verme. Se il verme subisce 30 o più danni in un singolo turno da una creatura al suo interno, il verme deve riuscire un tiro salvezza di Costituzione CD 21 al termine del suo turno o vomitare tutte le creature inghiottite, che cadono prone in uno spazio entro 3 metri dal verme. Se il verme muore, una creatura inghiottita non risulta più intralciata da esso e può fuggire dal cadavere usando 6 metri di movimento, uscendo prona."},{"name":"Pungiglione","usage":null,"description":"Attacco con arma da mischia: +9 a colpire, portata 3 m, una creatura. Colpisce: 19 (3d6 + 9) danni perforanti, e il bersaglio deve effettuare un tiro salvezza di Costituzione CD 19, subendo 42 (12d6) danni da veleno se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Verme Purpureo\nMastodontica mostruosità, disallineato\nFORZA 28 (+9)\nDESTREZZA 7 (-2)\nCOSTITUZIONE 22 (+6)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 8 (-1)\nCARISMA 4 (-3)\nClasse Armatura 18 (armatura naturale)\nPunti Ferita 247 (15d20 + 90)\nVelocità 15 m, scavo 9 m\nTiri Salvezza Costituzione +11, Saggezza +4\nSensi vista cieca 9 m, senso tellurico 18 m, Percezione passiva 9\nLinguaggi -\nSfida 15 (13.000 PE)\nScavatore di Tunnel. Il verme può scavare attraverso la roccia\nsolida a metà della velocità di scavare e lascia un tunnel di 3\nmetri di diametro dietro di sè.\nAzioni\nMultiattacco. Il verme effettua due attacchi: uno con il morso e\nuno con il pungiglione.\nMorso. Attacco con arma da mischia: +9 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 22 (3d8 + 9) danni perforanti. Se il bersaglio è una\ncreatura di taglia Grande, deve riuscire un tiro salvezza di\nDestrezza CD 19 o venire inghiottita dal verme. Mentre è\ninghiottita, la creatura è accecata e intralciata, ha copertura totale\ncontro gli attacchi e altri effetti provenienti dall''esterno del\nverme, e subisce 21 (6d6) danni da acido all''inizio di ciascun\nturno del verme.\nSe il verme subisce 30 o più danni in un singolo turno da una\ncreatura al suo interno, il verme deve riuscire un tiro salvezza di\nCostituzione CD 21 al termine del suo turno o vomitare tutte le\ncreature inghiottite, che cadono prone in uno spazio entro 3 metri\ndal verme. Se il verme muore, una creatura inghiottita non risulta\npiù intralciata da esso e può fuggire dal cadavere usando 6 metri\ndi movimento, uscendo prona.\nPungiglione. Attacco con arma da mischia: +9 a colpire, portata\n3 m, una creatura.\nColpisce: 19 (3d6 + 9) danni perforanti, e il bersaglio deve\neffettuare un tiro salvezza di Costituzione CD 19, subendo 42\n(12d6) danni da veleno se fallisce il tiro salvezza, o la metà di\nquesti danni se lo riesce."}}', '2026-03-30T15:54:05.482Z', '2026-03-30T16:00:32.398Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC92ZXNwYS1naWdhbnRlLmpzb24', 'vespa-gigante', 'Vespa Gigante', 'SRD', 'srd-extracted/vespa-gigante.json', '1/2', 0.5, 100, 'Media', 'bestia', 'disallineato', '{"slug":"vespa-gigante","general":{"name":"Vespa Gigante","challengeRating":{"fraction":"1/2","decimal":0.5,"display":"1/2","xp":100},"size":"Media","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":13,"formula":"3d8"},"speed":{"walk":"3 m","fly":"15 m"}},"abilities":{"strength":10,"dexterity":14,"constitution":10,"intelligence":1,"wisdom":10,"charisma":3},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Lancia","usage":null,"description":"Attacco con Arma da Mischia o a Gittata: +3 a colpire, portata 1,5 m o gittata 6/18 m, un bersaglio. Colpisce: 4 (1d6 + 1) danni perforanti o 5 (1d8 + 1) danni perforanti se impiegata con due mani per effettuare un attacco da mischia."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Vespa Gigante\nMedia bestia, disallineato\nFORZA 10 (+0)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 10 (+0)\nCARISMA 3 (-4)\nClasse Armatura 12\nPunti Ferita 13 (3d8)\nVelocità 3 m, volo 15 m\nSensi Percezione passiva 10\nLingue -\nSfida 1/2 (100 PE)\nAzioni\nPungiglione. Attacco con Arma da Mischia: +4 a colpire, portata\n1,5 m, una creatura.\nColpisce: 5 (1d6 + 2) danni perforanti e il bersaglio deve\neffettuare un tiro salvezza di Costituzione CD 11, e subire 10\n(3d6) danni da veleno se fallisce il tiro salvezza, o la metà di\nquesti danni se lo riesce. Se il danno da veleno riduce il bersaglio\na 0 punti ferita, il bersaglio è stabile ma avvelenato per 1 ora,\nanche dopo aver recuperato i punti ferita, e mentre è avvelenato\nin questo modo resta paralizzato.\nWorg\nI worg sono mostruosi predatori dall''aspetto simile ad\nun lupo che amano cacciare e divorare le creature più\ndeboli di loro.\nGrande mostruosità, neutrale malvagio\nFORZA 16 (+3)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 7 (-2)\nSAGGEZZA 11 (+0)\nCARISMA 8 (-1)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 26 (4d10 + 4)\nVelocità 15 m\nAbilità Percezione +4\nSensi visione al buio 18 m, Percezione passiva 14\nLingue Goblin, Worg\nSfida 1/2 (100 PE)\nUdito e Olfatto Affinato. Il worg ha vantaggio nelle prove di\nSaggezza (Percezione) basate su udito o olfatto.\nAzioni\nMorso. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d6 + 3) danni perforanti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Forza CD 13 o cadere\nprona.\n\n-- 139 of 151 --\n\nSRD Italia 5a Edizione - Compendio dei Mostri\nAppendice B:\nPersonaggi Non\nGiocanti\nQuesta appendice contiene le statistiche di vari\npersonaggi non giocanti (PNG) umanoidi che gli\navventurieri possono incontrare nel corso di una\ncampagna, da infimi popolani a potenti arcimaghi.\nQueste statistiche possono essere utilizzate per\nrappresentare PNG umani e non.\nPersonalizzare i PNG\nEsistono molti semplici modi di personalizzare i PNG di\nquesta appendice per l''uso nella tua campagna\ncasalinga.\nTratti Razziali. Puoi aggiungere tratti razziali ad un\nPNG. Ad esempio, un mezzuomo sacerdote avrebbe\nvelocità 7,5 metri e il tratto Fortunato. Aggiungere i tratti\nrazziali ad un PNG non ne modifica il grado di sfida.\nCambiare Incantesimi. Un modo per personalizzare\nun PNG incantatore è quello di rimpiazzare uno o più\ndei suoi incantesimi. Puoi sostituire qualsiasi\nincantesimo della lista di incantesimi del PNG con un\ndiverso incantesimo dello stesso livello dalla stessa\nlista di incantesimi. Cambiare incantesimi in questo\nmodo non modifica il grado di sfida del PNG.\nCambiare Armi e Armatura. Puoi migliorare o\npeggiorare l''armatura del PNG o aggiungere o\ncambiare armi. Le modifiche alla Classe Armatura e ai\ndanni possono modificare il grado di sfida del PNG.\nOggetti Magici. Più potente è un PNG, maggiori le\nprobabilità che possieda uno o più oggetti magici. Un\nmago, ad esempio, potrebbe avere una bacchetta o un\nbastone magico, oltre ad una o più pozioni e\npergamene. Fornire un PNG di un potente oggetto\nmagico capace di infliggere danni potrebbe modificarne\nil grado di sfida.\nAlcuni oggetti magici di esempio sono descritti più\navanti in questo documento.\nCombattenti\nI combattenti sono individui che si guadagnano da\nvivere mettendo la loro spada al servizio di un individuo\no un ideale.\nGuardia\nLe guardie comprendono membri della ronda cittadina,\nsentinelle di una cittadella o città fortificata e le guardie\ndel corpo di nobili e mercanti.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 13 (+1)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 11 (+0)\nCARISMA 10 (+0)\nClasse Armatura 16 (giaco di maglia, scudo)\nPunti Ferita 11 (2d8 + 2)\nVelocità 9 m\nAbilità Percezione +2\nSensi Percezione passiva 12\nLingue una qualsiasi lingua (di solito il Comune)\nSfida 1/8 (25 PE)\nAzioni\nLancia. Attacco con Arma da Mischia o a Gittata: +3 a colpire,\nportata 1,5 m o gittata 6/18 m, un bersaglio.\nColpisce: 4 (1d6 + 1) danni perforanti o 5 (1d8 + 1) danni\nperforanti se impiegata con due mani per effettuare un attacco da\nmischia."}}', '2026-03-30T15:54:05.574Z', '2026-03-30T16:00:32.486Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC92ZXRlcmFuby5qc29u', 'veterano', 'Veterano', 'SRD', 'srd-extracted/veterano.json', '3', 3, 700, NULL, NULL, NULL, '{"slug":"veterano","general":{"name":"Veterano","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura di strisce"},"hitPoints":{"average":58,"formula":"9d8 + 18"},"speed":{"walk":"9 m"}},"abilities":{"strength":16,"dexterity":13,"constitution":14,"intelligence":10,"wisdom":11,"charisma":10},"details":{"savingThrows":[{"ability":"Costituzione","bonus":4},{"ability":"Saggezza","bonus":2}],"skills":[{"name":"Atletica","bonus":5},{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 12"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"Il cavaliere effettua due attacchi da mischia."},{"name":"Spada Grossa","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni taglienti."},{"name":"Balestra Pesante","usage":null,"description":"Attacco con Arma a Gittata: +2 a colpire, gittata 30/120 m, un bersaglio. Colpisce: 5 (1d10) perforanti."},{"name":"Autorità","usage":"Ricarica dopo un Riposo Breve o Lungo","description":"Per 1 minuto, il cavaliere può pronunciare un comando speciale o avvertimento ogni qualvolta una creatura non ostile entro 9 metri da lui, e che possa vedere, effettua un tiro di attacco o tiro salvezza. La creatura può sommare un d4 al suo tiro purchè possa udire e comprendere il cavaliere. Una creatura può beneficiare di un solo dado Autorità alla volta. Questo effetto termina se il cavaliere è inabile."}],"bonusActions":[],"reactions":[{"name":"Parata","usage":null,"description":"Il cavaliere può aggiungere 2 alla sua CA contro un attacco da mischia che lo colpirebbe. Per farlo, il cavaliere deve vedere l''attaccante e star impugnando un''arma da mischia."}],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Veterano\nGuerrieri sopravvissuti a lungo, guadagnandosi una\ngrande fama di esperti e abili combattenti.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 16 (+3)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 11 (+0)\nCARISMA 10 (+0)\nClasse Armatura 17 (armatura di strisce)\nPunti Ferita 58 (9d8 + 18)\nVelocità 9 m\nAbilità Atletica +5, Percezione +2\nSensi Percezione passiva 12\nLingue una lingua qualsiasi (di solito il Comune)\nSfida 3 (700 PE)\nAzioni\nMultiattacco. Il veterano effettua due attacchi con la spada\nlunga. Se ha estratto una spada corta, può effettuare anche un\nattacco con la spada corta.\nSpada Lunga. Attacco con Arma da Mischia: +5 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 7 (1d8 + 3) danni taglienti, o 8 (1d10 + 3) danni\ntaglienti se usata con due mani.\nSpada Corta. Attacco con Arma da Mischia: +5 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 6 (1d6 + 3) danni perforanti.\nBalestra Pesante. Attacco con Arma a Gittata: +3 a colpire,\ngittata 30/120 m, un bersaglio.\nColpisce: 6 (1d10 + 1) danni perforanti.\nCavaliere\nI cavalieri sono combattenti che giurano fedeltà a\nsovrani, ordini religiosi, e nobili cause. L''allineamento\ndel cavaliere determina fino a che punto è disposto ad\nonorare il suo giuramento.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 16 (+3)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 11 (+0)\nCARISMA 15 (+2)\nClasse Armatura 18 (armatura di piastre)\nPunti Ferita 52 (8d8 + 16)\nVelocità 9 m\nTiri Salvezza Costituzione +4, Saggezza +2\nSensi Percezione passiva 10\nLingue una qualsiasi lingua (di solito il Comune)\nSfida 3 (700 PE)\nCoraggioso. Il cavaliere ha vantaggio ai tiri salvezza contro\nl''essere spaventato.\nAzioni\nMultiattacco. Il cavaliere effettua due attacchi da mischia.\nSpada Grossa. Attacco con Arma da Mischia: +5 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 10 (2d6 + 3) danni taglienti.\nBalestra Pesante. Attacco con Arma a Gittata: +2 a colpire,\ngittata 30/120 m, un bersaglio.\nColpisce: 5 (1d10) perforanti.\nAutorità (Ricarica dopo un Riposo Breve o Lungo). Per 1\nminuto, il cavaliere può pronunciare un comando speciale o\navvertimento ogni qualvolta una creatura non ostile entro 9 metri\nda lui, e che possa vedere, effettua un tiro di attacco o tiro\nsalvezza. La creatura può sommare un d4 al suo tiro purchè\npossa udire e comprendere il cavaliere. Una creatura può\nbeneficiare di un solo dado Autorità alla volta. Questo effetto\ntermina se il cavaliere è inabile.\nReazioni\nParata. Il cavaliere può aggiungere 2 alla sua CA contro un\nattacco da mischia che lo colpirebbe. Per farlo, il cavaliere deve\nvedere l''attaccante e star impugnando un''arma da mischia."}}', '2026-03-30T15:55:58.277Z', '2026-03-30T16:00:32.487Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC92aXZlcm5hLmpzb24', 'viverna', 'Viverna', 'SRD', 'srd-extracted/viverna.json', '6', 6, 2300, 'Grande', 'drago', 'disallineato', '{"slug":"viverna","general":{"name":"Viverna","challengeRating":{"fraction":"6","decimal":6,"display":"6","xp":2300},"size":"Grande","creatureType":"drago","subtype":"","typeLabel":"drago","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":110,"formula":"13d10 + 39"},"speed":{"walk":"6 m","fly":"24 m"}},"abilities":{"strength":19,"dexterity":10,"constitution":16,"intelligence":5,"wisdom":12,"charisma":6},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 14"}],"languages":[{"name":"-"}],"proficiencyBonus":3},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"La viverna può effettuare due attacchi: uno con il morso e uno con il pungiglione. Mentre vola, può usare i suoi artigli al posto di uno degli altri attacchi."},{"name":"Artigli","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (2d8 + 4) danni taglienti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 3 m, una creatura. Colpisce: 11 (2d6 + 4) danni perforanti."},{"name":"Pungiglione","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 3 m, una creatura. Colpisce: 11 (2d6 + 4) danni perforanti. Il bersaglio deve effettuare un tiro salvezza di Costituzione CD 15, e subire 24 (7d6) danni da veleno se lo fallisce, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Viverna\nGrande drago, disallineato\nFORZA 19 (+4)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 5 (-3)\nSAGGEZZA 12 (+1)\nCARISMA 6 (-2)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 110 (13d10 + 39)\nVelocità 6 m, volo 24 m\nAbilità Percezione +4\nSensi scurovisione 18 m, Percezione passiva 14\nLinguaggi -\nSfida 6 (2.300 PE)\nAzioni\nMultiattacco. La viverna può effettuare due attacchi: uno con il\nmorso e uno con il pungiglione. Mentre vola, può usare i suoi\nartigli al posto di uno degli altri attacchi.\nArtigli. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 13 (2d8 + 4) danni taglienti.\nMorso. Attacco con arma da mischia: +7 a colpire, portata 3 m,\nuna creatura.\nColpisce: 11 (2d6 + 4) danni perforanti.\nPungiglione. Attacco con arma da mischia: +7 a colpire, portata\n3 m, una creatura.\nColpisce: 11 (2d6 + 4) danni perforanti. Il bersaglio deve\neffettuare un tiro salvezza di Costituzione CD 15, e subire 24\n(7d6) danni da veleno se lo fallisce, o la metà di questi danni se\nlo riesce."}}', '2026-03-30T15:54:05.484Z', '2026-03-30T16:00:32.400Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC92cm9jay5qc29u', 'vrock', 'Vrock', 'SRD', 'srd-extracted/vrock.json', '6', 6, 2300, 'Grande', 'immondo', 'caotico malvagio', '{"slug":"vrock","general":{"name":"Vrock","challengeRating":{"fraction":"6","decimal":6,"display":"6","xp":2300},"size":"Grande","creatureType":"immondo","subtype":"demone","typeLabel":"immondo (demone)","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":104,"formula":"11d10 + 44"},"speed":{"walk":"12 m","fly":"18 m"}},"abilities":{"strength":17,"dexterity":15,"constitution":18,"intelligence":8,"wisdom":13,"charisma":8},"details":{"savingThrows":[{"ability":"Destrezza","bonus":5},{"ability":"Saggezza","bonus":4},{"ability":"Carisma","bonus":2}],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo","fulmine","fuoco; contundente"],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 11"}],"languages":[{"name":"Abissale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":3},"traits":[{"name":"Resistenza alla Magia","usage":null,"description":"Il demone ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il demone effettua due attacchi: uno con il becco e uno con gli speroni."},{"name":"Becco","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni perforanti."},{"name":"Speroni","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 14 (2d10 + 3) danni taglienti."},{"name":"Spore","usage":"Ricarica 6","description":"Una nube di spore tossiche si diffonde in un raggio di 4,5 metri intorno al demone. Le spore si propagano intorno agli angoli. Ogni creatura in quell''area deve riuscire un tiro salvezza di Costituzione CD 14 o restare avvelenata. Mentre è avvelenato in questo modo, un bersaglio subisce 5 (1d10) danni da veleno all''inizio di ciascun suo turno. Il bersaglio può ripetere il tiro salvezza al termine di ciascun suo turno, ponendo termine all''effetto se lo riesce. Anche svuotare una fiala di acqua sacra sul bersaglio pone termine all''effetto."},{"name":"Strillo Stordente","usage":"1/Giorno","description":"Il demone emette uno strillo orripilante. Ogni creatura entro 6 metri da esso e che lo possa udire, e non sia un demone, deve riuscire un tiro salvezza di Costituzione CD 14 o restare stordita fino al termine del prossimo turno del demone."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Vrock\nGrande immondo (demone), caotico malvagio\nFORZA 17 (+3)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 8 (-1)\nSAGGEZZA 13 (+1)\nCARISMA 8 (-1)\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 104 (11d10 + 44)\nVelocità 12 m, volo 18 m\nTiri Salvezza Destrezza +5, Saggezza +4, Carisma +2\nResistenze al Danno freddo, fulmine, fuoco; contundente,\nperforante e tagliente di attacchi non magici\nImmunità al Danno veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 36 m, Percezione passiva 11\nLinguaggi Abissale, telepatia 36 m\nSfida 6 (2.300 PE)\nResistenza alla Magia. Il demone ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nMultiattacco. Il demone effettua due attacchi: uno con il becco e\nuno con gli speroni.\nBecco. Attacco con arma da mischia: +6 a colpire, portata 1,5 m,\nun bersaglio.\nColpisce: 10 (2d6 + 3) danni perforanti.\nSperoni. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 14 (2d10 + 3) danni taglienti.\nSpore (Ricarica 6). Una nube di spore tossiche si diffonde in un\nraggio di 4,5 metri intorno al demone. Le spore si propagano\nintorno agli angoli. Ogni creatura in quell''area deve riuscire un\ntiro salvezza di Costituzione CD 14 o restare avvelenata. Mentre\nè avvelenato in questo modo, un bersaglio subisce 5 (1d10) danni\nda veleno all''inizio di ciascun suo turno. Il bersaglio può ripetere\nil tiro salvezza al termine di ciascun suo turno, ponendo termine\nall''effetto se lo riesce. Anche svuotare una fiala di acqua sacra\nsul bersaglio pone termine all''effetto.\nStrillo Stordente (1/Giorno). Il demone emette uno strillo\norripilante. Ogni creatura entro 6 metri da esso e che lo possa\nudire, e non sia un demone, deve riuscire un tiro salvezza di\nCostituzione CD 14 o restare stordita fino al termine del\nprossimo turno del demone."}}', '2026-03-30T15:54:05.292Z', '2026-03-30T16:00:32.249Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC93aWdodC5qc29u', 'wight', 'Wight', 'SRD', 'srd-extracted/wight.json', '3', 3, 700, 'Media', 'non morto', 'neutrale malvagio', '{"slug":"wight","general":{"name":"Wight","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"Media","creatureType":"non morto","subtype":"","typeLabel":"non morto","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":14,"note":"armatura borchiata"},"hitPoints":{"average":45,"formula":"6d8 + 18"},"speed":{"walk":"9 m"}},"abilities":{"strength":15,"dexterity":14,"constitution":16,"intelligence":10,"wisdom":13,"charisma":15},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":["necrotico; contundente","perforante e"],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato","sfinimento"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"le lingue che conosceva in vita"}],"proficiencyBonus":2},"traits":[{"name":"Natura Non Morta","usage":null,"description":"Il wight non ha bisogno di aria, cibo, bevande o sonno."},{"name":"Sensibilità alla Luce","usage":null,"description":"Mentre è alla luce del sole, il wight ha svantaggio ai tiri di attacco, oltre che alle prove di Saggezza (Percezione) basate sulla vista."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il wight può effettuare due attacchi con la spada lungha o due attacchi con l''arco lungo. Può usare Risucchiare"},{"name":"Vita al posto di uno dei suoi attacchi con la spada lungha","usage":null,"description":""},{"name":"Risucchiare Vita","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, una creatura. Colpisce: 5 (1d6 + 2) danni necrotici. Il bersaglio deve riuscire un tiro salvezza di Costituzione CD 13 o vedere i suoi punti ferita massimi ridotti di un ammontare pari al danno subito. Questa riduzione perdura finché il bersaglio non ha terminato un riposo lungo. Il bersaglio muore se l''effetto riduce i suoi punti ferita massimi a 0. Un umanoide ucciso da questo attacco si rianima 24 ore più tardi come zombi sotto il controllo del wight, a meno che l''umanoide non venga prima riportato in vita o il corpo sia distrutto. Il wight non può controllare più di dodici zombi alla volta."},{"name":"Spada Lunga","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d8 + 2) danni taglienti o 7 (1d10 + 2) danni taglienti se usata con due mani."},{"name":"Arco Lungo","usage":null,"description":"Attacco con arma a Distanza: +4 a colpire, gittata 45/180 m, un bersaglio. Colpisce: 6 (1d8 + 2) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Wight\nMedia non morto, neutrale malvagio\nFORZA 15 (+2)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 13 (+1)\nCARISMA 15 (+2)\nClasse Armatura 14 (armatura borchiata)\nPunti Ferita 45 (6d8 + 18)\nVelocità 9 m\nAbilità Furtività +4, Percezione +3\nResistenze al Danno necrotico; contundente, perforante e\ntagliente di attacchi non magici che non siano argentati\nImmunità al Danno veleno\nImmunità alle Condizioni avvelenato, sfinimento\nSensi scurovisione 18 m, Percezione passiva 13\nLinguaggi le lingue che conosceva in vita\nSfida 3 (700 PE)\nNatura Non Morta. Il wight non ha bisogno di aria, cibo,\nbevande o sonno.\nSensibilità alla Luce. Mentre è alla luce del sole, il wight ha\nsvantaggio ai tiri di attacco, oltre che alle prove di Saggezza\n(Percezione) basate sulla vista.\nAzioni\nMultiattacco. Il wight può effettuare due attacchi con la spada\nlungha o due attacchi con l''arco lungo. Può usare Risucchiare\nVita al posto di uno dei suoi attacchi con la spada lungha.\nRisucchiare Vita. Attacco con arma da mischia: +4 a colpire,\nportata 1,5 m, una creatura.\nColpisce: 5 (1d6 + 2) danni necrotici. Il bersaglio deve riuscire\nun tiro salvezza di Costituzione CD 13 o vedere i suoi punti\nferita massimi ridotti di un ammontare pari al danno subito.\nQuesta riduzione perdura finché il bersaglio non ha terminato un\nriposo lungo. Il bersaglio muore se l''effetto riduce i suoi punti\nferita massimi a 0.\nUn umanoide ucciso da questo attacco si rianima 24 ore più tardi\ncome zombi sotto il controllo del wight, a meno che l''umanoide\nnon venga prima riportato in vita o il corpo sia distrutto. Il wight\nnon può controllare più di dodici zombi alla volta.\nSpada Lunga. Attacco con arma da mischia: +4 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 6 (1d8 + 2) danni taglienti o 7 (1d10 + 2) danni\ntaglienti se usata con due mani.\nArco Lungo. Attacco con arma a Distanza: +4 a colpire, gittata\n45/180 m, un bersaglio.\nColpisce: 6 (1d8 + 2) danni perforanti."}}', '2026-03-30T15:54:05.491Z', '2026-03-30T16:00:32.401Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC93cmFpdGguanNvbg', 'wraith', 'Wraith', 'SRD', 'srd-extracted/wraith.json', '5', 5, 1800, 'Media', 'non morto', 'neutrale malvagio', '{"slug":"wraith","general":{"name":"Wraith","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Media","creatureType":"non morto","subtype":"","typeLabel":"non morto","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":13,"note":""},"hitPoints":{"average":67,"formula":"9d8 + 27"},"speed":{"walk":"0 m","fly":"18 m (fluttua)"}},"abilities":{"strength":6,"dexterity":16,"constitution":16,"intelligence":12,"wisdom":14,"charisma":15},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":["acido","freddo","fulmine","fuoco","tuono;"],"damageImmunities":["necrotico","veleno"],"conditionImmunities":["affascinato","afferrato","avvelenato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 12"}],"languages":[{"name":"le lingue che conosceva in vita"}],"proficiencyBonus":3},"traits":[{"name":"Movimento Incorporeo","usage":null,"description":"Il wraith può attraversare creature e oggetti come fossero terreno difficile. Subisce 5 (1d10) danni da forza se termina il proprio turno all''interno di un oggetto."},{"name":"Natura Non Morta","usage":null,"description":"Il wraith non ha bisogno di aria, cibo, bevande o sonno."},{"name":"Sensibilità alla Luce","usage":null,"description":"Mentre è alla luce del sole, il wraith ha svantaggio ai tiri di attacco, oltre che alle prove di Saggezza (Percezione) basate sulla vista."}],"actions":[{"name":"Risucchiare Vita","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, una creatura. Colpisce: 21 (4d8 + 3) danni necrotici. Il bersaglio deve riuscire un tiro salvezza di Costituzione CD 14 o vedere i suoi punti ferita massimi ridotti di un ammontare pari al danno subito. Questa riduzione perdura finché il bersaglio non ha terminato un riposo lungo. Il bersaglio muore se l''effetto riduce i suoi punti ferita massimi a 0."},{"name":"Creare Spettro","usage":null,"description":"Il wraith prende a bersaglio un umanoide entro 3 metri da esso e che sia morto da non più di 1 minuto e per cause violente. Lo spirito del bersaglio si anima come spettro nello spazio del suo cadavere e nello spazio più vicino non occupato."},{"name":"Lo spettro è sotto il controllo del wraith","usage":null,"description":"Il wraith non può tenere più di sette spettri alla volta sotto il suo controllo."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Wraith\nMedia non morto, neutrale malvagio\nFORZA 6 (-2)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 12 (+1)\nSAGGEZZA 14 (+2)\nCARISMA 15 (+2)\nClasse Armatura 13\nPunti Ferita 67 (9d8 + 27)\nVelocità 0 m, volo 18 m (fluttua)\nResistenze al Danno acido, freddo, fulmine, fuoco, tuono;\ncontundente, perforante e tagliente di attacchi non magici che\nnon siano argentati\nImmunità al Danno necrotico, veleno\nImmunità alle Condizioni affascinato, afferrato, avvelenato,\nintralciato, paralizzato, pietrificato, prono, sfinimento\nSensi scurovisione 18 m, Percezione passiva 12\nLinguaggi le lingue che conosceva in vita\nSfida 5 (1.800 PE)\nMovimento Incorporeo. Il wraith può attraversare creature e\noggetti come fossero terreno difficile. Subisce 5 (1d10) danni da\nforza se termina il proprio turno all''interno di un oggetto.\nNatura Non Morta. Il wraith non ha bisogno di aria, cibo,\nbevande o sonno.\nSensibilità alla Luce. Mentre è alla luce del sole, il wraith ha\nsvantaggio ai tiri di attacco, oltre che alle prove di Saggezza\n(Percezione) basate sulla vista.\nAzioni\nRisucchiare Vita. Attacco con arma da mischia: +6 a colpire,\nportata 1,5 m, una creatura.\nColpisce: 21 (4d8 + 3) danni necrotici. Il bersaglio deve riuscire\nun tiro salvezza di Costituzione CD 14 o vedere i suoi punti\nferita massimi ridotti di un ammontare pari al danno subito.\nQuesta riduzione perdura finché il bersaglio non ha terminato un\nriposo lungo. Il bersaglio muore se l''effetto riduce i suoi punti\nferita massimi a 0.\nCreare Spettro. Il wraith prende a bersaglio un umanoide entro 3\nmetri da esso e che sia morto da non più di 1 minuto e per cause\nviolente. Lo spirito del bersaglio si anima come spettro nello\nspazio del suo cadavere e nello spazio più vicino non occupato.\nLo spettro è sotto il controllo del wraith. Il wraith non può tenere\npiù di sette spettri alla volta sotto il suo controllo."}}', '2026-03-30T15:54:05.492Z', '2026-03-30T16:00:32.402Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC94b3JuLmpzb24', 'xorn', 'Xorn', 'SRD', 'srd-extracted/xorn.json', '5', 5, 1800, 'Media', 'elementale', 'neutrale', '{"slug":"xorn","general":{"name":"Xorn","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Media","creatureType":"elementale","subtype":"","typeLabel":"elementale","alignment":"neutrale","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":73,"formula":"7d8 + 42"},"speed":{"walk":"6 m","burrow":"6 m"}},"abilities":{"strength":17,"dexterity":10,"constitution":22,"intelligence":11,"wisdom":10,"charisma":11},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":3},{"name":"Percezione","bonus":6}],"damageVulnerabilities":[],"damageResistances":["perforante e tagliente di attacchi non"],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"senso tellurico","value":"18 m"},{"name":"Percezione"}],"languages":[{"name":"Terran"}],"proficiencyBonus":3},"traits":[{"name":"Mimetismo di Pietra","usage":null,"description":"Lo xorn ha vantaggio alle prove di Destrezza (Furtività) effettuate per nascondersi su terreno roccioso."},{"name":"Scorrere sulla Terra","usage":null,"description":"Lo xorn può scavare attraversa la terra e la pietra non magiche e non lavorate. Quando lo fa, lo xorn non disturba il materiale che sposta."},{"name":"Senso del Tesoro","usage":null,"description":"Lo xorn può individuare precisamente, con l''olfatto, la posizione di metalli e pietre preziose, come monete e gemme, entro 18 metri da esso."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Lo xorn effettua tre attacchi di artiglio e un attacco di morso."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d6 + 3) danni taglienti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (3d6 + 3) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Xorn\nMedia elementale, neutrale\nFORZA 17 (+3)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 22 (+6)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 11 (+0)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 73 (7d8 + 42)\nVelocità 6 m, scavo 6 m\nAbilità Furtività +3, Percezione +6\nResistenze al Danno perforante e tagliente di attacchi non\nmagici che non siano di adamantio\nSensi scurovisione 18 m, senso tellurico 18 m, Percezione\npassiva 18\nLinguaggi Terran\nSfida 5 (1.800 PE)\nMimetismo di Pietra. Lo xorn ha vantaggio alle prove di\nDestrezza (Furtività) effettuate per nascondersi su terreno\nroccioso.\nScorrere sulla Terra. Lo xorn può scavare attraversa la terra e la\npietra non magiche e non lavorate. Quando lo fa, lo xorn non\ndisturba il materiale che sposta.\nSenso del Tesoro. Lo xorn può individuare precisamente, con\nl''olfatto, la posizione di metalli e pietre preziose, come monete e\ngemme, entro 18 metri da esso.\nAzioni\nMultiattacco. Lo xorn effettua tre attacchi di artiglio e un attacco\ndi morso.\nArtiglio. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (1d6 + 3) danni taglienti.\nMorso. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 13 (3d6 + 3) danni perforanti."}}', '2026-03-30T15:54:05.493Z', '2026-03-30T16:00:32.403Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC96b21iaS1vZ3JlLmpzb24', 'zombi-ogre', 'Zombi Ogre', 'SRD', 'srd-extracted/zombi-ogre.json', '2', 2, 450, 'Grande', 'non morto', 'neutrale malvagio', '{"slug":"zombi-ogre","general":{"name":"Zombi Ogre","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"non morto","subtype":"","typeLabel":"non morto","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":8,"note":""},"hitPoints":{"average":85,"formula":"9d10 + 36"},"speed":{"walk":"9 m"}},"abilities":{"strength":19,"dexterity":6,"constitution":18,"intelligence":3,"wisdom":6,"charisma":5},"details":{"savingThrows":[{"ability":"Saggezza","bonus":0}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 8"}],"languages":[{"name":"comprende Comune e Gigante ma non può parlare"}],"proficiencyBonus":2},"traits":[{"name":"Natura Non Morta","usage":null,"description":"Lo zombi non ha bisogno di aria, cibo, bevande o sonno."},{"name":"Tempra dei Non Morti","usage":null,"description":"Se il danno riduce lo zombi a 0 punti ferita, lo zombi deve effettuare un tiro salvezza di Costituzione CD 5 + il danno subito, a meno che il danno non sia radiante o un colpo critico. Se riesce, lo zombi scende invece a 1 punto ferita."}],"actions":[{"name":"Mazza Chiodata","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (2d8 + 4) danni contundenti. Appendice A: Creature Varie Questa appendice contiene le statistiche di vari animali, parassiti e altre creature. Le statistiche sono organizzate in ordine alfabetico."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Zombi Ogre\nGrande non morto, neutrale malvagio\nFORZA 19 (+4)\nDESTREZZA 6 (-2)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 6 (-2)\nCARISMA 5 (-3)\nClasse Armatura 8\nPunti Ferita 85 (9d10 + 36)\nVelocità 9 m\nTiri Salvezza Saggezza +0\nImmunità al Danno veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 18 m, Percezione passiva 8\nLinguaggi comprende Comune e Gigante ma non può parlare\nSfida 2 (450 PE)\nNatura Non Morta. Lo zombi non ha bisogno di aria, cibo,\nbevande o sonno.\nTempra dei Non Morti. Se il danno riduce lo zombi a 0 punti\nferita, lo zombi deve effettuare un tiro salvezza di Costituzione\nCD 5 + il danno subito, a meno che il danno non sia radiante o\nun colpo critico. Se riesce, lo zombi scende invece a 1 punto\nferita.\nAzioni\nMazza Chiodata. Attacco con arma da mischia: +6 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 13 (2d8 + 4) danni contundenti.\n\n-- 111 of 151 --\n\nSRD Italia 5a Edizione - Compendio dei Mostri\nAppendice A: Creature\nVarie\nQuesta appendice contiene le statistiche di vari animali,\nparassiti e altre creature. Le statistiche sono\norganizzate in ordine alfabetico."}}', '2026-03-30T15:54:05.496Z', '2026-03-30T16:00:32.406Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC96b21iaS5qc29u', 'zombi', 'Zombi', 'SRD', 'srd-extracted/zombi.json', '1/4', 0.25, 50, 'Media', 'non morto', 'neutrale malvagio', '{"slug":"zombi","general":{"name":"Zombi","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Media","creatureType":"non morto","subtype":"","typeLabel":"non morto","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":8,"note":""},"hitPoints":{"average":22,"formula":"3d8 + 9"},"speed":{"walk":"6 m"}},"abilities":{"strength":13,"dexterity":6,"constitution":16,"intelligence":3,"wisdom":6,"charisma":5},"details":{"savingThrows":[{"ability":"Saggezza","bonus":0}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 8"}],"languages":[{"name":"comprende tutte le lingue che parlava in vita ma non"}],"proficiencyBonus":2},"traits":[{"name":"Natura Non Morta","usage":null,"description":"Lo zombi non ha bisogno di aria, cibo, bevande o sonno."},{"name":"Tempra dei Non Morti","usage":null,"description":"Se il danno riduce lo zombi a 0 punti ferita, lo zombi deve effettuare un tiro salvezza di Costituzione CD 5 + il danno subito, a meno che il danno non sia radiante o un colpo critico. Se riesce, lo zombi scende invece a 1 punto ferita."}],"actions":[{"name":"Schianto","usage":null,"description":"Attacco con arma da mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d6 + 1) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Zombi\nMedia non morto, neutrale malvagio\nFORZA 13 (+1)\nDESTREZZA 6 (-2)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 6 (-2)\nCARISMA 5 (-3)\nClasse Armatura 8\nPunti Ferita 22 (3d8 + 9)\nVelocità 6 m\nTiri Salvezza Saggezza +0\nImmunità al Danno veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 18 m, Percezione passiva 8\nLinguaggi comprende tutte le lingue che parlava in vita ma non\npuò parlare\nSfida 1/4 (50 PE)\nNatura Non Morta. Lo zombi non ha bisogno di aria, cibo,\nbevande o sonno.\nTempra dei Non Morti. Se il danno riduce lo zombi a 0 punti\nferita, lo zombi deve effettuare un tiro salvezza di Costituzione\nCD 5 + il danno subito, a meno che il danno non sia radiante o\nun colpo critico. Se riesce, lo zombi scende invece a 1 punto\nferita.\nAzioni\nSchianto. Attacco con arma da mischia: +3 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d6 + 1) danni contundenti."}}', '2026-03-30T15:54:05.494Z', '2026-03-30T16:00:32.405Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('aiuto', 'aiuto', 'Aiuto', 2, 'Abiurazione', '1 azione', '9 metri', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/aiuto/', '["chierico","paladino"]', '{"name":"Aiuto","level":2,"school":"Abiurazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (una sottile striscia di tessuto bianco)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, i punti ferita del bersaglio aumentano di ulteriori 5 punti per ogni slot incantesimo sopra il 2°.","ritual":false,"description":"Il tuo incantesimo aumenta la robustezza e risolutezza dei tuoi alleati. Scegli fino a tre creature a gittata. Per la durata, i punti ferita massimi e i punti ferita attuali di ciascun bersaglio aumentano di 5.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/aiuto/","classes":["chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('allarme', 'allarme', 'Allarme', 1, 'Abiurazione', '1 minuto', '9 metri', '8 ore', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/allarme/', '["mago","ranger"]', '{"name":"Allarme","level":1,"school":"Abiurazione","casting_time":"1 minuto","range":"9 metri","components":"V, S, M (una campanella e un pezzo di pregiato filo d’argento)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Predisponi un allarme contro intrusioni indesiderate. Scegli una porta, una finestra o un’area a gittata che non sia più grande di un cubo di 6 metri di spigolo. Fino al termine dell’incantesimo, sarai avvertito da un allarme ogni volta che una creatura di taglia Minuscola o superiore entri in contatto o acceda all’area protetta. Quando lanci l’incantesimo, puoi indicare delle creature che non faranno scattare l’allarme. Scegli anche se l’allarme è udibile o solo mentale. Un allarme mentale, qualora ti trovi entro 1,5 chilometri dall’area protetta, ti avverte con un rumore nella tua mente. Il rumore è in grado di svegliarti se stai dormendo. Un allarme udibile produce il suono di una campanella per 10 secondi, udibile entro 18 metri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/allarme/","classes":["mago","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('alleato-planare', 'alleato-planare', 'Alleato Planare', 6, 'Evocazione', '10 minuti', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/alleato-planare/', '["chierico"]', '{"name":"Alleato Planare","level":6,"school":"Evocazione","casting_time":"10 minuti","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Supplichi un’entità ultraterrena perché ti conceda aiuto. L’essere ti deve essere noto: un dio, un primordiale, un principe dei demoni, o qualche altra creatura di grande potere. Quell’entità invia un celestiale, elementale o immondo a essa leale perché ti aiuti, facendo comparire la creatura in uno spazio non occupato a gittata. Se conosci il nome di una specifica creatura, puoi pronunciarne il nome quando lanci questo incantesimo per richiedere l’aiuto di quella creatura, sebbene tu possa comunque riceverne un’altra (a discrezione del GM). Quando la creatura appare, non è sotto l’obbligo di agire in alcun modo particolare. Puoi chiedere alla creatura di svolgere un servizio in cambio di una ricompensa, ma essa non è obbligata a soddisfarti. Il compito richiesto potrebbe essere facile (“portaci in volo oltre il baratro” o “aiutaci a combattere questa battaglia”) o complesso (“spia i nostri nemici” o “proteggici durante la nostra esplorazione del sotterraneo”). Devi essere in grado di comunicare con la creatura per patteggiare i suoi servigi. La ricompensa può assumere diverse forme. Un celestiale potrebbe chiedere una considerevole donazione di oro od oggetti magici a un tempio alleato, mentre un immondo potrebbe richiedere un sacrificio umano o il dono di un tesoro. Alcune creature potrebbero scambiare i loro servigi per una missione che dovrai intraprendere per conto loro.\nCome regola generale, un compito che può essere misurato in minuti richiede una ricompensa di 100 mo al minuto. Un compito misurato in ore, richiede 1.000 mo all’ora. Un compito misurato in giorni (massimo 10 giorni) richiede 10.000 mo al giorno. Il GM può modificare queste ricompense in base alle circostanze nelle quali si è lanciato l’incantesimo. Se il compito è allineato alla morale della creatura, la richiesta di pagamento potrebbe essere dimezzata o addirittura annullata. I compiti non pericolosi di solito chiedono solo la metà di quanto suggerito come pagamento, mentre i compiti molto pericolosi possono richiedere donazioni superiori. È raro che queste creature accettino compiti che sembrino suicida. Dopo che la creatura ha completato il compito, o quando il periodo di servizio concordato è terminato, la creatura tornerà al suo piano natio dopo averti fatto rapporto, se appropriato al compito svolto e se possibile. Se non sei in grado di concordare un prezzo per i servigi della creatura, la creatura tornerà immediatamente al suo piano natio. Una creatura arruolata per unirsi al tuo gruppo è considerata come un suo membro, e riceve una quota piena delle ricompense in punti esperienza.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/alleato-planare/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('allucinazione-mortale', 'allucinazione-mortale', 'Allucinazione Mortale', 4, 'Illusione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/allucinazione-mortale/', '["mago"]', '{"name":"Allucinazione Mortale","level":4,"school":"Illusione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":"4d10","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello o più alto, il danno aumenta di 1d10 per ogni livello dello slot sopra il 4°.","ritual":false,"description":"Attingi agli incubi di una creatura a gittata e che puoi vedere, e crei una manifestazione illusoria delle sue più insite paure, visibile solo per quella creatura. Il bersaglio deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, il bersaglio è spaventato per la durata. Alla fine di ciascun turno del bersaglio, prima del termine dell’incantesimo, il bersaglio deve superare un tiro salvezza su Saggezza o subire 4d10 danni psichici. Se supera il tiro salvezza, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/allucinazione-mortale/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('alterare-se-stesso', 'alterare-se-stesso', 'Alterare Sé Stesso', 2, 'Trasmutazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/alterare-se-stesso/', '["mago","stregone"]', '{"name":"Alterare Sé Stesso","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Assumi una forma diversa. Quando lanci questo incantesimo, scegli una della seguenti opzioni, l’effetto della quale permane per la durata dell’incantesimo. Per la durata dell’incantesimo puoi terminare un’opzione per ottenere i benefici di un’altra.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/alterare-se-stesso/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('amicizia-con-gli-animali', 'amicizia-con-gli-animali', 'Amicizia con gli Animali', 1, 'Ammaliamento', '1 azione', '9 metri', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/amicizia-con-gli-animali/', '["bardo","druido","ranger"]', '{"name":"Amicizia con gli Animali","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un po’ di cibo)","duration":"24 ore","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, puoi agire su di una bestia aggiuntiva per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Questo incantesimo ti permette di convincere una bestia che non vuoi arrecargli danno. Scegli una bestia a gittata che puoi vedere. Questa deve vederti e udirti. Se l’Intelligenza della bestia è 4 o più, l’incantesimo fallisce. Altrimenti, la bestia deve superare un tiro salvezza su Saggezza o restare affascinata da te per la durata dell’incantesimo. Se tu o uno dei tuoi compagni danneggiate il bersaglio, l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/amicizia-con-gli-animali/","classes":["bardo","druido","ranger"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('anatema', 'anatema', 'Anatema', 1, 'Ammaliamento', '1 minuto', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/anatema/', '["bardo","chierico"]', '{"name":"Anatema","level":1,"school":"Ammaliamento","casting_time":"1 minuto","range":"9 metri","components":"V, S, M (un goccio di sangue)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Carisma","attack_roll":true,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, puoi prendere come bersaglio una creatura aggiuntiva per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Fino a tre creature di tua scelta che puoi vedere, e che sono a gittata, devono effettuare un tiro salvezza su Carisma. Ogni bersaglio che fallisca questo tiro salvezza ed effettua un tiro per colpire o un tiro salvezza prima del termine dell’incantesimo, deve tirare un d4 e sottrarre il numero così ottenuto dal tiro per colpire o tiro salvezza.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/anatema/","classes":["bardo","chierico"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('animale-messaggero', 'animale-messaggero', 'Animale Messaggero', 2, 'Ammaliamento', '1 azione', '9 metri', '24 ore', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/animale-messaggero/', '["bardo","druido","ranger"]', '{"name":"Animale Messaggero","level":2,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un tocco di cibo)","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, la durata dell’incantesimo aumenta di 48 ore per ogni livello dello slot sopra il 2°.","ritual":true,"description":"Tramite questo incantesimo, usi un animale per consegnare un messaggio. Scegli una bestia Minuscola a gittata e che puoi vedere, come uno scoiattolo, una ghiandaia o un pipistrello. Specifichi un luogo, che devi aver visitato in passato, e un destinatario che corrisponda a una descrizione generica, come “un uomo o una donna che vesta l’uniforme della guardia cittadina” o “un nano dai capelli rossi che indossa un cappello a punta”. Pronuncia anche un messaggio di massimo venticinque parole. La bestia bersaglio viaggia per la durata dell’incantesimo verso il luogo specificato,coprendo circa 75 chilometri in 24 ore per un messaggero volante, o 40 chilometri per gli altri animali. Quando il messaggero arriva a destinazione, consegna il messaggio alla creatura da te descritta, replicando il suono della tua voce. Il messaggero parla solo a una creatura corrispondente alla descrizione da te fornita. Se il messaggero non riesce a raggiungere la destinazione prima del termine dell’incantesimo, il messaggio è perduto, e la bestia ritorna verso il punto in cui hai lanciato l’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/animale-messaggero/","classes":["bardo","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('animare-morti', 'animare-morti', 'Animare Morti', 3, 'Necromanzia', '1 minuto', '3 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/animare-morti/', '["chierico","mago"]', '{"name":"Animare Morti","level":3,"school":"Necromanzia","casting_time":"1 minuto","range":"3 metri","components":"V, S, M (una goccia di sangue, un pezzo di carne e un pizzico di polvere d’ossa)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, animi o riaffermi il controllo su due creature non morte in più per ogni livello dello slot sopra il 3°. Ciascuna di queste creature deve provenire da un cadavere o pila di ossa differenti.","ritual":false,"description":"Questo incantesimo crea un servitore non morto. Scegli una pila di ossa o un cadavere di un umanoide Medio o Piccolo a gittata. Il tuo incantesimo imbeve il bersaglio di una nefanda parvenza di vita, rianimandolo come creatura non morta. Il bersaglio diventa uno scheletro se scegli le ossa o uno zombi se scegli un cadavere. Durante ciascun tuo turno, puoi usare un’azione bonus per comandare mentalmente qualsiasi creatura da te creata con questo incantesimo che si trovi entro 18 metri da te (se controlli più creature, puoi comandarle tutte o solo alcune di loro allo stesso momento, inviando lo stesso comando a tutte). Decidi quale azione la creatura svolgerà e dove si muoverà durante il suo prossimo turno, oppure inviale un comando generale, come quello di stare di guardia a una particolare stanza o corridoio. Se non invii alcun comando, la creatura si limita a difendersi dalle creature ostili. Una volta ricevuto un ordine, la creatura continuerà a svolgerlo fino al suo compimento. La creatura è sotto il tuo controllo per 24 ore, dopodiché smetterà di eseguire i comandi che le impartirai. Per mantenere il controllo sulla creatura per altre 24 ore, devi lanciare di nuovo questo incantesimo su di essa prima del termine dell’attuale periodo di 24 ore. Questo impiego dell’incantesimo riafferma il tuo controllo su di un massimo di quattro creature che hai animato con questo incantesimo, piuttosto che animarne una nuova.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/animare-morti/","classes":["chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('animare-oggetti', 'animare-oggetti', 'Animare Oggetti', 5, 'Trasmutazione', '1 minuto', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/animare-oggetti/', '["bardo","mago","stregone"]', '{"name":"Animare Oggetti","level":5,"school":"Trasmutazione","casting_time":"1 minuto","range":"36 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, puoi animare due oggetti aggiuntivi per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Gli oggetti prendono vita al tuo comando. Scegli fino a dieci oggetti non magici a gittata e che non siano indossati o trasportati. I bersagli Medi contano come due oggetti, i bersagli Grandi contano come quattro oggetti, i bersagli Enormi contano come otto oggetti. Non puoi animare oggetti di taglia più grossa di Enorme. Ogni bersaglio si anima e diventa una creatura sotto il tuo controllo fino al termine dell’incantesimo o finché non viene ridotto a 0 punti ferita. Con un’azione bonus, puoi comandare mentalmente qualsiasi creatura che hai generato con questo incantesimo e che si trovi entro 150 metri da te (se controlli più creature, puoi comandarne solo alcune o tutte allo stesso tempo, impartendo lo stesso comando a ciascuna). Decidi tu quale azione intraprenderà la creatura e dove si muoverà durante il suo turno successivo, o puoi emettere un comando generico, come quello di fare la guardia a una particolare stanza o corridoio. Se non impartisci comandi, la creatura si limiterà a difendersi dalle creature ostili. Una volta dato un ordine, la creatura continuerà a seguirlo finché non avrà completato il suo compito.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/animare-oggetti/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('anti-individuazione', 'anti-individuazione', 'Anti-Individuazione', 3, 'Abiurazione', '1 azione', 'Contatto', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/anti-individuazione/', '["bardo","mago","ranger"]', '{"name":"Anti-Individuazione","level":3,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un pizzico di polvere di diamante del valore di 25 mo sparsa sul bersaglio, che l’incantesimo consuma)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata, nascondi il bersaglio con cui sei stato in contatto dalla magia di divinazione. Il bersaglio può essere una creatura consenziente o un luogo o un oggetto che occupi uno spazio equivalente a un cubo non superiore ai 3 metri di spigolo. Il bersaglio non può divenire bersaglio di alcuna magia di divinazione o essere percepito tramite sensi di scrutamento magici.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/anti-individuazione/","classes":["bardo","mago","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('antipatia-simpatia', 'antipatia-simpatia', 'Antipatia/Simpatia', 8, 'Ammaliamento', '1 ora', '18 metri', '10 giorni', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/antipatia-simpatia/', '["druido","mago"]', '{"name":"Antipatia/Simpatia","level":8,"school":"Ammaliamento","casting_time":"1 ora","range":"18 metri","components":"V, S, M (o un pezzo di allume immerso nell’aceto per l’effetto antipatia o un goccio di miele per l’effetto simpatia)","duration":"10 giorni","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo attrae o repelle delle creature di tua scelta. Prendi un bersaglio a gittata, che sia un oggetto Enorme o più piccolo o una creatura o un’area non più grande di un cubo di 60 metri di spigolo. Poi specifica una specie di creature intelligenti, come i draghi rossi, i goblin o i vampiri. Investi il bersaglio di un’aura che attrae o respinge le creature specificate per la durata. Scegli antipatia o simpatia come effetto dell’aura.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/antipatia-simpatia/","classes":["druido","mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('arma-magica', 'arma-magica', 'Arma Magica', 2, 'Trasmutazione', '1 azione bonus', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/arma-magica/', '["mago","paladino"]', '{"name":"Arma Magica","level":2,"school":"Trasmutazione","casting_time":"1 azione bonus","range":"Contatto","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il bonus aumenta a +2. Quando usi uno slot incantesimo di 6° livello o più alto, il bonus aumenta a +3.","ritual":false,"description":"Lanci l’incantesimo a contatto di un’arma non magica. Fino al termine dell’incantesimo, l’arma diventa un’arma magica con un bonus di +1 ai tiri per colpire e di danno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/arma-magica/","classes":["mago","paladino"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('arma-spirituale', 'arma-spirituale', 'Arma Spirituale', 2, 'Invocazione', '1 azione bonus', '18 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/arma-spirituale/', '["chierico"]', '{"name":"Arma Spirituale","level":2,"school":"Invocazione","casting_time":"1 azione bonus","range":"18 metri","components":"V, S","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, il danno aumenta di 1d8 per ogni due livelli dello slot sopra il 2°","ritual":false,"description":"In un punto nella gittata, crei un’arma spettrale fluttuante, che resta per la durata o finché non lanci di nuovo questo incantesimo. Quando lanci l’incantesimo, puoi effettuare un attacco da mischia con incantesimo contro una creatura entro 1,5 metri dall’arma. Se colpisci, il bersaglio subisce danni da forza pari a 1d8 + il tuo modificatore di caratteristica da incantatore. Durante il tuo turno, con un’azione bonus, puoi spostare l’arma di 6 metri e ripetere l’attacco contro una creatura entro 1,5 metri dall’arma. L’arma può assumere qualsiasi forma tu voglia. I chierici di divinità che sono associate a un’arma particolare (la mazza di S. Cutberto e il martello di Thor) generano l’effetto di questo incantesimo a forma di quell’arma.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/arma-spirituale/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('armatura-magica', 'armatura-magica', 'Armatura Magica', 1, 'Abiurazione', '1 azione', 'Contatto', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/armatura-magica/', '["mago","stregone"]', '{"name":"Armatura Magica","level":1,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un pezzo di cuoio lavorato)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente che non indossa un’armatura. Una forza magica protettiva circonda il bersaglio fino al termine dell’incantesimo. La CA base del bersaglio diventa 13 + il suo modificatore di Destrezza. L’incantesimo termina se il bersaglio indossa un’armatura o interrompe l’incantesimo con un’azione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/armatura-magica/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('artificio-druidico', 'artificio-druidico', 'Artificio Druidico', 0, 'Trasmutazione', '1 azione', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/artificio-druidico/', '["druido"]', '{"name":"Artificio Druidico","level":0,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Sussurrando agli spiriti della natura, crei, a gittata, uno dei seguenti effetti:\nCrei un minuscolo e innocuo effetto sensoriale che predice quale clima ci sarà nel luogo in cui ti trovi per le prossime 24 ore. L’effetto potrebbe manifestarsi come una sfera dorata per i cieli limpidi, una nube per la pioggia, fiocchi di neve per la neve, e così via. L’effetto persiste per 1 round. Fai immediatamente sbocciare un fiore, un seme o simile pianta. Crei un istantaneo e innocuo effetto sensoriale, come foglie che cadono, uno sbuffo di vento, il suono di un piccolo animale, o il lieve tanfo di una puzzola. L’effetto deve entrare in un cubo di 1,5 metri di spigolo. Accendi o spegni istantaneamente una candela, una torcia o un piccolo falò.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/artificio-druidico/","classes":["druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-adescante', 'attacco-adescante', 'Attacco Adescante', 0, 'Manovra', 'N/A (quando colpisci con un attacco)', 'Bersaglio colpito', 'Fino alla fine del tuo prossimo turno', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco Adescante","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco)","range":"Bersaglio colpito","components":"-","duration":"Fino alla fine del tuo prossimo turno","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce una\ncreatura con un attacco con un''arma, può spendere un\ndado di superiorità per indurre il bersaglio ad attaccarlo.\nIl guerriero aggiunge il dado di superiorità al tiro per i danni\ndell''attacco, e il bersaglio deve effettuare un tiro salvezza\nsu Saggezza. Se lo fallisce, il bersaglio subisce svantaggio\na tutti i tiri per colpire contro bersagli diversi dal guerriero\nfino alla fine del turno successivo del guerriero.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-con-affondo', 'attacco-con-affondo', 'Attacco con Affondo', 0, 'Manovra', 'N/A (quando effettui un attacco in mischia nel tuo turno)', 'Portata dell’arma + 1,5 m per quell’attacco', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco con Affondo","level":0,"school":"Manovra","casting_time":"N/A (quando effettui un attacco in mischia nel tuo turno)","range":"Portata dell’arma + 1,5 m per quell’attacco","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero effettua\nun attacco con un''arma da mischia nel suo turno, può\nspendere un dado di superiorità per aumentare di 1,5 metri\nla propria portata per quell''attacco. Se colpisce, aggiunge il\ndado di superiorità al tiro per i danni dell''attacco.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-con-finta', 'attacco-con-finta', 'Attacco con Finta', 0, 'Manovra', 'Azione bonus', 'Creatura entro 1,5 m', 'Fino alla fine del turno', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco con Finta","level":0,"school":"Manovra","casting_time":"Azione bonus","range":"Creatura entro 1,5 m","components":"-","duration":"Fino alla fine del turno","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Il guerriero può spendere un dado\ndi superiorità e usare un''azione bonus nel suo turno per\nfintare, scegliendo una creatura entro 1,5 metri da sé come\nbersaglio. Il guerriero dispone di vantaggio al suo prossimo\ntiro per colpire contro quella creatura in questo turno.\nSe quell''attacco colpisce, il guerriero aggiunge il dado di\nsuperiorità al tiro per i danni dell''attacco.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-con-manovra', 'attacco-con-manovra', 'Attacco con Manovra', 0, 'Manovra', 'N/A (quando colpisci con un attacco)', 'Alleato che ti vede o ti sente', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco con Manovra","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco)","range":"Alleato che ti vede o ti sente","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce\nuna creatura con un attacco con un''arma, può spendere\nun dado di superiorità per spostare uno dei suoi compagni\nin una posizione più vantaggiosa. Il guerriero aggiunge il\ndado di superiorità al tiro per i danni dell''attacco e sceglie\nuna creatura amica che sia in grado di vederlo o di sentirlo.\nQuella creatura può usare la sua reazione per muoversi\nfino alla metà della sua velocità senza provocare attacchi di\nopportunità da parte del bersaglio dell''attacco del guerriero.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-con-spazzata', 'attacco-con-spazzata', 'Attacco con Spazzata', 0, 'Manovra', 'N/A (quando colpisci con un attacco in mischia)', 'Creatura entro 1,5 m dal bersaglio originale ed entro la tua portata', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco con Spazzata","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco in mischia)","range":"Creatura entro 1,5 m dal bersaglio originale ed entro la tua portata","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce\nuna creatura con un attacco con un''arma da mischia,\npuò spendere un dado di superiorità per tentare di\ninfliggere danni a un''altra creatura con lo stesso attacco.\nIl guerriero sceglie un''altra creatura entro 1,5 metri dal\nbersaglio originale ed entro la propria portata. Se il tiro\nper colpire originale colpirebbe anche la seconda creatura,\nquest''ultima subisce danni pari al risultato del tiro ottenuto\ncon il dado di superiorità del guerriero. I danni sono dello\nstesso tipo dell''attacco originale.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-con-spinta', 'attacco-con-spinta', 'Attacco con Spinta', 0, 'Manovra', 'N/A (quando colpisci con un attacco)', 'Bersaglio colpito', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco con Spinta","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco)","range":"Bersaglio colpito","components":"-","duration":"Istantanea","concentration":false,"saving_throw":"Forza","attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce una\ncreatura con un attacco con un''arma, può spendere un\ndado di superiorità per tentare di spingere il bersaglio\nrigettandolo indietro. Il guerriero aggiunge il dado di\nsuperiorità al tiro per i danni dell''attacco. Se il bersaglio è\ndi taglia Grande o inferiore, deve effettuare un tiro salvezza\nsu Forza. Se lo fallisce, il guerriero spinge il bersaglio fino\na un massimo di 4,5 metri allontanandolo da sé.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-disarmante', 'attacco-disarmante', 'Attacco Disarmante', 0, 'Manovra', 'N/A (quando colpisci con un attacco)', 'Bersaglio colpito', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco Disarmante","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco)","range":"Bersaglio colpito","components":"-","duration":"Istantanea","concentration":false,"saving_throw":"Forza","attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce una\ncreatura con un attacco con un''arma, può spendere un\ndado di superiorità per tentare di disarmare il bersaglio,\ncostringendolo a lasciare cadere un oggetto che sta\nimpugnando a scelta del guerriero. Il guerriero aggiunge\nil dado di superiorità al tiro per i danni dell''attacco, e il\nbersaglio deve effettuare un tiro salvezza su Forza. Se\nlo fallisce, lascia cadere l''oggetto scelto dal guerriero.\nL''oggetto cade ai piedi della creatura.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-minaccioso', 'attacco-minaccioso', 'Attacco Minaccioso', 0, 'Manovra', 'N/A (quando colpisci con un attacco)', 'Bersaglio colpito', 'Fino alla fine del tuo prossimo turno', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco Minaccioso","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco)","range":"Bersaglio colpito","components":"-","duration":"Fino alla fine del tuo prossimo turno","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce una\ncreatura con un attacco con un''arma, può spendere un\ndado di superiorità per tentare di spaventare il bersaglio.\nIl guerriero aggiunge il dado di superiorità al tiro per i danni\ndell''attacco, e il bersaglio deve effettuare un tiro salvezza\nsu Saggezza. Se lo fallisce, il bersaglio è spaventato dal\nguerriero fino alla fine del turno successivo di quest''ultimo.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-preciso', 'attacco-preciso', 'Attacco Preciso', 0, 'Manovra', 'N/A (prima o dopo il tiro per colpire, prima di applicare gli effetti)', 'Se stesso', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco Preciso","level":0,"school":"Manovra","casting_time":"N/A (prima o dopo il tiro per colpire, prima di applicare gli effetti)","range":"Se stesso","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero effettua un tiro\nper colpire con un''arma contro una creatura, può spendere\nun dado di superiorità per aggiungerlo al tiro. Può usare\nquesta manovra prima o dopo avere effettuato il tiro per\ncolpire, ma prima di applicare qualsiasi effetto dell''attacco.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('attacco-sbilanciante', 'attacco-sbilanciante', 'Attacco Sbilanciante', 0, 'Manovra', 'N/A (quando colpisci con un attacco)', 'Bersaglio colpito', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Attacco Sbilanciante","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco)","range":"Bersaglio colpito","components":"-","duration":"Istantanea","concentration":false,"saving_throw":"Forza","attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce\nuna creatura con un attacco con un''arma, può spendere\nun dado di superiorità per tentare di buttare a terra il\nbersaglio. Il guerriero aggiunge il dado di superiorità al tiro\nper i danni dell''attacco. Se il bersaglio è di taglia Grande\no inferiore, deve effettuare un tiro salvezza su Forza. Se lo\nfallisce, cade a terra prono.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('aura-magica-dell-arcanista', 'aura-magica-dell-arcanista', 'Aura Magica dell’Arcanista', 2, 'Illusione', '1 azione', 'Contatto', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/aura-magica-dellarcanista/', '["mago"]', '{"name":"Aura Magica dell’Arcanista","level":2,"school":"Illusione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un piccolo quadretto di seta)","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Poni un’illusione su di una creatura od oggetto con cui sei in contatto, così che gli incantesimi di divinazione rivelino false informazioni su di esso. Il bersaglio può essere una creatura consenziente o un oggetto che non sia trasportato o indossato da un’altra creatura. Quando lanci questo incantesimo, scegli uno o entrambi i seguenti effetti. L’effetto permane per la durata. Se esegui questo incantesimo sulla stessa creatura od oggetto ogni giorno per 30 giorni, piazzando ogni volta lo stesso effetto, l’illusione permarrà finché non viene dissolta.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/aura-magica-dellarcanista/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('aura-sacra', 'aura-sacra', 'Aura Sacra', 8, 'Abiurazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/aura-sacra/', '["chierico"]', '{"name":"Aura Sacra","level":8,"school":"Abiurazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un minuscolo reliquario del valore di almeno 1.000 mo contenente una reliquia sacra, come un pezzo di tessuto dell’abito di un santo o un frammento di pergamena di un testo religioso)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Irradi da te luce divina che si raccoglie in una debole luminosità con raggio di 9 metri intorno a te. Quando lanci l’incantesimo, le creature da te scelte in questo raggio emanano luce fioca con un raggio di 1,5 metri e hanno vantaggio a tutti i tiri salvezza, mentre le altre creature hanno svantaggio sui tiri per colpire contro di loro fino al termine dell’incantesimo. Inoltre, quando un immondo o non morto colpisce una creatura bersaglio con un attacco in mischia, l’aura risplende di una luce intensa. L’attaccante deve superare un tiro salvezza su Costituzione o restare accecato fino al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/aura-sacra/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('bacche-benefiche', 'bacche-benefiche', 'Bacche Benefiche', 1, 'Trasmutazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/bacche-benefiche/', '["druido","ranger"]', '{"name":"Bacche Benefiche","level":1,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un rametto di vischio)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fino a dieci bacche compaiono nella tua mano e vengono infuse di magia per la durata. Una creatura può usare la sua azione per mangiare una bacca. Mangiare una bacca ripristina 1 punto ferita, e la bacca inoltre provvede nutrimento sufficiente per alimentare una creatura per un giorno.\nLe bacche perdono la loro efficacia se non vengono consumate entro 24 ore dal lancio dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/bacche-benefiche/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('bagliore-lunare', 'bagliore-lunare', 'Bagliore Lunare', 2, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/bagliore-lunare/', '["druido"]', '{"name":"Bagliore Lunare","level":2,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (diversi semi di bella di notte e un pezzo di felpato opalescente)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":"2d10","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, il danno aumenta di 1d10 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Un fascio argenteo di luce pallida risplende in un cilindro di raggio 1,5 metri, alto 12 metri centrato in un punto a gittata. Fino al termine dell’incantesimo, una luce fioca riempie il cilindro. Quando una creatura entra nell’area dell’incantesimo per la prima volta durante un turno o inizia qui il suo turno, è avvolta da fiamme spettrali che provocano un dolore terribile, e deve effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza subisce 2d10 danni radianti, o la metà di questi danni se lo supera. Un mutaforma effettua il tiro salvezza con svantaggio. Se lo fallisce ritorna immediatamente alla sua forma originale e non può assumere una forma diversa finché non esce dalla luce dell’incantesimo. Durante ciascun tuo turno dopo aver lanciato l’incantesimo, puoi usare un’azione per muovere il fascio di 18 metri in qualsiasi direzione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/bagliore-lunare/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('bagliore-solare', 'bagliore-solare', 'Bagliore Solare', 6, 'Invocazione', '1 azione', 'Incantatore (linea di 18 metri)', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/bagliore-solare/', '["druido","mago","stregone"]', '{"name":"Bagliore Solare","level":6,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore (linea di 18 metri)","components":"V, S, M (una lente d’ingrandimento)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":"6d8","scaling":null,"ritual":false,"description":"Una fascio di luce brillante esplode dalla tua mano in una linea larga 1,5 metri e lunga 18 metri. Ogni creatura sulla linea deve effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza, la creatura subisce 6d8 danni radianti e rimane accecata fino al tuo prossimo turno. Se supera il tiro salvezza, subisce la metà dei danni e non è accecata. I non morti e le melme hanno svantaggio su questo tiro salvezza.\nPuoi creare una nuova linea di luminosità con un’azione durante qualsiasi tuo turno fino al termine dell’incantesimo. Per la durata, una particella di luce brillante risplende nella tua mano. Produce luce intensa in un raggio di 9 metri e luce fioca per ulteriori 9 metri. Questa luce è considerata luce solare.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/bagliore-solare/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('banchetto-degli-eroi', 'banchetto-degli-eroi', 'Banchetto degli Eroi', 6, 'Evocazione', '10 minuti', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/banchetto-degli-eroi/', '["chierico","druido"]', '{"name":"Banchetto degli Eroi","level":6,"school":"Evocazione","casting_time":"10 minuti","range":"9 metri","components":"V, S, M (una ciotola incrostata di gemme del valore di almeno 1.000 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei un magnifico banchetto, comprensivo di cibi e bevande prelibate. Il banchetto viene consumato in 1 ora e scompare al termine di questo periodo, ma gli effetti benefici non si faranno sentire fino al termine dell’ora. Fino ad altre dodici creature possono partecipare al banchetto. Una creatura che partecipi al banchetto ottiene diversi benefici. La creatura viene guarita da tutte le malattie e i veleni, diventa immune al veleno e all’essere spaventata, e ha vantaggio su tutti i tiri salvezza su Saggezza. I suoi punti ferita massimi aumentano di 2d10, e guarisce lo stesso quantitativo di punti ferita attuali. Questi benefici durano 24 ore.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/banchetto-degli-eroi/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('barriera-di-lame', 'barriera-di-lame', 'Barriera di Lame', 6, 'Invocazione', '1 azione', '18 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/barriera-di-lame/', '["chierico"]', '{"name":"Barriera di Lame","level":6,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"6d10","scaling":null,"ritual":false,"description":"Crei un muro verticale di lame rotanti fatte di energia magica, affilate come rasoi. Il muro compare a gittata e resta per la durata. Puoi creare un muro diritto lungo fino a 30 metri, alto 6 metri e spesso 1,5 metri, o un muro circolare di 18 metri massimo di diametro, alto 6 metri e spesso 1,5 metri. Il muro fornisce tre quarti di copertura alle creature dietro di esso, e il suo spazio è terreno difficile. Quando una creatura entra per la prima volta in un turno nell’area del muro o comincia il suo turno lì, la creatura deve effettuare un tiro salvezza su Destrezza. Se la creatura fallisce il tiro salvezza subisce 6d10 danni taglienti, o la metà se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/barriera-di-lame/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('beffa-crudele', 'beffa-crudele', 'Beffa Crudele', 0, 'Ammaliamento', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/beffa-crudele/', '["bardo"]', '{"name":"Beffa Crudele","level":0,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":"Saggezza","attack_roll":true,"damage":"1d4","scaling":null,"ritual":false,"description":"Scateni una serie di insulti avvolti da una subdola malia contro una creatura a gittata e che puoi vedere. Se il bersaglio ti può udire (sebbene non sia necessario che ti comprenda), deve superare un tiro salvezza su Saggezza o subire 1d4 danni psichici e avere svantaggio al prossimo tiro per colpire che effettuerà prima del termine del suo prossimo turno. Il danno dell’incantesimo aumenta di 1d4 quando raggiungi il 5° livello (2d4), 11° livello (3d4) e 17° livello (4d4).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/beffa-crudele/","classes":["bardo"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('benedizione', 'benedizione', 'Benedizione', 1, 'Ammaliamento', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/benedizione/', '["chierico","paladino"]', '{"name":"Benedizione","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, S, M (uno spruzzo di acqua sacra)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":true,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, puoi aggiungere una creatura come bersaglio per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Benedici fino a tre creature a gittata, scelte da te. Ogni qualvolta un bersaglio effettua un tiro per colpire o un tiro salvezza prima del termine dell’incantesimo, può tirare un d4 aggiuntivo e sommare il risultato ottenuto al tiro per colpire o al tiro salvezza.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/benedizione/","classes":["chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('blocca-mostri', 'blocca-mostri', 'Blocca Mostri', 5, 'Ammaliamento', '1 azione', '27 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/blocca-mostri/', '["bardo"]', '{"name":"Blocca Mostri","level":5,"school":"Ammaliamento","casting_time":"1 azione","range":"27 metri","components":"V, S, M (un piccolo pezzo dritto di ferro)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, puoi aggiungere una creatura come bersaglio per ogni livello dello slot sopra il 5°. Quando lanci l’incantesimo, le creature bersaglio devono trovarsi entro 9 metri l’una dall’altra.","ritual":false,"description":"Scegli una creatura a gittata e che puoi vedere. Il bersaglio deve superare un tiro salvezza su Saggezza, o restare paralizzato per la durata. Questo incantesimo non ha effetto su non morti o costrutti. Al termine di ciascun suo turno, il bersaglio può effettuare un altro tiro salvezza su Saggezza. Se lo supera, per quel bersaglio l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/blocca-mostri/","classes":["bardo"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('blocca-persone', 'blocca-persone', 'Blocca Persone', 2, 'Ammaliamento', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/blocca-persone/', '["bardo","chierico","druido","mago","stregone","warlock"]', '{"name":"Blocca Persone","level":2,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un piccolo pezzo dritto di ferro)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, puoi aggiungere una creatura come bersaglio per ogni livello dello slot sopra il 2°. Quando lanci l’incantesimo, gli umanoidi bersaglio devono trovarsi entro 9 metri l’uno dall’altro.","ritual":false,"description":"Scegli un umanoide a gittata e che puoi vedere. Il bersaglio deve superare un tiro salvezza su Saggezza o restare paralizzato per la durata. Al termine di ciascun suo turno, il bersaglio può effettuare un altro tiro salvezza su Saggezza. Se lo supera, per quel bersaglio l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/blocca-persone/","classes":["bardo","chierico","druido","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('bocca-magica', 'bocca-magica', 'Bocca Magica', 2, 'Illusione', '1 minuto', '9 metri', 'Finché non viene dissolto', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/bocca-magica/', '["bardo","mago"]', '{"name":"Bocca Magica","level":2,"school":"Illusione","casting_time":"1 minuto","range":"9 metri","components":"V, S, M (un piccolo pezzo di favo e polvere di giada del valore di almeno 10 mo, che l’incantesimo consuma)","duration":"Finché non viene dissolto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Impianti un messaggio in un oggetto a gittata, messaggio che viene pronunciato quando si soddisfa la condizione di attivazione. Scegli un oggetto che puoi vedere e che non sia indossato o trasportato da un’altra creatura. Poi pronuncia il messaggio, che deve essere di 25 parole o meno, ma può essere distribuito in un periodo di massimo 10 minuti. Infine, determina la circostanza che attiverà l’incantesimo, affinché questo trasmetta il tuo messaggio. Quando la circostanza si manifesta, una bocca magica appare sull’oggetto e recita il messaggio con la tua voce e allo stesso volume con cui l’hai pronunciato. Se l’oggetto da te scelto ha una bocca o qualcosa che assomiglia a una bocca (per esempio, la bocca di una statua), la bocca magica appare così che le parole sembrino provenire dalla bocca dell’oggetto. Quando lanci questo incantesimo, puoi far sì che l’incantesimo termini dopo aver trasmesso il suo messaggio, o che perduri e ripeta il messaggio ogni volta che la condizione si attiva. La circostanza di attivazione può essere generica o dettagliata quanto desideri, ma deve essere basata su condizioni visibili o udibili che avvengono entro 9 metri dall’oggetto. Per esempio, potresti istruire la bocca di parlare quando una qualsiasi creatura si avvicina entro 9 metri dall’oggetto o quando una campanella d’argento suona entro 9 metri da esso.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/bocca-magica/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('caduta-morbida', 'caduta-morbida', 'Caduta Morbida', 1, 'Trasmutazione', '1 reazione, che effettui quando tu o una creatura entro 18 metri da te cadete', '18 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/caduta-morbida/', '["bardo","mago","stregone"]', '{"name":"Caduta Morbida","level":1,"school":"Trasmutazione","casting_time":"1 reazione, che effettui quando tu o una creatura entro 18 metri da te cadete","range":"18 metri","components":"V, M (una piccola piuma o un pezzo di piuma)","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scegli fino a cinque creature a gittata. La velocità di discesa di una creatura che cade diminuisce a 18 metri per round fino al termine dell’incantesimo. Se la creatura atterra prima del termine dell’incantesimo, non subisce danni da caduta e può atterrare sui suoi piedi; per quella creatura l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/caduta-morbida/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('calmare-emozioni', 'calmare-emozioni', 'Calmare Emozioni', 2, 'Ammaliamento', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/calmare-emozioni/', '["bardo","chierico"]', '{"name":"Calmare Emozioni","level":2,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Tenti di sopprimere le forti emozioni in un gruppo di persone. Ogni umanoide in una sfera di 6 metri di raggio centrata su di un punto a gittata da te scelto, deve effettuare un tiro salvezza su Carisma; se lo desidera, una creatura può scegliere di fallire questo tiro salvezza. Se una creatura fallisce il tiro salvezza, scegli uno di questi due effetti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/calmare-emozioni/","classes":["bardo","chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('camminare-nel-vento', 'camminare-nel-vento', 'Camminare nel Vento', 6, 'Trasmutazione', '1 minuto', '9 metri', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/camminare-nel-vento/', '["druido"]', '{"name":"Camminare nel Vento","level":6,"school":"Trasmutazione","casting_time":"1 minuto","range":"9 metri","components":"V, S, M (fuoco e acqua sacra)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata, tu e fino ad altre dieci creature consenzienti a gittata, che puoi vedere, assumete forma gassosa, diventando nubi. Mentre è in forma di nube, una creatura ha velocità di volo 90 metri e ha resistenza ai danni dalle armi non magiche. Ritornare alla forma normale richiede 1 minuto, durante il quale la creatura è inabile e non può muoversi. Fino al termine dell’incantesimo, una creatura può tornare alla forma di nube, che richiede una trasformazione di un minuto. Se una creatura è in forma di nube e sta volando quando l’effetto ha termine, la creatura scende 18 metri per round al minuto finché non atterra, al sicuro. Se non riesce ad atterrare dopo 1 minuto, la creatura cadrà per la distanza rimanente.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/camminare-nel-vento/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('camminare-sull-acqua', 'camminare-sull-acqua', 'Camminare sull’Acqua', 3, 'Trasmutazione', '1 azione', '9 metri', '1 ora', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/camminare-sullacqua/', '["druido","ranger","stregone"]', '{"name":"Camminare sull’Acqua","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un pezzo di sughero)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Questo incantesimo conferisce la capacità di muoversi attraverso superfici liquide (come acqua, acido, fango, neve, sabbie mobili o lava) come se fossero innocuo terreno solido (le creature che attraversano la lava fusa possono comunque subire danni dal calore). Fino a dieci creature consenzienti a gittata, e che puoi vedere, ricevono questa capacità per tutta la durata. Se il tuo bersaglio è immerso in un liquido, l’incantesimo riporta il bersaglio in superficie del liquido a una velocità di 18 metri per round.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/camminare-sullacqua/","classes":["druido","ranger","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('campo-anti-magia', 'campo-anti-magia', 'Campo Anti-Magia', 8, 'Abiurazione', '1 azione', 'Incantatore (sfera di 3 metri di raggio)', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/campo-anti-magia/', '["chierico"]', '{"name":"Campo Anti-Magia","level":8,"school":"Abiurazione","casting_time":"1 azione","range":"Incantatore (sfera di 3 metri di raggio)","components":"V, S, M (un pizzico di ferro in polvere o lime di ferro)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Vieni circondato da una sfera invisibile di anti-magia di 3 metri di raggio. Quest’area è separata dall’energia magica che permea il multiverso. All’interno della sfera non si possono lanciare incantesimi, le creature richiamate scompaiono e anche gli oggetti magici diventano normali. Fino al termine dell’incantesimo, la sfera si muove con te, centrata su di te. Gli incantesimi e altri effetti magici, eccetto quelli creati da un artefatto o divinità, sono soppressi all’interno della sfera né vi possono penetrare. Uno slot speso per lanciare un incantesimo soppresso è consumato. Mentre un effetto è soppresso, non funziona, ma il tempo che trascorre soppresso è conteggiato per la sua durata.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/campo-anti-magia/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('camuffare-se-stesso', 'camuffare-se-stesso', 'Camuffare Sé Stesso', 1, 'Illusione', '1 azione', 'Incantatore', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/camuffare-se-stesso/', '["bardo","mago","stregone"]', '{"name":"Camuffare Sé Stesso","level":1,"school":"Illusione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Cambi il tuo aspetto, assieme a quello dei tuoi abiti, armatura, armi e altri oggetti che indossi, fino al termine dell’incantesimo o finché non impieghi un’azione per interrompere l’incantesimo. Puoi apparire 30 centimetri più basso o più alto, magro, grasso o una via di mezzo. Non puoi modificare la tua conformazione fisica, quindi devi adottare una forma che abbia la medesima distribuzione di arti. Per tutto il resto, l’illusione è limitata solo dalla tua fantasia. I cambi apportati da questo incantesimo non sono in grado di sostenere un’ispezione fisica. Per esempio, se usi questo incantesimo per aggiungere un cappello al tuo abbigliamento, gli oggetti attraversano il cappello, e chiunque lo tocchi non avvertirebbe nulla e finirebbe per toccarti la testa e i capelli. Se usi questo incantesimo per apparire più magro di quello che sei, la mano di una persona che provasse a toccarti rimbalzerebbe su di te,mentre alla vista sembrerebbe fermarsi a mezz’aria. Per distinguere il tuo camuffamento, una creatura può usare la sua azione per ispezionare il tuo aspetto e deve superare una prova di Intelligenza (Indagare) contro la CD del tiro salvezza dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/camuffare-se-stesso/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('capanna', 'capanna', 'Capanna', 3, 'Invocazione', '1 minuto', 'Incantatore (semisfera di 3 metri di raggio)', '8 ore', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/capanna/', '["bardo","mago"]', '{"name":"Capanna","level":3,"school":"Invocazione","casting_time":"1 minuto","range":"Incantatore (semisfera di 3 metri di raggio)","components":"V, S, M (una piccola biglia di cristallo)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Una cupola di forza immobile del raggio di 3 metri si forma intorno e sopra di te, restando stazionaria per la durata. L’incantesimo termina se lasci l’area. Nove creature di taglia Media o inferiore possono entrare nella cupola insieme a te. L’incantesimo fallisce se l’area include una creatura più grande o più di dieci creature. Le creature e gli oggetti all’interno della cupola, quando lanci questo incantesimo, la possono attraversare liberamente. Tutte le altre creature e oggetti sono proibiti dall’attraversarla. Incantesimi e altri effetti magici non possono estendersi oltre la cupola o attraversarla. L’atmosfera all’interno dello spazio è confortevole e asciutta, quale che sia il clima all’esterno. Fino al termine dell’incantesimo, puoi comandare che l’interno diventi illuminato fioco o buio. La cupola è opaca dall’esterno, di qualsiasi colore tu scelga, ma è trasparente dall’interno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/capanna/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('caratteristica-potenziata', 'caratteristica-potenziata', 'Caratteristica Potenziata', 2, 'Trasmutazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/caratteristica-potenziata/', '["bardo","chierico","druido","stregone"]', '{"name":"Caratteristica Potenziata","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (pelo o piuma di una bestia)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, puoi prendere come bersaglio un’ulteriore creatura per ognilivello dello slot sopra il 2°.","ritual":false,"description":"Conferisci un potenziamento magico a una creatura con cui sei in contatto. Scegli uno degli effetti seguenti; il bersaglio ottiene quell’effetto fino al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/caratteristica-potenziata/","classes":["bardo","chierico","druido","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('carne-in-pietra', 'carne-in-pietra', 'Carne in Pietra', 6, 'Trasmutazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/carne-in-pietra/', '["mago","warlock"]', '{"name":"Carne in Pietra","level":6,"school":"Trasmutazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un pizzico di lime, acqua e terra)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Cerchi di trasformare in pietra una creatura a gittata che puoi vedere. Se il corpo del bersaglio è fatto di carne, la creatura deve effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza, è intralciata e la sua carne comincia a indurirsi. Se supera il tiro salvezza, la creatura non subisce l’incantesimo. Una creatura intralciata da questo incantesimo deve effettuare un altro tiro salvezza su Costituzione al termine di ciascun suo turno. Se supera il tiro salvezza con successo per tre volte, l’incantesimo termina. Se fallisce il tiro salvezza per tre volte, viene trasformata in pietra e resta vittima della condizione pietrificato per la durata. I successi e i fallimenti non devono essere continuativi; tenere traccia di entrambi finché il bersaglio non ne ottiene tre di un tipo. Se la creatura viene danneggiata fisicamente mentre è pietrificata, soffre di deformità simili ai danni arrecati alla pietra, se ritorna al suo stato originale. Se mantieni la tua concentrazione su questo incantesimo per la sua intera possibile durata, la creatura è trasformata in pietra finché l’effetto non viene rimosso.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/carne-in-pietra/","classes":["mago","warlock"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('catena-di-fulmini', 'catena-di-fulmini', 'Catena di Fulmini', 6, 'Invocazione', '1 azione', '45 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/catena-di-fulmini/', '["mago"]', '{"name":"Catena di Fulmini","level":6,"school":"Invocazione","casting_time":"1 azione","range":"45 metri","components":"V, S, M (un po’ di pelliccia; un pezzo d’ambra, vetro o una verga di cristallo; e tre spille d’argento)","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"10d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, un’ulteriore saetta parte dal primo bersaglio verso un altro bersaglio per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Crei una saetta di luce che colpisce un bersaglio a gittata che puoi vedere, scelto da te. Tre saette colpiscono il bersaglio e fino ad altri tre bersagli, ciascuno dei quali deve trovarsi entro 9 metri dal primo bersaglio. Un bersaglio può essere una creatura o oggetto e può essere bersaglio di una sola saetta. Un bersaglio deve effettuare un tiro salvezza su Destrezza. Il bersaglio subisce 10d8 danni da fulmine se fallisce il tiro salvezza, o la metà di questi danni se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/catena-di-fulmini/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('cecita-sordita', 'cecita-sordita', 'Cecità/Sordità', 2, 'Necromanzia', '1 azione', '9 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/cecita-sordita/', '["bardo","chierico","mago","stregone"]', '{"name":"Cecità/Sordità","level":2,"school":"Necromanzia","casting_time":"1 azione","range":"9 metri","components":"V","duration":"1 minuto","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, puoi prendere come bersaglio una creatura aggiuntiva per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Puoi accecare o assordare un nemico. Scegli una creatura a gittata e che puoi vedere. Il bersaglio deve effettuare un tiro salvezza su Costituzione. Se lo fallisce, il bersaglio è accecato o assordato (a tua scelta) per la durata. Al termine di ciascun suo turno, il bersaglio può effettuare un tiro salvezza su Costituzione. Se lo supera, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/cecita-sordita/","classes":["bardo","chierico","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('celare', 'celare', 'Celare', 7, 'Trasmutazione', '1 azione', 'Contatto', 'Fino a che dissolto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/celare/', '["mago"]', '{"name":"Celare","level":7,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (una polvere composta da polvere di diamante, smeraldo, rubino e zaffiro del valore di almeno 50.000 mo, che l’incantesimo consuma)","duration":"Fino a che dissolto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Tramite questo incantesimo, una creatura consenziente o un oggetto può essere nascosto, impossibile da individuare per la durata. Eseguendo questo incantesimo ed entrando in contatto con un bersaglio, questo diventa invisibile e non può essere preso come bersaglio dagli incantesimi di divinazione, né percepito da sensori di scrutamento creati da incantesimi di divinazione. Se il bersaglio è una creatura, cade in uno stato di animazione sospesa. Per lui il tempo cessa di scorrere, e non invecchia. Puoi predisporre una condizione per cui l’incantesimo termini anticipatamente. La condizione può essere qualsiasi cosa tu voglia, ma deve avvenire o essere visibile entro 1,5 chilometri dal bersaglio. Esempi includono “dopo 1.000 anni” o “quando il tarrasque si risveglia”. Questo incantesimo termina anche qualora il bersaglio subisca danni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/celare/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('cerchio-di-morte', 'cerchio-di-morte', 'Cerchio di Morte', 6, 'Invocazione', '1 azione', '45 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/cerchio-di-morte/', '["mago","stregone","warlock"]', '{"name":"Cerchio di Morte","level":6,"school":"Invocazione","casting_time":"1 azione","range":"45 metri","components":"V, S, M (una perla nera ridotta in polvere del valore di almeno 500 mo)","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"8d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, il danno aumenta di 2d6 per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Una sfera di energia negativa del raggio di 18 metri, erutta in un punto a gittata. Ogni creatura in quell’area deve effettuare un tiro salvezza su Costituzione. Un bersaglio subisce 8d6 danni necrotici se fallisce il tiro salvezza, o la metà di questi danni se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/cerchio-di-morte/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('cerchio-di-teletrasporto', 'cerchio-di-teletrasporto', 'Cerchio di Teletrasporto', 5, 'Evocazione', '1 minuto', '3 metri', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/cerchio-di-teletrasporto/', '["bardo","mago","stregone"]', '{"name":"Cerchio di Teletrasporto","level":5,"school":"Evocazione","casting_time":"1 minuto","range":"3 metri","components":"V, M (gessi e inchiostri rari infusi di gemme preziose del valore di almeno 50 mo, che l’incantesimo consuma)","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Mentre lanci l’incantesimo, tracci un cerchio di 3 metri di diametro sul pavimento, inscritto con sigilli che collegano il posto in cui ti trovi a un cerchio di teletrasporto permanente di tua scelta, di cui conosci la sequenza dei sigilli e che si trovi sullo stesso piano di esistenza in cui ti trovi tu. Un portale luminoso si apre all’interno del cerchio tracciato da te e resta aperto fino al termine del tuo prossimo turno. Qualsiasi creatura che entri nel portale, riappare istantaneamente entro 1,5 metri dal cerchio di destinazione o nello spazio non occupato più vicino, se non può comparire entro 1,5 metri da esso.\nMolti grandi templi, gilde, e altri luoghi importanti possiedono dei cerchi di teletrasporto permanenti, incisi da qualche parte nelle loro prossimità. Ciascuno di questi cerchi possiede una sequenza di sigilli unica: una serie di rune magiche disposte seguendo una trama precisa. Quando ottieni la capacità di lanciare questo incantesimo, apprendi le sequenze di sigilli di due destinazioni sul Piano Materiale, determinate dal GM. Nel corso delle tue avventure puoi imparare nuove sequenze di sigilli. Puoi mandare a memoria una sequenza di sigilli dopo averla studiata per almeno 1 minuto. Puoi creare un cerchio di teletrasporto permanente eseguendo questo incantesimo nello stesso luogo ogni giorno per un anno. Non devi usare il cerchio di teletrasporto quando lanci l’incantesimo in questo modo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/cerchio-di-teletrasporto/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('cerchio-magico', 'cerchio-magico', 'Cerchio Magico', 3, 'Abiurazione', '1 minuto', '3 metri', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/cerchio-magico/', '["chierico","mago","paladino","warlock"]', '{"name":"Cerchio Magico","level":3,"school":"Abiurazione","casting_time":"1 minuto","range":"3 metri","components":"V, S, M (acqua sacra o argento e ferro in polvere del valore di almeno 100 mo, che l’incantesimo consuma)","duration":"1 ora","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, la durata aumenta di 1 ora per ogni livello dello slot sopra il 3°.","ritual":false,"description":"Crei un cilindro di energia magica di 3 metri di raggio e alto 6 metri, centrato su di un punto del terreno a gittata e che puoi vedere. Rune luminose compaiono dovunque il cilindro si intersechi con il pavimento o altra superficie. Scegli uno o più dei seguenti tipi di creature: celestiali, elementali, fatati, immondi o non morti. Il circolo influisce su di una creatura del tipo scelto nei modi seguenti:\nLa creatura non può entrare consapevolmente nel cilindro tramite alcun mezzo non magico. Se la creatura prova a usare il teletrasporto o il viaggio tra i piani per farlo, deve prima superare un tiro salvezza su Carisma. La creatura ha svantaggio ai tiri per colpire contro i bersagli all’interno del cilindro. I bersagli all’interno del cilindro non possono essere affascinati, spaventati o posseduti dalla creatura.\nQuando lanci questo incantesimo, puoi decidere che la magia operi in direzione opposta, impedendo a una creatura del tipo specificato di lasciare il cilindro e proteggendo i bersagli all’esterno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/cerchio-magico/","classes":["chierico","mago","paladino","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('charme-su-persone', 'charme-su-persone', 'Charme su Persone', 1, 'Ammaliamento', '1 azione', '9 metri', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/charme-su-persone/', '["bardo","druido","mago","stregone","warlock"]', '{"name":"Charme su Persone","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"1 ora","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, puoi aggiungere una creatura come bersaglio per ogni livello dello slot sopra il 1°. Quando lanci l’incantesimo, le creature bersaglio devono trovarsi entro 9 metri l’una dall’altra.","ritual":false,"description":"Cerchi di affascinare un umanoide a gittata e che puoi vedere. Egli deve effettuare un tiro salvezza su Saggezza, e avrà vantaggio se sta combattendo con te o i tuoi alleati. Se fallisce il tiro salvezza, è affascinato da te fino al termine dell’incantesimo o finché tu o i tuoi alleati non gli facciate qualcosa di nocivo. La creatura affascinata ti considera un amichevole conoscente. Quando l’incantesimo termina, la creatura è consapevole di essere stata affascinata da te.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/charme-su-persone/","classes":["bardo","druido","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('chiaroveggenza', 'chiaroveggenza', 'Chiaroveggenza', 3, 'Divinazione', '10 minuti', '1,5 chilometri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/chiaroveggenza/', '["bardo","chierico","mago","stregone"]', '{"name":"Chiaroveggenza","level":3,"school":"Divinazione","casting_time":"10 minuti","range":"1,5 chilometri","components":"V, S, M (un focus del valore di almeno 100 mo, che sia un corno ingioiellato per udire o un occhio di vetro per guardare)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei un sensore invisibile in un luogo a te familiare e che sia a gittata (un luogo che hai già visitato o visto precedentemente) o in un luogo ovvio ma che non ti è familiare (come dietro una porta o un angolo, o in mezzo un boschetto di alberi). Il sensore rimane sul posto per la durata, e non può essere attaccato né altrimenti vi si può interagire.\nQuando lanci questo incantesimo, scegli se vedere o udire. Puoi usare il senso scelto tramite il sensore, come ti trovassi nel suo spazio. Con un’azione, puoi passare da udire a sentire e viceversa.\nUna creatura che può vedere il sensore (una creatura munita di vedere invisibilità o di visione del vero) lo percepisce come un orbe intangibile e luminoso delle dimensioni del tuo pugno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/chiaroveggenza/","classes":["bardo","chierico","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('clone', 'clone', 'Clone', 8, 'Necromanzia', '1 ora', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/clone/', '["mago"]', '{"name":"Clone","level":8,"school":"Necromanzia","casting_time":"1 ora","range":"Contatto","components":"V, S, M (un diamante del valore di almeno 1.000 mo e almeno 16 centimetri cubi di carne della creatura che deve essere clonata, che l’incantesimo consuma, e un recipiente da almeno 2.000 mo di valore che abbia un coperchio sigillabile e sia grande a sufficienza da contenere una creatura Media, come una grossa urna, una bara, una fossa piena di fango nel terreno o un contenitore di cristallo pieno di acqua salata)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo produce il duplicato inerte di una creatura vivente come salvaguardia dalla morte. Questo clone si forma all’interno di un recipiente sigillato e raggiunge la massima dimensione e maturità dopo 120 giorni; puoi anche decidere che il clone sia una versione più giovane della stessa creatura. Rimane inerte e sopravvive all’infinito, purché il recipiente resti indisturbato. In qualsiasi momento dopo che il clone è maturato, se la creatura originale muore, la sua anima si trasferisce nel clone, purché l’anima sia libera e consenziente a tornare. Il clone è fisicamente identico all’originale e ha la stessa personalità, ricordi e caratteristiche, ma nulladell’equipaggiamento dell’originale. I resti fisici della creatura originale, se esistono ancora, divengono inerti e non possono essere riportati alla vita, dato che l’anima della creatura è altrove.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/clone/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('colpo-accurato', 'colpo-accurato', 'Colpo Accurato', 0, 'Divinazione', '1 azione', '9 metri', 'Concentrazione, massimo 1 round', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/colpo-accurato/', '["bardo","mago","stregone","warlock"]', '{"name":"Colpo Accurato","level":0,"school":"Divinazione","casting_time":"1 azione","range":"9 metri","components":"S","duration":"Concentrazione, massimo 1 round","concentration":true,"saving_throw":null,"attack_roll":true,"damage":null,"scaling":null,"ritual":false,"description":"Allunghi la mano e punti il dito verso un bersaglio a gittata. La tua magia ti conferisce una breve comprensione delle difese del bersaglio. Durante il tuo prossimo turno, purché questo incantesimo non sia terminato, ottieni vantaggio al primo tiro per colpire contro quel bersaglio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/colpo-accurato/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('colpo-del-comandante', 'colpo-del-comandante', 'Colpo del Comandante', 0, 'Manovra', 'Azione bonus (quando usi l’azione Attacco rinunciando a uno dei tuoi attacchi)', 'Alleato che ti vede o ti sente', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Colpo del Comandante","level":0,"school":"Manovra","casting_time":"Azione bonus (quando usi l’azione Attacco rinunciando a uno dei tuoi attacchi)","range":"Alleato che ti vede o ti sente","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero effettua\nl''azione di Attacco nel suo turno, può rinunciare a uno dei\nsuoi attacchi e usare un''azione bonus per ordinare a uno\ndei suoi compagni di colpire. Quando lo fa, sceglie una\ncreatura amica che sia in grado di vederlo o di sentirlo\ne spende un dado di superiorità. Quella creatura può\nimmediatamente usare la sua reazione per effettuare un\nattacco con un''arma, aggiungendo il dado di superiorità al\ntiro per i danni dell''attacco.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('colpo-distraente', 'colpo-distraente', 'Colpo Distraente', 0, 'Manovra', 'N/A (quando colpisci con un attacco)', 'Bersaglio colpito', 'Fino all’inizio del tuo prossimo turno', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Colpo Distraente","level":0,"school":"Manovra","casting_time":"N/A (quando colpisci con un attacco)","range":"Bersaglio colpito","components":"-","duration":"Fino all’inizio del tuo prossimo turno","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero colpisce una\ncreatura con un attacco con un''arma, può spendere un dado di\nsuperiorità per distrarre la creatura e procurare ai suoi alleati\nun''apertura. Il guerriero aggiunge il dado di superiorità al tiro\nper i danni dell''attacco. Il prossimo tiro per colpire effettuato\ncontro il bersaglio da un attaccante che non sia il guerriero\ndispone di vantaggio, purché sia effettuato prima dell''inizio\ndel turno successivo del guerriero.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('colpo-infuocato', 'colpo-infuocato', 'Colpo Infuocato', 5, 'Invocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/colpo-infuocato/', '["chierico"]', '{"name":"Colpo Infuocato","level":5,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (pizzico di zolfo)","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"4d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, il danno da fuoco o il danno radiante (a tua scelta) aumenta di 1d6 per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Una colonna verticale di fuoco divino scende dal cielo e si abbatte sul luogo da te specificato. Ogni creatura in un cilindro di 3 metri di raggio e alto 12 metri centrato su di un punto a gittata deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 4d6 danni da fuoco e 4d6 danni radianti se fallisce il tiro salvezza, o la metà di questi danni se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/colpo-infuocato/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('comando', 'comando', 'Comando', 1, 'Ammaliamento', '1 azione', '18 metri', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/comando/', '["chierico","paladino"]', '{"name":"Comando","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V","duration":"1 round","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, puoi agire su di un’ulteriore creatura per ogni livello dello slotsopra il 1°. Nel momento in cui lanci l’incantesimo, le creature bersaglio devono trovarsi entro 9 metri l’una da l’altra.","ritual":false,"description":"Pronunci un comando di una parola verso una creatura a gittata e che puoi vedere. Il bersaglio deve superare un tiro salvezza su Saggezza o eseguire il comando durante il suo prossimo turno. L’incantesimo non ha effetto se il bersaglio è non morto, se non capisce la tua lingua, o se il tuo comando gli recherebbe danni. Seguono alcuni tipici comandi e i loro effetti. Puoi dare comandi diversi da quelli descritti qui, e in quel caso il GM determinerà il comportamento del bersaglio. Se il bersaglio non può eseguire il tuo comando, l’incantesimo ha fine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/comando/","classes":["chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('comprensione-dei-linguaggi', 'comprensione-dei-linguaggi', 'Comprensione dei Linguaggi', 1, 'Divinazione', '1 azione', 'Incantatore', '1 ora', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/comprensione-dei-linguaggi/', '["bardo","mago","stregone","warlock"]', '{"name":"Comprensione dei Linguaggi","level":1,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un pizzico di sale e fuliggine)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Per la durata, capisci il significato letterale di qualsiasi linguaggio parlato che ascolti. Capisci anche qualsiasi linguaggio scritto che vedi, ma devi essere a contatto con la superficie su cui le parole sono scritte. Per leggere una pagina di testo impieghi 1 minuto. Questo incantesimo non decodifica i messaggi segreti in un testo o glifo, come un sigillo arcano, che non faccia parte di un linguaggio scritto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/comprensione-dei-linguaggi/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('compulsione', 'compulsione', 'Compulsione', 4, 'Ammaliamento', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/compulsione/', '["bardo"]', '{"name":"Compulsione","level":4,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Le creature di tua scelta entro la gittata, che puoi vedere e che ti possono sentire, devono effettuare un tiro salvezza su Saggezza. Un bersaglio supera automaticamente il tiro salvezza se non può essere affascinato. Fino al termine dell’incantesimo, puoi usare un’azione bonus durante ciascun tuo turno per indicare una direzione orizzontale rispetto a te. Ogni bersaglio soggetto all’incantesimo deve usare quanto più possibile del suo movimento, durante il suo prossimo turno, per muoversi in quella direzione. Il bersaglio non può effettuare nessuna azione prima di muoversi. Dopo essersi mosso in questo modo, il bersaglio può effettuare un altro tiro salvezza su Saggezza per tentare di terminare l’effetto. Un bersaglio non può essere obbligato a muoversi dentro un pericolo palesemente letale, come fiamme o pozzi, ma per muoversi nella direzione indicata potrà provocare attacchi di opportunità.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/compulsione/","classes":["bardo"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('comunione', 'comunione', 'Comunione', 5, 'Divinazione', '1 minuto', 'Incantatore', '1 minuto', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/comunione/', '["chierico","druido","ranger"]', '{"name":"Comunione","level":5,"school":"Divinazione","casting_time":"1 minuto","range":"Incantatore","components":"V, S, M (incenso e una fiala di acqua sacra o blasfema)","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Comunichi con la tua divinità o un agente divino e gli poni fino a tre domande a cui si può dare risposta con un sì o un no. Devi porre le domande prima della fine dell’incantesimo. Riceverai la risposta corretta a ciascuna domanda. Le creature divine non sono necessariamente onniscienti, quindi potresti ricevere “non è chiaro” come risposta a una domanda che riguarda informazioni non pertinenti alle conoscenze della divinità. Nel caso in cui una risposta di una parola potrebbe essere fuorviante o contraria agli interessi della divinità, il GM potrebbe invece dare una breve frase come risposta. Se lanci l’incantesimo due o più volte prima di aver terminato il tuo prossimo riposo lungo, c’è una probabilità cumulativa del 25% che per ogni lancio dopo il primo tu non ottenga alcuna risposta. Il GM effettua questo tiro in segreto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/comunione/","classes":["chierico","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('comunione-con-la-natura', 'comunione-con-la-natura', 'Comunione con la Natura', 5, 'Divinazione', '1 minuto', 'Incantatore', 'Istantanea', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/comunione-con-la-natura/', '["druido","ranger"]', '{"name":"Comunione con la Natura","level":5,"school":"Divinazione","casting_time":"1 minuto","range":"Incantatore","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Per un istante diventi tutt’uno con la natura e ottieni informazioni sul territorio circostante. In ambienti esterni, l’incantesimo ti fornisce informazioni sul territorio entro 5 chilometri da te. In grotte e altri ambienti naturali sotterranei, il raggio è limitato a 100 metri. L’incantesimo non funziona nei luoghi in cui la natura è stata soppiantata da costruzioni, come in sotterranei e paesi.\nApprendi immediatamente informazioni su un massimo di tre argomenti a tua scelta su uno dei seguenti soggetti, in relazione all’area:\nterreno e corpi d’acqua piante, minerali, animali e popolazioni prevalenti potenti celestiali, elementali, fatati, immondi o non morti influenze da altri piani di esistenza edifici","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/comunione-con-la-natura/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('confusione', 'confusione', 'Confusione', 4, 'Ammaliamento', '1 azione', '27 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/confusione/', '["bardo","druido","mago","stregone"]', '{"name":"Confusione","level":4,"school":"Ammaliamento","casting_time":"1 azione","range":"27 metri","components":"V, S, M (tre gusci di noce)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello o più alto, il raggio della sfera aumenta di 1,5 metri per ogni livello dello slot sopra il 4°.","ritual":false,"description":"Questo incantesimo assale e piega la mente delle creature, generando illusioni e provocando azioni incontrollate. Quando lanci questo incantesimo ogni creatura, in una sfera di 3 metri di raggio centrata su di un punto da te scelto entro la gittata, deve superare un tiro salvezza su Saggezza o subirne gli effetti. Un bersaglio soggetto all’incantesimo non può effettuare reazioni e deve tirare un d10 all’inizio di ciascun suo turno per determinare il proprio comportamento per quel turno.\nd10 Comportamento 1 La creatura usa tutto il suo movimento per muoversi in una direzione casuale. Per determinare la direzione, tira un d8 assegnando a ciascuna faccia un punto cardinale. La creatura non effettuerà nessuna azione in questo turno. 2-6 La creatura non può muoversi né attaccare in questo turno. 7-8 La creatura usa la sua azione per effettuare un attacco da mischia contro una creatura determinata a caso entro la sua portata. Se non c’è nessuna creatura a portata, per questo turno la creatura non farà nulla. 9-10 La creatura può agire e muoversi normalmente.\nAl termine di ciascun suo turno, un bersaglio soggetto all’incantesimo può effettuare un tiro salvezza su Saggezza. Se lo supera, per lui l’effetto ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/confusione/","classes":["bardo","druido","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('cono-di-freddo', 'cono-di-freddo', 'Cono di Freddo', 5, 'Invocazione', '1 azione', 'Incantatore (cono di 18 metri)', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/cono-di-freddo/', '["mago","stregone"]', '{"name":"Cono di Freddo","level":5,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore (cono di 18 metri)","components":"V, S, M (un piccolo cristallo o cono di vetro)","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"8d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Un’esplosione di aria fredda erutta dalle tue mani. Ogni creatura in un cono di 18 metri deve effettuare un tiro salvezza su Costituzione. Una creatura subisce 8d8 danni da freddo se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Una creatura uccisa da questo incantesimo diventa una statua di ghiaccio fino a quando disgela.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/cono-di-freddo/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('conoscenza-delle-leggende', 'conoscenza-delle-leggende', 'Conoscenza delle Leggende', 5, 'Divinazione', '10 minuti', 'Incantatore', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/conoscenza-delle-leggende/', '["bardo","chierico","mago"]', '{"name":"Conoscenza delle Leggende","level":5,"school":"Divinazione","casting_time":"10 minuti","range":"Incantatore","components":"V, S, M (incenso del valore di almeno 250 mo, che l’incantesimo consuma, e quattro strisce d’avorio del valore di almeno 50 mo)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Nomina o descrivi una persona, luogo od oggetto. L’incantesimo ti porta alla mente un breve riassunto delle conoscenze più importanti sull’argomento da te nominato. Se la cosa da te nominata non ha alcuna rilevanza leggendaria, non ottieni alcuna informazione. Maggiori informazioni hai sull’argomento, più precise e dettagliate saranno le informazioni che riceverai. L’informazione che riceverai sarà accurata, ma celata magari in linguaggio metaforico.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/conoscenza-delle-leggende/","classes":["bardo","chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('contagio', 'contagio', 'Contagio', 5, 'Necromanzia', '1 azione', 'Contatto', '7 giorni', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/contagio/', '["chierico","druido"]', '{"name":"Contagio","level":5,"school":"Necromanzia","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"7 giorni","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Tramite il contatto puoi infliggere malattie. Effettua un attacco da mischia con incantesimo contro una creatura a portata. Se colpisci, infetti la creatura con una malattia a tua scelta tra quelle descritte di seguito. Al termine di ciascun turno del bersaglio, esso deve effettuare un tiro salvezza su Costituzione. Dopo aver fallito tre di questi tiri salvezza, gli effetti della malattia permangono per la durata, e la creatura non effettua più tiri salvezza. Dopo aver superato tre di questi tiri salvezza, la creatura recupera dalla malattia, e l’incantesimo ha termine. Dato che questo incantesimo induce nel suo bersaglio una malattia naturale, qualsiasi effetto che rimuova le malattie o migliori gli effetti delle malattie si applica a essa.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/contagio/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('contattare-altri-piani', 'contattare-altri-piani', 'Contattare Altri Piani', 5, 'Divinazione', '1 minuto', 'Incantatore', '1 minuto', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/contattare-altri-piani/', '["mago","warlock"]', '{"name":"Contattare Altri Piani","level":5,"school":"Divinazione","casting_time":"1 minuto","range":"Incantatore","components":"V","duration":"1 minuto","concentration":false,"saving_throw":"Intelligenza","attack_roll":false,"damage":"6d6","scaling":null,"ritual":true,"description":"Contatti mentalmente un semidio, lo spirito di un saggio da tempo defunto, o qualche altra misteriosa entità di un altro piano. Contattare l’intelligenza extraplanare può affaticare o addirittura spezzare la tua mente. Quando lanci questo incantesimo, effettua un tiro salvezza su Intelligenza con CD 15. Se lo fallisci, subisci 6d6 danni psichici e resti demente fino al termine di un riposo lungo. Mentre sei demente, non puoi effettuare azioni, non puoi capire quello che dicono le altre creature, non puoi leggere, e parli solo farneticando. L’incantesimo ristorare superiore può porre fine a questo effetto. Se superi il tiro salvezza, puoi porre all’entità fino a cinque domande. Devi porre le domande prima del termine dell’incantesimo. Il GM risponderà a ciascuna domanda con una parola: “sì”, “no”, “forse”, “mai”, “irrilevante” o “confuso” (se l’entità non conosce la risposta alla domanda). Se una risposta di una parola potrebbe risultare fuorviante, il GM potrebbe invece dare come risposta una breve frase.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/contattare-altri-piani/","classes":["mago","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('contingenza', 'contingenza', 'Contingenza', 6, 'Invocazione', '10 minuti', 'Incantatore', '10 giorni', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/contingenza/', '["mago"]', '{"name":"Contingenza","level":6,"school":"Invocazione","casting_time":"10 minuti","range":"Incantatore","components":"V, S, M (una statuetta raffigurante te stesso scolpita in avorio e decorata con gemme del valore di almeno 1.500 mo)","duration":"10 giorni","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scegli un incantesimo di 5° livello o più basso che puoi lanciare, che abbia il tempo di lancio di 1 azione, e che può avere te come bersaglio. Lanci quell’incantesimo (detto incantesimo contingente) come parte del lancio di contingenza, spendendo gli slot incantesimo di entrambi, ma senza che l’incantesimo contingente abbia effetto. Avrà invece effetto quando si avvererà una determinata circostanza. Descrivi questa circostanza mentre lanci i due incantesimi. Per esempio, contingenza lanciato assieme a respirare sott’acqua potrebbe stipulare che respirare sott’acqua entra in azione quando sei immerso nell’acqua o simile liquido. L’incantesimo contingente ha effetto immediatamente dopo che la circostanza si verifica per la prima volta, che tu lo voglia o no, e poi contingenza termina. L’incantesimo contingente agisce solo su di te, anche se normalmente può prendere come bersaglio anche altri. Puoi usare un solo incantesimo contingenza alla volta. Se lanci di nuovo questo incantesimo, l’effetto di un altro incantesimo contingenza su di te avrà termine. Inoltre, contingenza per te ha termine se la componente materiale non dovesse più trovarsi sulla tua persona.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/contingenza/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('controincantesimo', 'controincantesimo', 'Controincantesimo', 3, 'Abiurazione', '1 reazione, che effettui quando vedi una creatura entro 18 metri da te lanciare un incantesimo', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/controincantesimo/', '["mago","stregone","warlock"]', '{"name":"Controincantesimo","level":3,"school":"Abiurazione","casting_time":"1 reazione, che effettui quando vedi una creatura entro 18 metri da te lanciare un incantesimo","range":"18 metri","components":"S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, l’incantesimo interrotto non ha effetto se il suo livello è uguale o inferiore al livello dello slot incantesimo che usi.","ritual":false,"description":"Cerchi di interrompere una creatura nell’atto di lanciare un incantesimo. Se la creatura sta lanciando un incantesimo di 3° livello o più basso, l’incantesimo fallisce e non ha effetto. Se sta eseguendo un incantesimo di 4° livello o più alto, effettui una prova di caratteristica utilizzando la tua caratteristica da incantatore. La CD è uguale a 10 + il livello dell’incantesimo da interrompere. Se la superi, l’incantesimo della creatura fallisce e non ha effetto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/controincantesimo/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('controllare-acqua', 'controllare-acqua', 'Controllare Acqua', 4, 'Trasmutazione', '1 azione', '90 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/controllare-acqua/', '["chierico","druido","mago"]', '{"name":"Controllare Acqua","level":4,"school":"Trasmutazione","casting_time":"1 azione","range":"90 metri","components":"V, S, M (un goccio d’acqua e un pizzico di polvere)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fino al termine dell’incantesimo, controlli qualsiasi acqua libera all’interno dell’area che hai scelto fino a un cubo di 30 metri di spigolo. Quando lanci questo incantesimo puoi scegliere qualsiasi tra i seguenti effetti. Come azione, durante il tuo turno, puoi ripetere lo stesso effetto o sceglierne uno diverso.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/controllare-acqua/","classes":["chierico","druido","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('controllare-tempo-atmosferico', 'controllare-tempo-atmosferico', 'Controllare Tempo Atmosferico', 8, 'Trasmutazione', '10 minuti', 'Incantatore (raggio di 1,5 chilometri)', 'Concentrazione, massimo 8 ore', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/controllare-tempo-atmosferico/', '["chierico","druido","mago"]', '{"name":"Controllare Tempo Atmosferico","level":8,"school":"Trasmutazione","casting_time":"10 minuti","range":"Incantatore (raggio di 1,5 chilometri)","components":"V, S, M (incenso bruciato e po’ di terra e legno mescolati nell’acqua)","duration":"Concentrazione, massimo 8 ore","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata, assumi il controllo del clima entro 7,5 chilometri da te. Per lanciare questo incantesimo devi essere all’esterno. Muoversi in un posto dove non hai la visuale aperta verso il cielo, termina l’incantesimo anticipatamente. Quando lanci questo incantesimo, cambia le attuali condizioni climatiche, determinate dal GM in base alla stagione e la latitudine. Puoi modificare le precipitazioni, la temperatura e il vento. Ci vogliono 1d4 x 10 minuti perché la nuova condizione prenda effetto. Una volta che la condizione avrà preso effetto, potrai cambiarla di nuovo. Quando l’incantesimo termina, il clima tornerà gradualmente alla norma. Quando cambi le condizioni climatiche, trova l’attuale condizione sulla seguente tabella e cambiala di uno stadio, verso l’alto o il basso. Quando cambi il vento, puoi cambiarne anche la direzione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/controllare-tempo-atmosferico/","classes":["chierico","druido","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('costrizione', 'costrizione', 'Costrizione', 5, 'Ammaliamento', '1 minuto', '18 metri', '30 giorni', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/costrizione/', '["bardo","chierico","druido","mago","paladino"]', '{"name":"Costrizione","level":5,"school":"Ammaliamento","casting_time":"1 minuto","range":"18 metri","components":"V","duration":"30 giorni","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":"5d10","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° o 8° livello, la durata è 1 anno. Quando lanci questo incantesimo usando unoslot incantesimo di 9° livello, l’incantesimo dura finché non viene terminato da uno degli incantesimi sopra menzionati.","ritual":false,"description":"Imponi un comando magico a una creatura a gittata che puoi vedere, obbligandolo ad adempiere un determinato compito o vietandole di svolgere un’azione o corso d’attività deciso da te. Se la creatura ti può capire, deve superare un tiro salvezza su Saggezza o restare affascinata da te per la durata. Mentre la creatura è affascinata da te, subisce 5d10 danni psichici ogni volta che agisce in maniera direttamente contraria alle tue istruzioni, ma non più di una volta al giorno. Una creatura che non ti può capire ignora gli effetti di questo incantesimo. Puoi dare qualsiasi comando di tua scelta, tranne un’attività che provocherebbe morte certa. Dovessi tu pronunciare un comando suicida, l’incantesimo avrebbe termine. Puoi terminare l’incantesimo usando un’azione. Anche rimuovi maledizione, ristorare superiore o desiderio vi pongono termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/costrizione/","classes":["bardo","chierico","druido","mago","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('creare-cibo-e-acqua', 'creare-cibo-e-acqua', 'Creare Cibo e Acqua', 3, 'Evocazione', '1 azione', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/creare-cibo-e-acqua/', '["chierico","paladino"]', '{"name":"Creare Cibo e Acqua","level":3,"school":"Evocazione","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei 22,5 chili di cibo e 120 litri d’acqua sul terreno o in contenitori a gittata, sufficienti a sostenere fino a quindici umanoidi o cinque cavalcature per 24 ore. Il cibo è blando ma nutriente, e marcisce dopo 24 ore se non viene consumato. L’acqua è pulita e non va a male.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/creare-cibo-e-acqua/","classes":["chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('creare-non-morti', 'creare-non-morti', 'Creare Non Morti', 6, 'Necromanzia', '1 azione', '3 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/creare-non-morti/', '["chierico","mago","warlock"]', '{"name":"Creare Non Morti","level":6,"school":"Necromanzia","casting_time":"1 azione","range":"3 metri","components":"V, S, M (un vaso di terracotta pieno di terra di cimitero, un vaso di terracotta pieno di acqua salmastra, e un onice nero del valore di 50 mo per ogni cadavere)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello, puoi rianimare o riasserire il controllo su quattro ghoul. Quando lanci questo incantesimo usando uno slot incantesimo di 8° livello, puoi animare o riasserire il controllo su cinque ghoul o due ghast o wight. Quando lanci questo incantesimo usando uno slot incantesimo di 9° livello puoi animare o riasserire il controllo su sei ghoul, tre ghast o wight, o due mummie.","ritual":false,"description":"Puoi lanciare questo incantesimo solo di notte. Scegli fino a tre cadaveri di umanoidi Medi o Piccoli a gittata. Ogni cadavere diventa un ghoul sotto il tuo controllo (il GM possiede le statistiche di gioco di queste creature). Durante il tuo turno, con un’azione bonus, puoi comandare mentalmente qualsiasi creatura da te animata con questo incantesimo, se la creatura si trova entro 36 metri da te (se controlli più creature, puoi comandarle tutte o solo alcune nello stesso momento, impartendo lo stesso comando a ciascuna). Decidi tu quale azione effettuerà la creatura e dove si muoverà durante il suo prossimo turno, oppure puoi impartire un comando generico, come quello di fare la guardia a una specifica stanza o corridoio. Se non impartisci comandi, le creature si limiteranno a difendersi dalle creature ostili. Una volta ricevuto un comando, la creatura continuerà a eseguirlo finche il compito sarà completo. La creatura è sotto il tuo controllo per 24 ore, dopodiché smetterà di rispondere ai comandi che gli impartisci. Per mantenere il controllo della creatura per altre 24 ore, devi lanciare questo incantesimo sulla creatura prima che l’attuale periodo di 24 ore abbia termine. Questo impiego dell’incantesimo riasserisce il tuo controllo su di un massimo di tre creature che hai animato con questo incantesimo, anziché animarne di nuove.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/creare-non-morti/","classes":["chierico","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('creare-o-distruggere-acqua', 'creare-o-distruggere-acqua', 'Creare o Distruggere Acqua', 1, 'Trasmutazione', '1 azione', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/creare-o-distruggere-acqua/', '["chierico","druido"]', '{"name":"Creare o Distruggere Acqua","level":1,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un goccio d’acqua per creare acqua o qualche granello di sale per distruggerla)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, crei o distruggi ulteriori 40 litri d’acqua, o le dimensioni delcubo aumentano di 1,5 metri di spigolo, per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Crei o distruggi l’acqua.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/creare-o-distruggere-acqua/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('creazione', 'creazione', 'Creazione', 5, 'Illusione', '1 minuto', '9 metri', 'Speciale', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/creazione/', '["mago","stregone"]', '{"name":"Creazione","level":5,"school":"Illusione","casting_time":"1 minuto","range":"9 metri","components":"V, S, M (un minuscolo pezzo di materiale dello stesso tipo di oggetto che intendi creare)","duration":"Speciale","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, il cubo aumenta di 1,5 metri di spigolo per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Afferri pezzi di materia d’ombra dal Mondo delle Ombre per creare, a gittata, oggetti non viventi di materia vegetale: beni morbidi, corda, legno o qualcosa di simile. Puoi usare questo incantesimo anche per creare oggetti minerali come pietra, cristallo o metallo. L’oggetto creato non può essere più grosso di un cubo di 1,5 metri di spigolo, e l’oggetto deve essere di una forma e materiale che hai già visto in passato. La durata dipende dal materiale dell’oggetto. Se l’oggetto è composto da più materiali, usa la durata più breve.\nMateriale Durata Materia vegetale 1 giorno Pietra o cristallo 12 ore Metalli preziosi 1 ora Gemme 10 minuti Adamantio o mithral 1 minuto\nUsare qualsiasi materiale creato da questo incantesimo come componente materiale di un altro incantesimo farà fallire il nuovo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/creazione/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('crescita-di-spine', 'crescita-di-spine', 'Crescita di Spine', 2, 'Trasmutazione', '1 azione', '45 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/crescita-di-spine/', '["druido","ranger"]', '{"name":"Crescita di Spine","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"45 metri","components":"V, S, M (sette spine affilate o sette ramoscelli, ciascuno di esse appuntito ad un’estremità)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"2d4","scaling":null,"ritual":false,"description":"Il terreno in un raggio di 6 metri centrato su di un punto a gittata si contorce e genera spuntoni e spine molto acuminate. Per la durata, l’area diventa terreno difficile. Quando una creatura entra o si muove all’interno dell’area, subisce 2d4 danni perforanti per ogni 1,5 metri percorsi.\nLa trasformazione del terreno è talmente ben camuffata da sembrare naturale. Qualsiasi creatura che non abbia visto l’area al momento del lancio dell’incantesimo deve effettuare una prova di Saggezza (Percezione) contro la CD del tiro salvezza dell’incantesimo, per riconoscere il pericolo rappresentato dal terreno prima di entrarvi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/crescita-di-spine/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('crescita-vegetale', 'crescita-vegetale', 'Crescita Vegetale', 3, 'Trasmutazione', '1 azione o 8 ore', '45 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/crescita-vegetale/', '["bardo","druido","ranger"]', '{"name":"Crescita Vegetale","level":3,"school":"Trasmutazione","casting_time":"1 azione o 8 ore","range":"45 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo incanala vitalità nei vegetali entro una specifica area. Esistono due usi possibili per questo incantesimo, che conferiscono benefici immediati o a lungo termine. Se lanci questo incantesimo impiegando 1 azione, scegli un punto a gittata. Tutte i vegetali normali in un raggio di 30 metri centrato su quel punto diventano densi e folti. Una creatura che attraversa l’area quadruplica il costo del suo movimento. Puoi escludere dai suoi effetti una o più aree di qualsiasi dimensione all’interno dell’area dell’incantesimo.\nSe lanci questo incantesimo nel corso di 8 ore, nutri la terra. Tutti i vegetali in un raggio di 750 metri centrato su di un punto a gittata diventano super produttivi per 1 anno. I vegetali producono il doppio del normale ammontare di cibo al momento del raccolto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/crescita-vegetale/","classes":["bardo","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('cura-ferite', 'cura-ferite', 'Cura Ferite', 1, 'Invocazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/cura-ferite/', '["bardo","chierico","druido","paladino","ranger"]', '{"name":"Cura Ferite","level":1,"school":"Invocazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, la cura aumenta di 1d8 per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Una creatura a contatto con te recupera un numero di punti ferita uguale a 1d8 + il tuo modificatore di caratteristica da incantatore. Questo incantesimo non ha effetto su non morti e costrutti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/cura-ferite/","classes":["bardo","chierico","druido","paladino","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('cura-ferite-di-massa', 'cura-ferite-di-massa', 'Cura Ferite di Massa', 5, 'Invocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/cura-ferite-di-massa/', '["bardo","chierico","druido"]', '{"name":"Cura Ferite di Massa","level":5,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, la cura aumenta di 1d8 per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Un’onda di energia guaritrice parte da un punto a gittata, scelto da te. Scegli fino a sei creatura in una sfera di 9 metri di raggio centrata su quel punto. Ogni bersaglio recupera punti ferita uguali a 3d8 + il tuo modificatore di caratteristica da incantatore. Questo incantesimo non ha effetto su non morti o costrutti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/cura-ferite-di-massa/","classes":["bardo","chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('danza-irresistibile', 'danza-irresistibile', 'Danza Irresistibile', 8, 'Ammaliamento', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/danza-irresistibile/', '["bardo","mago"]', '{"name":"Danza Irresistibile","level":8,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scegli una creatura a gittata e che puoi vedere. Il bersaglio comincia un comico balletto sul posto: agitando le gambe, battendo i piedi e saltellando per la durata. Le creature che non possono essere affascinate sono immuni a questo incantesimo. Una creatura che balla deve usare tutto il suo movimento per ballare senza lasciare il suo spazio e ha svantaggio ai tiri salvezza su Destrezza e i tiri per colpire. Mentre il bersaglio è soggetto a questo incantesimo, le altre creature hanno vantaggio ai tiri per colpire contro di lui. Con un’azione, una creatura che balla effettua un tiro salvezza su Saggezza per recuperare il controllo di se stessa. Se lo supera, l’incantesimo ha fine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/danza-irresistibile/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dardo-di-fuoco', 'dardo-di-fuoco', 'Dardo di Fuoco', 0, 'Invocazione', '1 azione', '36 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dardo-di-fuoco/', '["mago","stregone"]', '{"name":"Dardo di Fuoco","level":0,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1d10","scaling":null,"ritual":false,"description":"Scagli una scintilla infuocata a una creatura od oggetto a gittata. Effettua un attacco a distanza con incantesimo contro il bersaglio. Se colpisci, il bersaglio subisce 1d10 danni da fuoco. Un oggetto infiammabile colpito da questo incantesimo prende fuoco, se non è indossato o trasportato. Il danno dell’incantesimo aumenta di 1d10 quando raggiungi il 5° livello (2d10), 11° livello (3d10) e 17° livello (4d10).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dardo-di-fuoco/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dardo-incantato', 'dardo-incantato', 'Dardo Incantato', 1, 'Invocazione', '1 azione', '36 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dardo-incantato/', '["mago","stregone","warlock"]', '{"name":"Dardo Incantato","level":1,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1d4 + 1","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, l’incantesimo crea un dardo aggiuntivo per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Crei tre dardi luminosi di forza magica. Ciascun dardo colpisce una creatura a gittata che puoi vedere, scelta da te. Un dardo infligge 1d4 + 1 danni da forza al suo bersaglio. I dardi colpiscono tutti simultaneamente, e li puoi dirigere perché colpiscano una o più creature.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dardo-incantato/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dardo-tracciante', 'dardo-tracciante', 'Dardo Tracciante', 1, 'Invocazione', '1 azione', '36 metri', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dardo-tracciante/', '["chierico"]', '{"name":"Dardo Tracciante","level":1,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":true,"damage":"4d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, il danno aumenta di 1d6 per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Un lampo di luce viaggia verso una creatura a gittata, scelta da te. Effettua un attacco a distanza con incantesimo contro il bersaglio. Se colpisci, il bersaglio subisce 4d6 danni radianti, e il prossimo tiro per colpire effettuato contro di lui prima del termine del tuo prossimo turno ha vantaggio, grazie alla mistica luce fioca che continuerà a brillare intorno al bersaglio fino ad allora.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dardo-tracciante/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('deflagrazione-occulta', 'deflagrazione-occulta', 'Deflagrazione Occulta', 0, 'Invocazione', '1 azione', '36 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/deflagrazione-occulta/', '["warlock"]', '{"name":"Deflagrazione Occulta","level":0,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":true,"damage":"1d10","scaling":null,"ritual":false,"description":"Un fascio di energia crepitante si dirige verso una creatura a gittata. Effettua un attacco a distanza con incantesimo contro il bersaglio. Se colpisci, il bersaglio subisce 1d10 danni da forza. Quando raggiungi i livelli più elevati, l’incantesimo crea più fasci di energia: due fasci di energia al 5° livello, tre all’11° livello e quattro al 17° livello. Puoi dirigere questi fasci di energia contro lo stesso bersaglio o dividerli tra più bersagli. Effettua un tiro per colpire separato per ogni fascio di energia.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/deflagrazione-occulta/","classes":["warlock"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('desiderio', 'desiderio', 'Desiderio', 9, 'Evocazione', '1 azione', 'Incantatore', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/desiderio/', '["mago","stregone"]', '{"name":"Desiderio","level":9,"school":"Evocazione","casting_time":"1 azione","range":"Incantatore","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1d10","scaling":null,"ritual":false,"description":"Desiderio è il più potente incantesimo che una creatura mortale possa lanciare. Semplicemente parlando ad alta voce, puoi modificare le stesse fondamenta della realtà a seconda dei tuoi bisogni. L’uso basilare di questo incantesimo è quello di riprodurre l’effetto di qualsiasi altro incantesimo di 8° livello o più basso. Non devi soddisfare nessuno dei requisiti dell’incantesimo, comprese le componenti materiali costose. L’incantesimo ha semplicemente effetto. In alternativa, puoi creare uno dei seguenti effetti a tua scelta:\nCrei un oggetto del valore massimo di 25.000 mo,che non sia un oggetto magico. L’oggetto non può avere dimensioni superiori ai 90 metri in qualsiasi dimensione, e compare in uno spazio non occupato sul terreno. Permetti fino a venti creature che puoi vedere di recuperare tutti i punti ferita, e termini tutti gli effetti su di loro descritti dall’incantesimo ristorare superiore. Conferisci a un massimo di dieci creature che puoi vedere la resistenza a un tipo di danno a tua scelta. Conferisci a un massimo di dieci creature che puoi vedere l’immunità a un singolo incantesimo o altro effetto magico per 8 ore. Per esempio, potresti rendere te e tutti tuoi compagni immuni all’attacco risucchia vita del lich. Annulli un qualsiasi evento recente obbligando a ritirare qualsiasi tiro effettuato nell’ultimo round (compreso il tuo ultimo turno). La realtà si rimodella per assecondare il nuovo risultato. Puoi far sì che il nuovo tiro abbia vantaggio o svantaggio, e puoi scegliere se usare il tiro originale o il nuovo tiro.\nPotresti anche riuscire a ottenere altro, oltre gli obiettivi negli esempi di cui sopra. Definisci i tuoi desideri quanto più possibile al GM. Il GM ha grande spazio di manovra nel decidere cosa accada in questi casi; maggiore il desiderio, più grosse le probabilità che qualcosa vada storto. L’incantesimo potrebbe semplicemente fallire, l’effetto desiderato manifestarsi solo in parte, oppure potresti subire delle conseguenze impreviste, in base a come hai proferito il desiderio.Lo stress del lanciare questo incantesimo per creare qualsiasi effetto che non sia riprodurre un altro incantesimo ti indebolisce. Dopo averne retto lo stress, ogni volta che lancerai un incantesimo, fino a che non avrai terminato un riposo lungo, subirai 1d10 danni necrotici per livello dell’incantesimo. Questo danno non può essere ridotto o diminuito in alcun modo. Inoltre, la tua Forza scende a 3, se non è già a 3 o meno, per 2d4 giorni. Per ciascun giorno che trascorri a riposare e non svolgere altro che un’attività leggera, il tuo tempo di recupero rimanente diminuisce di 2 giorni. Infine, c’è una probabilità del 33 percento che tu non sia mai più in grado di lanciare desiderio a causa dello stress sofferto per il lancio dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/desiderio/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('destriero-fantomatico', 'destriero-fantomatico', 'Destriero Fantomatico', 3, 'Illusione', '1 minuto', '9 metri', '1 ora', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/destriero-fantomatico/', '["mago"]', '{"name":"Destriero Fantomatico","level":3,"school":"Illusione","casting_time":"1 minuto","range":"9 metri","components":"V, S","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Una creatura quasi reale simile a un cavallo di taglia Grande, appare sul terreno in uno spazio non occupato di tua scelta e a gittata. Decidi tu l’aspetto della creatura, e questa compare equipaggiata di sella, morso e briglia. Qualsiasi equipaggiamento creato dall’incantesimo svanisce in una nuvola di fumo se viene portato a più di 3 metri di distanza dal destriero. Per la durata, tu o una creatura di tua scelta potete cavalcare il destriero. La creatura usa le statistiche del cavallo da corsa, eccetto che ha velocità 30 metri e può percorrere 15 chilometri in un’ora, o 20 chilometri ad andatura veloce. Quando l’incantesimo termina, il destriero inizia gradualmente a svanire, dando al cavallerizzo 1 minuto per smontare di sella. L’incantesimo termina se usi un’azione per interromperlo o se il destriero subisce danni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/destriero-fantomatico/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('disco-fluttuante', 'disco-fluttuante', 'Disco Fluttuante', 1, 'Evocazione', '1 azione', '9 metri', '1 ora', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/disco-fluttuante/', '["mago"]', '{"name":"Disco Fluttuante","level":1,"school":"Evocazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (una goccia di mercurio)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Questo incantesimo crea un piano di forza orizzontale, perfettamente circolare, di 1 metro di diametro e 2,5 centimetri di spessore che fluttua a 1 metro da terra, in uno spazio non occupato di tua scelta a gittata e che puoi vedere. Il disco rimane attivo per la durata, e può sostenere 250 chili. Se gli viene poggiato sopra un peso superiore, l’incantesimo termina e tutto quello che vi si trova sopra cade a terra. Finché ti trovi entro 6 metri da esso, il disco è immobile. Se ti muovi più di 6 metri lontano da esso, il disco ti segue in modo da rimanere sempre a 6 metri da te. Può muoversi attraverso terreno disomogeneo, su e giù per le scale, pendenze e simili, ma non può superare cambi di altitudine di 3 o più metri. Per esempio, il disco non può attraversare un fossato profondo 3 metri, né potrebbe lasciare il fossato se fosse creato in fondo a esso. Se ti allontani più di 30 metri dal disco (di solito perché non riesce ad aggirare un ostacolo nel seguirti), l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/disco-fluttuante/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('disintegrazione', 'disintegrazione', 'Disintegrazione', 6, 'Trasmutazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/disintegrazione/', '["stregone"]', '{"name":"Disintegrazione","level":6,"school":"Trasmutazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (una calamita e un pizzico di polvere)","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"10d6 + 40","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, il danno aumenta di 3d6 per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Un sottile raggio verde parte dal tuo dito puntato verso un bersaglio a gittata e che puoi vedere. Il bersaglio può essere una creatura, un oggetto o una creazione di forza magica, come un muro creato da muro di forza. Una creatura bersaglio di questo incantesimo deve effettuare un tiro salvezza su Destrezza. Il bersaglio subisce 10d6 + 40 danni da forza se fallisce il tiro salvezza. Se questo danno riduce il bersaglio a 0 punti ferita, questi è disintegrato. Una creatura disintegrata e tutto quello che indossa e trasporta, eccetto gli oggetti magici, viene ridotta a una pila di sottile polvere grigia. La creatura può essere riportata in vita solo tramite un incantesimo resurrezione pura o desiderio. Questo incantesimo disintegra automaticamente gli oggetti non magici o una creazione di forza magica di taglia Grande o più piccola. Se il bersaglio è un oggetto non magico o una creazione di forza di taglia Enorme o più grossa, questo incantesimo disintegra una porzione di essa pari a un cubo di 3 metri di spigolo. Gli oggetti magici ignorano questo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/disintegrazione/","classes":["stregone"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dissolvi-il-bene-e-il-male', 'dissolvi-il-bene-e-il-male', 'Dissolvi il Bene e il Male', 5, 'Abiurazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dissolvi-il-bene-e-il-male/', '["paladino"]', '{"name":"Dissolvi il Bene e il Male","level":5,"school":"Abiurazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (acqua sacra o argento e ferro in polvere)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un’energia luminosa ti circonda e ti protegge da fatati, non morti e creature originarie di luoghi al di là del Piano Materiale. Per la durata, i celestiali, elementali, fatati, immondi e non morti hanno svantaggio ai tiri per colpire contro di te. Puoi terminare l’incantesimo anticipatamente usando una delle seguenti funzioni speciali.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dissolvi-il-bene-e-il-male/","classes":["paladino"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dissolvi-magie', 'dissolvi-magie', 'Dissolvi Magie', 3, 'Abiurazione', '1 azione', '36 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dissolvi-magie/', '["bardo","chierico","druido","mago","paladino","stregone","warlock"]', '{"name":"Dissolvi Magie","level":3,"school":"Abiurazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, poni immediatamente fine agli effetti degli incantesimi sul bersaglio il cui livello dell’incantesimo è uguale o inferiore al livello dello slot incantesimo da te usato.","ritual":false,"description":"Scegli una creatura, oggetto o effetto magico a gittata. Qualsiasi incantesimo di 3° livello o più basso sul bersaglio ha fine. Per ogni incantesimo di 4° livello o più alto sul bersaglio, effettua una prova di caratteristica usando la tua caratteristica da incantatore. La CD della prova è uguale a 10 + il livello dell’incantesimo da dissolvere. Se superi la prova, l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dissolvi-magie/","classes":["bardo","chierico","druido","mago","paladino","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dito-della-morte', 'dito-della-morte', 'Dito della Morte', 7, 'Necromanzia', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dito-della-morte/', '["mago","stregone","warlock"]', '{"name":"Dito della Morte","level":7,"school":"Necromanzia","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"7d8 + 30","scaling":null,"ritual":false,"description":"Invii una scarica di energia negativa a una creatura a gittata e che puoi vedere, provocandole profondo dolore. Il bersaglio deve effettuare un tiro salvezza su Costituzione. Il bersaglio subisce 7d8 + 30 danni necrotici se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Un umanoide ucciso da questo incantesimo si rianima come zombi sotto il tuo comando permanente all’inizio del tuo prossimo turno, e seguirà i tuoi ordini verbali al meglio delle sue capacità.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dito-della-morte/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('divinazione', 'divinazione', 'Divinazione', 4, 'Divinazione', '1 azione', 'Incantatore', 'Istantanea', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/divinazione/', '["chierico"]', '{"name":"Divinazione","level":4,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (incenso e un’offerta sacrificale appropriata alla tua religione, il cui valore complessivo sia di 25 mo, che saranno consumati dall’incantesimo)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"La tua magia e un’offerta votiva ti mettono in comunicazione con un dio o il servitore di un dio. Gli puoi porre una singola domanda in merito a uno specifico obiettivo, evento o attività che debba verificarsi entro 7 giorni. Il GM dà una risposta veritiera. La replica potrebbe essere una breve frase, una rima criptica o un presagio. L’incantesimo non tiene conto di ogni possibile circostanza che possa modificare il risultato, come il lancio di ulteriori incantesimi o la perdita o l’arrivo di un alleato. Se lanci l’incantesimo due o più volte prima di aver terminato il tuo prossimo riposo lungo, c’è una probabilità cumulativa del 25% che per ogni lancio dopo il primo tu ottenga una lettura erronea. Il GM effettua questo tiro in segreto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/divinazione/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dominare-bestie', 'dominare-bestie', 'Dominare Bestie', 4, 'Ammaliamento', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dominare-bestie/', '["druido","stregone"]', '{"name":"Dominare Bestie","level":4,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello, la durata è concentrazione, massimo 10 minuti. Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello, la durata è concentrazione, massimo 1 ora. Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, la durata è concentrazione, massimo 8 ore.","ritual":false,"description":"Cerchi di affascinare una bestia a gittata che puoi vedere. Essa deve superare un tiro salvezza su Saggezza o restare affascinata per la durata, ricevendo vantaggio al tiro se tu o i tuoi alleati la state combattendo. Mentre la bestia è affascinata, finché voi due vi trovate sullo stesso piano di esistenza mantieni un collegamento telepatico con essa. Puoi usare questo collegamento telepatico per inviare comandi alla creatura mentre sei cosciente (non richiede un’azione), a cui essa obbedirà al suo meglio. Puoi specificare un corso d’azione semplice e generico, come “Attacca quella creatura”, “Corri laggiù”, o “Prendi quell’oggetto”. Se la creatura completa l’ordine e non riceve ulteriori indicazioni da te, si difenderà e preserverà al meglio delle sue capacità. Puoi impiegare la tua azione per assumere il totale e preciso controllo del bersaglio. Fino al termine del tuo prossimo turno, il bersaglio effettuerà solo le azioni decise da te, e non farà nulla che tu non gli permetta di fare. Durante questo periodo, puoi anche far usare una reazione al bersaglio, ma ciò richiede l’uso della tua reazione. Ogni volta che il bersaglio subisce danni, effettua un nuovo tiro salvezza su Saggezza contro l’incantesimo. Se supera il tiro salvezza, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dominare-bestie/","classes":["druido","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dominare-mostri', 'dominare-mostri', 'Dominare Mostri', 8, 'Ammaliamento', '1 azione', '18 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dominare-mostri/', '["bardo","mago","stregone","warlock"]', '{"name":"Dominare Mostri","level":8,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 9° livello, la durata è concentrazione, massimo 8 ore.","ritual":false,"description":"Cerchi di affascinare una creatura a gittata che puoi vedere. Essa deve superare un tiro salvezza su Saggezza o restare affascinata per la durata, ricevendo vantaggio al tiro se tu o i tuoi alleati la state combattendo. Mentre la creatura è affascinata, finché voi due vi trovate sullo stesso piano di esistenza mantieni un collegamento telepatico con essa. Puoi usare questo collegamento telepatico per inviare comandi alla creatura mentre sei cosciente (non richiede un’azione), a cui essa obbedirà al suo meglio. Puoi specificare un corso d’azione semplice e generico, come “Attacca quella creatura”, “Corri laggiù”, o “Prendi quell’oggetto”. Se la creatura completa l’ordine e non riceve ulteriori indicazioni da te, si difenderà e preserverà al meglio delle sue capacità. Puoi impiegare la tua azione per assumere il totale e preciso controllo del bersaglio. Fino al termine del tuo prossimo turno la creatura effettuerà solo le azioni decise da te, e non farà nulla che tu non le permetta di fare. Durante questo periodo, puoi anche far usare una reazione alla creatura, ma ciò richiede l’uso della tua reazione. Ogni volta che il bersaglio subisce danni, effettua un nuovo tiro salvezza su Saggezza contro l’incantesimo. Se supera il tiro salvezza, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dominare-mostri/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('dominare-persone', 'dominare-persone', 'Dominare Persone', 5, 'Ammaliamento', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/dominare-persone/', '["bardo","mago","stregone"]', '{"name":"Dominare Persone","level":5,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello, la durata è concentrazione, massimo 10 minuti. Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello, la durata è concentrazione, massimo 1 ora. Quando lanci questo incantesimo usando uno slot incantesimo di 8° livello o più alto, la durata è concentrazione, massimo 8 ore.","ritual":false,"description":"Cerchi di affascinare un umanoide a gittata che puoi vedere. Esso deve superare un tiro salvezza su Saggezza o restare affascinato per la durata, ricevendo vantaggio al tiro se tu o i tuoi alleati lo state combattendo. Mentre il bersaglio è affascinato, finché voi due vi trovate sullo stesso piano di esistenza mantieni un collegamento telepatico con esso. Puoi usare questo collegamento telepatico per inviare comandi al bersaglio mentre sei cosciente (non richiede un’azione), a cui esso obbedirà al suo meglio. Puoi specificare un corso d’azione semplice e generico, come “Attacca quella creatura”, “Corri laggiù”, o “Prendi quell’oggetto”. Se il bersaglio completa l’ordine e non riceve ulteriori indicazioni da te, si difenderà e preserverà al meglio delle sue capacità. Puoi impiegare la tua azione per assumere il totale e preciso controllo del bersaglio. Fino al termine del tuo prossimo turno, il bersaglio effettuerà solo le azioni decise da te, e non farà nulla che tu non gli permetta di fare. Durante questo periodo, puoi anche far usare una reazione al bersaglio, ma ciò richiede l’uso della tua reazione. Ogni volta che il bersaglio subisce danni, effettua un nuovo tiro salvezza su Saggezza contro l’incantesimo. Se supera il tiro salvezza, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/dominare-persone/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('eroismo', 'eroismo', 'Eroismo', 1, 'Ammaliamento', '1 azione', 'Contatto', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/eroismo/', '["bardo","paladino"]', '{"name":"Eroismo","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una creatura consenziente con cui sei in contatto viene infusa di coraggio. Fino al termine dell’incantesimo, la creatura è immune all’essere spaventata e, all’inizio di ciascun suo turno, ottiene punti ferita temporanei pari al tuo modificatore di caratteristica da incantatore. Quando l’incantesimo ha termine, il bersaglio perde tutti i punti ferita temporanei rimanenti derivati da questo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/eroismo/","classes":["bardo","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('esilio', 'esilio', 'Esilio', 4, 'Abiurazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/esilio/', '["chierico","mago","paladino","stregone","warlock"]', '{"name":"Esilio","level":4,"school":"Abiurazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un oggetto disprezzato dal bersaglio)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello o più alto, puoi prendere come bersaglio un’ulteriore creatura per ognislot incantesimo sopra il 4°.","ritual":false,"description":"Cerchi di spedire una creatura a gittata e che puoi vedere in un altro piano di esistenza. Il bersaglio deve superare un tiro salvezza su Carisma o venire esiliato. Se il bersaglio è natio del piano di esistenza in cui ti trovi, esili il bersaglio in un semipiano innocuo. Mentre è lì, il bersaglio è inabile. Il bersaglio rimane lì fino al termine dell’incantesimo, quando riapparirà nello spazio che aveva lasciato o nello spazio non occupato più vicino, se il suo spazio originale adesso è occupato. Se il bersaglio è natio di un diverso piano di esistenza da quello in cui ti trovi, il bersaglio svanisce emettendo un lieve scoppio, tornando al suo piano natio. Se l’incantesimo termina prima che sia trascorso 1 minuto, il bersaglio riappare nello spazio che aveva lasciato o nello spazio non occupato più vicino, se il suo spazio originale è occupato.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/esilio/","classes":["chierico","mago","paladino","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('esplosione-solare', 'esplosione-solare', 'Esplosione Solare', 8, 'Invocazione', '1 azione', '45 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/esplosione-solare/', '["druido","mago","stregone"]', '{"name":"Esplosione Solare","level":8,"school":"Invocazione","casting_time":"1 azione","range":"45 metri","components":"V, S, M (fuoco e un pezzo di pietra di sole)","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"12d6","scaling":null,"ritual":false,"description":"Un’intensa luce solare illumina in un raggio di 18 metri centrato su di un punto a gittata, scelto da te. Tutte le creature all’interno della luce devono effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza, una creatura subisce 12d6 danni radianti e resta accecata per 1 minuto. Se lo supera, subisce la metà dei danni e non resta accecata dall’incantesimo. Non morti e melme hanno svantaggio a questo tiro salvezza. Una creatura accecata da questo incantesimo effettua un altro tiro salvezza su Costituzione alla fine di ciascun suo turno. Se supera il tiro salvezza, non è più accecata. Nella sua area, questo incantesimo dissolve qualsiasi oscurità generata da un incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/esplosione-solare/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('estasiare', 'estasiare', 'Estasiare', 2, 'Ammaliamento', '1 azione', 'Incantatore', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/estasiare/', '["bardo","warlock"]', '{"name":"Estasiare","level":2,"school":"Ammaliamento","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"1 minuto","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Intessi una serie di parole svianti, facendo sì che delle creature di tua scelta entro la gittata, che puoi vedere e possano sentirti, effettuino un tiro salvezza su Saggezza. Qualsiasi creatura che non può restare affascinata supera il tiro salvezza automaticamente, e se tu o i tuoi compagni state combattendo una creatura, questa ha vantaggio al tiro salvezza. Se fallisce il tiro salvezza, il bersaglio ha svantaggio sulle prove di Saggezza (Percezione) effettuate per percepire una qualsiasi creatura diversa da te fino al termine dell’incantesimo o finché il bersaglio non può più sentirti. L’incantesimo termina se sei reso inabile o non puoi più parlare.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/estasiare/","classes":["bardo","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('evoca-animali', 'evoca-animali', 'Evoca Animali', 3, 'Evocazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/evoca-animali/', '["druido","ranger"]', '{"name":"Evoca Animali","level":3,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando certi slot incantesimo di livello più alto, scegli una delle opzioni di cui sopra, ma apparirà un numero maggiore di creature: il doppio con uno slot di 5° livello, il triplo con uno slot di 7° livello, e il quadruplo con uno slot di 9° livello.","ritual":false,"description":"Evochi spiriti fatati che assumono l’aspetto di bestie e compaiono in spazi non occupati a gittata e che puoi vedere. Scegli una delle seguenti opzioni per determinare ciò che appare:\nUna bestia di grado di sfida 2 o inferiore Due bestie di grado di sfida 1 o inferiore Quattro bestie di grado di sfida 1/2 o inferiore Otto bestie di grado di sfida 1/4 o inferiore\nOgni bestia è considerata anche un fatato, e sparisce quando scende a 0 punti ferita o quando l’incantesimo termina. Le creature evocate sono amichevoli verso di te e i tuoi compagni. Tirare l’iniziativa per le creature evocate come gruppo, che agisce durante il proprio turno. Esse obbediscono a qualsiasi comando verbale che gli viene dato (senza bisogno che tu compia azioni). Se non dai comandi alle bestie, si difenderanno dalle creature ostili, ma non compiranno altre azioni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/evoca-animali/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('evoca-celestiale', 'evoca-celestiale', 'Evoca Celestiale', 7, 'Evocazione', '1 minuto', '27 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/evoca-celestiale/', '["chierico"]', '{"name":"Evoca Celestiale","level":7,"school":"Evocazione","casting_time":"1 minuto","range":"27 metri","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 9° livello, evochi un celestiale di grado di sfida 5 o inferiore.","ritual":false,"description":"Evochi un celestiale di grado sfida 4 o inferiore, che appare in uno spazio non occupato a gittata e che puoi vedere. Il celestiale sparisce quando scende a 0 punti ferita o l’incantesimo termina. Il celestiale è amichevole verso di te e i tuoi compagni per la durata dell’incantesimo. Tira l’iniziativa per il celestiale, che agisce durante il proprio turno. Obbedisce a qualsiasi comando verbale che gli viene dato (senza bisogno che tu compia azioni), purché non violi il suo allineamento. Se non dai comandi al celestiale, si difenderà dalle creature ostili, ma non compirà altre azioni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/evoca-celestiale/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('evoca-creature-boschive', 'evoca-creature-boschive', 'Evoca Creature Boschive', 4, 'Evocazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/evoca-creature-boschive/', '["druido","ranger"]', '{"name":"Evoca Creature Boschive","level":4,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (una bacca di agrifoglio per creatura convocata)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando certi slot incantesimo di livello più alto, scegli una delle opzioni di cui sopra, ma apparirà un numero maggiore di creature: il doppio con uno slot di 6° livello e il triplo con uno slot di 8° livello.","ritual":false,"description":"Evochi spiriti fatati che compaiono in spazi non occupati a gittata e che puoi vedere. Scegli una delle seguenti opzioni per determinare ciò che appare:\nUn fatato di grado di sfida 2 o inferiore Due fatati di grado di sfida 1 o inferiore Quattro fatati di grado di sfida 1/2 o inferiore Otto fatati di grado di sfida 1/4 o inferiore\nUna creatura evocata sparisce quando scende a 0 punti ferita o quando l’incantesimo termina. Le creature evocate sono amichevoli verso di te e i tuoi compagni. Tirare l’iniziativa per le creature evocate come gruppo, che agisce durante il proprio turno. Esse obbediscono a qualsiasi comando verbale che gli viene dato (senza bisogno che tu compia azioni). Se non dai comandi ai fatati, si difenderanno dalle creature ostili, ma non compiranno altre azioni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/evoca-creature-boschive/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('evoca-elementale', 'evoca-elementale', 'Evoca Elementale', 5, 'Evocazione', '1 minuto', '27 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/evoca-elementale/', '["druido","mago"]', '{"name":"Evoca Elementale","level":5,"school":"Evocazione","casting_time":"1 minuto","range":"27 metri","components":"V, S, M (incenso bruciato per l’aria, argilla malleabile per la terra, zolfo e fosforo per il fuoco, o acqua e sabbia per l’acqua)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, il grado di sfida aumenta di 1 per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Evochi un servitore elementale. Scegli un’area a gittata composta di acqua, aria, fuoco o terra e che riempia un cubo di 3 metri di spigolo. Un elementale di grado di sfida 5 o minore appropriato all’area da te scelta compare in uno spazio non occupato entro 3 metri da essa. L’elementale sparisce quando scende a 0 punti ferita o l’incantesimo termina. L’elementale è amichevole verso di te e i tuoi compagni per la durata dell’incantesimo. Tira l’iniziativa per l’elementale, che agisce durante il proprio turno. Obbedisce a qualsiasi comando verbale che gli viene dato (senza bisogno che tu compia azioni). Se non dai comandi all’elementale, si difenderà dalle creature ostili, ma non compirà altre azioni. Se la tua concentrazione viene infranta, l’elementale non sparisce. Invece, perderai il controllo dell’elementale, che diventerà ostile verso di te e i tuoi compagni, e potrebbe attaccarvi. Un elementale fuori controllo non può essere congedato da te, e sparisce 1 ora dopo che lo hai convocato.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/evoca-elementale/","classes":["druido","mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('evoca-elementali-minori', 'evoca-elementali-minori', 'Evoca Elementali Minori', 4, 'Evocazione', '1 minuto', '27 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/evoca-elementali-minori/', '["druido","mago"]', '{"name":"Evoca Elementali Minori","level":4,"school":"Evocazione","casting_time":"1 minuto","range":"27 metri","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando certi slot incantesimo di livello più alto, scegli una delle opzioni di cui sopra, ma apparirà un numero maggiore di creature: il doppio con uno slot di 6° livello e il triplo con uno slot di 8° livello.","ritual":false,"description":"Evochi degli elementali che compariranno in spazi non occupati a gittata e che puoi vedere. Scegli una della seguenti opzioni per decidere cosa appare:\nUn elementale di grado di sfida 2 o meno Due elementali di grado di sfida 1 o meno Quattro elementali di grado di sfida 1/2 o meno Otto elementali di grado di sfida 1/4 o meno\nUn elementale evocato sparisce quando scende a 0 punti ferita o l’incantesimo termina. Un elementale evocato è amichevole verso di te e i tuoi compagni. Tirare l’iniziativa per gli elementali evocati come gruppo, che agisce durante il proprio turno. Essi obbediscono a qualsiasi comando verbale che gli viene dato (senza bisogno che tu compia azioni). Se non dai comandi agli elementali, si difenderanno dalle creature ostili, ma non compiranno altre azioni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/evoca-elementali-minori/","classes":["druido","mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('evoca-folletto', 'evoca-folletto', 'Evoca Folletto', 6, 'Evocazione', '1 minuto', '27 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/evoca-folletto/', '["druido","warlock"]', '{"name":"Evoca Folletto","level":6,"school":"Evocazione","casting_time":"1 minuto","range":"27 metri","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, il grado di sfida aumenta di 1 per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Evochi uno spirito fatato di grado di sfida 6 o inferiore, o uno spirito fatato che assuma la forma di una bestia di grado di sfida 6 o inferiore. Esso compare in uno spazio non occupato a gittata e che puoi vedere. La creatura fatata sparisce quando scende a 0 punti ferita o quando l’incantesimo termina. La creatura fatata è amichevole verso di te e i tuoi compagni. Tirare l’iniziativa per la creatura fatata, che agisce durante i propri turni. Essa obbedisce a qualsiasi comando verbale che gli viene dato (senza bisogno che tu compia azioni), purché non violi il suo allineamento. Se non dai comandi, si difenderà dalle creature ostili, ma non compirà altre azioni. Se la tua concentrazione viene infranta, la creatura fatata non sparisce. Invece, perderai il controllo della creatura fatata, che diventerà ostile verso di te e i tuoi compagni, e potrebbe attaccarvi. Una creatura fatata fuori controllo non può essere congedata da te, e sparisce 1 ora dopo che l’hai evocata.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/evoca-folletto/","classes":["druido","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('evocazioni-istantanee', 'evocazioni-istantanee', 'Evocazioni Istantanee', 6, 'Evocazione', '1 minuto', 'Contatto', 'Fino a che dissolto', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/evocazioni-istantanee/', '["mago"]', '{"name":"Evocazioni Istantanee","level":6,"school":"Evocazione","casting_time":"1 minuto","range":"Contatto","components":"V, S, M (uno zaffiro del valore di 1.000 mo)","duration":"Fino a che dissolto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Entri a contatto con un oggetto del peso di 5 chili o meno e la cui dimensione più grossa non superi i 180 centimetri. L’incantesimo lascia un marchio sulla superficie dell’oggetto e ne incide invisibilmente il nome sullo zaffiro usato come componente materiale. Ogni volta che lanci questo incantesimo, devi usare uno zaffiro diverso. In qualsiasi momento successivo, puoi usare la tua azione per pronunciare il nome dell’oggetto e frantumare lo zaffiro. L’oggetto appare istantaneamente nella tua mano quale che sia la distanza fisica o planare che vi separa, e l’incantesimo ha termine. Se un’altra creatura sta impugnando o trasportando l’oggetto, frantumare lo zaffiro non trasporterà l’oggetto da te, ma invece apprenderai chi sia la creatura che ne è in possesso e indicativamente dove si trovi in questo momento. Dissolvi magie, o un effetto simile applicato con successo allo zaffiro, termina l’effetto dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/evocazioni-istantanee/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fabbricare', 'fabbricare', 'Fabbricare', 4, 'Trasmutazione', '10 minuti', '36 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fabbricare/', '["mago"]', '{"name":"Fabbricare","level":4,"school":"Trasmutazione","casting_time":"10 minuti","range":"36 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Converti le materie prime in prodotti finiti dello stesso materiale. Per esempio, puoi fabbricare un ponte di legno da un cumulo di alberi, una corda da un mucchio di canapa, e abiti dal lino o la lana. Scegli le materie prima che puoi vedere a gittata. Puoi fabbricare un oggetto di taglia Grande o inferiore (contenuto in un cubo di 3 metri di spigolo, o otto cubi connessi di 1,5 metri di spigolo) data una sufficiente quantità di materie prime. Se stai lavorando con il metallo, la pietra o altre sostanze minerali, l’oggetto fabbricato non può essere più grande di taglia Media (contenuto in un singolo cubo di 1,5 metri di spigolo). La qualità degli oggetti creati da questo incantesimo è commisurata alla qualità delle materie prime. Tramite questo incantesimo non si possono creare o trasmutare creature od oggetti magici. Inoltre non puoi usarlo per creare oggetti che normalmente richiedono un alto livello di lavorazione, come i gioielli, le armi, il vetro o le armature, a meno che tu non abbia la competenza con il tipo di strumenti da artigiano utilizzati per costruire questi oggetti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fabbricare/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('faro-di-speranza', 'faro-di-speranza', 'Faro di Speranza', 3, 'Abiurazione', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/faro-di-speranza/', '["chierico"]', '{"name":"Faro di Speranza","level":3,"school":"Abiurazione","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo conferisce speranza e vitalità. Scegli un qualsiasi numero di creature a gittata. Per la durata, ciascun bersaglio ha vantaggio ai tiri salvezza su Saggezza e ai tiri salvezza da morte, e da ogni cura ottiene il massimo numero di punti ferita possibili.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/faro-di-speranza/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fatale', 'fatale', 'Fatale', 9, 'Illusione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fatale/', '["mago"]', '{"name":"Fatale","level":9,"school":"Illusione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":"4d10","scaling":null,"ritual":false,"description":"Attingendo alle paure più intime di un gruppo di creature, crei delle creature illusorie nella loro mente, visibili solo a loro. Ogni creatura in una sfera di 9 metri di raggio centrata su di un punto a tua scelta nella gittata, deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, la creatura diventa spaventata per la durata. L’illusione affonda nelle paure più intime della creatura, manifestando i suoi incubi peggiori come una implacabile minaccia. Alla fine di ciascun turno della creatura spaventata, questa deve superare un tiro salvezza su Saggezza o subire 4d10 danni psichici. Se supera il tiro salvezza, per quella creatura l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fatale/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('favore-divino', 'favore-divino', 'Favore Divino', 1, 'Invocazione', '1 azione bonus', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/favore-divino/', '["paladino"]', '{"name":"Favore Divino","level":1,"school":"Invocazione","casting_time":"1 azione bonus","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"1d4","scaling":null,"ritual":false,"description":"Le tue preghiere potenziano te e la tua arma. Fino al termine dell’incantesimo, quando colpisce, la tua arma infligge 1d4 danni radianti aggiuntivi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/favore-divino/","classes":["paladino"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('ferire', 'ferire', 'Ferire', 6, 'Necromanzia', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/ferire/', '["chierico"]', '{"name":"Ferire","level":6,"school":"Necromanzia","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"14d6","scaling":null,"ritual":false,"description":"Scateni una malattia virulenta su di una creatura a gittata che puoi vedere. Il bersaglio deve effettuare un tiro salvezza su Costituzione. Il bersaglio subisce 14d6 danni necrotici se fallisce il tiro salvezza, o la metà di questi danni se lo supera. il danno non può ridurre i punti ferita del bersaglio sotto l’1. Se il bersaglio fallisce il tiro salvezza, i suoi punti ferita massimi sono ridotti per 1 ora di un ammontare uguale al danno necrotico subito. Qualsiasi effetto che rimuova una malattia permette ai punti ferita massimi del personaggio di poter tornare al valore normale prima che trascorra quel tempo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/ferire/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fermare-il-tempo', 'fermare-il-tempo', 'Fermare il Tempo', 9, 'Trasmutazione', '1 azione', 'Incantatore', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fermare-il-tempo/', '["mago","stregone"]', '{"name":"Fermare il Tempo","level":9,"school":"Trasmutazione","casting_time":"1 azione","range":"Incantatore","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fermi brevemente il flusso del tempo per tutti, tranne che per te. Il tempo non scorre per le altre creature, mentre tu effettui 1d4 + 1 turni di fila, durante i quali puoi effettuare azioni e muoverti come sempre. Questo incantesimo termina se una delle azioni che usi durante questo periodo, o qualsiasi effetto che crei durante questo periodo, ha effetto su di una creatura diversa da te o su di un oggetto indossato o trasportato da qualcuno che non sia tu. Inoltre, l’incantesimo termina se ti muovi in un posto lontano più di 300 metri da quello in cui lo hai lanciato.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fermare-il-tempo/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fiamma-perenne', 'fiamma-perenne', 'Fiamma Perenne', 2, 'Invocazione', '1 azione', 'Contatto', 'Fino a che dissolto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fiamma-perenne/', '["chierico","mago"]', '{"name":"Fiamma Perenne","level":2,"school":"Invocazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (polvere di rubino del valore di 50 mo, che l’incantesimo consuma)","duration":"Fino a che dissolto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una luminosità simile a quella prodotta da una fiaccola si sprigiona da un oggetto con cui sei in contatto. L’effetto sembra quello di una normale fiamma, ma non produce calore né necessita ossigeno. Una fiamma perpetua può essere celata o nascosta ma non può essere smorzata né spenta.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fiamma-perenne/","classes":["chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fiamma-sacra', 'fiamma-sacra', 'Fiamma Sacra', 0, 'Invocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fiamma-sacra/', '["chierico"]', '{"name":"Fiamma Sacra","level":0,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"1d8","scaling":null,"ritual":false,"description":"Una luminosità simile a quella prodotta da una fiaccola discende su di una creatura a gittata che puoi vedere. Il bersaglio deve superare un tiro salvezza su Destrezza o subire 1d8 danni radianti. Il bersaglio non riceve il beneficio della copertura per questo tiro salvezza. Il danno dell’incantesimo aumenta di 1d8 quando raggiungi il 5° livello (2d8), l’11° livello (3d8) e il 17° livello (4d8).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fiamma-sacra/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fiotto-acido', 'fiotto-acido', 'Fiotto Acido', 0, 'Evocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fiotto-acido/', '["mago","stregone"]', '{"name":"Fiotto Acido","level":0,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"1d6","scaling":null,"ritual":false,"description":"Scagli una bolla di acido. Scegli una creatura a gittata o due creature a gittata che siano entro 1,5 metri l’una dall’altra. Il bersaglio deve superare un tiro salvezza su Destrezza o subire 1d6 danni da acido. Il danno dell’incantesimo aumenta di 1d6 quando raggiungi il 5° livello (2d6), 11° livello (3d6) e 17° livello (4d6).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fiotto-acido/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('folata-di-vento', 'folata-di-vento', 'Folata di Vento', 2, 'Invocazione', '1 azione', 'Incantatore (linea di 18 metri)', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/folata-di-vento/', '["druido","mago","stregone"]', '{"name":"Folata di Vento","level":2,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore (linea di 18 metri)","components":"V, S, M (un seme di legume)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Forza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una linea di forte vento lunga 18 metri e larga 3 metri esplode partendo da te in una direzione a tua scelta, per la durata dell’incantesimo. Ogni creatura che inizia il suo turno dentro la linea deve superare un tiro salvezza su Forza o venire spinta lontano da te di 4,5 metri, seguendo la direzione della linea. Qualsiasi creatura sulla linea deve spendere il doppio del movimento per avvicinarsi a te.\nLa folata disperde gas o vapori, estingue candele, torce e simili fiamme non protette nell’area. Le fiamme protette, come quelle della lanterne, si agitano, e hanno una probabilità del 50% di estinguersi.\nCome azione bonus durante ciascun tuo turno, prima del termine dell’incantesimo, puoi cambiare la direzione in cui la linea si proietta da te.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/folata-di-vento/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fondersi-nella-pietra', 'fondersi-nella-pietra', 'Fondersi nella Pietra', 3, 'Trasmutazione', '1 azione', 'Contatto', '8 ore', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fondersi-nella-pietra/', '["chierico","druido"]', '{"name":"Fondersi nella Pietra","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"6d6","scaling":null,"ritual":true,"description":"Entri in un oggetto o superficie di pietra grossi abbastanza da contenere tutto il tuo corpo, fondendoti con la pietra assieme a tutto l’equipaggiamento che trasporti per la durata. Usando il tuo movimento, entri nella pietra in un punto con cui sei in contatto. Non resta nulla della tua presenza che rimanga visibile o altrimenti possa essere individuato da sensi non magici. Mentre sei fuso con la pietra, non puoi vedere ciò cheavviene all’esterno, e qualsiasi prova di Saggezza (Percezione) che effettui per ascoltare i suoni prodotti fuori da essa è fatta con svantaggio. Resti consapevole del passare del tempo e puoi lanciare incantesimi su di te mentre sei fuso con la pietra. Puoi usare il tuo movimento per lasciare la pietra e ricomparire nel punto in cui vi sei entrato, terminando così l’incantesimo. Altrimenti non puoi muoverti. I danni minori alla pietra non ti danneggiano, ma la sua parziale distruzione o cambio di forma (di modo che tu non vi entri più) ti espellono da essa e ti infliggono 6d6 danni contundenti. La completa distruzione della pietra (o la sua trasmutazione in un’altra sostanza) ti fa espellere e ti infligge 50 danni contundenti. Se vieni espulso, cadi prono in uno spazio non occupato, nel punto più vicino a quello in cui sei entrato nella pietra.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fondersi-nella-pietra/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('forma-eterea', 'forma-eterea', 'Forma Eterea', 7, 'Trasmutazione', '1 azione', 'Incantatore', 'Massimo 8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/forma-eterea/', '["bardo","mago","stregone","warlock"]', '{"name":"Forma Eterea","level":7,"school":"Trasmutazione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"Massimo 8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 8° livello o più alto, puoi prendere come bersaglio fino a tre creature consenzienti (te compreso) per ogni livello dello slot sopra il 7°. Quando lanci l’incantesimo, le creature devono trovarsi entro 3 metri da te.","ritual":false,"description":"Entri nelle regioni di confine del Piano Etereo, nell’area che si sovrappone al tuo piano attuale. Resti sul Confine Etereo per la durata o finché non usi un’azione per interrompere l’incantesimo. Se ti muovi verso l’alto o il basso, il costo del movimento è raddoppiato. Puoi vedere e udire il piano da cui provieni, ma tutto quello che si trova lì ti appare grigio, e non puoi vedere a più di 18 metri di distanza. Mentre sei sul Piano Etereo, può interagire solo con altre creature su quel piano. Le creature che non sono sul Piano Etereo non ti possono percepire né interagire con te, a meno che una capacità speciale o la magia gli fornisca la possibilità di farlo. Ignori tutti gli oggetti e gli effetti che non sono sul Piano Etereo, potendo così attraversare gli oggetti che percepisci sul piano da cui provieni. Quando l’incantesimo termina, ritorni immediatamente al piano da cui provieni nel punto che occupi attualmente. Se quando accade occupi lo stesso spazio di un oggetto solido o di una creatura, vieni immediatamente spostato nel più vicino spazio non occupato che puoi occupare e subisci 6 danni da forza per ogni metro di cui vieni spostato (o sua frazione). Questo incantesimo non ha effetto se lo esegui mentre sei già nel Piano Etereo o su di un piano che non vi confina, come uno dei Piani Esterni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/forma-eterea/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('forma-gassosa', 'forma-gassosa', 'Forma Gassosa', 3, 'Trasmutazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/forma-gassosa/', '["mago","stregone","warlock"]', '{"name":"Forma Gassosa","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un pezzo di garza e un filo di fumo)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Trasformi una creatura consenziente con cui sei in contatto, insieme a tutto ciò che sta indossando e trasportando, in una nube vaporosa per la durata. L’incantesimo termina se la creatura scende a 0 punti ferita. Le creature incorporee ignorano questo effetto. Mentre è in questa forma, l’unico metodo di movimento del bersaglio è una velocità di volo 3 metri. Il bersaglio può entrare e occupare lo spazio di un’altra creatura. Il bersaglio ha resistenza ai danni non magici, e ha vantaggio ai tiri salvezza su Forza, Destrezza e Costituzione. Il bersaglio può attraversare piccoli buchi, strettoie, e anche semplici fori, sebbene consideri i liquidi come superfici solide. Il bersaglio non può cadere e resta fluttuante nell’aria anche se stordito o altrimenti reso inabile. Mentre è nella forma di una nube vaporosa, il bersaglio non può parlare né manipolare oggetti, e qualsiasi oggetto stesse indossando o trasportando non può essere gettato, usato o altrimenti impiegato. Il bersaglio non può attaccare né lanciare incantesimi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/forma-gassosa/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('forme-animali', 'forme-animali', 'Forme Animali', 8, 'Trasmutazione', '1 azione', '9 metri', 'Concentrazione, massimo 24 ore', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/forme-animali/', '["druido"]', '{"name":"Forme Animali","level":8,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"Concentrazione, massimo 24 ore","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Trasformi magicamente altre creature in bestie. Scegli un qualsiasi numero di creature consenzienti a gittata e che puoi vedere. Trasformi ciascun bersaglio nella forma di una bestia di taglia Grande o minore con un grado di sfida 4 o inferiore. Nei turni successivi, puoi usare la tua azione per trasformare le creature soggette in nuove forme. La trasformazione permane per ciascun bersaglio per la durata dell’incantesimo, o finché quel bersaglio scende a 0 punti ferita o muore. Puoi scegliere una forma diversa per ciascun bersaglio. Le statistiche di gioco del bersaglio sono rimpiazzate dalle statistiche della bestia scelta, a eccezione dell’allineamento e dei punteggi di Intelligenza, Saggezza e Carisma che restano quelli del bersaglio. Il bersaglio assume i punti ferita della sua nuova forma e, quando ritorna alla sua forma normale, ritorna al numero di punti ferita che aveva prima di trasformarsi. Se si ritrasforma perché è sceso a 0 punti ferita, il danno in eccesso viene applicato alla forma originale. Purché il danno in eccesso non riduca la forma normale della creatura a 0 punti ferita, essa non è priva di sensi. La creatura è limitata nelle azioni che può svolgere dalla natura della sua nuova forma, e non può parlare né lanciare incantesimi.\nL’equipaggiamento del bersaglio si fonde nella nuova forma. Il bersaglio non può attivare, impugnare o in altro modo beneficiare del suo equipaggiamento.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/forme-animali/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('frantumare', 'frantumare', 'Frantumare', 2, 'Invocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/frantumare/', '["bardo","mago","stregone","warlock"]', '{"name":"Frantumare","level":2,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un frammento di metallo)","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"3d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Un forte squillo, molto intenso, erutta da un punto a gittata di tua scelta. Ogni creatura in una sfera di 3 metri di raggio centrata su quel punto deve effettuare un tiro salvezza su Costituzione. Una creatura subisce 3d8 danni da tuono se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Una creatura composta di materiale inorganico, come pietra, cristallo o metallo, ha svantaggio sul tiro salvezza. Un oggetto non magico che non è indossato né trasportato subisce anch’esso danni se si trova nell’area dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/frantumare/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('freccia-acida', 'freccia-acida', 'Freccia Acida', 2, 'Invocazione', '1 azione', '27 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/freccia-acida/', '["mago"]', '{"name":"Freccia Acida","level":2,"school":"Invocazione","casting_time":"1 azione","range":"27 metri","components":"V, S, M (una foglia di rabarbaro in polvere e uno stomaco di pitone)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"4d4","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, il danno (sia iniziale che successivo) aumenta di 1d4 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Una freccia verde luminosa saetta verso un bersaglio a gittata ed esplode con uno spruzzo d’acido. Effettua un attacco a distanza con incantesimo contro il bersaglio. Se colpisci, il bersaglio subisce immediatamente 4d4 danni da acido e 2d4 danni da acido al termine del suo prossimo turno. Se manchi, la freccia spruzza il bersaglio di acido infliggendo la metà dei danni iniziali e non arrecando danni al termine del prossimo turno del bersaglio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/freccia-acida/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fulmine', 'fulmine', 'Fulmine', 3, 'Invocazione', '1 azione', 'Incantatore (linea di 30 metri)', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fulmine/', '["mago","stregone"]', '{"name":"Fulmine","level":3,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore (linea di 30 metri)","components":"V, S, M (un pezzo di pelliccia e una verga d’ambra, cristallo o vetro)","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"8d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il danno aumenta di 1d6 per ogni livello dello slot sopra il 3°.","ritual":false,"description":"Esplodi un fulmine che forma una linea lunga 30 metri e larga 1,5 metri che parte da dove ti trovi in una direzione scelta da te. Ogni creatura sulla linea deve superare un tiro salvezza su Destrezza. La creatura subisce 8d6 danni da fulmine se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Il fulmine incendia gli oggetti infiammabili nell’area che non sono indossati o trasportati.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fulmine/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('fuorviare', 'fuorviare', 'Fuorviare', 5, 'Illusione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/fuorviare/', '["bardo","mago"]', '{"name":"Fuorviare","level":5,"school":"Illusione","casting_time":"1 azione","range":"Incantatore","components":"S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Diventi invisibile nello stesso momento in cui un tuo doppione illusorio compare nel posto in cui ti trovi. Il doppione resta per la durata dell’incantesimo, ma l’invisibilità termina se attacchi o lanci un incantesimo. Puoi usare la tua azione per far muovere il doppione illusorio fino al doppio della tua velocità e fargli compiere un gesto, parlare e comportarsi in qualsiasi maniera tu voglia. Puoi vedere attraverso i suoi occhi e udire tramite le sue orecchie come se fossi nello spazio in cui si trova lui. Durante ciascun tuo turno, con un’azione bonus, puoi passare dall’usare i suoi sensi all’usare i tuoi, o viceversa. Mentre stai usando i suoi sensi, sei accecato e assordato riguardo i tuoi dintorni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/fuorviare/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('gabbia-di-forza', 'gabbia-di-forza', 'Gabbia di Forza', 7, 'Invocazione', '1 azione', '30 metri', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/gabbia-di-forza/', '["bardo","mago","warlock"]', '{"name":"Gabbia di Forza","level":7,"school":"Invocazione","casting_time":"1 azione","range":"30 metri","components":"V, S, M (polvere di rubino del valore di 1.500 mo)","duration":"1 ora","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una prigione cubica, immobile e invisibile, composta di forza magica compare intorno a un’area a gittata da te scelta. La prigione può essere una gabbia o una scatola solida, a tua scelta. Una prigione nella forma di una gabbia può avere 6 metri di lato ed essere composta da sbarre di 1,5 centimetri separate di 1,5 centimetri tra di loro. Una prigione a forma di scatola può avere 3 metri di lato, creando una barriera solida che impedisce a qualsiasi materia di attraversarla e bloccando qualsiasi incantesimo lanciato dall’interno o l’esterno dell’area. Quando lanci questo incantesimo, qualsiasi creatura che è completamente all’interno della gabbia, è intrappolata. Le creature solo parzialmente nell’area della gabbia, o quelle troppo grosse per entrarvi,vengono spinte via dal centro dell’area finché non ne sono completamente fuori. Una creatura all’interno della gabbia non può lasciarla tramite mezzi non magici. Se la creatura prova a usare il teletrasporto o il viaggio interplanare per lasciare la gabbia, deve prima effettuare un tiro salvezza su Carisma. Se lo supera, la creatura può usare quella magia per sfuggire alla gabbia. Se lo fallisce, la creatura non può uscire dalla gabbia e spreca l’uso dell’incantesimo o dell’effetto. La gabbia si estende anche sul Piano Etereo, bloccando così il viaggio etereo. Questo incantesimo non può essere dissolto da dissolvi magie.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/gabbia-di-forza/","classes":["bardo","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('giara-magica', 'giara-magica', 'Giara Magica', 6, 'Necromanzia', '1 minuto', 'Incantatore', 'Fino a che dissolto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/giara-magica/', '["mago"]', '{"name":"Giara Magica","level":6,"school":"Necromanzia","casting_time":"1 minuto","range":"Incantatore","components":"V, S, M (una gemma, cristallo, reliquario o qualche altro contenitore ornamentale del valore di almeno 500 mo)","duration":"Fino a che dissolto","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Il tuo corpo entra in uno stato catatonico mentre la tua anima lo abbandona ed entra nel contenitore da te usato come componente materiale. Mentre la tua anima occupa il contenitore, sei consapevole dei tuoi dintorni come se fossi nello spazio del contenitore. Non puoi muoverti né usare reazioni. L’unica azione che puoi effettuare è quella di proiettare la tua anima fino a 30 metri di distanza, fuori dal contenitore, ritornando al tuo corpo vivente (e terminando l’incantesimo) o cercando di possedere un corpo umanoide. Puoi tentare di possedere qualsiasi umanoide entro 30 metri da te e che tu possa vedere (le creature protette dagli incantesimi protezione dal bene e dal male o cerchio magico non possono essere possedute). Il bersaglio deve effettuare un tiro salvezza su Carisma e, se lo fallisce, la tua anima entra nel corpo del bersaglio, mentre l’anima del bersaglio resta intrappolata nel contenitore. Se lo supera, il bersaglio resiste ai tuoi tentativi di possederlo, e non puoi tentare di possederlo nuovamente prima che siano trascorse 24 ore. Una volta che possiedi il corpo di una creatura, lo puoi controllare. Le tue statistiche di gioco sono rimpiazzate dalle statistiche della creatura, a eccezione del tuo allineamento e dei tuoi punteggi di Intelligenza, Saggezza e Carisma. Mantieni i benefici forniti dai tuoi privilegi di classe. Se il bersaglio possiede dei livelli di classe, non puoi usare nessuno dei suoi privilegi di classe.\nNel frattempo, l’anima della creatura posseduta può percepire i dintorni del contenitore usando i propri sensi, ma non può muoversi né effettuare alcuna azione.\nMentre possiedi un corpo, puoi usare la tua azione per ritornare dal corpo ospite al contenitore, se ti trovi entro 30 metri da esso, riportando l’anima della creatura ospite nel suo corpo. Se il corpo ospite muore mentre sei al suo interno, la creatura muore, e tu devi effettuare un tiro salvezza su Carisma contro la tua CD dei tiri salvezza degli incantesimi. Se lo superi, ritorni al contenitore, se si trova entro 30 metri da te. Altrimenti, morirai.\nSe il contenitore viene distrutto o l’incantesimo termina, la tua anima ritorna immediatamente al tuo corpo. Se il tuo corpo è più di 30 metri lontano o se è morto mentre cerchi di farvi ritorno, morirà anche la tua anima. Se l’anima di un’altra creatura è nel contenitore quando viene distrutto, l’anima della creatura ritorna al suo corpo, se il corpo è vivo e si trova entro 30 metri. Altrimenti, la creatura muore.\nQuando l’incantesimo termina, il contenitore viene distrutto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/giara-magica/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('glifo-di-interdizione', 'glifo-di-interdizione', 'Glifo di Interdizione', 3, 'Abiurazione', '1 azione', 'Contatto', 'Fino a che dissolto o attivato', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/glifo-di-interdizione/', '["bardo","chierico","mago"]', '{"name":"Glifo di Interdizione","level":3,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V. S, M (incenso e diamante in polvere del valore di almeno 200 mo, che l’incantesimo consuma)","duration":"Fino a che dissolto o attivato","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il danno del glifo rune esplosive aumenta di 1d8 per ogni livello dello slot sopra il 3°. Se crei un glifo incantesimo, puoi inserire qualsiasi incantesimo fino allo stesso livello dello slot incantesimo usato per glifo di interdizione.","ritual":false,"description":"Quando lanci questo incantesimo, inscrivi un glifo che danneggia altre creature su di una superficie (come un tavolo o una sezione di pavimento o muro) o all’interno di un oggetto che può essere chiuso (come un libro, una pergamena o un forziere) per celare il glifo. Se scegli una superficie, il glifo può coprire un’area di superficie non maggiore di 3 metri di diametro. Se scegli un oggetto, quell’oggetto deve restare al suo posto; se l’oggetto viene spostato più di 3 metri dal punto in cui è stato lanciato l’incantesimo, il glifo è spezzato, e l’incantesimo termina senza essere statoattivato. Il glifo è quasi invisibile e può essere trovato con una prova di Intelligenza (Indagare) contro la CD del tiro salvezza dei tuoi incantesimi. Decidi tu cosa attivi il glifo al momento del lancio dell’incantesimo. Per i glifi inscritti su di una superficie, l’attivazione tipica comprende entrare in contatto o stare sopra il glifo, rimuovere un altro oggetto che copra il glifo, avvicinarsi a una certa distanza dal glifo, o manipolare l’oggetto su cui è inscritto il glifo. Per i glifi inscritti su di un oggetto, l’attivazione tipica comprende aprire l’oggetto, avvicinarsi a una certa distanza dall’oggetto, o vedere o leggere il glifo. Una volta che il glifo è stato attivato, l’incantesimo ha termine. Puoi definire meglio l’attivazione così che l’incantesimo si attivi solo in determinate circostanze o secondo certe peculiarità fisiche (come l’altezza o il peso), specie di creatura (per esempio, l’interdizione potrebbe agire contro le aberrazioni o gli elfi oscuri), o l’allineamento. Puoi anche predisporre condizioni per evitare che il glifo venga attivato, come la pronuncia di una parola d’ordine.\nQuando inscrivi il glifo scegli rune esplosive o glifo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/glifo-di-interdizione/","classes":["bardo","chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('globo-di-invulnerabilita', 'globo-di-invulnerabilita', 'Globo di Invulnerabilità', 6, 'Abiurazione', '1 azione', 'Incantatore (raggio di 3 metri)', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/globo-di-invulnerabilita/', '["mago","stregone"]', '{"name":"Globo di Invulnerabilità","level":6,"school":"Abiurazione","casting_time":"1 azione","range":"Incantatore (raggio di 3 metri)","components":"V. S, M (una pallina di vetro o di cristallo che si frantuma quando l’incantesimo termina)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, la barriera blocca incantesimi di un livello più alto per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Una barriera immobile e lievemente scintillante si erge in un raggio di 3 metri intorno a te e vi rimane per la durata. Qualsiasi incantesimo di 5° livello o più basso lanciato dall’esterno della barriera non può agire sulle creature o gli oggetti al suo interno, anche se l’incantesimo viene lanciato usando uno slot incantesimo di livello più alto. Questi incantesimi possono prendere come bersaglio creature e oggetti all’interno della barriera, ma non avranno effetto su di essi. Allo stesso modo, l’area all’interno della barriera viene esclusa dalle aree di effetto di questi incantesimi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/globo-di-invulnerabilita/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('guardiani-spirituali', 'guardiani-spirituali', 'Guardiani Spirituali', 3, 'Evocazione', '1 azione', 'Incantatore (raggio di 4,5 metri)', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/guardiani-spirituali/', '["chierico"]', '{"name":"Guardiani Spirituali","level":3,"school":"Evocazione","casting_time":"1 azione","range":"Incantatore (raggio di 4,5 metri)","components":"V, S, M (un simbolo sacro)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":"3d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 3°.","ritual":false,"description":"Richiami degli spiriti che ti proteggano. Per la durata dell’incantesimo, essi fluttueranno intorno a te a una distanza di 4,5 metri. Se sei buono o neutrale, la forma spettrale sarà angelica o fatata (a tua scelta). Se sei malvagio, avranno un aspetto immondo.\nQuando lanci questo incantesimo, puoi designare un qualsiasi numero di creature che ne siano immuni. La velocità di una creatura soggetta viene dimezzata all’interno dell’area, e quando una creatura entra nell’area per la prima volta durante un turno o inizia il suo turno lì, deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza subisce 3d8 danni radianti (se sei buono o neutrale) o 3d8 danni necrotici (se sei malvagio), o la metà di questi danni se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/guardiani-spirituali/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('guardiano-della-fede', 'guardiano-della-fede', 'Guardiano della Fede', 4, 'Evocazione', '1 azione', '9 metri', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/guardiano-della-fede/', '["chierico"]', '{"name":"Guardiano della Fede","level":4,"school":"Evocazione","casting_time":"1 azione","range":"9 metri","components":"V","duration":"8 ore","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un guardiano spettrale Grande compare per la durata e fluttua in uno spazio non occupato a gittata e che puoi vedere, scelto da te. Il guardiano occupa quello spazio ed è indistinguibile eccetto per una spada luminosa e uno scudo con il simbolo della tua divinità. Qualsiasi creatura a te ostile che entri in uno spazio entro 3 metri dal guardiano per la prima volta durante un turno, deve effettuare un tiro salvezza su Destrezza. La creatura subisce 20 danni radianti se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Il guardiano svanisce dopo aver inflitto un totale di 60 danni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/guardiano-della-fede/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('guarigione', 'guarigione', 'Guarigione', 6, 'Invocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/guarigione/', '["chierico","druido"]', '{"name":"Guarigione","level":6,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, l’ammontare guarito aumenta di 10 per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Scegli una creatura a gittata e che puoi vedere. Un’ondata di energia positiva travolge la creatura, facendole recuperare 70 punti ferita. L’incantesimo pone anche termine a qualsiasi cecità, sordità e malattia che affligga il bersaglio. Questo incantesimo non ha effetto su costrutti o non morti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/guarigione/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('guarigione-di-massa', 'guarigione-di-massa', 'Guarigione di Massa', 9, 'Invocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/guarigione-di-massa/', '["chierico"]', '{"name":"Guarigione di Massa","level":9,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un effluvio di energia guaritrice scorre da te verso le creature ferite che ti circondano. Ripristini fino a 700 punti ferita, divisi come preferisci tra qualsiasi creatura a gittata e che puoi vedere. Le creature guarite da questo incantesimo sono curate anche di tutte le malattie e da qualsiasi effetto che le renda accecate o assordate. Questo incantesimo non ha effetto su costrutti o non morti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/guarigione-di-massa/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('guida', 'guida', 'Guida', 0, 'Divinazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/guida/', '["chierico","druido"]', '{"name":"Guida","level":0,"school":"Divinazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente. Una volta, prima che l’incantesimo termini, il bersaglio può tirare un d4 e sommare il risultato tirato a una prova di caratteristica a sua scelta. Può tirare il dado prima o dopo aver effettuato la prova di caratteristica. L’incantesimo ha poi termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/guida/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('guscio-anti-vita', 'guscio-anti-vita', 'Guscio Anti-Vita', 5, 'Abiurazione', '1 azione', 'Incantatore (raggio di 3 metri)', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/guscio-anti-vita/', '["druido"]', '{"name":"Guscio Anti-Vita","level":5,"school":"Abiurazione","casting_time":"1 azione","range":"Incantatore (raggio di 3 metri)","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una barriera luminosa si estende fino a un raggio di 3 metri intorno a te, muovendosi con te e rimanendo centrata su di te, tenendo distanti le creature che non siano non morti o costrutti. La barriera permane per la durata. La barriera impedisce a una creatura soggetta di attraversarla in alcun modo. Una creatura soggetta può lanciare incantesimi o effettuare attacchi con armi a distanza o con portata attraverso la barriera. Se ti muovi in modo che una creatura soggetta venga forzata ad attraversare la barriera, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/guscio-anti-vita/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('identificare', 'identificare', 'Identificare', 1, 'Divinazione', '1 minuto', 'Contatto', 'Istantanea', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/identificare/', '["bardo","mago"]', '{"name":"Identificare","level":1,"school":"Divinazione","casting_time":"1 minuto","range":"Contatto","components":"V, S, M (una perla del valore di almeno 100 mo e una piuma di gufo)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Scegli un oggetto con cui devi restare a contatto per tutto il lancio dell’incantesimo. Se si tratta di un oggetto magico o altro oggetto imbevuto di magia, ne apprendi le proprietà e come usarle, se richiede sintonia per l’uso, e quante cariche abbia, se ne ha. Apprendi se degli incantesimi stiano agendo sull’oggetto e cosa siano. Se l’oggetto è stato creato da un incantesimo, apprendi quale incantesimo lo abbia creato. Se invece durante l’esecuzione resti a contatto con una creatura, apprendi se degli incantesimi stiano agendo su di essa e quali siano.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/identificare/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('illusione-minore', 'illusione-minore', 'Illusione Minore', 0, 'Illusione', '1 azione', '9 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/illusione-minore/', '["bardo","mago","stregone","warlock"]', '{"name":"Illusione Minore","level":0,"school":"Illusione","casting_time":"1 azione","range":"9 metri","components":"S, M (un pezzo di vello)","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei l’immagine di un oggetto o un suono a gittata per la durata dell’incantesimo. L’illusione ha termine se la interrompi con un’azione o lanci di nuovo questo incantesimo.\nSe crei un suono, il suo volume può variare da quello di un bisbiglio a un urlo. Può essere la tua voce, la voce di qualcun altro, il ruggito di un leone, un battito di tamburi, o qualsiasi altro suono tu scelga. Il suono continua incessante per tutta la durata, oppure puoi produrre suoni diversi in momenti diversi prima del termine dell’incantesimo.\nSe crei l’immagine di un oggetto (come una sedia, un’impronta fangosa o un piccolo forziere) non può essere più grande di un cubo di 1,5 metri di spigolo. L’immagine non può produrre suoni, luci, odori o qualsiasi altro effetto sensoriale. L’interazione fisica con l’oggetto lo rivela come illusione, perché le cose lo possono attraversare.\nUna creatura che usa la sua azione per esaminare il suono o l’immagine può determinare che si tratta di un’illusione con una prova riuscita di Intelligenza (Indagare) contro la CD del tiro salvezza del tuo incantesimo. Se una creatura riconosce l’illusione per quello che è, per lei l’illusione sbiadisce.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/illusione-minore/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('illusione-programmata', 'illusione-programmata', 'Illusione Programmata', 6, 'Illusione', '1 azione', '36 metri', 'Fino a che dissolto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/illusione-programmata/', '["bardo","mago"]', '{"name":"Illusione Programmata","level":6,"school":"Illusione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un pezzo di vello e polvere di giada del valore di almeno 25 mo)","duration":"Fino a che dissolto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei, a gittata, l’illusione di un oggetto, creatura o qualche altro fenomeno visibile che si attiva quando viene soddisfatta una specifica condizione. Fino ad allora l’illusione è impercettibile. Non può essere più grande di un cubo di 9 metri di spigolo, e decidi tu quando lanci l’incantesimo, come si comporti l’illusione e che suoni produca. L’esibizione programmata può durare fino a 5 minuti. Quando occorrono le condizioni da te specificate, l’illusione si manifesta e si comporta nel modo da te descritto. Una volta che l’illusione ha terminato la sua esibizione, scompare e rimane dormiente per 10 minuti. Dopo questo periodo, l’illusione può essere attivata di nuovo. La condizione di attivazione può essere generica o dettagliata quanto vuoi, sebbene debba essere basata su condizioni visibili o udibili che avvengano entro 9 metri dall’area. Per esempio, potresti creare un’illusione di te stesso che appare e avverta chi tenti di aprire una porta munita di trappola, oppure potresti predisporre l’illusione perché si attivi solo quando una creatura pronunci la parola o la frase giusta. L’interazione fisica con l’immagine la rivela come illusione, dato che le cose le passano attraverso. Una creatura che usi la sua azione per esaminare l’immagine può determinare che è un’illusione con una prova riuscita di Intelligenza (Indagare) contro la CD del tiro salvezza dell’incantesimo. Se una creatura riconosce l’illusione per quello che è, essa può vedere attraverso l’immagine, e qualsiasi suono prodotto dall’immagine le suona artefatto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/illusione-programmata/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('immagine-maggiore', 'immagine-maggiore', 'Immagine Maggiore', 3, 'Illusione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/immagine-maggiore/', '["bardo","mago","stregone","warlock"]', '{"name":"Immagine Maggiore","level":3,"school":"Illusione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un pezzo di vello)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, l’incantesimo dura finché non viene dissolto, senza richiedere la tua concentrazione.","ritual":false,"description":"Crei l’immagine di un oggetto, una creatura o qualche altro fenomeno visibile non più grande di un cubo di 6 metri di spigolo. L’immagine appare in un punto a gittata che puoi vedere e vi rimane per la durata dell’incantesimo. L’immagine sembra completamente reale, e comprende suoni, odori e la temperatura appropriata alla cosa raffigurata. Non puoi generare calore o freddo sufficiente a provocare danni, né un suono abbastanza forte da infliggere danno da tuono o assordare una creatura, o un odore che possa far star male una creatura (come il fetore di un troglodita). Finché resti a gittata dell’illusione, puoi usare un’azione per far muovere l’immagine in qualsiasi altro punto a gittata. Quando l’immagine cambia posizione, puoi alterarne l’aspetto così che i suoi movimenti appaiano naturali. Per esempio, se crei l’immagine di una creatura e la muovi, puoi alterare l’immagine in modo che sembri camminare. Allo stesso modo, puoi impiegare l’illusione per produrre suoni diversi in momenti diversi, fino a farle portare avanti una conversazione.\nL’interazione fisica con l’immagine la rivela come illusione, dato che le cose vi passano attraverso. Una creatura che usa la sua azione per esaminare l’immagine può determinare che si tratta di un’illusione con una prova riuscita di Intelligenza (Indagare) contro la CD del tiro salvezza del tuo incantesimo. Se una creatura riconosce l’illusione per quello che è, la creatura può vedervi attraverso, e per quella creatura tutte le altre qualità sensoriali svaniscono.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/immagine-maggiore/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('immagine-proiettata', 'immagine-proiettata', 'Immagine Proiettata', 7, 'Illusione', '1 azione', '750 chilometri', 'Concentrazione, massimo 1 giorno', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/immagine-proiettata/', '["bardo","mago"]', '{"name":"Immagine Proiettata","level":7,"school":"Illusione","casting_time":"1 azione","range":"750 chilometri","components":"V, S, M (una tua piccola riproduzione fatta di materiali del valore almeno di 5 mo)","duration":"Concentrazione, massimo 1 giorno","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei una copia illusoria di te stesso che permane per la durata. La copia può apparire in qualsiasi luogo entro la gittata che tu abbia già visto, ignorando qualsiasi ostacolo frapposto. L’illusione riproduce il tuo aspetto e i tuoi rumori ma è intangibile. Se l’illusione subisce danni, scompare, e l’incantesimo ha termine.\nPuoi usare la tua azione per far muovere questa illusione fino al doppio della tua velocità e farle compiere un gesto, parlare e comportarsi in qualsiasi maniera tu voglia. Imita alla perfezione i tuoi comportamenti.\nPuoi vedere attraverso i suoi occhi e udire tramite le sue orecchie come se fossi nello spazio in cui essa si trova. Durante ciascun tuo turno, con un’azione bonus, puoi passare dall’usare i suoi sensi all’usare i tuoi, o viceversa. Mentre stai usando i suoi sensi, sei accecato e assordato riguardo i tuoi dintorni.\nL’interazione fisica con l’immagine la rivela come illusione, dato che le cose le passano attraverso. Una creatura che usi la sua azione per esaminare l’immagine può determinare che è un’illusione con una prova riuscita di Intelligenza (Indagare) contro la CD del tiro salvezza dell’incantesimo. Se una creatura riconosce l’illusione per quello che è, essa può vedere attraverso l’immagine, e qualsiasi suono prodotto dall’immagine le suona artefatto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/immagine-proiettata/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('immagine-silenziosa', 'immagine-silenziosa', 'Immagine Silenziosa', 1, 'Illusione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/immagine-silenziosa/', '["bardo","mago","stregone"]', '{"name":"Immagine Silenziosa","level":1,"school":"Illusione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un pezzo di vello)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei l’immagine di un oggetto, una creatura o qualche altro fenomeno visibile non più grande di un cubo di 4,5 metri di spigolo. L’immagine appare in un punto a gittata che puoi vedere e resta per la durata dell’incantesimo. L’immagine è puramente visiva; non è accompagnata da suoni, odori o altri effetti sensoriali. Puoi usare un’azione per far muovere l’immagine in qualsiasi altro punto a gittata. Quando l’immagine cambia posizione, puoi alterarne l’aspetto così che i suoi movimenti appaiano naturali. Per esempio, se crei l’immagine di una creatura e la muovi, puoi alterare l’immagine in modo che sembri camminare. L’interazione fisica con l’immagine la rivela come illusione, dato che le cose vi passano attraverso. Una creatura che usa la sua azione per esaminare l’immagine può determinare che si tratta di un’illusione con una prova riuscita di Intelligenza (Indagare) contro la CD del tiro salvezza del tuo incantesimo. Se una creatura riconosce l’illusione per quello che è, la creatura può vedervi attraverso.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/immagine-silenziosa/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('immagine-speculare', 'immagine-speculare', 'Immagine Speculare', 2, 'Illusione', '1 azione', 'Incantatore', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/immagine-speculare/', '["mago","stregone","warlock"]', '{"name":"Immagine Speculare","level":2,"school":"Illusione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Nel tuo spazio compaiono tre duplicati illusori di te stesso. Fino al termine dell’incantesimo, i duplicati si muovono con te e imitano le tue azioni, scambiandosi di posto in modo da rendere impossibile determinare quale sia l’immagine reale. Puoi usare la tua azione per congedare i duplicati illusori. Ogni volta che una creatura ti prenda come bersaglio di un attacco nella durata dell’incantesimo, tira un d20 per determinare se l’attacco colpisca invece uno dei tuoi duplicati. Se hai tre duplicati, devi tirare 6 o più per spostare l’attacco della creatura contro un duplicato. Con due duplicati, devi tirare 8 o più. Con un duplicato, devi tirare 11 o più. La CA del duplicato è pari a 10 + il tuo modificatore di Destrezza. Se un attacco colpisce un duplicato, questo è distrutto. Un duplicato può essere distrutto solo da un attacco che lo colpisce. Ignora invece tutti gli altri danni o effetti. L’incantesimo ha termine quando tutti e tre i duplicati sono stati distrutti. Una creatura che non può vedere, o si affida a sensi diversi dalla vista (come la vista cieca), o che può distinguere le illusioni come false (come la visione del vero), ignora gli effetti di questo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/immagine-speculare/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('imprigionare', 'imprigionare', 'Imprigionare', 9, 'Abiurazione', '1 azione', '9 metri', 'Fino a dissolvimento', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/imprigionare/', '["mago","warlock"]', '{"name":"Imprigionare","level":9,"school":"Abiurazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (una raffigurazione su vello o una statuetta incisa con le fattezze del bersaglio, e una componente speciale che varia a seconda della versione che scegli dell’incantesimo, del valore di almeno 500 mo per Dado Vita del bersaglio)","duration":"Fino a dissolvimento","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei dei vincoli magici per bloccare una creatura a gittata e che puoi vedere. Il bersaglio deve superare un tiro salvezza su Saggezza o essere avvinto dall’incantesimo; se lo supera, è immune all’incantesimo qualora lo lanci di nuovo. Mentre è soggetta a questo incantesimo, la creatura non ha bisogno di respirare, mangiare o bere e non invecchia. Gli incantesimi di divinazione non possono localizzare né percepire il bersaglio. Quando lanci questo incantesimo, scegli una delle seguenti forme di prigionia.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/imprigionare/","classes":["mago","warlock"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('inaridire', 'inaridire', 'Inaridire', 4, 'Necromanzia', '1 azione', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/inaridire/', '["druido","mago","stregone","warlock"]', '{"name":"Inaridire","level":4,"school":"Necromanzia","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"8d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 4°.","ritual":false,"description":"Energia necromantica avvolge una creatura di tua scelta a gittata e che puoi vedere, deprivandola di linfa e vitalità. Il bersaglio deve effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza, il bersaglio subisce 8d8 danni necrotici, o la metà di questi danni se supera il tiro salvezza. L’incantesimo non ha effetto su non morti o costrutti. Se il bersaglio è un vegetale non magico che non sia anche una creatura, come un albero o un cespuglio, non effettua alcun tiro salvezza, avvizzisce e muore all’istante.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/inaridire/","classes":["druido","mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('incoraggiamento', 'incoraggiamento', 'Incoraggiamento', 0, 'Manovra', 'Azione bonus', 'Alleato che ti vede o ti sente', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Incoraggiamento","level":0,"school":"Manovra","casting_time":"Azione bonus","range":"Alleato che ti vede o ti sente","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Nel proprio turno, il guerriero può\nusare un''azione bonus e spendere un dado di superiorità\nper incitare uno dei suoi compagni. Quando lo fa, sceglie\nuna creatura amica che sia in grado di vederlo o di sentirlo.\nQuella creatura ottiene un ammontare di punti ferita\ntemporanei pari al risultato del tiro del dado di superiorità\n+ il modificatore di Carisma del guerriero.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('individuazione-dei-pensieri', 'individuazione-dei-pensieri', 'Individuazione dei Pensieri', 2, 'Divinazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/individuazione-dei-pensieri/', '["bardo","mago","stregone"]', '{"name":"Individuazione dei Pensieri","level":2,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un pezzo di rame)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata, puoi leggere i pensieri di certe creature. Quando lanci questo incantesimo e come tua azione in ciascun turno successivo sino al termine dell’incantesimo, puoi concentrare la tua mente su qualsiasi creatura che tu possa vedere e si trovi entro 9 metri da te. Se la creatura che hai scelto ha un punteggio di Intelligenza 3 o meno o non parla nessun linguaggio, la creatura ignora l’effetto. Inizialmente, apprendi solo i pensieri di superficie della creatura: quelli più ricorrenti. Con un’azione, puoi o spostare la tua attenzione sui pensieri di un’altra creatura o tentare di sondare più a fondo la mente della stessa creatura. Se sondi più a fondo, il bersaglio deve effettuare un tiro salvezza su Saggezza. Se lo fallisce, ottieni una percezione dei suoi ragionamenti (se ve ne sono), del suo stato emotivo, e di ogni cosa abbia prevalenza nei suoi pensieri (come una preoccupazione, l’amore, o l’odio). Se supera il tiro salvezza, l’incantesimo termina. A ogni modo, il bersaglio sa che stai sondando la sua mente e, a meno che non sposti la tua attenzione verso la mente di un’altra creatura, nel suo turno la creatura può usare la propria azione per effettuare una prova di Intelligenza contesa dalla tua prova di Intelligenza; se la vince, l’incantesimo termina. Le domande poste verbalmente alla creatura bersaglio, ovviamente, modellano il corso dei suoi pensieri, cosicché questo incantesimo risulta particolarmente efficace negli interrogatori. Puoi anche usare questo incantesimo per individuare la presenza di creature pensanti che non puoi vedere. Quando lanci questo incantesimo o come tua azione nella sua durata, puoi cercare pensieri entro 9 metri da te. L’incantesimo può penetrare le barriere, ma è bloccato da 60 centimetri di pietra, 5 centimetri di metallo che non sia il piombo, o un sottile foglio di piombo. Non puoi individuare una creatura con Intelligenza 3 o meno, o una creatura che non parla alcun linguaggio. Una volta individuata in questo modo la presenza di una creatura, puoi leggerne i pensieri per la durata dell’incantesimo finché resta nella gittata, come descritto sopra, anche se non puoi vederla.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/individuazione-dei-pensieri/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('individuazione-del-bene-e-del-male', 'individuazione-del-bene-e-del-male', 'Individuazione del Bene e del Male', 1, 'Divinazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/individuazione-del-bene-e-del-male/', '["chierico","paladino"]', '{"name":"Individuazione del Bene e del Male","level":1,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata, apprendi se entro 9 metri da te si trova un’aberrazione, celestiale, elementale, fatato, immondo o non morto, e la sua posizione. Allo stesso modo, apprendi se entro 9 metri da te si trovi un luogo o oggetto che sia stato consacrato o dissacrato magicamente. L’incantesimo può penetrare la maggior parte delle barriere, ma è bloccato da 30 centimetri di pietra, 2,5 centimetri di metallo comune, un sottile foglio di piombo o 1 metro di legno o terra.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/individuazione-del-bene-e-del-male/","classes":["chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('individuazione-del-magico', 'individuazione-del-magico', 'Individuazione del Magico', 1, 'Divinazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 10 minuti', 1, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/individuazione-del-magico/', '["bardo","chierico","druido","mago","ranger","stregone"]', '{"name":"Individuazione del Magico","level":1,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Per la durata, percepisci la presenza della magia entro 9 metri da te. Se percepisci la magia in questo modo, puoi usare la tua azione per vedere una flebile aura che si estende intorno a qualsiasi creatura o oggetto visibile nell’area che rechi magia, e ne apprendi anche la scuola di magia, se ce l’ha. L’incantesimo può penetrare la maggior parte delle barriere, ma è bloccato da 30 centimetri di pietra, 2,5 centimetri di metallo comune, un sottile foglio di piombo o 1 metro di legno o terra.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/individuazione-del-magico/","classes":["bardo","chierico","druido","mago","ranger","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('individuazione-delle-malattie-e-dei-veleni', 'individuazione-delle-malattie-e-dei-veleni', 'Individuazione delle Malattie e dei Veleni', 1, 'Divinazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 10 minuti', 1, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/individuazione-delle-malattie-e-dei-veleni/', '["chierico","ranger"]', '{"name":"Individuazione delle Malattie e dei Veleni","level":1,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (una foglia di tasso)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Per la durata, percepisci la presenza e posizione di veleni, creature velenose e malattie entro 9 metri da te. Inoltre riesci a identificare il tipo di veleno, creatura velenosa o malattia. L’incantesimo può penetrare la maggior parte delle barriere, ma è bloccato da 30 centimetri di pietra, 2,5 centimetri di metallo comune, un sottile foglio di piombo o 1 metro di legno o terra.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/individuazione-delle-malattie-e-dei-veleni/","classes":["chierico","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('infliggi-ferite', 'infliggi-ferite', 'Infliggi Ferite', 1, 'Necromanzia', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/infliggi-ferite/', '["chierico"]', '{"name":"Infliggi Ferite","level":1,"school":"Necromanzia","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"3d10","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, il danno aumenta di 1d10 per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Effettua un attacco in mischia con incantesimo contro una creatura a portata. Se colpisci, il bersaglio subisce 3d10 danni necrotici.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/infliggi-ferite/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('ingrandire-ridurre', 'ingrandire-ridurre', 'Ingrandire/Ridurre', 2, 'Trasmutazione', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/ingrandire-ridurre/', '["mago","stregone"]', '{"name":"Ingrandire/Ridurre","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un pizzico di ferro in polvere)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fai sì che una creatura od oggetto a gittata e che puoi vedere ingrandisca o rimpicciolisca per la durata dell’incantesimo. Scegli una creatura o un oggetto che non sia né indossato né trasportato. Se il bersaglio non è consenziente, può effettuare un tiro salvezza su Costituzione. Se lo supera, l’incantesimo non ha effetto. Se il bersaglio è una creatura, tutto ciò che sta indossando e trasportando cambia taglia assieme a essa. Qualsiasi oggetto lasciato cadere da una creatura soggetta a questo incantesimo ritorna subito alla sua taglia normale.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/ingrandire-ridurre/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('intimorire-infernale', 'intimorire-infernale', 'Intimorire Infernale', 1, 'Invocazione', '1 reazione, che puoi effettuare in risposta al danno arrecatoti da una creatura entro 18 metri da te che puoi vedere', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/intimorire-infernale/', '["warlock"]', '{"name":"Intimorire Infernale","level":1,"school":"Invocazione","casting_time":"1 reazione, che puoi effettuare in risposta al danno arrecatoti da una creatura entro 18 metri da te che puoi vedere","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"2d10","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, il danno aumenta di 1d10 per ogni livello sopra il 1°.","ritual":false,"description":"Punti il dito, e la creatura che ti ha danneggiato viene momentaneamente avvolta da fiamme diaboliche. La creatura deve effettuare un tiro salvezza su Destrezza. Subisce 2d10 danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/intimorire-infernale/","classes":["warlock"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('intralciare', 'intralciare', 'Intralciare', 1, 'Evocazione', '1 azione', '27 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/intralciare/', '["druido"]', '{"name":"Intralciare","level":1,"school":"Evocazione","casting_time":"1 azione","range":"27 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Forza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Rampicanti e rami stritolanti spuntano dal terreno in un quadrato di 6 metri di lato a partire da un punto a gittata. Per la durata, questi vegetali trasformano il terreno nell’area in terreno difficile. Una creatura nell’area nel momento in cui lanci questo incantesimo deve superare un tiro salvezza su Forza o restare intralciata da questi vegetali fino al termine dell’incantesimo. Una creatura intralciata dai vegetali può usare le sue azioni per effettuare una prova di Forza contro la CD del tiro salvezza dell’incantesimo. Se la supera, si libera. Quando l’incantesimo ha termine, i vegetali evocati svaniscono.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/intralciare/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('inversione-della-gravita', 'inversione-della-gravita', 'Inversione della Gravità', 7, 'Trasmutazione', '1 azione', '30 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/inversione-della-gravita/', '["druido","mago","stregone"]', '{"name":"Inversione della Gravità","level":7,"school":"Trasmutazione","casting_time":"1 azione","range":"30 metri","components":"V, S, M (una calamita e un fil di ferro)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo inverte la gravità in un cilindro di raggio 15 metri, alto 30 metri, centrato in un punto a gittata. Quando lanci questo incantesimo, tutte le creature e gli oggetti che non sono in qualche modo ancorati al terreno cadono verso l’alto e raggiungono la cima dell’area. Una creatura può tentare un tiro salvezza su Destrezza per afferrare un oggetto fisso a portata, per evitare di cadere in questo modo, in caso lo superi.\nSe lungo questa caduta si incontra un oggetto solido (il soffitto), gli oggetti e le creature che cadono vi impattano come accadrebbe durante una normale caduta. Se un oggetto o creatura raggiunge la cima dell’area senza colpire nulla, rimane lì, oscillando lievemente, per la durata.\nAl termine della durata, gli oggetti e le creature colpite ricadono verso il basso.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/inversione-della-gravita/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('inviare', 'inviare', 'Inviare', 3, 'Invocazione', '1 azione', 'Illimitata', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/inviare/', '["chierico","mago"]', '{"name":"Inviare","level":3,"school":"Invocazione","casting_time":"1 azione","range":"Illimitata","components":"V, S, M (un piccolo pezzo di cavo di rame)","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Invii un breve messaggio di 25 parole o meno a una creatura con cui sei familiare. La creatura sente il messaggio nella sua mente, ti riconosce come mittente, e può risponderti in modo simile. L’incantesimo permette a creature con un punteggio di Intelligenza almeno di 1 di comprendere il significato del tuo messaggio. Puoi inviare il messaggio attraverso qualsiasi distanza e anche su altri piani di esistenza, ma se il bersaglio è su di un piano diverso dal tuo, c’è una probabilità del 5% che il messaggio non arrivi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/inviare/","classes":["chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('invisibilita', 'invisibilita', 'Invisibilità', 2, 'Illusione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/invisibilita/', '["mago","stregone","warlock"]', '{"name":"Invisibilità","level":2,"school":"Illusione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un ciglio avvolto nella gomma arabica)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, puoi scegliere un’ulteriore creatura bersaglio per ogni livellodello slot sopra il 2°.","ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura. Il bersaglio diventa invisibile fino alla fine dell’incantesimo. Qualsiasi cosa il bersaglio stia indossando o trasportando diventa invisibile finché resta sul bersaglio. L’incantesimo ha fine per il bersaglio che attacca o esegue un incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/invisibilita/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('invisibilita-superiore', 'invisibilita-superiore', 'Invisibilità Superiore', 4, 'Illusione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/invisibilita-superiore/', '["bardo","mago","stregone"]', '{"name":"Invisibilità Superiore","level":4,"school":"Illusione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura. Il bersaglio diventa invisibile fino alla fine dell’incantesimo. Qualsiasi cosa indossata o trasportata dal bersaglio diventa invisibile finché resta addosso al bersaglio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/invisibilita-superiore/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('invocare-il-fulmine', 'invocare-il-fulmine', 'Invocare il Fulmine', 3, 'Evocazione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/invocare-il-fulmine/', '["druido"]', '{"name":"Invocare il Fulmine","level":3,"school":"Evocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"3d10","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il danno aumenta di 1d10 per ogni livello dello slot sopra il 3°.","ritual":false,"description":"Una nube di tempesta compare nella forma di un cilindro alto 3 metri con un raggio di 18 metri, centrato su di un punto che puoi vedere, 30 metri sopra di te. L’incantesimo fallisce automaticamente se non puoi vedere il punto nell’aria dove apparirà la nube di tempesta (per esempio, se sei in una stanza che non può accogliere la nube). Quando lanci l’incantesimo, scegli un punto che puoi vedere entro la gittata. Un fulmine si abbatterà dalla nuvola su quel punto. Ogni creatura entro 1,5 metri da quel punto deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 3d10 danni da fulmine se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Durante ciascun tuo turno fino al termine dell’incantesimo, puoi usare la tua azione per richiamare un altro fulmine in questo modo, prendendo come bersaglio lo stesso punto o uno diverso. Se quando lanci questo incantesimo ti trovi all’esterno in condizioni di tempesta, l’incantesimo ti fornisce il controllo della tempesta esistente invece di crearne una nuova. Sotto queste condizioni, il danno dell’incantesimo aumenta di 1d10.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/invocare-il-fulmine/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('labirinto', 'labirinto', 'Labirinto', 8, 'Evocazione', '1 azione', '18 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/labirinto/', '["mago"]', '{"name":"Labirinto","level":8,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Bandisci una creatura a gittata e che puoi vedere in un semipiano labirintico. Il bersaglio rimane lì per la durata dell’incantesimo o finché non fugge dal labirinto. Il bersaglio può impiegare la sua azione per tentare di fuggire. Quando lo fa, effettua una prova di Intelligenza CD 20. Se la supera, fugge, e l’incantesimo termina (un minotauro o un demone goristro riescono automaticamente). Quando l’incantesimo termina, il bersaglio riappare nello spazio che aveva lasciato o, se quello spazio è occupato, nel più vicino spazio non occupato.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/labirinto/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('lama-infuocata', 'lama-infuocata', 'Lama Infuocata', 2, 'Invocazione', '1 azione bonus', 'Incantatore', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/lama-infuocata/', '["druido"]', '{"name":"Lama Infuocata","level":2,"school":"Invocazione","casting_time":"1 azione bonus","range":"Incantatore","components":"V, S, M (una foglia di sommacco)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"3d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il danno aumenta di 1d6 per ogni due livelli dello slot sopra il 2°.","ritual":false,"description":"Crei nella tua mano una lama infuocata. La lama è simile in dimensioni e forma a una scimitarra, e rimane per la durata. Se lasci andare la lama, questa sparisce, ma ne puoi creare un’altra con un’azione bonus.\nPuoi usare la tua azione per effettuare un attacco in mischia con incantesimo usando la lama infuocata. Se colpisci, il bersaglio subisce 3d6 danni da fuoco. La lama infuocata emana luce intensa in un raggio di 3 metri e luce fioca per ulteriori 3 metri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/lama-infuocata/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('legame-planare', 'legame-planare', 'Legame Planare', 5, 'Abiurazione', '1 ora', '18 metri', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/legame-planare/', '["bardo","chierico","druido","mago"]', '{"name":"Legame Planare","level":5,"school":"Abiurazione","casting_time":"1 ora","range":"18 metri","components":"V, S, M (un gioiello del valore di almeno 1.000 mo, che l’incantesimo consuma)","duration":"24 ore","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot di livello più alto, la durata aumenta a 10 giorni per uno slot di 6° livello, a 30 giorni per uno slot di 7° livello, a 180 giorni per uno slot di 8° livello e a un anno e un giorno per uno slot di 9° livello.","ritual":false,"description":"Con questo incantesimo, cerchi di vincolare un celestiale, elementale, fatato o immondo al tuo servizio. La creatura deve restare nella gittata per l’intero lancio dell’incantesimo. (Di solito, la creatura viene prima evocata al centro di un cerchio magico invertito per tenerla intrappolata mentre questo incantesimo viene lanciato). Al completamento del lancio, il bersaglio deve effettuare un tiro salvezza su Carisma. Se fallisce il tiro salvezza, è vincolato al tuo servizio per la durata. Se la creatura è stata evocata o creata da un altro incantesimo, la durata di quell’incantesimo viene estesaper corrispondere alla durata di questo incantesimo. Una creatura vincolata deve eseguire le tue istruzioni al meglio delle sue capacità. Potresti comandare la creatura di accompagnarti nel corso di un’avventura, di proteggere un luogo o di consegnare un messaggio. La creatura obbedisce le tue istruzioni alla lettera, ma se ti è ostile, cercherà di distorcere le tue parole ai suoi fini. Se la creatura adempie completamente alle tue istruzioni prima del termine dell’incantesimo, qualora vi troviate sullo stesso piano di esistenza ritornerà da te per comunicarti l’avvenuto. Se vi trovate su piani di esistenza diversi, ritornerà nel luogo dove l’hai vincolata e rimarrà lì fino al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/legame-planare/","classes":["bardo","chierico","druido","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('legame-telepatico', 'legame-telepatico', 'Legame Telepatico', 5, 'Divinazione', '1 azione', '9 metri', '1 ora', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/legame-telepatico/', '["mago"]', '{"name":"Legame Telepatico","level":5,"school":"Divinazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (pezzi di gusci d’uovo da due differenti specie di creature)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Stabilisci un collegamento telepatico tra un massimo di otto creature consenzienti a gittata di tua scelta, collegando psichicamente ciascuna creatura alle altre per la durata dell’incantesimo. Le creature con punteggio di Intelligenza 2 o meno ignorano questo incantesimo. Fino al termine dell’incantesimo, i bersagli possono comunicare telepaticamente tramite questo legame, che condividano o meno un linguaggio comune. La comunicazione è possibile a qualsiasi distanza, ma non può estendersi su differenti piani di esistenza.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/legame-telepatico/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('lentezza', 'lentezza', 'Lentezza', 3, 'Trasmutazione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/lentezza/', '["mago","stregone"]', '{"name":"Lentezza","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (una goccia di melassa)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Modifichi lo scorrere del tempo intorno a un massimo di sei creature di tua scelta in un cubo di 12 metri di spigolo a gittata. Ciascun bersaglio deve superare un tiro salvezza su Saggezza o subire gli effetti dell’incantesimo per la sua durata. La velocità di un bersaglio soggetto all’incantesimo è dimezzata, questi subisce una penalità di -2 alla CA e ai tiri salvezza su Destrezza, e non può usare reazioni. Durante il suo turno, può usare un’azione o un’azione bonus, ma non entrambe. Quali che siano le capacità o gli oggetti magici della creatura, durante il suo turno questa non può effettuare più di un attacco in mischia o a distanza. Se la creatura tenta di lanciare un incantesimo con tempo di lancio 1 azione, tira un d20. Con 11 o più, l’incantesimo non avrà effetto fino al prossimo turno della creatura, e la creatura dovrà usare la sua azione in quel turno per completare l’incantesimo. Se non potrà farlo, l’incantesimo viene sprecato. Una creatura sotto l’effetto di questo incantesimo effettua un altro tiro salvezza su Saggezza al termine del suo turno. Se supera questo tiro salvezza, l’effetto ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/lentezza/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('levitazione', 'levitazione', 'Levitazione', 2, 'Trasmutazione', '1 azione', '18 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/levitazione/', '["mago","stregone"]', '{"name":"Levitazione","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (o un piccolo laccio di cuoio oppure un pezzo di cavo d’oro piegato a forma di tazza con un lungo stelo alla fine)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una creatura o oggetto a gittata che puoi vedere, scelto da te, si alza verticalmente fino a 6 metri e rimane sospeso per la durata dell’incantesimo. L’incantesimo può levitare un bersaglio pesante fino a 250 chili. Una creatura non consenziente che superi un tiro salvezza su Costituzione ignora l’effetto. Il bersaglio può muoversi solo spingendo o tirando verso un oggetto fisso o superficie a portata (per esempio un muro o un soffitto). Durante il tuo turno puoi cambiare l’altitudine del bersaglio fino a 6 metri in entrambe le direzioni. Se sei tu il bersaglio, ti puoi muovere verso l’alto o il basso come parte del tuo movimento. Altrimenti puoi usare la tua azione per muovere il bersaglio, che deve rimanere nella gittata dell’incantesimo. Quando l’incantesimo termina, qualora sia ancora in aria, il bersaglio fluttua dolcemente a terra.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/levitazione/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('liberta-di-movimento', 'liberta-di-movimento', 'Libertà di Movimento', 4, 'Abiurazione', '1 azione', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/liberta-di-movimento/', '["bardo","chierico","druido","ranger"]', '{"name":"Libertà di Movimento","level":4,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (una striscia di cuoio, avvolta intorno a un braccio o simile appendice)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente. Per la sua durata, il movimento del bersaglio ignora il terreno difficile, mentre gli incantesimi o altri effetti magici non possono ridurre la sua velocità né far sì che il bersaglio sia paralizzato o intralciato. Il bersaglio può spendere 1,5 metri di movimento per liberarsi automaticamente da qualsiasi restrizione non magica, come manette o una creatura da cui è afferrato. Infine, trovarsi sott’acqua non comporta penalità al movimento o gli attacchi del bersaglio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/liberta-di-movimento/","classes":["bardo","chierico","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('lingue', 'lingue', 'Lingue', 3, 'Divinazione', '1 azione', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/lingue/', '["bardo","chierico","mago","stregone","warlock"]', '{"name":"Lingue","level":3,"school":"Divinazione","casting_time":"1 azione","range":"Contatto","components":"V, M (un piccolo modello di argilla di uno ziggurat)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo conferisce alla creatura con cui sei stato in contatto al momento del lancio dell’incantesimo la capacità di comprendere qualsiasi linguaggio parlata che ode. Inoltre, quando il bersaglio parla, qualsiasi creatura che conosca almeno un linguaggio e può udire il bersaglio, comprende ciò che dice.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/lingue/","classes":["bardo","chierico","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('localizza-animali-o-vegetali', 'localizza-animali-o-vegetali', 'Localizza Animali o Vegetali', 2, 'Divinazione', '1 azione', 'Incantatore', 'Istantanea', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/localizza-animali-o-vegetali/', '["bardo","druido","ranger"]', '{"name":"Localizza Animali o Vegetali","level":2,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un pezzo di pelo di un segugio)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Descrivi o nomina uno specifico tipo di bestia o vegetale. Concentrandoti sulla voce della natura nei tuoi dintorni, apprendi la direzione e la distanza dalla più vicina creatura o vegetale di quella specie, se ce ne sono entro 7,5 chilometri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/localizza-animali-o-vegetali/","classes":["bardo","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('localizza-creatura', 'localizza-creatura', 'Localizza Creatura', 4, 'Divinazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/localizza-creatura/', '["bardo","chierico","druido","paladino","ranger"]', '{"name":"Localizza Creatura","level":4,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un pezzo di pelliccia di segugio)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Descrivi o nomina una creatura che ti è familiare. Percepisci la direzione della posizione della creatura, purché quella creatura si trovi entro 300 metri da te. Se la creatura si muove, conosci anche la direzione del suo movimento.\nL’incantesimo può localizzare una specifica creatura a te nota, o la più vicina creatura di una specie (come umano o unicorno), purché tu abbia visto una simile creatura da vicino (entro 9 metri) almeno una volta. Se la creatura che descrivi o nomini ha una forma diversa, per esempio è sotto gli effetti dell’incantesimo metamorfosi, questo incantesimo non sarà in grado di localizzare la creatura.\nQuesto incantesimo non può localizzare una creatura se un flusso di acqua corrente largo almeno 3 metri blocca un percorso diretto tra te e la creatura.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/localizza-creatura/","classes":["bardo","chierico","druido","paladino","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('localizza-oggetto', 'localizza-oggetto', 'Localizza Oggetto', 2, 'Divinazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/localizza-oggetto/', '["bardo","chierico","druido","mago","paladino","ranger"]', '{"name":"Localizza Oggetto","level":2,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un ramoscello biforcuto)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Descrivi o nomina un oggetto che ti è familiare. Percepisci la direzione della posizione dell’oggetto, purché quell’oggetto si trovi entro 300 metri da te. Se l’oggetto si muove, conosci anche la direzione del suo movimento.\nL’incantesimo può localizzare uno specifico oggetto a te noto, purché tu lo abbia visto da vicino (entro 9 metri) almeno una volta. In alternativa, l’incantesimo può localizzare l’oggetto più vicino di un particolare tipo, come certi tipi di abbigliamento, gioielleria, mobili, attrezzi o armi. Questo incantesimo non può localizzare un oggetto se qualsiasi spessore di piombo, anche un foglio sottile, blocca un percorso diretto tra di te e l’oggetto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/localizza-oggetto/","classes":["bardo","chierico","druido","mago","paladino","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('loquacita', 'loquacita', 'Loquacità', 8, 'Trasmutazione', '1 azione', 'Incantatore', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/loquacita/', '["bardo","warlock"]', '{"name":"Loquacità","level":8,"school":"Trasmutazione","casting_time":"1 azione","range":"Incantatore","components":"V","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fino al termine dell’incantesimo, quando effettui una prova di Carisma puoi rimpiazzare il numero tirato con 15. Inoltre, non importa quello che dici, la magia che determina se stai dicendo la verità indicherà sempre che sei onesto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/loquacita/","classes":["bardo","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('luce', 'luce', 'Luce', 0, 'Invocazione', '1 azione', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/luce/', '["bardo","chierico","mago","paladino","stregone"]', '{"name":"Luce","level":0,"school":"Invocazione","casting_time":"1 azione","range":"Contatto","components":"V, M (una lucciola o del muschio fosforescente)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di un oggetto che non sia più grosso di 3 metri in qualsiasi direzione. Fino al termine dell’incantesimo, l’oggetto irradia una luce intensa in un raggio di 6 metri e una luce fioca per ulteriori 6 metri. La luce può essere di qualsiasi colore tu voglia. Coprire completamente un oggetto con qualcosa di opaco blocca la luce. L’incantesimo termina se lo lanci di nuovo o lo interrompi con un’azione. Se un oggetto bersaglio è tenuto o indossato da una creatura ostile, quella creatura deve superare un tiro salvezza su Destrezza per evitare l’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/luce/","classes":["bardo","chierico","mago","paladino","stregone"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('luce-diurna', 'luce-diurna', 'Luce Diurna', 3, 'Invocazione', '1 azione', '18 metri', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/luce-diurna/', '["chierico","druido","paladino","ranger","stregone"]', '{"name":"Luce Diurna","level":3,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una sfera di luce con raggio 18 metri si espande da un punto a tua scelta entro la gittata. La sfera irradia luce intensa e luce fioca per ulteriori 18 metri. Se scegli un punto su di un oggetto che stai reggendo o che non è indossato o trasportato, la luce si irradia dall’oggetto e si muove con esso. Coprire completamente un oggetto con qualcosa di opaco, come un vaso o un elmo, blocca la luce. Se qualsiasi parte dell’area di questo incantesimo si sovrappone con l’area di oscurità creata da un incantesimo di 3° livello o più basso, l’incantesimo che ha creato l’oscurità viene dissolto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/luce-diurna/","classes":["chierico","druido","paladino","ranger","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('luci-danzanti', 'luci-danzanti', 'Luci Danzanti', 0, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/luci-danzanti/', '["bardo","mago","stregone"]', '{"name":"Luci Danzanti","level":0,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un pezzo di fosforo o legno stregato, o un lombrico)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei, a gittata, fino a quattro luci delle dimensioni di una torcia, facendole apparire come torce, lanterne o sfere luminose che fluttuano nell’aria per la durata dell’incantesimo. Puoi anche combinare le quattro luci in un’unica forma luminosa vagamente umanoide di taglia Media. Qualsiasi forma scegli, ciascuna luce emette una luce fioca in un raggio di 3 metri. Come azione bonus durante il tuo turno, puoi spostare le luci fino a 18 metri in un nuovo punto a gittata. Una luce deve trovarsi entro 6 metri da un’altra luce creata con questo incantesimo, e le luci svaniscono se eccedono la gittata dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/luci-danzanti/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('luminescenza', 'luminescenza', 'Luminescenza', 1, 'Invocazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/luminescenza/', '["bardo","druido"]', '{"name":"Luminescenza","level":1,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":true,"damage":null,"scaling":null,"ritual":false,"description":"Tutti gli oggetti in un cubo di 6 metri di spigolo a gittata vengono circondati da una luce blu, verde o viola (a tua scelta). Qualsiasi creatura nell’area quando l’incantesimo viene lanciato, viene anch’essa circondata dalla luce se fallisce un tiro salvezza su Destrezza. Per la durata dell’incantesimo, gli oggetti e le creature soggette emettono una luce fioca con raggio di 3 metri. Qualsiasi tiro per colpire contro una creatura od oggetto soggetto ha vantaggio se l’attaccante può vederlo, e la creatura od oggetto non può beneficiare dell’invisibilità.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/luminescenza/","classes":["bardo","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('mani-brucianti', 'mani-brucianti', 'Mani Brucianti', 1, 'Invocazione', '1 azione', 'Incantatore (cono di 4,5 metri)', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/mani-brucianti/', '["mago","stregone"]', '{"name":"Mani Brucianti","level":1,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore (cono di 4,5 metri)","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"3d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, il danno aumenta di 1d6 per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Mentre tieni le mani con i pollici che si toccano e le dita tese, un sottile fiotto di fiamme parte da ciascuna delle punta delle tue dita. Ogni creatura in un cono di 4,5 metri deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 3d6 danni da fuoco se fallisce il tiro salvezza, o la metà se lo supera. Il fuoco incendia gli oggetti infiammabili nell’area che non siano indossati o trasportati.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/mani-brucianti/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('mano-arcana', 'mano-arcana', 'Mano Arcana', 5, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/mano-arcana/', '["mago"]', '{"name":"Mano Arcana","level":5,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un guscio d’uovo e un guanto di pelle di serpente)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, il danno dell’opzione pugno serrato aumenta di 2d8 e il danno dell’opzione mano afferrante aumenta di 2d6 per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Crei una mano Grande, composta di energia trasparente e luminosa, in uno spazio non occupato a gittata e che puoi vedere. La mano permane per la durata dell’incantesimo, e si muove al tuo comando, imitando i movimenti della tua mano. La mano è un oggetto che ha CA 20 e punti ferita uguali ai tuoi punti ferita massimi. Ha Forza 26 (+8) e Destrezza 10 (+0). La mano non riempie il suo spazio. Quando lanci l’incantesimo e come azione bonus durante i tuoi turni successivi, puoi muovere la mano fino a 18 metri e poi generare uno dei seguenti effetti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/mano-arcana/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('mano-magica', 'mano-magica', 'Mano Magica', 0, 'Evocazione', '1 azione', '9 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/mano-magica/', '["bardo","mago","stregone","warlock"]', '{"name":"Mano Magica","level":0,"school":"Evocazione","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una mano spettrale fluttuante compare in un punto a gittata, scelto da te. La mano resta per la durata dell’incantesimo o finché non viene interrotta con un’azione. La mano svanisce se si dovesse trovare a più di 9 metri da te o se lanci nuovamente l’incantesimo. Puoi usare la tua azione per controllare la mano. Puoi usare la mano per manipolare un oggetto, aprire una porta o un contenitore non chiusi a chiave, inserire o recuperare un oggetto da un contenitore aperto, o versare fuori i contenuti di una fiala. Puoi muovere la mano di 9 metri ogni volta che la usi. La mano non può attaccare, attivare oggetti magici o trasportare più di 5 chili.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/mano-magica/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('marchio-del-cacciatore', 'marchio-del-cacciatore', 'Marchio del Cacciatore', 1, 'Divinazione', '1 azione bonus', '27 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/marchio-del-cacciatore/', '["ranger"]', '{"name":"Marchio del Cacciatore","level":1,"school":"Divinazione","casting_time":"1 azione bonus","range":"27 metri","components":"V","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"1d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° o 4° livello, puoi mantenere la concentrazione sull’incantesimo per un massimo di 8 ore. Quando usi uno slot incantesimo di 5° livello o superiore, puoi mantenere la concentrazione sull’incantesimo per un massimo di 24 ore.","ritual":false,"description":"Scegli una creatura a gittata che puoi vedere. La creatura è misticamente marchiata come tua preda. Fino al termine dell’incantesimo, infliggi 1d6 danni aggiuntivi al bersaglio ogni volta che lo colpisci con un attacco con arma, e hai vantaggio alle prove di Saggezza (Percezione) o Saggezza (Sopravvivenza) per trovarlo. Se il bersaglio scende a 0 punti ferita prima del termine dell’incantesimo, puoi usare un’azione bonus durante il tuo prossimo turno per marchiare una nuova creatura.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/marchio-del-cacciatore/","classes":["ranger"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('messaggio', 'messaggio', 'Messaggio', 0, 'Trasmutazione', '1 azione', '36 metri', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/messaggio/', '["bardo","mago","stregone"]', '{"name":"Messaggio","level":0,"school":"Trasmutazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un piccolo pezzo di cavo di rame)","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Punti il dito verso una creatura a gittata e sussurri un messaggio. Il bersaglio (e solo il bersaglio) ode il messaggio e può replicare con un sussurro che solo tu puoi udire. Puoi lanciare questo incantesimo anche attraverso oggetti solidi, se sei familiare col bersaglio e sai che questi si trova dietro la barriera. Il silenzio magico, 30 centimetri di pietra, 2,5 centimetri di metallo normale, un sottile foglio di piombo o 1 metro di legno bloccano l’incantesimo. L’incantesimo non deve seguire una linea retta, e può liberamente aggirare gli angoli o attraversare gli spiragli.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/messaggio/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('metamorfosi', 'metamorfosi', 'Metamorfosi', 4, 'Trasmutazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/metamorfosi/', '["bardo","druido","mago","stregone"]', '{"name":"Metamorfosi","level":4,"school":"Trasmutazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un bozzolo di bruco)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo trasforma una creatura a gittata, che puoi vedere, in una nuova forma. Una creatura non consenziente deve superare un tiro salvezza su Saggezza per evitare l’effetto. I mutaforma superano automaticamente il tiro salvezza. L’incantesimo non ha effetto su di un bersaglio con 0 punti ferita. La trasformazione permane per la durata dell’incantesimo o finché il bersaglio non scende a 0 punti ferita o muore. La nuova forma può essere quella di qualsiasi bestia il cui grado di sfida sia uguale o più basso di quello del bersaglio (o del livello del bersaglio, se questi non ha un grado di sfida). Le statistiche di gioco del bersaglio, compresi i punteggi delle caratteristiche mentali, vengono rimpiazzate dalle statistiche della bestia scelta. Egli mantiene però il suo allineamento e personalità. Il bersaglio assume i punti ferita della sua nuova forma. Quando ritorna alla sua forma normale, la creatura ritorna al numero di punti ferita che aveva prima di trasformarsi. Se però si ritrasforma perché ridotto a 0 punti ferita, qualsiasi danno in eccesso si ripercuote sulla sua normale forma. Purché il danno in eccesso non riduca la forma normale della creatura a 0 punti ferita, ella non cade priva di sensi.\nLa creatura è limitata nelle azioni che può svolgere dalla natura della sua nuova forma, e non può dialogare, lanciare incantesimi, o effettuare qualsiasi altra azione che richieda mani o di parlare. L’equipaggiamento del bersaglio si fonde nella nuova forma. La creatura non può attivare, usare, impugnare o beneficiare in alcun modo del suo equipaggiamento.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/metamorfosi/","classes":["bardo","druido","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('metamorfosi-pura', 'metamorfosi-pura', 'Metamorfosi Pura', 9, 'Trasmutazione', '1 azione', '9 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/metamorfosi-pura/', '["bardo","mago","warlock"]', '{"name":"Metamorfosi Pura","level":9,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un goccio di mercurio, un mucchietto di gomma arabica, e uno sbuffo di fumo)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scegli una creatura od oggetto non magico a gittata e che puoi vedere. L’incantesimo non ha effetto su di un bersaglio con 0 punti ferita. Trasformi la creatura in una creatura diversa, la creatura in un oggetto, o l’oggetto in una creatura (l’oggetto non deve essere indossato né trasportato da un’altra creatura). La trasformazione permane per la durata dell’incantesimo o finché il bersaglio non scende a 0 punti ferita o muore. Se ticoncentri su questo incantesimo per l’intera durata, la trasformazione diventa permanente.\nI mutaforma ignorano questo incantesimo. Una creatura non consenziente può effettuare un tiro salvezza su Saggezza e, se lo supera, ignora l’effetto di questo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/metamorfosi-pura/","classes":["bardo","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('miraggio-arcano', 'miraggio-arcano', 'Miraggio Arcano', 7, 'Illusione', '10 minuti', 'Vista', '10 giorni', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/miraggio-arcano/', '["bardo","druido","mago"]', '{"name":"Miraggio Arcano","level":7,"school":"Illusione","casting_time":"10 minuti","range":"Vista","components":"V, S","duration":"10 giorni","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fai sì che un pezzo di terreno a gittata, in un’area quadrata fino a 1,5 chilometri, appaia, risuoni e odori come qualche altro tipo di terreno. La conformazione generale del terreno rimane tuttavia la stessa. Campi aperti o una strada possono essere trasformati in un acquitrino, colline, un crepaccio o qualche altro tipo di terreno difficile o invalicabile. Un laghetto può essere trasformato in una radura erbosa, un precipizio in una lieve pendenza, un burrone cosparso di rocce in una strada ampia e liscia. Allo stesso modo, puoi modificare l’aspetto delle strutture, o aggiungerne dove non ve ne sono. L’incantesimo non camuffa, occulta né aggiungecreature. L’illusione comprende elementi uditivi, visivi, tattili e olfattivi, così da poter trasformare un terreno sgombro in terreno difficile (o viceversa) o impedire altrimenti il movimento nell’area. Qualsiasi pezzo di terreno illusorio (come una pietra o un bastone), che venga rimosso dall’area dell’incantesimo, svanisce immediatamente. Le creature con visione del vero possono vedere oltre l’illusione e distinguere la vera forma del terreno; tuttavia, gli altri elementi dell’illusione rimangono, così, sebbene la creatura sia consapevole della presenza dell’illusione, vi può comunque interagire fisicamente.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/miraggio-arcano/","classes":["bardo","druido","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('modificare-memoria', 'modificare-memoria', 'Modificare Memoria', 5, 'Ammaliamento', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/modificare-memoria/', '["bardo","mago"]', '{"name":"Modificare Memoria","level":5,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, puoi alterare i ricordi di un bersaglio riguardo un evento svoltosi fino a 7 giorni prima (6° livello), 30 giorni prima (7° livello), 1 anno prima (8° livello) o qualsiasi punto nel passato della creatura (9° livello).","ritual":false,"description":"Tenti di rimodellare i ricordi di un’altra creatura. Una creatura che puoi vedere deve effettuare un tiro salvezza su Saggezza. Se la stai combattendo, la creatura ha vantaggio sul tiro salvezza. Se fallisce il tiro salvezza, il bersaglio diventa affascinato da te per la durata dell’incantesimo. Il bersaglio affascinato è inabile e inconsapevole dell’ambiente circostante, sebbene sia ancora in grado di udirti. Se subisce danni o diviene bersaglio di un altro incantesimo, questo incantesimo termina, e nessuno dei ricordi del bersaglio viene modificato. Mentre il bersaglio resta affascinato da questo incantesimo, puoi agire sui ricordi del bersaglio in merito a un evento che abbia vissuto nelle ultime 24 ore e che non sia durato più di 10 minuti. Puoi eliminare permanentemente tutti i ricordi dell’evento, permettere al bersaglio di ricordare l’evento con perfetta chiarezza e dettagli particolareggiati, modificare il ricordo dei dettagli dell’evento, o creare il ricordo di un altro evento. Devi poter parlare al bersaglio per descrivere il modo in cui i suoi ricordi saranno colpiti, e questi deve essere in grado di comprendere il tuo linguaggio, affinché i ricordi modificati si instaurino nella sua memoria. Se l’incantesimo termina prima che tu abbia finito di descrivere i ricordi modificati, la memoria della creatura non viene alterata. Altrimenti, i ricordi modificati si instaurano al termine dell’incantesimo.\nUna memoria modificata non influisce necessariamente sul comportamento della creatura, in particolare se i suoi ricordi contraddicono le inclinazioni naturali, l’allineamento o la fede della creatura. Una memoria modificata in modo illogico, come impiantare il ricordo di quanto la creatura ami immergersi nell’acido, viene rimossa, come fosse un brutto sogno. Il GM può giudicare un ricordo modificato troppo insensato perché abbia alcun effetto su di una creatura.\nUn incantesimo rimuovi maledizione o ristorare superiore lanciato sul bersaglio ne ripristina i veri ricordi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/modificare-memoria/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('movimenti-del-ragno', 'movimenti-del-ragno', 'Movimenti del Ragno', 2, 'Trasmutazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/movimenti-del-ragno/', '["mago","stregone","warlock"]', '{"name":"Movimenti del Ragno","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (una goccia di bitume e un ragno)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente. Fino al termine dell’incantesimo, la creatura ottiene la capacità di spostarsi verso l’alto, il basso e lungo superfici verticali o stando a testa in giù sul soffitto, tenendo le mani libere. Il bersaglio ottiene anche velocità di scalata pari alla sua velocità di passeggio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/movimenti-del-ragno/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muovere-il-terreno', 'muovere-il-terreno', 'Muovere il Terreno', 6, 'Trasmutazione', '1 azione', '36 metri', 'Concentrazione, massimo 2 ore', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muovere-il-terreno/', '["druido","mago","stregone"]', '{"name":"Muovere il Terreno","level":6,"school":"Trasmutazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un badile di ferro e un piccola borsa contenente un misto di tipi di terreno – argilla, concime e sabbia)","duration":"Concentrazione, massimo 2 ore","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scegli un’area sul terreno a gittata, non più grande di 12 metri di lato. Per la durata, puoi rimodellare terriccio, sabbia o argilla nell’area in qualsiasi modo tu voglia. Puoi innalzare o abbassare l’altitudine dell’area, creare o riempire un fossato, erigere o abbassare un muro, o formare un pilastro. La portata di questi cambiamenti non può eccedere metà della dimensione più grossa dell’area. Così, se operi su di un quadrato di 12 metri di lato, puoi creare un pilastro alto 6 metri, innalzare o abbassare l’altitudine del terreno di 6 metri, scavare un fossato profondo 6 metri, e così via. Ci vogliono 10 minuti per completare questi mutamenti.\nAl termine di ogni 10 minuti trascorsi a concentrarsi sull’incantesimo, puoi scegliere una nuova area di terreno su cui operare. Dato che la trasformazione del terreno avviene lentamente, le creature nell’area di solito non possono restare intrappolate o ferite dal movimento del terreno. L’incantesimo non può manipolare la pietra naturale o le costruzioni in pietra. Le rocce e le strutture si muovono per adattarsi al nuovo terreno. Se il modo in cui modelli il terreno renderebbe una struttura instabile, questa potrebbe crollare.\nAllo stesso modo, questo incantesimo non influenza direttamente la crescita dei vegetali. La terra smossa trasporta con sé qualsiasi vegetale presente.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muovere-il-terreno/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muro-di-forza', 'muro-di-forza', 'Muro di Forza', 5, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muro-di-forza/', '["mago"]', '{"name":"Muro di Forza","level":5,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un pizzico di polvere prodotta frantumando una gemma trasparente)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un invisibile muro di forza si forma in un punto a gittata scelto da te. Il muro appare in qualsiasi orientamento da te desiderato, come una barriera orizzontale o verticale oppure angolata. Può fluttuare nell’aria o appoggiarsi su di una superficie solida. Puoi darle la forma di una cupola semisferica o di una sfera con un raggio massimo di 3 metri, oppure darle l’aspetto di una superficie piana composta da un massimo di dieci pannelli di 3 metri per 3 metri. Ogni pannello deve essere contiguo a un altro pannello. In qualsiasi forma, il muro ha uno spessore di 75 centimetri e resta per tutta la durata dell’incantesimo. Se il muro taglia uno spazio di una creatura, quando compare, la creatura viene spinta da un lato del muro (a tua discrezione). Nulla può attraversare fisicamente il muro. È immune a tutti i danni e non può essere dissolto da dissolvi magie. Tuttavia, il muro è distrutto all’istante dall’incantesimo disintegrazione. Il muro si estende anche sul Piano Etereo, impedendo ai viaggiatori eterei di attraversarlo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muro-di-forza/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muro-di-fuoco', 'muro-di-fuoco', 'Muro di Fuoco', 4, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muro-di-fuoco/', '["druido","mago","stregone"]', '{"name":"Muro di Fuoco","level":4,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un piccolo pezzo di fosforo)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"5d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 4°.","ritual":false,"description":"Crei un muro di fuoco su di una superficie solida a gittata. Puoi creare un muro lungo fino a 18 metri, alto fino a 6 metri e spesso 30 centimetri, o un muro circolare di 6 metri di diametro, 6 metri di altezza e 30 centimetri di spessore. Il muro è opaco e rimane per la durata dell’incantesimo. Quando il muro appare, ogni creatura nella sua area deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 5d8 danni da fuoco se fallisce il tiro salvezza, o la metà se lo supera. Un lato del muro, selezionato da te quando lanci questo incantesimo, infligge 5d8 danni da fuoco a ciascuna creatura che termini il suo turno entro 3 metri da quel lato o all’interno del muro. Una creatura subisce lo stesso danno quando entra nel muro per la prima volta durante un turno. L’altro lato del muro non infligge danni.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muro-di-fuoco/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muro-di-ghiaccio', 'muro-di-ghiaccio', 'Muro di Ghiaccio', 6, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muro-di-ghiaccio/', '["mago"]', '{"name":"Muro di Ghiaccio","level":6,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un piccolo pezzo di quarzo)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"10d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, entrambi i tipi di danno aumentano di 1d8 per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Crei un muro di ghiaccio su di una superficie solida a gittata. Puoi creare una cupola semisferica o una sfera con un raggio massimo di 3 metri, o puoi creare una superficie piana composta di un massimo di dieci panelli quadrati di 3 metri di lato. Ogni pannello deve essere contiguo ad almeno un altro pannello. In ogni forma, il muro è spesso 30 centimetri e rimane per la durata dell’incantesimo.\nSe, quando compare, il muro attraversa lo spazio di una creatura, la creatura viene spinta da una parte del muro (a tua scelta) e deve effettuare un tiro salvezza su Destrezza. Se fallisce il tiro salvezza, la creatura subisce 10d6 danni da freddo, o la metà di questi danni se lo supera.\nIl muro è un oggetto che può essere danneggiato e sfondato. Ogni sezione di 3 metri ha CA 12 e 30 punti ferita, ed è vulnerabile al danno da fuoco. Ridurre una sezione di 3 metri a 0 punti ferita la distrugge e lascia nello spazio che era occupato dal muro una brezza di vento gelido. Una creatura che si muova attraverso questa brezza di vento gelido per la prima volta in un turno, deve effettuare un tiro salvezza su Costituzione. Se lo fallisce, la creatura subisce 5d6 danni da freddo, o la metà di questi danni se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muro-di-ghiaccio/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muro-di-pietra', 'muro-di-pietra', 'Muro di Pietra', 5, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muro-di-pietra/', '["druido","mago","stregone"]', '{"name":"Muro di Pietra","level":5,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un piccolo blocco di granito)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un muro di pietra solida non magico si forma in un punto a gittata, scelto da te. Il muro è spesso 15 centimetri ed è composto di pannelli di 3 per 3 metri. Ogni pannello deve essere contiguo ad almeno un altro pannello. In alternativa, puoi creare pannelli 3 x 6 metri di soli 7,5 centimetri di spessore.\nSe, quando compare, il muro attraversa lo spazio di una creatura, la creatura viene spinta da una parte del muro (a tua scelta). Se la creatura fosse circondata da tutte le parti dal muro (o dal muro e un’altra superficie solida), la creatura può effettuare un tiro salvezza su Destrezza. Se lo supera, può usare la sua reazione per muoversi della sua velocità in modo da non essere più intrappolata nel muro. Il muro può aver qualsiasi forma tu desideri, sebbene non possa occupare lo stesso spazio di una creatura od oggetto. Il muro può anche non essere verticale o poggiare su di un piano. Deve, tuttavia, fondersi con ed essere sostenuto da pietra già esistente. Quindi, puoi usare questo incantesimo per creare un ponte su di un baratro o creare un rampa. Se crei un muro non verticale del genere, più lungo di 6 metri, devi dimezzare le dimensioni di ciascun pannello per creare dei supporti. Puoi modellare rozzamente la pietra per creare merlature, spalti e così via. Il muro è un oggetto fatto di pietra che può essere danneggiato e sfondato. Ogni pannello ha CA 15 e 30 punti ferita ogni 2,5 centimetri di spessore. Ridurre un pannello a 0 punti ferita lo distrugge e potrebbe far crollare i pannelli connessi, a discrezione del GM. Se mantieni la concentrazione su questo incantesimo per la sua intera durata, il muro diventa permanente e non può essere dissolto. Altrimenti, il muro sparisce al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muro-di-pietra/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muro-di-spine', 'muro-di-spine', 'Muro di Spine', 6, 'Evocazione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muro-di-spine/', '["druido"]', '{"name":"Muro di Spine","level":6,"school":"Evocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (una manciata di spine)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"7d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Crei un muro di cespugli robusti, malleabili e impigliati, ricolmi di spine appuntite. Il muro compare a gittata su di una superficie solida e rimane per la durata dell’incantesimo. Il muro che puoi creare può essere lungo fino a 18 metri, alto fino a 3 metri, e spesso fino a 1,5 metri o un circolo che abbia un diametro di 6 metri e sia alto fino a 6 metri e spesso 1,5 metri. Il muro blocca la linea di visuale.\nQuando il muro compare, ogni creatura nella sua area deve effettuare un tiro salvezza su Destrezza. Se fallisce il tiro salvezza, una creatura subisce 7d8 danni perforanti, o la metà di questi danni se lo supera.\nUna creatura può muoversi attraverso il muro, seppure in maniera lenta e dolorosa. Per ogni 1,5 metri che la creatura si muove attraverso il muro, deve spendere 6 metri di movimento. Inoltre, la prima volta che una creatura entra nel muro durante un turno o vi termina il suo turno dentro, la creatura deve effettuare un tiro salvezza su Destrezza. Subisce 7d8 danni taglienti se fallisce il tiro salvezza, o la metà di questi danni se lo supera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muro-di-spine/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muro-di-vento', 'muro-di-vento', 'Muro di Vento', 3, 'Invocazione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muro-di-vento/', '["druido","ranger"]', '{"name":"Muro di Vento","level":3,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S, M (un minuscolo ventaglio e una piuma di origini esotiche)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Forza","attack_roll":false,"damage":"3d8","scaling":null,"ritual":false,"description":"Un muro di forte vento si leva dal terreno in un punto a gittata di tua scelta. Puoi creare un muro lungo fino a 15 metri, alto 4,5 metri e spesso 30 centimetri. Puoi modellare il muro in qualsiasi maniera desideri purché componga un percorso continuo sul terreno. Il muro rimane per la durata dell’incantesimo. Quando il muro appare, ogni creatura all’interno della sua area deve effettuare un tiro salvezza su Forza. Una creatura subisce 3d8 danni contundenti se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Il forte vento tiene lontana foschia, fumo e altri gas. Le creature volanti di taglia Piccola o minore non possono attraversare il muro. I materiali leggeri trascinati nel muro volano verso l’alto. Frecce, quadrelli e altre munizioni normali vengono deviati e mancano automaticamente il bersaglio (i macigni scagliati dai giganti e dalle macchine d’assedio, e munizioni simili, ne ignorano invece gli effetti). Le creature in forma gassosa non possono attraversarlo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muro-di-vento/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('muro-prismatico', 'muro-prismatico', 'Muro Prismatico', 9, 'Abiurazione', '1 azione', '18 metri', '10 minuti', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/muro-prismatico/', '["mago"]', '{"name":"Muro Prismatico","level":9,"school":"Abiurazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"10 minuti","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un piano di luci brillanti e multicolore forma un muro verticale opaco, largo fino a 27 metri, alto 9 metri e spesso 2,5 centimetri, centrato su di un punto a gittata e che puoi vedere. In alternativa, puoi modellare il muro in una sfera, fino a 9 metri di diametro, centrata su di un punto a gittata di tua scelta. Il muro resta fisso sul posto per la durata dell’incantesimo. Se posizioni il muro in modo che attraversi lo spazio occupato da unacreatura, l’incantesimo fallisce, e la tua azione e lo slot incantesimo sono sprecati. Il muro irradia luce intensa fino a una gittata di 30 metri e luce fioca per ulteriori 30 metri. Tu e le creature indicate da te al momento del lancio dell’incantesimo potete attraversare e restare vicini al muro senza pericolo. Se un’altra creatura che può vedere il muro si muove entro 6 metri da esso o inizia lì il suo turno, deve superare un tiro salvezza su Costituzione o restare accecata per 1 minuto. Il muro consiste di sette strati, ognuno di un diverso colore. Quando una creatura cerca di immergersi o attraversare il muro, lo fa uno strato alla volta, attraverso tutti gli strati del muro. Mentre si immerge o attraversa ciascuno strato, la creatura deve superare un tiro salvezza su Destrezza o subire le proprietà di ciascuno strato, uno alla volta, come descritto di seguito. Il muro può essere distrutto, uno strato alla volta, in ordine dal rosso al violetto, in un modo specifico per ogni strato. Una volta che uno strato è distrutto, lo sarà per la durata dell’incantesimo. Una verga di cancellazione distrugge un muro prismatico, ma un campo anti-magia non ha effetto su di esso.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/muro-prismatico/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('nube-di-nebbia', 'nube-di-nebbia', 'Nube di Nebbia', 1, 'Evocazione', '1 azione', '36 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/nube-di-nebbia/', '["druido","mago","ranger","stregone"]', '{"name":"Nube di Nebbia","level":1,"school":"Evocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, il raggio della foschia aumenta di 6 metri per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Crei una sfera di foschia del raggio di 6 metri centrata su di un punto a gittata. La sfera si propaga intorno agli angoli, e la sua area è oscurata pesantemente. Rimane per la durata dell’incantesimo o finché un vento di velocità moderata o superiore (almeno 15 chilometri all’ora) non la disperde.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/nube-di-nebbia/","classes":["druido","mago","ranger","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('nube-di-pugnali', 'nube-di-pugnali', 'Nube di Pugnali', 2, 'Evocazione', '1 azione', '18 metri', 'Fino a 1 minuto', 1, 0, 'SRD', NULL, '["warlock"]', '{"name":"Nube di Pugnali","level":2,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (una scheggia di vetro)","duration":"Fino a 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"4d4 (taglienti)","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o superiore, i danni aumentano di 2d4 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Crei una nube di pugnali che riempie un cubo di 1,5 metri di lato, centrato su un punto a gittata che puoi vedere. Una creatura subisce 4d4 danni taglienti quando entra per la prima volta in un turno nell’area dell’incantesimo o quando inizia il suo turno lì.","usage":null,"rest":null,"_source":null,"classes":["warlock"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('nube-incendiaria', 'nube-incendiaria', 'Nube Incendiaria', 8, 'Evocazione', '1 azione', '45 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/nube-incendiaria/', '["mago","stregone"]', '{"name":"Nube Incendiaria","level":8,"school":"Evocazione","casting_time":"1 azione","range":"45 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"10d8","scaling":null,"ritual":false,"description":"Una nube di fumo turbinante attraversata da lapilli incandescenti si forma in una sfera di 6 metri di raggio centrata su di un punto a gittata. La nube si propaga intorno agli angoli ed è oscurata pesantemente. Rimane per la durata dell’incantesimo o finché un vento di velocità moderata o superiore (almeno 15 chilometri all’ora) non la disperde. Quando la nube appare, ogni creatura al suo interno deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 10d8 danni da fuoco se fallisce il tiro salvezza, e la metà di questi danni se lo supera. Una creatura deve effettuare il tiro salvezza anche quando entra per la prima volta nell’area o termina lì il suo turno. All’inizio di ciascun tuo turno, la nube si muove di 3 metri lontano da te in una direzione a tua scelta.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/nube-incendiaria/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('nube-maleodorante', 'nube-maleodorante', 'Nube Maleodorante', 3, 'Evocazione', '1 azione', '27 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/nube-maleodorante/', '["bardo","mago","stregone"]', '{"name":"Nube Maleodorante","level":3,"school":"Evocazione","casting_time":"1 azione","range":"27 metri","components":"V, S, M (un uovo marcio o foglie di cavolo puzzolente)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei, in un punto a gittata, una sfera di 6 metri di raggio composta di un gas giallo e nauseabondo. La nube si propaga dietro gli angoli e la sua area è oscurata pesantemente. La nube permane nell’aria per la durata. Ogni creatura che si trovi completamente all’interno della nube all’inizio del proprio turno, deve effettuare un tiro salvezza su Costituzione contro il veleno. Se il tiro salvezza fallisce, la creatura spende la sua azione di quel turno a vomitare e barcollare. Le creature che non hanno bisogno di respirare o che sono immuni al veleno superano automaticamente il tiro salvezza. Un vento moderato (almeno 15 chilometri all’ora) disperde la nube dopo 4 round. Un vento forte (almeno 30 chilometri all’ora) lo disperde dopo 1 round.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/nube-maleodorante/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('nube-mortale', 'nube-mortale', 'Nube Mortale', 5, 'Evocazione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/nube-mortale/', '["mago","stregone"]', '{"name":"Nube Mortale","level":5,"school":"Evocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":"5d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, il danno aumenta di 1d8 metri per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Crei una sfera di 6 metri di raggio formata da una nebbia velenosa giallo-verde centrata in un punto a gittata di tua scelta. La nebbia si propaga dietro gli angoli. Rimane per la durata dell’incantesimo o finché un forte vento non disperde la nebbia, terminando l’incantesimo. La sua area è oscurata pesantemente. Quando una creatura entra nell’area dell’incantesimo per la prima volta in un turno o inizia lì il suo turno, quella creatura deve effettuare un tiro salvezza su Costituzione. La creatura subisce 5d8 danni da veleno se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Le creature ne sono soggette anche se trattengono il respiro o non hanno bisogno di respirare. La nebbia si allontana di 3 metri da te all’inizio di ogni tuo turno, spostandosi lungo la superficie del terreno. I vapori, essendo più pesanti dell’aria, tendono a scendere verso il basso, arrivando addirittura a insinuarsi nelle aperture.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/nube-mortale/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('occhio-arcano', 'occhio-arcano', 'Occhio Arcano', 4, 'Divinazione', '1 azione', '9 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/occhio-arcano/', '["mago"]', '{"name":"Occhio Arcano","level":4,"school":"Divinazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un pezzo di manto di pipistrello)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei a gittata un occhio magico e invisibile, che fluttua nell’aria per la durata dell’incantesimo. Ricevi mentalmente le informazioni visive dall’occhio, che ha vista normale e scurovisione fino a 9 metri. L’occhio può guardare in tutte le direzioni.\nCon un’azione, puoi spostare l’occhio di 9 metri in qualsiasi direzione. Non c’è limite a quanto lontano possa spostarsi l’occhio, ma non può entrare in un altro piano di esistenza. Una barriera solida blocca il movimento dell’occhio, ma questo può attraversare un’apertura di una grandezza minima di 2,5 centimetri di diametro.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/occhio-arcano/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('onda-tonante', 'onda-tonante', 'Onda Tonante', 1, 'Invocazione', '1 azione', 'Incantatore (cubo di 4,5 metri di spigolo)', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/onda-tonante/', '["bardo","druido","mago","stregone"]', '{"name":"Onda Tonante","level":1,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore (cubo di 4,5 metri di spigolo)","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"2d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Un’onda di forza tonante si proietta da te. Ogni creatura in un cubo di 4,5 metri di spigolo che origina da te deve effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza, una creatura subisce 2d8 danni da tuono e viene allontana 3 metri da te. Se supera il tiro salvezza, la creatura subisce la metà dei danni e non viene allontanata. Inoltre, gli oggetti non ancorati che sono totalmente all’interno dell’area vengono spinti 3 metri lontano da te dall’effetto dell’incantesimo, e l’incantesimo produce un rimbombo tonante udibile fino a 90 metri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/onda-tonante/","classes":["bardo","druido","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('oscurita', 'oscurita', 'Oscurità', 2, 'Invocazione', '1 azione', '18 metri', 'Concentrazione massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/oscurita/', '["mago","stregone","warlock"]', '{"name":"Oscurità","level":2,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, M (pelo di pipistrello e un pizzico di bitume o un pezzo di carbone)","duration":"Concentrazione massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"L’oscurità magica si propaga da un punto a gittata, scelto da te, per riempire una sfera di 4,5 metri di raggio per la durata dell’incantesimo. L’oscurità si propaga intorno agli angoli. Una creatura con scurovisione non può vedere in questa oscurità, e la luce non magica non può illuminarla. Se il punto che hai scelto è su di un oggetto che stai trasportando o uno che non è indossato o trasportato, l’oscurità emana dall’oggetto e si muove con esso. Coprire completamente la fonte dell’oscurità con un oggetto opaco, come un vaso o un elmo, blocca l’oscurità. Se qualsiasi parte dell’area di questo incantesimo si sovrappone con l’area di luce creata da un incantesimo di 2° livello o più basso, l’incantesimo che ha creato la luce viene dissolto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/oscurita/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('palla-di-fuoco', 'palla-di-fuoco', 'Palla di Fuoco', 3, 'Invocazione', '1 azione', '45 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/palla-di-fuoco/', '["mago","stregone"]', '{"name":"Palla di Fuoco","level":3,"school":"Invocazione","casting_time":"1 azione","range":"45 metri","components":"V, S, M (una minuscola palla di guano di pipistrello e zolfo)","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"8d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il danno base aumenta di 1d6 per ogni livello dello slot sopra il 3°.","ritual":false,"description":"Un fascio di luce gialla parte dal tuo dito puntato verso un punto a gittata scelto da te, e poi esplode con un boato sommesso e si trasforma in un getto di fiamme. Ogni creatura in una sfera di 6 metri di raggio centrata in quel punto deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 8d6 danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Il fuoco si propaga intorno agli angoli. Il fuoco incendia gli oggetti infiammabili nell’area che non sono indossati o trasportati.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/palla-di-fuoco/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('palla-di-fuoco-ritardata', 'palla-di-fuoco-ritardata', 'Palla di Fuoco Ritardata', 7, 'Invocazione', '1 azione', '45 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/palla-di-fuoco-ritardata/', '["mago","stregone"]', '{"name":"Palla di Fuoco Ritardata","level":7,"school":"Invocazione","casting_time":"1 azione","range":"45 metri","components":"V, S, M (una minuscola palla di guano di pipistrello e zolfo)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 8° livello o più alto, il danno base aumenta di 1d6 per ogni livello dello slot sopra il 7°.","ritual":false,"description":"Un fascio di luce gialla parte dal tuo dito puntato, per condensarsi per la durata dell’incantesimo nella forma di una pallina luminosa in un punto a gittata, scelto da te. Quando l’incantesimo termina, o perché la tua concentrazione è spezzata o perché decidi tu di porgli fine, la pallina esplode con un boato sommesso e si trasforma in un getto di fiamme che si propaga dietro gli angoli. Ogni creatura in una sfera di 6 metri di raggio centrata in quel punto deve effettuare un tiro salvezza su Destrezza. Una creatura subisce danni da fuoco pari al danno totale accumulato se fallisce il tiro salvezza, o la metà di questi danni se lo supera.\nIl danno base dell’incantesimo è 12d6. Se al termine del tuo turno la pallina non è ancora detonata, il danno aumenta di 1d6. Se la pallina luminosa viene toccata prima che l’incantesimo abbia avuto fine, la creatura che la tocca deve effettuare un tiro salvezza su Destrezza. Se fallisce il tiro salvezza, l’incantesimo termina immediatamente, facendo eruttare fiamme dalla pallina. Se supera il tiro salvezza, la creatura può lanciare la pallina fino a 12 metri di distanza. Quando colpisce una creatura od oggetto solido, l’incantesimo ha fine e la pallina esplode.\nIl fuoco danneggia gli oggetti nell’area e incendia gli oggetti infiammabili che non sono indossati o trasportati.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/palla-di-fuoco-ritardata/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parata', 'parata', 'Parata', 0, 'Manovra', 'Reazione (quando subisci danni da un attacco in mischia)', 'Se stesso', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Parata","level":0,"school":"Manovra","casting_time":"Reazione (quando subisci danni da un attacco in mischia)","range":"Se stesso","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando un''altra creatura infligge danni al\nguerriero con un attacco in mischia, il guerriero può usare\nla sua reazione e spendere un dado di superiorità per\nridurre i danni del numero ottenuto con il tiro del suo dado\ndi superiorità + il suo modificatore di Destrezza.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parlare-con-gli-animali', 'parlare-con-gli-animali', 'Parlare con gli Animali', 1, 'Divinazione', '1 azione', 'Incantatore', '10 minuti', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parlare-con-gli-animali/', '["bardo","druido","ranger"]', '{"name":"Parlare con gli Animali","level":1,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"10 minuti","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Per la durata dell’incantesimo, ottieni la capacità di comprendere e comunicare verbalmente con le bestie. Il sapere e la consapevolezza di molte bestie sono limitati dal loro intelletto ma, come minimo, le bestie possono fornirti informazioni riguardo luoghi e mostri nelle vicinanze, compresi quelli che possono percepire o hanno percepito nei giorni passati. A discrezione del GM potresti riuscire a convincere una bestia a farti un piccolo favore.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parlare-con-gli-animali/","classes":["bardo","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parlare-con-i-morti', 'parlare-con-i-morti', 'Parlare con i Morti', 3, 'Necromanzia', '1 azione', '3 metri', '10 minuti', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parlare-con-i-morti/', '["bardo","chierico"]', '{"name":"Parlare con i Morti","level":3,"school":"Necromanzia","casting_time":"1 azione","range":"3 metri","components":"V, S, M (incenso acceso)","duration":"10 minuti","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Conferisci un’apparenza di vita e intelligenza a un cadavere a gittata, scelto da te, permettendogli di rispondere alle domande che gli poni. Il cadavere deve avere ancora una bocca e non può essere non morto. L’incantesimo fallisce se il cadavere è già stato bersaglio di questo incantesimo negli ultimi 10 giorni. Fino al termine dell’incantesimo, puoi porre al cadavere fino a cinque domande. Il cadavere conosce solo quello che già sapeva in vita, compresi i linguaggi parlati. Le risposte sono di solito brevi, criptiche o ripetitive, e il cadavere non è sotto nessun obbligo a darti risposte veritiere se gli sei ostile o ti riconosce come suo nemico. Questo incantesimo non riporta l’anima della creatura nel corpo, ma solo lo spirito che lo muove. Di conseguenza, il cadavere non può apprendere nuove informazioni, non capisce nulla di quello che è successo da quando è morto, e non può fare valutazioni su eventi futuri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parlare-con-i-morti/","classes":["bardo","chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parlare-con-le-piante', 'parlare-con-le-piante', 'Parlare con le Piante', 3, 'Trasmutazione', '1 azione', 'Incantatore (raggio di 9 metri)', '10 minuti', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parlare-con-le-piante/', '["bardo","druido","ranger"]', '{"name":"Parlare con le Piante","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"Incantatore (raggio di 9 metri)","components":"V, S","duration":"10 minuti","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Infondi i vegetali entro 9 metri da te di capacità senziente e di limitata mobilità, dandole la capacità di comunicare con te ed eseguire dei semplici comandi. Puoi interrogare i vegetali in merito a eventi avvenuti nell’ultimo giorno nell’area dell’incantesimo, ottenendo informazioni sulle creature di passaggio, il clima e altro. Puoi anche trasformare il terreno difficile prodotto dalla crescita dei vegetali (come cespugli e fitto sottobosco) in terreno ordinario per la durata dell’incantesimo. Oppure puoi trasformare del terreno normale in cui siano presenti dei vegetali in terreno difficile, che rimane per la durata dell’incantesimo facendo sì, per esempio, che rampicanti e rami rallentino gli inseguitori. A discrezione del GM i vegetali potrebbero svolgere anche altri compiti per tuo conto. L’incantesimo non permette ai vegetali di sradicarsi e muoversi, ma possono muovere liberamente rami, steli e gambi. Se una creatura vegetale si trova nell’area, puoi comunicare con essa come se parlaste lo stesso linguaggio, ma non ottieni alcuna capacità magica per influenzarla.\nQuesto incantesimo può far sì che i vegetali creati dall’incantesimo intralciare rilascino una creatura intralciata.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parlare-con-le-piante/","classes":["bardo","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parola-del-potere-stordire', 'parola-del-potere-stordire', 'Parola del Potere Stordire', 8, 'Ammaliamento', '1 azione bonus', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parola-del-potere-stordire/', '["bardo","mago","stregone","warlock"]', '{"name":"Parola del Potere Stordire","level":8,"school":"Ammaliamento","casting_time":"1 azione bonus","range":"18 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Pronunci una parola di potere che può travolgere la mente di una creatura a gittata e che puoi vedere, lasciandola confusa. Se il bersaglio ha 150 punti ferita o meno, è stordito. Altrimenti, l’incantesimo non ha effetto. Il bersaglio stordito deve effettuare un tiro salvezza su Costituzione al termine di ciascun suo turno. Se lo supera, l’effetto di stordimento ha fine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parola-del-potere-stordire/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parola-del-potere-uccidere', 'parola-del-potere-uccidere', 'Parola del Potere Uccidere', 9, 'Ammaliamento', '1 azione bonus', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parola-del-potere-uccidere/', '["bardo","mago","stregone","warlock"]', '{"name":"Parola del Potere Uccidere","level":9,"school":"Ammaliamento","casting_time":"1 azione bonus","range":"18 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Pronunci una parola di potere che costringe a morire all’istante una creatura a gittata che puoi vedere. Se la creatura che scegli ha 100 punti ferita o meno, muore. Altrimenti, l’incantesimo non ha effetto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parola-del-potere-uccidere/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parola-del-ritiro', 'parola-del-ritiro', 'Parola del Ritiro', 6, 'Evocazione', '1 azione', '1,5 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parola-del-ritiro/', '["chierico"]', '{"name":"Parola del Ritiro","level":6,"school":"Evocazione","casting_time":"1 azione","range":"1,5 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Te e fino a cinque creature consenzienti entro 1,5 metri da te vi teletrasportate istantaneamente in un luogo sicuro indicato precedentemente, detto santuario. Tu e tutte le creature teletrasportate con te, riapparite nello spazio non occupato più vicino al punto indicato quando hai preparato questo santuario (vedi sotto). Se lanci questo incantesimo senza aver prima preparato un santuario, l’incantesimo non ha effetto. Devi indicare un santuario, lanciando l’incantesimo all’interno del luogo, per esempio un tempio, che sia dedicato o fortemente collegato alla tua divinità. Se tenti di lanciare l’incantesimo in questa maniera in un’area che non sia dedicata alla tua divinità, l’incantesimo non ha effetto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parola-del-ritiro/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parola-divina', 'parola-divina', 'Parola Divina', 7, 'Invocazione', '1 azione bonus', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parola-divina/', '["chierico"]', '{"name":"Parola Divina","level":7,"school":"Invocazione","casting_time":"1 azione bonus","range":"9 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Pronunci una parola divina, infusa del potere che ha modellato il mondo all’alba della creazione. Scegli un qualsiasi numero di creature a gittata e che puoi vedere. Ogni creatura che può udirti deve effettuare un tiro salvezza su Carisma. Se fallisce il tiro salvezza, la creatura subisce un effetto in base ai suoi attuali punti ferita:\n0 punti ferita o meno: assordata per 1 minuto 40 punti ferita o meno: assordata e accecata per 10minuti 30 punti ferita o meno: accecata, assordata estordita per 1 ora 20 punti ferita o meno: uccisa all’istante\nQuali che siano i suoi attuali punti ferita, un celestiale, elementale, fatato o immondo che fallisca il tiro salvezza è obbligato a tornare al suo piano di origine (se non vi si trova già) e non può tornare sul tuo attuale piano prima che siano passate 24 ore, a meno dell’uso dell’incantesimo desiderio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parola-divina/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parola-guaritrice', 'parola-guaritrice', 'Parola Guaritrice', 1, 'Invocazione', '1 azione bonus', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parola-guaritrice/', '["bardo","chierico","druido"]', '{"name":"Parola Guaritrice","level":1,"school":"Invocazione","casting_time":"1 azione bonus","range":"18 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, la cura aumenta di 1d4 per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Una creatura a gittata che puoi vedere, scelta da te, recupera punti ferita pari a 1d4 + il tuo modificatore di caratteristica da incantatore. Questo incantesimo non ha effetto su non morti o costrutti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parola-guaritrice/","classes":["bardo","chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('parola-guaritrice-di-massa', 'parola-guaritrice-di-massa', 'Parola Guaritrice di Massa', 3, 'Invocazione', '1 azione bonus', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/parola-guaritrice-di-massa/', '["chierico"]', '{"name":"Parola Guaritrice di Massa","level":3,"school":"Invocazione","casting_time":"1 azione bonus","range":"18 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, i punti ferita recuperati aumentano di 1d4 per ogni livello dello slot sopra il 3°.","ritual":false,"description":"Mentre pronunci parole di cura, fino a sei creature a gittata che puoi vedere, scelte da te, recuperano punti ferita pari a 1d4 + il tuo modificatore di caratteristica da incantatore. Questo incantesimo non ha effetto su non morti o costrutti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/parola-guaritrice-di-massa/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('passapareti', 'passapareti', 'Passapareti', 5, 'Trasmutazione', '1 azione', '9 metri', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/passapareti/', '["mago"]', '{"name":"Passapareti","level":5,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un pizzico di semi di sesamo)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata dell’incantesimo, compare un passaggio in un punto a gittata che puoi vedere, su di una superficie di legno, calcina o pietra (come una parete, un soffitto o un pavimento) scelta da te. Scegli le dimensioni dell’apertura: al massimo larga 1,5 metri, alta 2,4 metri e profonda 6 metri. Il passaggio non crea instabilità nella struttura che lo circonda. Quando l’apertura sparisce, qualsiasi creatura od oggetto ancora nel passaggio creato dall’incantesimo viene espulso al sicuro nello spazio non occupato più vicino alla superficie su cui hai lanciato l’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/passapareti/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('passare-senza-tracce', 'passare-senza-tracce', 'Passare Senza Tracce', 2, 'Abiurazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/passare-senza-tracce/', '["druido","ranger"]', '{"name":"Passare Senza Tracce","level":2,"school":"Abiurazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (ceneri di una foglia di vischio bruciata e un ramoscello di abete rosso)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un velo d’ombra e silenzio si irradia da te, proteggendo te e i tuoi compagni dall’essere individuati. Per la durata dell’incantesimo, ogni creatura a tua scelta entro 9 metri da te (te compreso) riceve un bonus di +10 alle prove di Destrezza (Furtività) e le sue tracce non possono essere seguite eccetto che da mezzi magici. Una creatura che riceve questo bonus non lascia tracce né altri segni del suo passaggio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/passare-senza-tracce/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('passo-velato', 'passo-velato', 'Passo Velato', 2, 'Evocazione', '1 azione bonus', 'Incantatore', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/passo-velato/', '["mago","stregone","warlock"]', '{"name":"Passo Velato","level":2,"school":"Evocazione","casting_time":"1 azione bonus","range":"Incantatore","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Avvolto rapidamente da una foschia argentata, ti teletrasporti di massimo 9 metri in uno spazio non occupato che puoi vedere.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/passo-velato/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('passo-veloce', 'passo-veloce', 'Passo Veloce', 1, 'Trasmutazione', '1 azione', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/passo-veloce/', '["bardo","druido","mago","ranger"]', '{"name":"Passo Veloce","level":1,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un pizzico di terra)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, puoi prendere come bersaglio un’ulteriore creatura per ogni livello dello slot sopra il 1°.","ritual":false,"description":"La velocità di una creatura con cui sei in contatto aumenta di 3 metri fino al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/passo-veloce/","classes":["bardo","druido","mago","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('paura', 'paura', 'Paura', 3, 'Illusione', '1 azione', 'Incantatore (cono di 9 metri)', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/paura/', '["bardo","mago","stregone","warlock"]', '{"name":"Paura","level":3,"school":"Illusione","casting_time":"1 azione","range":"Incantatore (cono di 9 metri)","components":"V, S, M (una piuma bianca o il cuore di una gallina)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Proietti un’immagine illusoria delle peggiori paure di una creatura. Ogni creatura in un cono di 9 metri deve superare un tiro salvezza su Saggezza o far cadere qualsiasi cosa stia impugnando e restare spaventata per la durata dell’incantesimo. Mentre è spaventata da questo incantesimo, una creatura deve, durante ciascun suo turno, effettuare l’azione Scattare e muoversi lontano da te tramite il tragitto più sicuro, a meno che non abbia spazio per muoversi. Se la creatura termina il suo turno in un posto dove non ha linea di visuale su di te, può effettuare un tiro salvezza su Saggezza. Se lo supera, l’incantesimo, per quella creatura, ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/paura/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('pelle-di-corteccia', 'pelle-di-corteccia', 'Pelle di Corteccia', 2, 'Trasmutazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/pelle-di-corteccia/', '["druido","ranger"]', '{"name":"Pelle di Corteccia","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (una manciata di corteccia di quercia)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"La pelle del bersaglio con cui sei in contatto al momento del lancio dell’incantesimo diventa ruvida e dall’aspetto simile alla corteccia fino al termine dell’incantesimo, e la CA del bersaglio non può essere inferiore a 16, quale che sia l’armatura che sta indossando.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/pelle-di-corteccia/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('pelle-di-pietra', 'pelle-di-pietra', 'Pelle di Pietra', 4, 'Abiurazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/pelle-di-pietra/', '["druido","mago","ranger","stregone"]', '{"name":"Pelle di Pietra","level":4,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (polvere di diamante del valore di 100 mo, che l’incantesimo consuma)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente, la cui pelle si tramuta in una sostanza dura come la pietra. Fino alla fine dell’incantesimo il bersaglio ha resistenza ai danni contundenti, perforanti e taglienti di natura non magica.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/pelle-di-pietra/","classes":["druido","mago","ranger","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('piaga-degli-insetti', 'piaga-degli-insetti', 'Piaga degli Insetti', 5, 'Evocazione', '1 azione', '90 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/piaga-degli-insetti/', '["chierico","druido","stregone"]', '{"name":"Piaga degli Insetti","level":5,"school":"Evocazione","casting_time":"1 azione","range":"90 metri","components":"V, S, M (qualche granello di zucchero, qualche chicco di grano, e una passata di lardo)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":"4d10","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 6° livello o più alto, il danno aumenta di 1d10 per ogni livello dello slot sopra il 5°.","ritual":false,"description":"Uno sciame di locuste affamate riempie una sfera di 6 metri di raggio centrata in un punto a gittata scelto da te. La sfera si propaga intorno agli angoli. La sfera rimane per la durata dell’incantesimo, e la sua area è oscurata leggermente. L’area della sfera è terreno difficile.\nQuando l’area appare, ogni creatura al suo interno deve effettuare un tiro salvezza su Costituzione. Una creatura subisce 4d10 danni perforanti se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Una creatura deve effettuare questo tiro salvezza anche quando entra per la prima volta nell’area dell’incantesimo durante un turno o se termina il proprio turno al suo interno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/piaga-degli-insetti/","classes":["chierico","druido","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('porta-dimensionale', 'porta-dimensionale', 'Porta Dimensionale', 4, 'Evocazione', '1 azione', '150 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/porta-dimensionale/', '["bardo","mago","stregone","warlock"]', '{"name":"Porta Dimensionale","level":4,"school":"Evocazione","casting_time":"1 azione","range":"150 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"4d6","scaling":null,"ritual":false,"description":"Ti teletrasporti dalla tua attuale posizione in qualsiasi altro posto a gittata. Arrivi esattamente nel posto desiderato. Può essere un luogo che puoi vedere, uno che puoi visualizzare, o uno che puoi descrivere indicando distanza e direzione, come “30 metri verso il basso” o “90 metri in alto a nordovest con un angolo di 45 gradi.”\nPuoi portare con te oggetti il cui peso non ecceda la tua capacità di carico. Puoi portare con te anche una creatura consenziente della tua taglia o più piccola con equipaggiamento fino al limite della sua capacità di carico. La creatura deve essere entro 1,5 metri da te quando lanci questo incantesimo.\nSe dovessi arrivare in un posto già occupato da un oggetto o creatura, tu e la creatura che viaggia con te subite ciascuno 4d6 danni da forza, e l’incantesimo non riesce a teletrasportarvi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/porta-dimensionale/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('portale', 'portale', 'Portale', 9, 'Evocazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/portale/', '["chierico","mago","stregone"]', '{"name":"Portale","level":9,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un diamante del valore di almeno 5.000 mo)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Evochi in uno spazio non occupato a gittata che puoi vedere un portale collegato a un posto preciso su di un diverso piano di esistenza. Il portale è un’apertura circolare creata da te, da 1,5 a 6 metri di diametro. Puoi orientare il portale in qualsiasi direzione desideri. Il portale resta per la durata. Il portale ha un fronte e un dietro su entrambi i piani in cui compare. Il viaggio attraverso il portale è possibile solo muovendosi dal fronte. Qualsiasi cosa lo faccia viene istantaneamente trasportata nell’altro piano, comparendo nello spazio non occupato più vicino al portale. Divinità e altri sovrani planari possono impedire ai portali creati da incantesimi di aprirsi in loro presenza o in qualsiasi punto dei loro domini. Quando lanci questo incantesimo, puoi pronunciare il nome di una specifica creatura (lo pseudonimo, titolo o soprannome non funzionano). Se quella creatura si trova su di un piano diverso dal tuo, il portale si apre in prossimità della creatura nominata e attira la creatura attraverso di sé, verso lo spazio non occupato più vicino dal tuo lato del portale. Non detieni alcun potere speciale sulla creatura, ed essa è libera di agire come il GM ritiene appropriato. Potrebbe andarsene, attaccarti o aiutarti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/portale/","classes":["chierico","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('preghiera-di-guarigione', 'preghiera-di-guarigione', 'Preghiera di Guarigione', 2, 'Invocazione', '10 minuti', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/preghiera-di-guarigione/', '["chierico"]', '{"name":"Preghiera di Guarigione","level":2,"school":"Invocazione","casting_time":"10 minuti","range":"9 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, la cura aumenta di 1d8 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Fino a sei creature a gittata che puoi vedere, scelte da te, recuperano ciascuna punti ferita pari a 2d8 + il tuo modificatore di caratteristica da incantatore. Questo incantesimo non ha effetto su non morti o costrutti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/preghiera-di-guarigione/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('presagio', 'presagio', 'Presagio', 2, 'Divinazione', '1 minuto', 'Incantatore', 'Istantanea', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/presagio/', '["chierico"]', '{"name":"Presagio","level":2,"school":"Divinazione","casting_time":"1 minuto","range":"Incantatore","components":"V, S, M (dei bastoncini, ossa o simili oggetti marchiati appositamente e del valore di almeno 25 mo)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Gettando bastoncini intarsiati con gemme, facendo rotolare ossa di drago, impilando carte elaborate o impiegando qualche altro strumento di divinazione, ricevi un presagio da un’entità ultraterrena riguardo il risultato di uno specifico corso di azione che intendi intraprendere nei prossimi 30 minuti. Il GM sceglie tra i seguenti presagi:\nProsperità, per i risultati positivi Calamità, per i risultati negativi Prosperità e calamità, per i risultati sia positivi che negativi Nulla, per i risultati che non sono né particolarmente positivi né negativi\nL’incantesimo non tiene conto di ogni possibile circostanza che possa modificare il risultato, come il lancio di ulteriori incantesimi o la perdita o l’arrivo di un alleato. Se lanci l’incantesimo due o più volte prima di aver terminato il tuo prossimo riposo lungo, c’è una probabilità cumulativa del 25% che per ogni lancio dopo il primo tu ottenga una lettura erronea. Il GM effettua questo tiro in segreto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/presagio/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('prestidigitazione', 'prestidigitazione', 'Prestidigitazione', 0, 'Trasmutazione', '1 azione', '3 metri', 'Massimo 1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/prestidigitazione/', '["bardo","mago","stregone","warlock"]', '{"name":"Prestidigitazione","level":0,"school":"Trasmutazione","casting_time":"1 azione","range":"3 metri","components":"V, S","duration":"Massimo 1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo è un trucco magico minore che gli incantatori novizi impiegano per fare pratica. Crei a gittata uno dei seguenti effetti magici:\nCrei un effetto sensoriale innocuo e istantaneo come una pioggia di scintille, un soffio di vento, una debole nota musicale o uno strano odore. Illumini o spegni istantaneamente una candela, una torcia o piccolo fuoco da campo. Ripulisci o insozzi istantaneamente un oggetto non più grosso di 0,03 metri cubi. Raffreddi, riscaldi o insapori per 1 ora fino a 0,03 metri cubi di materiale non vivente. Fai comparire per 1 ora un colore, un piccolo segno o un simbolo su di un oggetto o una superficie. Crei un ninnolo non magico o un’immagine illusoria che entri nella tua mano e che resta fino al termine del tuo prossimo turno.\nSe lanci questo incantesimo più volte, puoi tenere attivi fino a tre effetti non istantanei alla volta, e puoi interrompere uno di questi effetti con un’azione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/prestidigitazione/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('previsione', 'previsione', 'Previsione', 9, 'Divinazione', '1 minuto', 'Contatto', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/previsione/', '["bardo","druido"]', '{"name":"Previsione","level":9,"school":"Divinazione","casting_time":"1 minuto","range":"Contatto","components":"V, S, M (una piuma di colibrì)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente per conferirle una limitata capacità di vedere nell’immediato futuro. Per la durata, il bersaglio non può essere sorpreso e ha vantaggio sui tiri per colpire, prove di caratteristica e tiri salvezza. Inoltre, sempre per la durata, le altre creature hanno svantaggio sui tiri per colpire contro il bersaglio. L’incantesimo ha immediatamente termine se lo lanci di nuovo prima che la sua durata abbia fine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/previsione/","classes":["bardo","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('produrre-fiamma', 'produrre-fiamma', 'Produrre Fiamma', 0, 'Evocazione', '1 azione', 'Incantatore', '10 minuti', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/produrre-fiamma/', '["druido"]', '{"name":"Produrre Fiamma","level":0,"school":"Evocazione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"10 minuti","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1d8","scaling":null,"ritual":false,"description":"Una fiammella compare nella tua mano. La fiammella resta lì per la durata dell’incantesimo e non danneggia né te né il tuo equipaggiamento. La fiamma produce luce intensa nel raggio di 3 metri e luce fioca per ulteriori 3 metri. L’incantesimo termina se lo interrompi con un’azione o se lo lanci di nuovo. Puoi usare la fiamma anche per attaccare, sebbene farlo ponga termine all’incantesimo. Quando lanci questo incantesimo, o con un’azione in un turno successivo, puoi scagliare la fiamma a una creatura entro 9 metri da te. Effettua un attacco a distanza con incantesimo. Se colpisci, il bersaglio subisce 1d8 danni da fuoco. Il danno dell’incantesimo aumenta di 1d8 quando arrivi al 5° livello (2d8), 11° livello (3d8) e 17° livello (4d8).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/produrre-fiamma/","classes":["druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('proibizione', 'proibizione', 'Proibizione', 6, 'Abiurazione', '10 minuti', 'Contatto', '1 giorno', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/proibizione/', '["chierico"]', '{"name":"Proibizione","level":6,"school":"Abiurazione","casting_time":"10 minuti","range":"Contatto","components":"V, S, M (uno spruzzo di acqua sacra, incensi rari, e un rubino in polvere del valore di 1.000 mo)","duration":"1 giorno","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"5d10","scaling":null,"ritual":true,"description":"Crei una interdizione al viaggio magico che protegge fino a 4.000 metri quadri di pavimento, fino a un’altezza di 9 metri dal suolo. Per la durata dell’incantesimo, le creature non possono teletrasportarsi nell’area o usare passaggi, come quello creato dall’incantesimo portale, per entrare nell’area. L’incantesimo protegge l’area dal viaggio planare, e quindi impedisce alle creature di accedere all’area tramite il Piano Astrale, il Piano Etereo, le Lande Fatate o il Mondo delle Ombre, o l’incantesimo spostamento planare. Inoltre, l’incantesimo danneggia i tipi di creatura scelti da te durante il lancio. Scegli uno o più dei seguenti: celestiali, elementali, fatati, immondi e non morti. Quando una creatura selezionata entra nell’area dell’incantesimo per la prima volta in un turno o inizia qui il suo turno, la creatura subisce 5d10 danni radianti o necrotici (a tua scelta, quando lanci l’incantesimo). Quando lanci questo incantesimo, puoi stabilire una parola d’ordine. Una creatura che pronuncia la parola d’ordine mentre entra nell’area dell’incantesimo, non subisce danni da esso. L’area dell’incantesimo non può sovrapporsi all’area di un altro incantesimo proibizione. Se esegui proibizione ogni giorno per 30 giorni nello stesso posto, l’incantesimo durerà finché non viene dissolto, e le componenti materiali saranno consumate durante l’ultimo lancio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/proibizione/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('proiezione-astrale', 'proiezione-astrale', 'Proiezione Astrale', 9, 'Necromanzia', '1 azione', '3 metri', 'Speciale', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/proiezione-astrale/', '["chierico","warlock"]', '{"name":"Proiezione Astrale","level":9,"school":"Necromanzia","casting_time":"1 azione","range":"3 metri","components":"V, S, M (per ogni creatura soggetta a questo incantesimo, devi fornire un giacinto del valore di almeno 1.000 mo e un lingotto d’argento elegantemente scolpito del valore di almeno 100 mo, tutti i quali sono consumati dall’incantesimo)","duration":"Speciale","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Tu e fino ad altre otto creature consenzienti a gittata proiettate i vostri corpi astrali nel Piano Astrale (l’incantesimo fallisce e il lancio è sprecato qualora vi trovaste già in quel piano). Il corpo materiale che ti lasci alle spalle è privo di sensi e in uno stato di animazione sospesa; non ha bisogno di cibo né di acqua e non invecchia. Il tuo corpo astrale assomiglia in tutto e per tutto alla tua forma mortale, replicando le tue statistiche di gioco e i tuoi oggetti. La principale differenza è l’aggiunta di un cordone argenteo che si estende dalle scapole per 30 centimetri dietro di te, divenendo poi invisibile. Il cordone è la tua connessione al tuo corpo materiale. Finché questa connessione resterà intatta, potrai tornare a casa. Se il cordone viene tagliato (un avvenimento che accade solo quando uno specifico effetto lo indica) la tua anima e corpo vengono separati, uccidendoti all’istante.\nLa tua forma astrale può viaggiare liberamente per il Piano Astrale e attraversare i portali che da lì conducono ad altri piani. Se entri in un nuovo piano o ritorni al piano su cui eri al momento del lancio dell’incantesimo, il tuo corpo e i tuoi oggetti vengono trasportati lungo il cordone argenteo, permettendoti di rientrare nel tuo corpo al momento dell’ingresso nel nuovo piano. La tua forma astrale è una incarnazione separata. Qualsiasi danno o altro effetto che si applica a essa, non ha effetto sul tuo corpo fisico, né vi compare al tuo ritorno.\nL’incantesimo ha termine per te e i tuoi compagni quando userai un’azione per interromperlo. Quando l’incantesimo termina, la creatura su cui agisce torna al proprio corpo fisico, e si risveglia. L’incantesimo potrebbe anche avere una fine anticipata per te o uno dei tuoi compagni. Un incantesimo dissolvi magie usato con successo sul corpo astrale o fisico termina l’incantesimo per quella creatura. Se il corpo originale della creatura o la sua forma astrale scende a 0 punti ferita, per quella creatura l’incantesimo ha termine. Se l’incantesimo ha termine e il cordone argenteo è intatto, il cordone trascina indietro al suo corpo la forma astrale della creatura, ponendo fine al suo stato di animazione sospesa. Se vieni riportato al tuo corpo prematuramente, i tuoi compagni devono restare nella loro forma astrale e trovare per proprio conto la via di ritorno ai loro corpi, di solito scendendo a 0 punti ferita.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/proiezione-astrale/","classes":["chierico","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('protezione-dai-veleni', 'protezione-dai-veleni', 'Protezione dai Veleni', 2, 'Abiurazione', '1 azione', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/protezione-dai-veleni/', '["chierico","druido","paladino"]', '{"name":"Protezione dai Veleni","level":2,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Neutralizzi il veleno che agisce su di una creatura avvelenata con cui sei in contatto. Se più di un veleno affligge il bersaglio, neutralizzi il veleno che sai essere presente, o ne neutralizzi uno a caso.\nPer la durata dell’incantesimo, il bersaglio ha vantaggio ai tiri salvezza contro l’essere avvelenato, e ha resistenza al danno da veleno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/protezione-dai-veleni/","classes":["chierico","druido","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('protezione-dal-bene-e-dal-male', 'protezione-dal-bene-e-dal-male', 'Protezione dal Bene e dal Male', 1, 'Abiurazione', '1 azione', 'Contatto', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/protezione-dal-bene-e-dal-male/', '["chierico","mago","paladino","warlock"]', '{"name":"Protezione dal Bene e dal Male","level":1,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (acqua sacra o argento e ferro in polvere, che l’incantesimo consuma)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fino al termine dell’incantesimo, una creatura consenziente in contatto con te al momento dell’esecuzione è protetta da certi tipi di creature: aberrazioni, celestiali, elementali, fatati, immondi e non morti. La protezione conferisce diversi benefici. Le creature di quei tipi hanno svantaggio ai tiri per colpire contro il bersaglio. Il bersaglio non può essere affascinato, spaventato o posseduto da loro. Se il bersaglio è già affascinato, spaventato o posseduto da una simile creatura, il bersaglio ha vantaggio su qualsiasi nuovo tiro salvezza contro l’effetto in questione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/protezione-dal-bene-e-dal-male/","classes":["chierico","mago","paladino","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('protezione-dall-energia', 'protezione-dall-energia', 'Protezione dall’Energia', 3, 'Abiurazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/protezione-dallenergia/', '["chierico","druido","mago","ranger","stregone"]', '{"name":"Protezione dall’Energia","level":3,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente. Per la durata dell’incantesimo, il bersaglio ha resistenza a un tipo di danno scelto da te: acido, freddo, fuoco, fulmine o tuono.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/protezione-dallenergia/","classes":["chierico","druido","mago","ranger","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('punizione-marchiante', 'punizione-marchiante', 'Punizione Marchiante', 2, 'Invocazione', '1 azione bonus', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/punizione-marchiante/', '["paladino"]', '{"name":"Punizione Marchiante","level":2,"school":"Invocazione","casting_time":"1 azione bonus","range":"Incantatore","components":"V","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"2d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, il danno aggiuntivo aumenta di 1d6 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"La prossima volta che colpisci una creatura con un attacco in mischia con arma nella durata dell’incantesimo, l’arma riluce di un bagliore astrale mentre colpisci. L’attacco infligge 2d6 danni radianti aggiuntivi al bersaglio, che diventa visibile qualora sia invisibile ed emette luce fioca in un raggio di 1,5 metri. Inoltre il bersaglio non può diventare invisibile fino al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/punizione-marchiante/","classes":["paladino"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('purificare-cibo-e-bevande', 'purificare-cibo-e-bevande', 'Purificare Cibo e Bevande', 1, 'Trasmutazione', '1 azione', '3 metri', 'Istantanea', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/purificare-cibo-e-bevande/', '["chierico","druido","paladino"]', '{"name":"Purificare Cibo e Bevande","level":1,"school":"Trasmutazione","casting_time":"1 azione","range":"3 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Tutti i cibi e le bevande non magiche in una sfera di 1,5 metri di raggio, centrata in un punto a gittata di tua scelta, vengono purificati e liberati da veleni e malattie.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/purificare-cibo-e-bevande/","classes":["chierico","druido","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('raggio-di-affaticamento', 'raggio-di-affaticamento', 'Raggio di Affaticamento', 2, 'Necromanzia', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/raggio-di-affaticamento/', '["mago","warlock"]', '{"name":"Raggio di Affaticamento","level":2,"school":"Necromanzia","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Un fascio nero di energia debilitante parte dal tuo dito diretto contro una creatura a gittata. Effettua un attacco a distanza con incantesimo contro il bersaglio. Se colpisci, il bersaglio infliggerà la metà dei danni con gli attacchi con arma che usano la Forza fino al termine dell’incantesimo.\nAl termine di ciascun turno del bersaglio, questi può effettuare un tiro salvezza su Costituzione contro l’incantesimo. Se lo supera, l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/raggio-di-affaticamento/","classes":["mago","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('raggio-di-gelo', 'raggio-di-gelo', 'Raggio di Gelo', 0, 'Invocazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/raggio-di-gelo/', '["mago","stregone"]', '{"name":"Raggio di Gelo","level":0,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1d8","scaling":null,"ritual":false,"description":"Un fascio gelato di luce azzurra colpisce una creatura a gittata. Effettua un attacco a distanza con incantesimo contro il bersaglio. Se colpisci, egli subisce 1d8 danni da freddo, e la sua velocità è ridotta di 3 metri fino all’inizio del tuo prossimo turno. Il danno dell’incantesimo aumenta di 1d8 quando raggiungi il 5° livello (2d8), l’11° livello (3d8) e il 17° livello (4d8).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/raggio-di-gelo/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('raggio-rovente', 'raggio-rovente', 'Raggio Rovente', 2, 'Invocazione', '1 azione', '36 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/raggio-rovente/', '["mago","stregone"]', '{"name":"Raggio Rovente","level":2,"school":"Invocazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"2d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, crei un raggio aggiuntivo per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Crei tre raggi di fuoco e li proietti verso tre bersagli a gittata. Puoi proiettarli contro lo stesso bersaglio o bersagli diversi. Effettua un attacco a distanza con incantesimo per ciascun raggio. Se colpisci, il bersaglio subisce 2d6 danni da fuoco.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/raggio-rovente/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('ragnatela', 'ragnatela', 'Ragnatela', 2, 'Evocazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/ragnatela/', '["mago","stregone"]', '{"name":"Ragnatela","level":2,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un pezzo di tela di ragno)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"2d4","scaling":null,"ritual":false,"description":"Evochi una spessa massa di tela densa e appiccicosa in un punto a gittata, scelto da te. Per la durata, la ragnatela riempie un cubo di 6 metri di spigolo da quel punto. La ragnatela è terreno difficile e rende quell’aera oscurata leggermente. Se la tela non è ancorate tra due masse solide (come pareti o alberi) o stesa lungo un pavimento, parete o soffitto, la ragnatela evocata crolla su se stessa, e l’incantesimo termina all’inizio del tuo prossimo turno. Le tele distese su di una superficie piatta hanno una profondità di 1,5 metri. Ogni creatura che inizia il suo turno nella ragnatela o che vi entra durante il proprio turno deve effettuare un tiro salvezza su Destrezza. Se lo fallisce, la creatura è intralciata finché rimane nella ragnatela o finché non si libera. Una creatura intralciata dalle ragnatele può usare la sua azione per effettuare una prova di Forza contro la CD del tiro salvezza dell’incantesimo. Se la supera, non è più intralciata. Le ragnatele sono infiammabili. Qualsiasi cubo di 1,5 metri di spigolo di ragnatela che venga esposto al fuoco, brucia in 1 round, infliggendo 2d4 danni da fuoco a qualsiasi creatura che inizi il suo turno in mezzo al fuoco.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/ragnatela/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('randello-incantato', 'randello-incantato', 'Randello Incantato', 0, 'Trasmutazione', '1 azione bonus', 'Contatto', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/randello-incantato/', '["druido"]', '{"name":"Randello Incantato","level":0,"school":"Trasmutazione","casting_time":"1 azione bonus","range":"Contatto","components":"V, S, M (vischio, una foglia di quadrifoglio, e una randello o bastone da combattimento)","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Il legno di un randello o bastone da combattimento che stai impugnando viene infuso del potere della natura. Per la durata dell’incantesimo, usando quell’arma puoi usare la tua caratteristica da incantatore al posto della Forza per i tiri per colpire e danno da mischia, e il dado di danno dell’arma diventa un d8. L’arma diventa anche magica, se già non lo è. L’incantesimo ha termine se lo lanci di nuovo o se lasci l’arma.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/randello-incantato/","classes":["druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('reggia-meravigliosa', 'reggia-meravigliosa', 'Reggia Meravigliosa', 7, 'Evocazione', '1 minuto', '90 metri', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/reggia-meravigliosa/', '["bardo","mago"]', '{"name":"Reggia Meravigliosa","level":7,"school":"Evocazione","casting_time":"1 minuto","range":"90 metri","components":"V, S, M (un portale in miniatura scolpito in avorio, un piccolo pezzo di marmo lucido, e un minuscolo cucchiaio d’argento, ciascuno di questi oggetti deve essere almeno del valore di 5 mo)","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Entro la gittata, evochi un’abitazione extradimensionale che rimane per la durata dell’incantesimo. Scegli dove è posizionato il suo portone d’ingresso. Il portone d’ingresso emette una lieve luminosità ed è largo 1,5 metri per 3 metri di altezza. Tu e tutte le creature da te indicate quando hai lanciato l’incantesimo potete entrare nell’abitazione extradimensionale, fino a quando il portone resta aperto. Puoi aprire o chiudere il portone se ti trovi entro 9 metri da esso. Mentre è chiuso, il portone è invisibile.\nOltre il portone si trova un magnifico ingresso, oltre il quale si dipanano numerose stanze. L’atmosfera è pulita, fresca e accogliente. Puoi creare quanti piani desideri, ma lo spazio non può eccedere 50 cubi ognuno di 3 metri di spigolo. Il luogo è ammobiliato e decorato come preferisci. Contiene cibo sufficiente a soddisfare un banchetto di 9 portate per 100 persone. Uno staff di 100 servitori quasi trasparenti è al servizio di chiunque vi faccia ingresso. Sta a te decidere l’aspetto visivo di questi servitori e il loro abbigliamento. Essi obbediscono assolutamente ai tuoi ordini. Ogni servitore può svolgere qualsiasi compito un normale servitore umano possa svolgere, ma non possono attaccare o effettuare alcuna azione che potrebbe arrecare direttamente danno a un’altra creatura. I servitori possono quindi raccogliere oggetti, pulire, riparare, ripiegare vestiti, accendere fuochi, servire cibi, versare vini e così via. I servitori possono recarsi in qualsiasi punto della dimora, ma non possono uscirne. I mobili e gli altri oggetti creati da questo incantesimo diventano fumo quando vengono portati fuori dalla dimora. Quando l’incantesimo termina, qualsiasi creatura all’interno dello spazio extradimensionale viene espulsa nello spazio aperto più vicino all’uscita.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/reggia-meravigliosa/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('regressione-mentale', 'regressione-mentale', 'Regressione Mentale', 8, 'Ammaliamento', '1 azione', '45 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/regressione-mentale/', '["bardo","druido","mago","warlock"]', '{"name":"Regressione Mentale","level":8,"school":"Ammaliamento","casting_time":"1 azione","range":"45 metri","components":"V, S, M (una manciata di sfere di argilla, cristallo, vetro o minerali)","duration":"Istantanea","concentration":false,"saving_throw":"Intelligenza","attack_roll":false,"damage":"4d6","scaling":null,"ritual":false,"description":"Assalti la mente di una creatura a gittata e che puoi vedere, cercando di frammentarne l’intelletto e la personalità. Il bersaglio subisce 4d6 danni psichici e deve effettuare un tiro salvezza su Intelligenza. Se fallisce il tiro salvezza, i punteggi di Intelligenza e Carisma della creatura scendono a 1. La creatura non può lanciare incantesimi, attivare oggetti magici, comprendere linguaggi, o comunicare in alcun modo comprensibile. La creatura può, tuttavia, identificare i suoi amici, seguirli e anche proteggerli. Ogni 30 giorni, la creatura può ripetere il tiro salvezza contro l’incantesimo. Se lo supera, l’incantesimo ha termine. L’incantesimo può essere terminato da ristorare superiore, guarigione o desiderio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/regressione-mentale/","classes":["bardo","druido","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('reincarnazione', 'reincarnazione', 'Reincarnazione', 5, 'Trasmutazione', '1 ora', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/reincarnazione/', '["druido"]', '{"name":"Reincarnazione","level":5,"school":"Trasmutazione","casting_time":"1 ora","range":"Contatto","components":"V, S, M (oli e unguenti rari del valore di almeno 1.000 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Entri a contatto con un umanoide morto o un frammento di umanoide morto. Purché la creatura non sia morta da più di 10 giorni, l’incantesimo gli forma un nuovo corpo adulto e poi ne richiama l’anima affinché entri nel corpo. Se l’anima del bersaglio non è libera o consenziente a farlo, l’incantesimo fallisce. La magia modella un nuovo corpo, che probabilmente provocherà un cambio di razza alla creatura. Il GM tira un d100 e consulta la seguente tabella per determinare quale forma assuma la creatura una volta riportata in vita, oppure sarà Il GM a scegliere la forma.\nd100 Razza 01-04 Dragonide 05-13 Nano di collina 14-21 Nano di montagna 22-25 Elfo oscuro 26-34 Elfo alto 35-42 Elfo dei boschi 43-46 Gnomo della foresta 47-52 Gnomo delle rocce 53-56 Mezzelfo 57-60 Mezzorco 61-68 Halfling piede lesto 69-76 Halfling tozzo 77-96 Umano 97-00 Tiefling\nLa creatura reincarnata ricorda la sua vita e le sue esperienze passate. Mantiene le capacità che aveva nella sua forma originale, eccetto il cambiamento della sua razza originale per la nuova e la conseguente modifica dei tratti razziali.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/reincarnazione/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('replica', 'replica', 'Replica', 0, 'Manovra', 'Reazione (quando una creatura manca un attacco in mischia contro di te)', 'Creatura a portata', 'Istantanea', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Replica","level":0,"school":"Manovra","casting_time":"Reazione (quando una creatura manca un attacco in mischia contro di te)","range":"Creatura a portata","components":"-","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":true,"damage":"1 dado di superiorità","scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando una creatura manca il guerriero con un\nattacco in mischia, il guerriero può usare la sua reazione e\nspendere un dado di superiorità per effettuare un attacco\ncon un''arma da mischia contro la creatura. Se la colpisce,\naggiunge il dado di superiorità al tiro per i danni dell''attacco.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('resistenza', 'resistenza', 'Resistenza', 0, 'Abiurazione', '1 azione', 'Contatto', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/resistenza/', '["chierico","druido"]', '{"name":"Resistenza","level":0,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un mantello in miniatura)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto con una creatura consenziente. Una volta prima del termine dell’incantesimo, il bersaglio può tirare un d4 e sommare il risultato ottenuto a un tiro salvezza a sua scelta. Può tirare il dado prima o dopo aver effettuato il tiro salvezza. Poi l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/resistenza/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('respirare-sott-acqua', 'respirare-sott-acqua', 'Respirare Sott’Acqua', 3, 'Trasmutazione', '1 azione', '9 metri', '24 ore', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/respirare-sottacqua/', '["druido","mago","ranger","stregone"]', '{"name":"Respirare Sott’Acqua","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (una cannuccia o una pagliuzza)","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Questo incantesimo consente a un massimo di dieci creature consenzienti a gittata e che puoi vedere, di respirare sott’acqua fino al termine dell’incantesimo. Le creature soggette mantengono anche il loro normale metodo di respirazione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/respirare-sottacqua/","classes":["druido","mago","ranger","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('resurrezione', 'resurrezione', 'Resurrezione', 7, 'Necromanzia', '1 ora', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/resurrezione/', '["bardo","chierico"]', '{"name":"Resurrezione","level":7,"school":"Necromanzia","casting_time":"1 ora","range":"Contatto","components":"V, S, M (un diamante del valore di almeno 1.000 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura morta da non più di un secolo, che non è morta di vecchiaia e che non sia non morta. Se la sua anima è libera e consenziente, il bersaglio ritornerà in vita con tutti i suoi punti ferita. Questo incantesimo neutralizza tutti i veleni e cura le normali malattie che affliggevano la creatura quando è morta. Tuttavia non rimuove malattie magiche, maledizioni e simili; se questi effetti non sono rimossi prima del lancio dell’incantesimo, affliggeranno il bersaglio al suo ritorno in vita. Questo incantesimo chiude tutte le ferite mortali e ripristina qualsiasi parte del corpo mancante. Tornare dalla morte è un’ordalia. Il bersaglio subisce una penalità di -4 a tutti i tiri per colpire, tiri salvezza e prove di caratteristica. Ogni volta che il bersaglio termina un riposo lungo, la penalità viene ridotta di 1 finché non scompare. Lanciare questo incantesimo per riportare in vita una creatura che è morta da un anno o più ti sfianca. Fino al termine di un riposo lungo, non potrai più lanciare incantesimi e avrai svantaggio su tutti i tiri per colpire, prove di caratteristica e tiri salvezza.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/resurrezione/","classes":["bardo","chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('resurrezione-pura', 'resurrezione-pura', 'Resurrezione Pura', 9, 'Trasmutazione', '1 ora', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/resurrezione-pura/', '["chierico","druido"]', '{"name":"Resurrezione Pura","level":9,"school":"Trasmutazione","casting_time":"1 ora","range":"Contatto","components":"V, S, M (un po’ di acqua sacra e diamanti del valore di 25.000 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura morta da non più di 200 anni e che sia morta per qualsiasi motivo ma non di vecchiaia. Se la sua anima è libera e consenziente, la creatura ritornerà in vita con tutti i suoi punti ferita.\nQuesto incantesimo chiude tutte le ferite, neutralizza qualsiasi veleno, cura tutte le malattie e rimuove qualsiasi maledizione che affliggeva la creatura quando è morta. L’incantesimo rimpiazza gli organi e gli arti danneggiati.\nL’incantesimo può fornire anche un nuovo corpo se l’originale non esiste più, in qual caso devi pronunciare il nome della creatura. La creatura riapparirà poi in uno spazio non occupato di tua scelta, entro 3 metri da te.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/resurrezione-pura/","classes":["chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('rianimare-morti', 'rianimare-morti', 'Rianimare Morti', 5, 'Necromanzia', '1 ora', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/rianimare-morti/', '["bardo","chierico","paladino"]', '{"name":"Rianimare Morti","level":5,"school":"Necromanzia","casting_time":"1 ora","range":"Contatto","components":"V, S, M (una diamante del valore di almeno 500 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Riporti in vita una creatura morta, purché questa non sia morta da più di 10 giorni. Se l’anima della creatura è sia consenziente che libera di riunirsi al corpo, la creatura torna in vita con 1 punto ferita. Questo incantesimo neutralizza anche qualsiasi veleno e cura le malattie non magiche che affliggevano la creatura al momento della morte. Questo incantesimo, tuttavia, non rimuove le malattie magiche, maledizioni o simili effetti; se questi non vengono rimossi prima del lancio dell’incantesimo, riprenderanno a manifestarsi quando la creatura torna in vita. L’incantesimo non può riportare in vita una creatura non morta. Questo incantesimo richiude tutte le ferite mortali, ma non ripristina le parti del corpo mancanti. Se la creatura è priva di parti del corpo o organi fondamentali per la sopravvivenza (la testa, per esempio) l’incantesimo fallisce automaticamente. Tornare dalla morte è un’ordalia. Il bersaglio subisce una penalità di -4 a tutti i tiri per colpire, tiri salvezza e prove di caratteristica. Ogni volta che il bersaglio termina un riposo lungo, la penalità viene ridotta di 1 finché non scompare.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/rianimare-morti/","classes":["bardo","chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('rigenerazione', 'rigenerazione', 'Rigenerazione', 7, 'Trasmutazione', '1 minuto', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/rigenerazione/', '["bardo","chierico","druido"]', '{"name":"Rigenerazione","level":7,"school":"Trasmutazione","casting_time":"1 minuto","range":"Contatto","components":"V, S, M (un rosario e acqua sacra)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura per stimolare la sua capacità di guarigione naturale. Il bersaglio recupera 4d8 + 15 punti ferita. Per la durata dell’incantesimo, il bersaglio recupera 1 punto ferita all’inizio di ciascun suo turno (10 punti ferita al minuto). Le membra recise del corpo del bersaglio (dita, gambe, code e così via), se ne ha, vengono ripristinate in 2 minuti. Se hai la parte recisa e la tieni appoggiata al moncherino, l’incantesimo fa sì che l’arto si ricucia istantaneamente col moncherino.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/rigenerazione/","classes":["bardo","chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('rimuovi-maledizione', 'rimuovi-maledizione', 'Rimuovi Maledizione', 3, 'Abiurazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/rimuovi-maledizione/', '["chierico","mago","paladino","warlock"]', '{"name":"Rimuovi Maledizione","level":3,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Tutte le maledizioni che affliggono una creatura o oggetto a contatto con te, terminano. Se l’oggetto è un oggetto magico maledetto, la maledizione resta, ma l’incantesimo infrange la sintonia del proprietario con l’oggetto così che lo possa rimuovere o gettare.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/rimuovi-maledizione/","classes":["chierico","mago","paladino","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('rinascita', 'rinascita', 'Rinascita', 3, 'Necromanzia', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/rinascita/', '["chierico","paladino"]', '{"name":"Rinascita","level":3,"school":"Necromanzia","casting_time":"1 azione","range":"Contatto","components":"V, S, M (diamante del valore di 300 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una creatura morta nell’ultimo minuto e con cui sei in contatto, ritorna in vita con 1 punto ferita. Questo incantesimo non può riportare in vita le persone morte di vecchiaia, né può ripristinare le parti del corpo mancanti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/rinascita/","classes":["chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('riparare', 'riparare', 'Riparare', 0, 'Trasmutazione', '1 minuto', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/riparare/', '["bardo","chierico","druido","mago","stregone"]', '{"name":"Riparare","level":0,"school":"Trasmutazione","casting_time":"1 minuto","range":"Contatto","components":"V, S, M (due calamite)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo ripara una singola rottura o spaccatura in un oggetto con cui sei a contatto, come una catenella spezzata, due metà di una chiave rotta, un mantello lacerato, o un otre che perde. Purché la rottura o la spaccatura non sia più grande di 30 centimetri in qualsiasi dimensione, sei in grado di ripararle, senza lasciare traccia dei danni subiti. Questo incantesimo può riparare fisicamente un oggetto magico o un costrutto, ma non è in grado di ripristinare le funzioni magiche di questi oggetti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/riparare/","classes":["bardo","chierico","druido","mago","stregone"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('riposo-inviolato', 'riposo-inviolato', 'Riposo Inviolato', 2, 'Necromanzia', '1 azione', 'Contatto', '10 giorni', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/riposo-inviolato/', '["chierico","mago"]', '{"name":"Riposo Inviolato","level":2,"school":"Necromanzia","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un pizzico di sale e un pezzo di rame posto su ciascun occhio del cadavere, che devono restare lì per la durata)","duration":"10 giorni","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Entri a contatto con un cadavere o altri resti. Per la durata, il bersaglio è protetto dalla putrefazione e non può diventare non morto. L’incantesimo, inoltre, estende il limite di tempo per rianimare il bersaglio dalla morte, dato che i giorni trascorsi sotto l’influenza di questo incantesimo non sono conteggiati nel limite di tempo di incantesimi come rianimare morti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/riposo-inviolato/","classes":["chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('risata-incontenibile', 'risata-incontenibile', 'Risata Incontenibile', 1, 'Ammaliamento', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/risata-incontenibile/', '["bardo","mago"]', '{"name":"Risata Incontenibile","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, S, M (piccole torte e una piuma che viene agitata nell’aria)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una creatura a gittata di tua scelta e che puoi vedere percepisce tutto come tremendamente ilare e divertente, scoppiando in fragorose risate finché è soggetta a questo incantesimo. Il bersaglio deve superare un tiro salvezza su Saggezza o cadere prono, restando inabile e incapace di rialzarsi per la durata. Le creature con un punteggio di Intelligenza 4 o meno, ignorano l’effetto. Al termine di ciascun suo turno, e ogni volta che subisce danni, il bersaglio può effettuare un altro tiro salvezza su Saggezza. Il bersaglio ha vantaggio al tiro salvezza se questo è stato provocato dai danni. Se lo supera, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/risata-incontenibile/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('riscaldare-il-metallo', 'riscaldare-il-metallo', 'Riscaldare il Metallo', 2, 'Trasmutazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/riscaldare-il-metallo/', '["bardo","druido"]', '{"name":"Riscaldare il Metallo","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un pezzo di ferro e una fiamma)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":"2d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, il danno aumenta di 1d8 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Scegli un manufatto di metallo, come un’arma di metallo o un’armatura di metallo media o pesante, a gittata e che puoi vedere. Fai sì che l’oggetto risplenda di rosso per il calore. Qualsiasi creatura in contatto fisico con l’oggetto subisce 2d8 danni da fuoco quando lanci questo incantesimo. Fino al termine dell’incantesimo, puoi usare un’azione bonus per infliggere di nuovo questo danno nei tuoi turni successivi. Se una creatura sta impugnando o indossando l’oggetto e subisce danno da esso, la creatura deve superare un tiro salvezza su Costituzione o gettare l’oggetto se ne è in grado. Se non getta l’oggetto, ha svantaggio ai tiri per colpire e le prove di caratteristica fino all’inizio del suo prossimo turno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/riscaldare-il-metallo/","classes":["bardo","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('ristorare-inferiore', 'ristorare-inferiore', 'Ristorare Inferiore', 2, 'Abiurazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/ristorare-inferiore/', '["bardo","chierico","druido","paladino","ranger"]', '{"name":"Ristorare Inferiore","level":2,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Puoi porre fine a una malattia o condizione che affligge una creatura con cui sei a contatto. La condizione può essere accecato, assordato, avvelenato o paralizzato.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/ristorare-inferiore/","classes":["bardo","chierico","druido","paladino","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('ristorare-superiore', 'ristorare-superiore', 'Ristorare Superiore', 5, 'Abiurazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/ristorare-superiore/', '["bardo","chierico","druido"]', '{"name":"Ristorare Superiore","level":5,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (polvere di diamante del valore di almeno 100 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Imbevi una creatura a contatto di energia positiva per annullare un effetto debilitante. Puoi ridurre il livello di sfinimento del bersaglio di uno, o terminare uno dei seguenti effetti che affliggono il bersaglio:\nUn effetto che ha affascinato o pietrificato il bersaglio Una maledizione, compresa la sintonia di un bersaglio con un oggetto maledetto Qualsiasi riduzione di uno dei punteggi di caratteristica del bersaglio Un effetto che riduce i punti ferita massimi del bersaglio","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/ristorare-superiore/","classes":["bardo","chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('risveglio', 'risveglio', 'Risveglio', 5, 'Trasmutazione', '8 ore', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/risveglio/', '["bardo"]', '{"name":"Risveglio","level":5,"school":"Trasmutazione","casting_time":"8 ore","range":"Contatto","components":"V, S, M (un’agata del valore di almeno 1.000 mo, che l’incantesimo consuma)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Dopo aver trascorso il tempo di lancio a disegnare tracciati magici con una gemma preziosa, entri a contatto con una bestia o vegetale Enorme o di taglia inferiore. Il bersaglio deve essere privo di punteggio di Intelligenza o avere Intelligenza 3 o meno. Il bersaglio ottiene Intelligenza 10. Il bersaglio ottiene anche la capacità di parlare un linguaggio che conosci. Se il bersaglio è un vegetale, ottiene la capacità di muovere i suoi arti, radici, liane, rampicanti e così via, e ottiene sensi simili a quelli di un umano. Il GM sceglierà le statistiche appropriate al tipo di vegetale risvegliato, come le statistiche per il cespuglio risvegliato o l’albero risvegliato. La bestia o vegetale risvegliato è affascinato da te per 30 giorni o finché tu o i tuoi compagni non gli arrecherete danno. Quando la condizione affascinato termina, la creatura risvegliata sceglie se rimanerti amichevole, in base a come l’hai trattata mentre era affascinata.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/risveglio/","classes":["bardo"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('ritirata-rapida', 'ritirata-rapida', 'Ritirata Rapida', 1, 'Trasmutazione', '1 azione bonus', 'Incantatore', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/ritirata-rapida/', '["mago","stregone","warlock"]', '{"name":"Ritirata Rapida","level":1,"school":"Trasmutazione","casting_time":"1 azione bonus","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo ti permette di muoverti a un’andatura incredibile. Quando lanci questo incantesimo, e poi con un’azione bonus durante ciascun tuo turno fino al termine dell’incantesimo, puoi effettuare l’azione Scattare.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/ritirata-rapida/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('saltare', 'saltare', 'Saltare', 1, 'Abiurazione', '1 azione', 'Contatto', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/saltare/', '["druido","mago","ranger","stregone"]', '{"name":"Saltare","level":1,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (la zampa posteriore di una cavalletta)","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"La distanza di salto della creatura con cui sei in contatto al momento del lancio è triplicata fino al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/saltare/","classes":["druido","mago","ranger","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('salvare-i-morenti', 'salvare-i-morenti', 'Salvare i Morenti', 0, 'Necromazia', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/salvare-i-morenti/', '["chierico"]', '{"name":"Salvare i Morenti","level":0,"school":"Necromazia","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una creatura a 0 punti ferita, con cui sei a contatto, diventa stabile. L’incantesimo non ha effetto su non morti o costrutti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/salvare-i-morenti/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('santificare', 'santificare', 'Santificare', 5, 'Invocazione', '24 ore', 'Contatto', 'Fino a che dissolto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/santificare/', '["chierico"]', '{"name":"Santificare","level":5,"school":"Invocazione","casting_time":"24 ore","range":"Contatto","components":"V, S, M (erbe, oli e incensi del valore di almeno 1.000 mo, che l’incantesimo consuma)","duration":"Fino a che dissolto","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Infondi l’area circostante a un punto con cui sei in contatto di potere sacro (o blasfemo). L’area può avere un raggio massimo di 18 metri, e l’incantesimo fallisce se include un’area già sotto l’effetto di un incantesimo santificare. L’area soggetta all’incantesimo genera i seguenti effetti. Per prima cosa, celestiali, elementali, fatati, immondi e non morti non possono entrare nell’area, né una simile creatura può affascinare, spaventare o possederne altre al suo interno. Qualsiasi creatura affascinata, spaventata o posseduta da una creatura simile non è più affascinata, spaventata o posseduta dal momento in cui entra in quest’area. Puoi escludere uno o più tipi di queste creature da questo effetto. Seconda cosa, puoi vincolare un effetto ulteriore all’area. Scegli l’effetto dalla lista seguente, o scegline uno presentatoti dal GM. Alcuni di questi effetti si applicano alle creature nell’area; puoi decidere se gli effetti si applichino a tutte le creature, le creature che seguono una specifica divinità o capo, o le creature di un tipo specifico, come orchi o troll. Quando una creatura soggetta all’incantesimo entra in quest’area per la prima volta durante un turno o inizia il suo turno qui, deve effettuare un tiro salvezza su Carisma. Se lo supera, la creatura ignora l’effetto aggiuntivo finché non lascia l’area.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/santificare/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('santuario', 'santuario', 'Santuario', 1, 'Abiurazione', '1 azione bonus', '9 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/santuario/', '["chierico","mago"]', '{"name":"Santuario","level":1,"school":"Abiurazione","casting_time":"1 azione bonus","range":"9 metri","components":"V, S, M (un piccolo specchio d’argento)","duration":"1 minuto","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Proteggi una creatura a gittata dagli attacchi. Fino al termine dell’incantesimo, qualsiasi creatura che prenda come bersaglio la creatura protetta con un attacco o incantesimo dannoso deve prima effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, l’attaccante deve scegliere un nuovo bersaglio o perdere l’attacco o l’incantesimo. Questo incantesimo non protegge la creatura protetta dagli effetti ad area, come lo scoppio di una palla di fuoco. Se la creatura protetta effettua un attacco o lancia un incantesimo che agisce su creature nemiche, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/santuario/","classes":["chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('santuario-privato', 'santuario-privato', 'Santuario Privato', 4, 'Abiurazione', '10 minuti', '36 metri', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/santuario-privato/', '["mago"]', '{"name":"Santuario Privato","level":4,"school":"Abiurazione","casting_time":"10 minuti","range":"36 metri","components":"V, S, M (un sottile foglio di piombo, un pezzo di vetro opaco, un batuffolo di cotone o tessuto, e crisolito in polvere)","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello o più alto, puoi aumentare le dimensioni del cubo di 30 metri di spigolo per ogni livello dello slot sopra il 4°. Quindi, usando uno slot incantesimo di 5° livello, potresti proteggere un cubo fino a 60 metri di spigolo.","ritual":false,"description":"Proteggi con la magia un’area. L’area è un cubo che può essere piccolo fino a 1,5 metri di spigolo o grande fino a 30 metri di spigolo. L’incantesimo agisce fino al termine della durata o finché non usi un’azione per interromperlo. Quando lanci l’incantesimo, decidi che tipo di protezione questo fornisce, scegliendo una o più delle seguenti proprietà:\nIl suono non può attraversare il perimetro dell’area protetta. Il perimetro dell’area protetta appare buio e nebbioso, impedendo di vedervi attraverso (anche alla scurovisione). Sensori creati da incantesimi di divinazione non possono apparire all’interno dell’area protetta o attraversare la sua barriera perimetrale. Le creature nell’area non possono essere bersaglio di incantesimi di divinazione. Nulla può teletrasportarsi dentro o fuori dell’area protetta. All’interno dell’area protetta, il viaggio planare è interdetto.\nLanciare questo incantesimo sullo stesso punto ogni giorno per un anno, rende l’effetto permanente.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/santuario-privato/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scagliare-maledizione', 'scagliare-maledizione', 'Scagliare Maledizione', 3, 'Necromanzia', '1 azione', 'Contatto', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scagliare-maledizione/', '["bardo","chierico","mago"]', '{"name":"Scagliare Maledizione","level":3,"school":"Necromanzia","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":"1d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello, la durata diventa concentrazione, massimo 10 minuti. Se usi uno slot incantesimo di 5° livello o più alto, la durata diventa 8 ore. Se usi uno slot incantesimo di 7° livello o più alto, la durata diventa 24 ore. Se usi uno slot incantesimo di 9° livello, la durata diventa permanente finché non dissolta. Utilizzare uno slot incantesimo di 5° livello o più alto fornisce una durata che non richiede concentrazione.","ritual":false,"description":"Una creatura con cui sei a contatto deve superare un tiro salvezza su Saggezza o restare maledetta per la durata dell’incantesimo. Quando lanci questo incantesimo, scegli la natura della maledizione tra le seguenti opzioni:\nScegli un punteggio di caratteristica. Mentre è maledetto, il bersaglio ha svantaggio alle prove di caratteristica e i tiri salvezza basati su quel punteggio di caratteristica. Mentre è maledetto, il bersaglio ha svantaggio sui tiri per colpire contro di te. Mentre è maledetto, il bersaglio deve effettuare un tiro salvezza su Saggezza all’inizio di ciascun suo turno. Se lo fallisce, spreca l’azione di quel suo turno senza fare nulla. Mentre il bersaglio è maledetto, i tuoi attacchi e incantesimi infliggono 1d8 danni necrotici aggiuntivi contro di lui.\nL’incantesimo rimuovi maledizione termina questo effetto. A discrezione del GM, puoi scegliere una maledizione dall’effetto diverso, ma non dovrebbe essere comunque più potente di quelle descritte qui sopra. Il GM detiene il giudizio finale sull’effetto di una maledizione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scagliare-maledizione/","classes":["bardo","chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scarto-elusivo', 'scarto-elusivo', 'Scarto Elusivo', 0, 'Manovra', 'N/A (quando ti muovi)', 'Se stesso', 'Fino a fine del movimento', 0, 0, 'SRD', NULL, '["guerriero"]', '{"name":"Scarto Elusivo","level":0,"school":"Manovra","casting_time":"N/A (quando ti muovi)","range":"Se stesso","components":"-","duration":"Fino a fine del movimento","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Il dado di superiorità passa a d10 al 10° livello, d12 al 18°","ritual":false,"description":"Quando il guerriero si muove, può\nspendere un dado di superiorità, tirarlo e aggiungere il\nrisultato ottenuto alla sua CA finché non smette di muoversi.","usage":"1 dado di superiorità","rest":"Riposo breve o lungo","_source":null,"classes":["guerriero"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scassinare', 'scassinare', 'Scassinare', 2, 'Trasmutazione', '1 azione', '18 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scassinare/', '["bardo","mago","stregone"]', '{"name":"Scassinare","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"18 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scegli un oggetto a gittata e che puoi vedere. L’oggetto può essere una porta, scatola, delle manette, una serratura o un altro oggetto che possieda un metodo comune o magico per prevenirne l’accesso. Un bersaglio che è chiuso da una serratura comune o che è bloccato o sbarrato viene aperto, sbloccato o liberato. Se l’oggetto ha più serrature, solo una di queste viene aperta. Se scegli un bersaglio che è tenuto chiuso con serratura arcana, quell’incantesimo resta soppresso per 10 minuti, durante i quali il bersaglio può essere aperto come di norma.\nQuando lanci questo incantesimo, un sonoro bussare, udibile fino a 90 metri di distanza, emana dall’oggetto bersaglio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scassinare/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sciame-di-meteore', 'sciame-di-meteore', 'Sciame di Meteore', 9, 'Invocazione', '1 azione', '1,5 chilometri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sciame-di-meteore/', '["mago","stregone"]', '{"name":"Sciame di Meteore","level":9,"school":"Invocazione","casting_time":"1 azione","range":"1,5 chilometri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"20d6","scaling":null,"ritual":false,"description":"Sfere incandescenti di fuoco si schiantano a terra in quattro punti differenti a gittata e che puoi vedere. Ogni creatura, in una sfera di 12 metri di raggio centrata sul punto scelto da te, deve effettuare un tiro salvezza su Destrezza. La sfera si propaga intorno agli angoli. Una creatura subisce 20d6 danni da fuoco e 20d6 danni contundenti se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Una creatura nell’area di più di uno scoppio infuocato ne subisce gli effetti solo una volta. L’incantesimo danneggia gli oggetti nell’area e incendia gli oggetti infiammabili che non sono indossati o trasportati.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sciame-di-meteore/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scolpire-pietra', 'scolpire-pietra', 'Scolpire Pietra', 4, 'Trasmutazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scolpire-pietra/', '["chierico","druido","mago"]', '{"name":"Scolpire Pietra","level":4,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (argilla malleabile, che deve essere lavorata per ottenere una vaga forma dell’oggetto di pietra)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scolpisci in qualsiasi forma che si presti ai tuoi scopi un oggetto di pietra di taglia Media o inferiore o una sezione di pietra non più grossa di 1,5 metri in qualsiasi direzione, con cui sei in contatto. Così, per esempio, potresti scolpire una grossa pietra in un’arma, idolo o feretro, o creare un piccolo passaggio attraverso il muro, purché il muro sia spesso meno di 1,5 metri. Potresti anche modellare una porta di pietra o la sua cornice per sigillare la porta. L’oggetto che crei può avere fino a due cardini e un chiavistello, ma è impossibile creare meccanismi più complessi.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scolpire-pietra/","classes":["chierico","druido","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scopri-il-percorso', 'scopri-il-percorso', 'Scopri il Percorso', 6, 'Divinazione', '1 minuto', 'Incantatore', 'Concentrazione, massimo 1 giorno', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scopri-il-percorso/', '["bardo","chierico","druido"]', '{"name":"Scopri il Percorso","level":6,"school":"Divinazione","casting_time":"1 minuto","range":"Incantatore","components":"V, S, M (degli attrezzi da divinazione – dei bastoncini d’avorio, ossa, carte, denti o rune incise – del valore di almeno 100 mo e un oggetto dal luogo che desideri trovare)","duration":"Concentrazione, massimo 1 giorno","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo ti permette di trovare la rotta fisica più breve e diretta verso uno specifico luogo fisso con cui hai familiarità ed è sullo stesso piano di esistenza. Se indichi una destinazione su di un altro piano di esistenza, una destinazione che si muove (come una fortezza mobile) o una destinazione non specifica (come “la tana di un drago verde”), l’incantesimo fallisce. Per la durata dell’incantesimo, finché sei nello stesso piano di esistenza della destinazione, saprai quanto è distante e in che direzione si trovi. Mentre sei in viaggio verso di essa, ogni volta che ti si presenterà la possibilità di scegliere tra percorsi diversi, determinerai automaticamente qual è la via più breve e la rotta più diretta (ma non necessariamente la più sicura) per raggiungere la destinazione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scopri-il-percorso/","classes":["bardo","chierico","druido"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scopri-trappole', 'scopri-trappole', 'Scopri Trappole', 2, 'Divinazione', '1 azione', '36 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scopri-trappole/', '["chierico","druido","ranger"]', '{"name":"Scopri Trappole","level":2,"school":"Divinazione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Avverti la presenza di qualsiasi trappola a gittata che sia nella tua linea di visuale. Una trappola, ai fini di questo incantesimo, comprende qualsiasi cosa che sia in grado di infliggere un effetto improvviso o inaspettato che tu possa considerare dannoso o indesiderabile, e che è stato espressamente inteso come tale dal suo creatore. Di conseguenza, l’incantesimo percepirebbe un’area sotto l’incantesimo allarme, un glifo di interdizione, o una botola meccanica, ma non rivelerebbe una debolezza naturale del pavimento, un soffitto instabile o una buca nascosta. L’incantesimo si limita a rivelare la presenza delle trappole. Non apprendi la posizione delle trappole, ma apprendi la natura generica del pericolo posto dalle trappole che hai percepito.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scopri-trappole/","classes":["chierico","druido","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scrigno-segreto', 'scrigno-segreto', 'Scrigno Segreto', 4, 'Evocazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scrigno-segreto/', '["mago"]', '{"name":"Scrigno Segreto","level":4,"school":"Evocazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un forziere lavorato, 1 metro x 50 cm x 50 cm, costruito con rari materiali del valore di almeno 5.000 mo, e una sua replica Minuscola fatta degli stessi materiali e del valore di almeno 50)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Nascondi un forziere e tutti i suoi contenuti sul Piano Etereo. Quando lanci questo incantesimo devi essere in contatto con il forziere e la replica in miniatura che serve da componente materiale. Il forziere può contenere fino a 0,25 metri cubi di materiale non vivente (1 x metro x 50 centimetri x 50 centimetri). Mentre il forziere rimane sul Piano Etereo, puoi usare un’azione per entrare in contatto con la replica e richiamare il forziere. Esso riapparirà in uno spazio non occupato sul terreno entro 1,5 metri da te. Puoi rispedire il forziere nel Piano Etereo, usando un’azione ed entrando in contatto sia col forziere che con la replica.\nDopo 60 giorni, c’è una percentuale cumulativa del 5% al giorno che l’effetto dell’incantesimo abbia termine. L’effetto termina se l’incantesimo viene lanciato nuovamente, se la replica del forziere viene distrutta, o se decidi di terminare l’incantesimo con un’azione. Se l’incantesimo termina e il forziere si trova sul Piano Etereo, viene irrimediabilmente perduto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scrigno-segreto/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scritto-illusorio', 'scritto-illusorio', 'Scritto Illusorio', 1, 'Illusione', '1 minuto', 'Contatto', '10 giorni', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scritto-illusorio/', '["bardo","mago","warlock"]', '{"name":"Scritto Illusorio","level":1,"school":"Illusione","casting_time":"1 minuto","range":"Contatto","components":"S, M (un inchiostro a base di piombo del valore di almeno 10 mo, che l’incantesimo consuma)","duration":"10 giorni","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Scrivi su di una pergamena, un pezzo di carta o qualche altro materiale adatto a scrivere e lo infondi di una potente illusione che permane per la durata dell’incantesimo. Per te e qualsiasi creatura da te indicata al lancio dell’incantesimo, la scritta appare normale, con la tua grafia, e trasmette qualsiasi significato volevi comunicare quando hai vergato il testo. Per tutti gli altri, la scritta appare come se fosse redatta in una scrittura ignota o magica, che risulta incomprensibile. In alternativa, puoi far sì che la scritta sembri un messaggio totalmente diverso, in una grafia e linguaggio differente, sebbene debba essere un linguaggio a te conosciuto. In caso l’incantesimo venisse dissolto, sia la scritta originale che l’illusione svaniscono. Una creatura con visione del vero può leggere il messaggio nascosto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scritto-illusorio/","classes":["bardo","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scrutare', 'scrutare', 'Scrutare', 5, 'Divinazione', '10 minuti', 'Incantatore', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scrutare/', '["bardo","chierico","druido","mago","warlock"]', '{"name":"Scrutare","level":5,"school":"Divinazione","casting_time":"10 minuti","range":"Incantatore","components":"V, S, M (un focus del valore di almeno 1.000 mo, come una sfera di cristallo, un specchio d’argento o una fonte ricolma di acqua sacra)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Puoi vedere e udire una particolare creatura a tua scelta che si trovi sul tuo stesso piano di esistenza. Il bersaglio deve effettuare un tiro salvezza su Saggezza, modificato da quanto bene conosci il bersaglio e dal tipo di legame che hai nei suoi confronti. Se il bersaglio sa che stai lanciando l’incantesimo, può fallire volontariamente il tiro salvezza, in caso desiderasse essere osservato da te.\nConoscenza Modificatore al Tiro Salvezza Di seconda mano (ne hai sentito parlare) +5 Di prima mano (hai incontrato il bersaglio) +0 Familiare (conosci bene il bersaglio) -5\nLegame Modificatore al Tiro Salvezza Descrizione o immagine -2 Proprietà o indumento -4 Parte del corpo, ciocca di capelli, pezzo d’unghia, o simile -10\nSe supera il tiro salvezza, il bersaglio ignora gli effetti dell’incantesimo, e non potrai usare di nuovo questo incantesimo contro di lui prima che siano passate 24 ore.\nSe il tiro salvezza fallisce, l’incantesimo crea un sensore invisibile entro 3 metri dal bersaglio. Tramite il sensore puoi udire e vedere come se fossi sul posto. Il sensore si muove assieme al bersaglio, rimanendo entro 3 metri da lui per la durata dell’incantesimo. Una creatura che può vedere oggetti invisibili vede il sensore come una sfera luminosa delle dimensioni all’incirca di un pugno. Invece di prendere come bersaglio una creatura, puoi scegliere come bersaglio dell’incantesimo un luogo che hai già visto in passato. Quando scegli questa opzione, il sensore compare in quel luogo ma non si muove.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scrutare/","classes":["bardo","chierico","druido","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scudo', 'scudo', 'Scudo', 1, 'Abiurazione', '1 reazione, che effettui quando sei colpito da un attacco o bersaglio dell’incantesimo dardo incantato', 'Incantatore', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scudo/', '["mago","stregone"]', '{"name":"Scudo","level":1,"school":"Abiurazione","casting_time":"1 reazione, che effettui quando sei colpito da un attacco o bersaglio dell’incantesimo dardo incantato","range":"Incantatore","components":"V, S","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Compare una barriera di forza magica invisibile a proteggerti. Fino all’inizio del tuo prossimo turno hai un bonus di +5 alla CA, compreso l’attacco innescante, e non subisci danni da dardo incantato.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scudo/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scudo-della-fede', 'scudo-della-fede', 'Scudo della Fede', 1, 'Abiurazione', '1 azione bonus', '18 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scudo-della-fede/', '["chierico","paladino"]', '{"name":"Scudo della Fede","level":1,"school":"Abiurazione","casting_time":"1 azione bonus","range":"18 metri","components":"V, S, M (una piccola pergamena con su scritto un frammento di testo sacro)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Compare un campo scintillante che circonda una creatura a gittata, scelta da te, conferendole un bonus di +2 alla CA per la durata dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scudo-della-fede/","classes":["chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scudo-di-fuoco', 'scudo-di-fuoco', 'Scudo di Fuoco', 4, 'Invocazione', '1 azione', 'Incantatore', '10 minuti', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scudo-di-fuoco/', '["mago"]', '{"name":"Scudo di Fuoco","level":4,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un po’ di fosforo o una lucciola)","duration":"10 minuti","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"2d8","scaling":null,"ritual":false,"description":"Fiamme sottili e vaporose avvolgono il tuo corpo per la durata dell’incantesimo, emettendo luce intensa in un raggio di 3 metri e luce fioca per ulteriori 3 metri. Puoi terminare l’incantesimo in anticipo, usando un’azione per interromperlo.\nLe fiamme ti forniscono uno scudo caldo o uno scudo freddo, a tua scelta. Lo scudo caldo ti conferisce resistenza al danno da freddo, mentre lo scudo freddo ti fornisce resistenza al danno da caldo.\nInoltre, ogni qualvolta una creatura entro 1,5 metri da te ti colpisce con un attacco in mischia, lo scudo erutta fiamme. L’attaccante subisce 2d8 danni da fuoco da uno scudo caldo, o 2d8 danni da freddo da uno scudo freddo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scudo-di-fuoco/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('scurovisione', 'scurovisione', 'Scurovisione', 2, 'Trasmutazione', '1 azione', 'Contatto', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/scurovisione/', '["druido","mago","ranger","stregone"]', '{"name":"Scurovisione","level":2,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (o un pizzico di carota o di agata secca)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una creatura consenziente con cui sei in contatto ottiene la capacità di vedere al buio. Per la durata dell’incantesimo, quella creatura ha scurovisione fino a una gittata di 18 metri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/scurovisione/","classes":["druido","mago","ranger","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('segugio-fedele', 'segugio-fedele', 'Segugio Fedele', 4, 'Evocazione', '1 azione', '9 metri', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/segugio-fedele/', '["mago"]', '{"name":"Segugio Fedele","level":4,"school":"Evocazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (un minuscolo fischietto d’argento, e un pezzo d’osso, e un filo)","duration":"8 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"4d8","scaling":null,"ritual":false,"description":"Puoi evocare un cane da guardia fantasma in uno spazio non occupato a gittata e che puoi vedere, dove rimarrà per la durata dell’incantesimo, finché non viene congedato con un’azione, o finché non si allontanerà più di 30 metri da te. Il segugio è invisibile a tutte le creature eccetto che a te e non può essere danneggiato. Quando una creatura di taglia Piccola o superiore si avvicina entro 9 metri da esso senza aver prima pronunciato la parola d’ordine da te specificata quando hai lanciato l’incantesimo, il segugio inizia ad abbaiare a grande volume. Il segugio vede le creature invisibili e può vedere nel Piano Etereo. Esso ignora le illusioni. All’inizio di ciascun tuo turno, il segugio tenta di mordere una creatura entro 1,5 metri da esso e che ti sia ostile. Il bonus di attacco del segugio è uguale al tuo modificatore di caratteristica da incantatore + il tuo bonus di competenza. Se colpisce, infligge 4d8 danni perforanti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/segugio-fedele/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sembrare', 'sembrare', 'Sembrare', 5, 'Illusione', '1 azione', '9 metri', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sembrare/', '["bardo","mago","stregone"]', '{"name":"Sembrare","level":5,"school":"Illusione","casting_time":"1 azione","range":"9 metri","components":"V, S","duration":"8 ore","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo ti permette di cambiare l’aspetto di un qualsiasi numero di creature a gittata e che puoi vedere. Fornisci a ciascun bersaglio un nuovo aspetto illusorio. Una creatura non consenziente può effettuare un tiro salvezza su Carisma e, se lo supera, ignora l’incantesimo. L’incantesimo camuffa l’aspetto fisico oltre che gli abiti, le armature, le armi e l’equipaggiamento. Puoi far sembrare ciascuna creatura 30 centimetri più bassa o più alta, sembrare magra, grassa o una via di mezzo. Non puoi cambiare la conformazione del corpo del bersaglio, e quindi devi scegliere una forma che abbia la stessa distribuzione basilare di arti. Per tutto il resto, l’illusione è limitata solo dalla tua fantasia. L’incantesimo permane per la sua durata, a meno che tu non usi una tua azione per interromperlo prima. I cambi apportati da questo incantesimo non sono in grado di sostenere un’ispezione fisica. Per esempio, se usi questo incantesimo per aggiungere un cappello all’abbigliamento di una creatura, gli oggetti attraversano il cappello, e chiunque lo tocchi non avvertirebbe nulla e finirebbe per toccare la testa e i capelli della creatura. Se usi questo incantesimo per apparire più magro di quello che sei, la mano di una persona che provasse a toccarti rimbalzerebbe su di te, mentre alla vista sembrerebbe fermarsi a mezz’aria. Una creatura può usare la sua azione per ispezionare un bersaglio ed effettuare una prova di Intelligenza (Indagare) contro la CD del tiro salvezza dell’incantesimo. Se la riesce, capisce che il bersaglio è camuffato.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sembrare/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('semipiano', 'semipiano', 'Semipiano', 8, 'Evocazione', '1 azione', '18 metri', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/semipiano/', '["mago","warlock"]', '{"name":"Semipiano","level":8,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"S","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei una porta d’ombra su di una superficie piana a gittata e che puoi vedere. La porta è grande abbastanza da permettere il passaggio senza problemi a una creatura Media. Quando viene aperta, la porta conduce a un semipiano che appare come una stanza vuota di 9 metri in ciascuna dimensione, fatta di legno e pietra. Quando l’incantesimo termina, la porta scompare, e qualsiasi creatura od oggetto all’interno del semipiano rimane intrappolato lì, mentre la porta scompare anche dall’altro lato. Ogni volta che esegui questo incantesimo, crei un nuovo semipiano, oppure permetti alla porta d’ombra di connettersi a un semipiano creato da un precedente lancio dell’incantesimo. Inoltre, se conosci la natura e i contenuti di un semipiano creato dal lancio di questo incantesimo da parte di un’altra creatura, puoi far sì che la porta d’ombra si colleghi invece a quel semipiano.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/semipiano/","classes":["mago","warlock"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('serratura-arcana', 'serratura-arcana', 'Serratura Arcana', 2, 'Abiurazione', '1 azione', 'Contatto', 'Fino a che dissolto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/serratura-arcana/', '["mago"]', '{"name":"Serratura Arcana","level":2,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (polvere d’oro del valore di almeno 25 mo, che viene consumata dall’incantesimo)","duration":"Fino a che dissolto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una porta, finestra, portale, forziere o altro ingresso chiuso, e questo diventa chiuso a chiave per la durata. Tu e le creature che hai indicato, quando hai lanciato questo incantesimo, potete aprire l’oggetto normalmente. Puoi anche predisporre una parola d’ordine che, quando pronunciata entro 1,5 metri dall’oggetto, sopprime l’incantesimo per 1 minuto. Altrimenti l’apertura è invalicabile fino a che non viene distrutta o l’incantesimo è dissolto o soppresso. Lanciare scassinare sull’oggetto sopprime serratura arcana per 10 minuti.\nMentre è soggetto a questo incantesimo, l’oggetto è più difficile da distruggere o aprire a forza; la CD per romperlo o scassinare una serratura su di esso aumenta di 10.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/serratura-arcana/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('servitore-inosservato', 'servitore-inosservato', 'Servitore Inosservato', 1, 'Evocazione', '1 azione', '18 metri', '1 ora', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/servitore-inosservato/', '["bardo","mago","warlock"]', '{"name":"Servitore Inosservato","level":1,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un pezzo di corda e un pezzo di legno)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Questo incantesimo crea una forza invisibile, senza cervello e informe, che svolge dei semplici compiti al tuo comando, fino al termine dell’incantesimo. Il servitore si forma in uno spazio sul terreno non occupato, entro la gittata. Ha CA 10, 1 punto ferita, Forza 2 e non può attaccare. Se scende a 0 punti ferita, l’incantesimo ha termine. Come azione bonus, durante ciascun tuo turno, puoi comandare mentalmente il servitore di muoversi fino a 4,5 metri e interagire con un oggetto. Il servitore può svolgere dei semplici compiti alla stregua di un servitore umano, come raccogliere cose, pulire, riparare, piegare abiti, accendere fuochi, servire il cibo e versare il vino. Una volta impartito il comando, il servitore svolgerà il compito al meglio delle sue capacità finché non l’avràcompletato, e poi aspetterà il tuo prossimo comando. Se comandi al servitore di svolgere un compito che lo farà muovere a più di 18 metri da te, l’incantesimo termina.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/servitore-inosservato/","classes":["bardo","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sfera-congelante', 'sfera-congelante', 'Sfera Congelante', 6, 'Invocazione', '1 azione', '90 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sfera-congelante/', '["mago"]', '{"name":"Sfera Congelante","level":6,"school":"Invocazione","casting_time":"1 azione","range":"90 metri","components":"V, S, M (una piccola sfera di cristallo)","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"10d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, il danno aumenta di 1d6 per ogni livello dello slot sopra il 6°.","ritual":false,"description":"Un globo gelido di energia fredda parte dalla punta delle tue dita verso un punto di tua scelta a gittata, dove esplode in una sfera di 18 metri di raggio. Ogni creatura nell’area deve effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza, una creatura subisce 10d6 danni da freddo. Se lo supera, subisce la metà di questi danni. Se il globo colpisce un corpo d’acqua o un liquido composto principalmente d’acqua (escluse però le creature a base d’acqua), congela il liquido fino a una profondità di 15 centimetri in un’area quadrata di 9 metri di lato. Il ghiaccio dura 1 minuto. Le creature che stavano nuotando sulla superficie dell’acqua congelata restano intrappolate nel ghiaccio. Una creatura intrappolata può usare un’azione per effettuare una prova di Forza contro la CD del tiro salvezza dell’incantesimo, al fine di liberarsi. Se lo desideri, dopo aver completato l’incantesimo, puoi trattenerti dallo sparare il globo. Un piccolo globo, circa delle dimensioni di una pietra da fionda, freddo al contatto, appare nella tua mano. In qualsiasi momento, tu, o una creatura a cui hai dato il globo, potete lanciare il globo (fino a una gittata di 12 metri). Questo si frantumerà all’impatto, con lo stesso effetto del normale lancio dell’incantesimo. Puoi anche poggiare il globo a terra senza che si frantumi. Dopo 1 minuto, se il globo non è già stato frantumato, esploderà.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sfera-congelante/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sfera-elastica', 'sfera-elastica', 'Sfera Elastica', 4, 'Invocazione', '1 azione', '90 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sfera-elastica/', '["mago"]', '{"name":"Sfera Elastica","level":4,"school":"Invocazione","casting_time":"1 azione","range":"90 metri","components":"V, S, M (un pezzo semisferico di cristallo trasparente e un pezzo semisferico corrispondente di gomma arabica)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Una sfera di energia luminosa avvolge una creatura od oggetto di taglia Grande o inferiore a gittata. Una creatura non consenziente deve effettuare un tiro salvezza su Destrezza. Se lo fallisce, la creatura è avvolta dall’incantesimo per la sua durata. Nulla (né oggetti fisici, né energia, né altri effetti di incantesimi) può attraversare questa barriera, in entrata o uscita, sebbene una creatura all’interno della sfera possa respirare senza problemi. La sfera è immune a tutti i danni, e una creatura al suo interno non può essere danneggiata da attacchi o effetti originanti dall’esterno, né una creatura all’interno della sfera può danneggiare nulla che si trovi all’esterno.\nLa sfera è priva di peso e grande giusto a sufficienza per contenere la creatura o l’oggetto al suo interno. Una creatura avvolta può usare la sua azione per spingere contro le pareti della sfera e quindi farla rotolare fino alla metà della velocità della creatura. Allo stesso modo, il globo può essere raccolto e mosso da altre creature. Un incantesimo disintegrazione che prenda come bersaglio il globo lo distrugge senza danneggiare nulla al suo interno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sfera-elastica/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sfera-infuocata', 'sfera-infuocata', 'Sfera Infuocata', 2, 'Evocazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sfera-infuocata/', '["druido","mago"]', '{"name":"Sfera Infuocata","level":2,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un po’ di sego, un pizzico di zolfo, e una manciata di ferro in polvere)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"2d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 3° livello o più alto, il danno aumenta di 1d6 per ogni livello dello slot sopra il 2°.","ritual":false,"description":"Per la durata dell’incantesimo compare una sfera di 1,5 metri di diametro in uno spazio a gittata, scelto da te. Qualsiasi creatura che termini il suo turno entro 1,5 metri dalla sfera deve effettuare un tiro salvezza su Destrezza. La creatura subisce 2d6 danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Con un’azione bonus, puoi spostare la sfera di 9 metri. Se fai schiantare la sfera contro una creatura, la creatura deve effettuare un tiro salvezza contro il danno della sfera, e la sfera smetterà di muoversi per quel turno. Quando muovi la sfera, la puoi spostare oltre barriere alte fino a 1,5 metri, e farle saltare spazi larghi fino a 3 metri. La sfera incendia gli oggetti infiammabili non indossati o trasportati, e irradia una luce intensa in un raggio di 6 metri e una luce fioca per ulteriori 6 metri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sfera-infuocata/","classes":["druido","mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sfocatura', 'sfocatura', 'Sfocatura', 2, 'Illusione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sfocatura/', '["mago","stregone"]', '{"name":"Sfocatura","level":2,"school":"Illusione","casting_time":"1 azione","range":"Incantatore","components":"V","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Il tuo corpo diventa sfocato, indistinto e tremolante a chiunque ti veda. Per la durata dell’incantesimo, tutte le creature hanno svantaggio sui tiri per colpire contro di te. Gli attaccanti che non si affidano alla vista sono immuni a questo effetto, per esempio se hanno vista cieca o sono in grado di distinguere le illusioni, come per visione del vero.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sfocatura/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sguardo-penetrante', 'sguardo-penetrante', 'Sguardo Penetrante', 6, 'Necromanzia', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sguardo-penetrante/', '["bardo","mago","stregone","warlock"]', '{"name":"Sguardo Penetrante","level":6,"school":"Necromanzia","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata dell’incantesimo, i tuoi occhi si tramutano in un vuoto nero infuso di terribile potere. Una creatura a tua scelta entro 18 metri da te e che puoi vedere, deve superare un tiro salvezza su Saggezza o, per la durata, subire uno dei seguenti effetti di tua scelta. Durante ciascun tuo turno, fino al termine dell’incantesimo, puoi usare la tua azione per prendere come bersaglio un’altra creatura, ma non puoi prendere di nuovo come bersaglio una creatura che abbia superato un tiro salvezza contro questo lancio di sguardo penetrante.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sguardo-penetrante/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('silenzio', 'silenzio', 'Silenzio', 2, 'Illusione', '1 azione', '36 metri', 'Concentrazione, massimo 10 minuti', 1, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/silenzio/', '["bardo","chierico","ranger"]', '{"name":"Silenzio","level":2,"school":"Illusione","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"Per la durata dell’incantesimo, nessun suono può essere creato all’interno o attraversare una sfera di 6 metri di raggio centrata su di un punto a gittata, scelto da te. Qualsiasi creatura o oggetto che si trovi completamente all’interno della sfera è immune al danno da tuono, e le creature che sono completamente al suo interno sono assordate. È impossibile lanciare un incantesimo che comprende una componente verbale mentre si è al suo interno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/silenzio/","classes":["bardo","chierico","ranger"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('simbolo', 'simbolo', 'Simbolo', 7, 'Abiurazione', '1 azione', 'Contatto', 'Fino a che dissolto o attivato', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/simbolo/', '["bardo","chierico","mago"]', '{"name":"Simbolo","level":7,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (mercurio, fosforo e diamante e opale in polvere con un valore totale di almeno 1.000 mo, che l’incantesimo consuma)","duration":"Fino a che dissolto o attivato","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Quando lanci questo incantesimo, inscrivi un glifo dannoso su di una superficie (come una sezione di pavimento, muro o un tavolo) o all’interno di un oggetto che può essere chiuso per nascondere il glifo (come un libro, una pergamena o un forziere). Se scegli una superficie, il glifo può coprire un’area di superficie non maggiore di 3 metri di diametro. Se scegli un oggetto, quell’oggetto deve restare al suo posto; se l’oggetto viene spostato più di 3 metri dal punto in cui è stato lanciato l’incantesimo, il glifo è spezzato, e l’incantesimo termina senza essere stato attivato. Il glifo è quasi invisibile e può essere trovato con una prova di Intelligenza (Indagare) contro la CD del tiro salvezza dei tuoi incantesimi.\nDecidi tu cosa attivi il glifo al momento del lancio dell’incantesimo. Per i glifi inscritti su di una superficie, l’attivazione tipica comprende entrare in contatto o stare sopra il glifo, rimuovere un altro oggetto che copra il glifo, avvicinarsi a una certa distanza dal glifo, o manipolare l’oggetto su cui è inscritto il glifo. Per i glifi inscritti su di un oggetto, l’attivazione tipica comprende aprire l’oggetto, avvicinarsi a una certa distanza dall’oggetto, o vedere o leggere il glifo. Puoi definire meglio l’attivazione così che l’incantesimo si attivi solo in determinate circostanze o secondo certe peculiarità fisiche (come l’altezza o il peso) o specie di creatura (per esempio, la protezione potrebbe agire contro le megere o i mutaforma). Puoi anche predisporre condizioni per evitare che il glifo venga attivato, come la pronuncia di una parola d’ordine. Quando inscrivi il glifo scegli una delle opzioni seguenti come suo effetto. Una volta attivato, il glifo riluce, riempiendo una sfera di 18 metri di raggio di luce fioca per 10 minuti, dopo i quali l’incantesimo termina. Ogni creatura nella sfera quando il glifo si attiva diventa bersaglio del suo effetto, così come una creatura che entri per la prima volta nella sfera durante un turno o termine lì il suo turno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/simbolo/","classes":["bardo","chierico","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('simulacro', 'simulacro', 'Simulacro', 7, 'Illusione', '12 ore', 'Contatto', 'Fino a che dissolto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/simulacro/', '["mago"]', '{"name":"Simulacro","level":7,"school":"Illusione","casting_time":"12 ore","range":"Contatto","components":"V, S, M (neve o ghiaccio in quantità per creare una copia a dimensioni reali della creatura duplicata; un po’ di capelli, unghie o altro pezzo del corpo di quella creatura da piazzare in mezzo alla neve o al ghiaccio; e un rubino in polvere del valore di 1.500 mo, sparso sopra il duplicato e consumato dall’incantesimo)","duration":"Fino a che dissolto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Modelli un duplicato illusorio di una bestia o umanoide che resti a gittata per l’intero tempo di lancio dell’incantesimo. Il duplicato è una creatura, in parte reale e formata di ghiaccio o neve, che può effettuare azioni e interagire come una normale creatura. Sembra essere identica all’originale, ma ha la metà dei punti ferita massimi di quella creatura e si presenta priva di equipaggiamento. Altrimenti, l’illusione usa tutte le statistiche della creatura che duplica. Il simulacro è amichevole verso di te e le creature da te indicate. Obbedisce ai comandi da te pronunciati, muovendosi e agendo in accordo ai tuoi desideri e agendo durante il tuo turno in combattimento. Il simulacro è privo della capacità di apprendere o diventare più potente, e quindi non accresce mai di livello o nelle caratteristiche, né può recuperare gli slot incantesimi spesi. Se il simulacro è danneggiato, puoi ripararlo in un laboratorio alchemico, usando erbe rare e minerali del valore di 100 mo per punto ferita recuperato. Il simulacro rimane finché non scende a 0 punti ferita, a quel punto si ritrasforma in neve e si scioglie all’istante. Se lanci di nuovo questo incantesimo, qualsiasi duplicato da te creato con questo incantesimo attualmente attivo viene immediatamente distrutto.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/simulacro/","classes":["mago"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sogno', 'sogno', 'Sogno', 5, 'Illusione', '1 azione', 'Speciale', '8 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sogno/', '["bardo","mago","warlock"]', '{"name":"Sogno","level":5,"school":"Illusione","casting_time":"1 azione","range":"Speciale","components":"V, S, M (una manciata di sabbia, una punta di inchiostro, e una penna per scrivere presa da un volatile addormentato)","duration":"8 ore","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":"3d6","scaling":null,"ritual":false,"description":"Questo incantesimo modella i sogni di una creatura. Scegli una creatura a te nota come bersaglio dell’incantesimo. Il bersaglio deve trovarsi sul tuo stesso piano di esistenza. Le creature che non dormono, come gli elfi, non possono essere soggette a questo incantesimo. Tu o una creatura consenziente con cui sei a contatto entrate in uno stato di trance, agendo da messaggero. Mentre è in trance, il messaggero è consapevole di ciò che lo circonda, ma non può effettuare azioni o muoversi. Per la durata dell’incantesimo, se il bersaglio è addormentato, il messaggero appare nei sogni del bersaglio e può conversare con lui finché questi rimane addormentato. Il messaggero può anche modellare l’ambiente del sogno, creando terreni, oggetti e altre immagini. Il messaggero può emergere dalla trance in qualsiasi momento, terminando anticipatamente l’effetto dell’incantesimo. Al risveglio, il bersaglio ricorda perfettamente il suo sogno. Se il bersaglio è sveglio quando lanci l’incantesimo, il messaggero ne viene a conoscenza e può porre fine alla trance (e all’incantesimo) o aspettare che il bersaglio si addormenti. A quel punto il messaggero potrà comparire nei sogni del bersaglio. Puoi fare apparire il messaggero al bersaglio con un aspetto mostruoso e terrificante. Se lo fai, il messaggero può consegnare un messaggio di al massimo dieci parole e poi il bersaglio deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, gli echi della spaventosa mostruosità generano un incubo per la durata del sonno del bersaglio che gli impedisce di ottenere qualsiasi beneficio da quel riposo. Inoltre, quando il bersaglio si sveglia, subisce 3d6 danni psichici. Se possiedi una ciocca di capelli, delle unghie tagliate, o simile porzione del corpo del bersaglio, egli effettuerà il suo tiro salvezza con svantaggio.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sogno/","classes":["bardo","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sonno', 'sonno', 'Sonno', 1, 'Ammaliamento', '1 azione', '27 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sonno/', '["bardo","mago","stregone"]', '{"name":"Sonno","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"27 metri","components":"V, S, M (un pizzico di sabbia, petali di rosa o un grillo)","duration":"1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, tira 2d8 aggiuntivi per ogni slot incantesimo sopra il 1°.","ritual":false,"description":"Questo incantesimo pone le creature in un torpore magico. Tira 5d8; il totale è il numero di punti ferita di creature su cui l’incantesimo può agire. Le creature, entro 6 metri dal punto a gittata scelto da te, sono influenzate in ordine ascendente di punti ferita (ignorando le creature svenute). A partire dalla creatura con il numero più basso di punti ferita attuali, ogni creatura soggetta a questo incantesimo perde i sensi fino al terminedell’incantesimo, chi dorme subisce danni, o qualcuno usa un’azione per scuotere o prendere a schiaffi l’addormentato. Sottrarre i punti ferita di ciascuna creatura dal totale prima di considerare la creatura con il valore di punti ferita più basso successiva. I punti ferita di una creatura devono essere uguali o inferiori al totale rimanente perché l’effetto agisca su di essa.\nNon morti e creature che non possono essere affascinate non sono influenzate da questo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sonno/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sortilegio', 'sortilegio', 'Sortilegio', 1, 'Ammaliamento', '1 azione bonus', '27 metri', '1 ora', 1, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/sortilegio/', '["warlock"]', '{"name":"Sortilegio","level":1,"school":"Ammaliamento","casting_time":"1 azione bonus","range":"27 metri","components":"V, S, M (l''occhio pietrificato di un girino)","duration":"1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":true,"description":"L''incantatore scaglia una maledizione su una creatura entro gittata e che egli sia in grado di vedere. Finché l''incantesimo non termina, l''incantatore infligge ld6 danni necrotici extra al bersaglio ogni volta che lo colpisce con un attacco. Inoltre, quando l''incantatore lancia l''incantesimo, sceglie una caratteristica. Il bersaglio subisce svantaggio alle prove di caratteristica effettuate con la caratteristica scelta. Se il bersaglio scende a O punti ferita prima che questo incantesimo termini, l''incantatore può usare un''azione bonus in un suo turno successivo per maledire una nuova creatura. Un incantesimo rimuovi maledizione lanciato sul bersaglio termina questo incantesimo prematuramente. Al Livelll Superiori. Quando l''incantatore lancia questo incantesimo usando uno slot incantesimo di 3a o 4 livello. può mantenere la concentrazione sull''incantesimo fino a un massimo di 8 ore. Quando usa uno slot incantesimo di s􀁍 livello o superiore, può mantenere la concentrazione sull''incantesimo fino a un massimo di 24 ore.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/sortilegio/","classes":["warlock"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('spada-arcana', 'spada-arcana', 'Spada Arcana', 7, 'Invocazione', '1 azione', '18 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/spada-arcana/', '["bardo","mago"]', '{"name":"Spada Arcana","level":7,"school":"Invocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (una spada di platino in miniatura con l’impugnatura e il pomello di rame e zinco, del valore di 250 mo)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"3d10","scaling":null,"ritual":false,"description":"Per la durata dell’incantesimo, crei a gittata un piano di forza a forma di spada fluttuante. Quando la spada appare, effettui un attacco in mischia con incantesimo contro un bersaglio scelto da te entro 1,5 metri dalla spada. Se colpisci, il bersaglio subisce 3d10 danni da forza. Fino al termine dell’incantesimo, puoi usare un’azione bonus ogni tuo turno per muovere la spada di 6 metri in un punto che puoi vedere e ripetere questo attacco contro lo stesso bersaglio o uno differente.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/spada-arcana/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('spostamento-planare', 'spostamento-planare', 'Spostamento Planare', 7, 'Evocazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/spostamento-planare/', '["chierico","druido","mago","stregone","warlock"]', '{"name":"Spostamento Planare","level":7,"school":"Evocazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (una verga di metallo biforcuta del valore di almeno 250 mo, sintonizzata verso uno specifico piano di esistenza)","duration":"Istantanea","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Tu e un massimo di altre otto creature consenzienti, che si stringono le mani per formare un cerchio, venite trasportati su di un diverso piano di esistenza. Puoi specificare una destinazione bersaglio in termini generici, e riapparirai all’interno o in prossimità di quella destinazione, a discrezione del GM. In alternativa, se conosci la sequenza di sigilli di un cerchio di teletrasporto verso un altro piano di esistenza, l’incantesimo può condurti a quel cerchio. Se il cerchio di teletrasporto è troppo piccolo per contenere tutte le creature che trasporti con te, esse riappariranno nello spazio non occupato più vicino possibile al cerchio. Puoi usare questo incantesimo per bandire una creatura non consenziente in un altro piano. Scegli una creatura a portata ed effettua un attacco in mischia con incantesimo contro di essa. Se colpisci, la creatura deve effettuare un tiro salvezza su Carisma. Se la creatura fallisce il tiro salvezza, viene trasportata in un luogo casuale sul piano di esistenza da te specificato. Una creatura così trasportata dovrà trovare per proprio conto il modo di tornare sul tuo attuale piano di esistenza.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/spostamento-planare/","classes":["chierico","druido","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('spruzzo-colorato', 'spruzzo-colorato', 'Spruzzo Colorato', 1, 'Illusione', '1 azione', 'Incantatore (cono di 4,5 metri)', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/spruzzo-colorato/', '["mago","stregone"]', '{"name":"Spruzzo Colorato","level":1,"school":"Illusione","casting_time":"1 azione","range":"Incantatore (cono di 4,5 metri)","components":"V, S, M (un pizzico di polvere o sabbia che sia colorata di rosso, giallo e blu)","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, tira 2d10 aggiuntivi per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Dalla tua mano si sprigiona una raffica di luci colorate e abbaglianti. Tira 6d10; il totale è l’ammontare di punti ferita di creature su cui questo incantesimo agisce. Le creature, in un cono di 4,5 metri che origina da te, sono soggette in ordine ascendente dei loro attuali punti ferita (ignorando le creature prive di sensi e le creature che non possono vedere). A partire dalla creatura che ha il minor numero di punti ferita attuali, ciascuna creatura soggetta a questo incantesimo resta accecata fino al termine dell’incantesimo. Sottrarre i punti ferita di ciascuna creatura dal totale prima di passare alla creatura col totale più basso di punti ferita successiva. I punti ferita di una creatura devono essere uguali o minori del totale rimanente perché l’incantesimo agisca su di essa.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/spruzzo-colorato/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('spruzzo-prismatico', 'spruzzo-prismatico', 'Spruzzo Prismatico', 7, 'Invocazione', '1 azione', 'Incantatore (cono di 18 metri)', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/spruzzo-prismatico/', '["mago","stregone"]', '{"name":"Spruzzo Prismatico","level":7,"school":"Invocazione","casting_time":"1 azione","range":"Incantatore (cono di 18 metri)","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Otto raggi di luce multicolore partono dalla tua mano. Ogni raggio è di un diverso colore e ha un potere e uno scopo diverso. Ogni creatura in un cono di 18 metri deve effettuare un tiro salvezza su Destrezza. Per ogni bersaglio, tirare un d8 per determinare quale sia il colore del raggio che lo ha colpito.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/spruzzo-prismatico/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('spruzzo-velenoso', 'spruzzo-velenoso', 'Spruzzo Velenoso', 0, 'Evocazione', '1 azione', '3 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/spruzzo-velenoso/', '["druido","mago","stregone","warlock"]', '{"name":"Spruzzo Velenoso","level":0,"school":"Evocazione","casting_time":"1 azione","range":"3 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Costituzione","attack_roll":false,"damage":"1d12","scaling":null,"ritual":false,"description":"Stendi la mano verso una creatura a gittata e che puoi vedere, e proietti una nube di gas velenoso dal tuo palmo. La creatura deve superare un tiro salvezza su Costituzione o subire 1d12 danni da veleno. Il danno dell’incantesimo aumenta di 1d12 quando raggiungi il 5° livello (2d12), 11° livello (3d12) e 17° livello (4d12).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/spruzzo-velenoso/","classes":["druido","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('stretta-folgorante', 'stretta-folgorante', 'Stretta Folgorante', 0, 'Invocazione', '1 azione', 'Contatto', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/stretta-folgorante/', '["mago","stregone"]', '{"name":"Stretta Folgorante","level":0,"school":"Invocazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":true,"damage":"1d8","scaling":null,"ritual":false,"description":"Dalle tue mani saettano lampi che infliggono una scossa a una creatura con cui provi a entrare in contatto. Effettua un attacco in mischia con incantesimo contro il bersaglio. Hai vantaggio sul tiro per colpire se il bersaglio sta indossando un’armatura fatta di metallo. Se colpisci, il bersaglio subisce 1d8 danni da fulmine, e non può effettuare reazioni fino all’inizio del suo prossimo turno. Il danno dell’incantesimo aumenta di 1d8 quando raggiungi il 5° livello (2d8), l’11° livello (3d8) e il 17° livello (4d8).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/stretta-folgorante/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('suggestione', 'suggestione', 'Suggestione', 2, 'Ammaliamento', '1 azione', '9 metri', 'Concentrazione, massimo 8 ore', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/suggestione/', '["bardo","mago","stregone","warlock"]', '{"name":"Suggestione","level":2,"school":"Ammaliamento","casting_time":"1 azione","range":"9 metri","components":"V, M (la lingua di un serpente e un pezzo di favo o un goccio di olio dolce)","duration":"Concentrazione, massimo 8 ore","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Suggerisci un corso di attività (limitato a una o due frasi) e influenzi magicamente una creatura a gittata e che puoi vedere e udire e ti possa capire, scelta da te. Le creature che non possono essere affascinate sono immuni a questo effetto. La suggestione deve essere pronunciata in modo che il corso d’azione suoni ragionevole. Chiedere a una creatura di pugnalarsi, gettarsi su di una lancia, darsi fuoco, o fare qualche altro atto palesemente dannoso nega automaticamente gli effetti dell’incantesimo. Il bersaglio deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, esso segue il corso d’azione da te descritto al meglio delle suecapacità. Il corso d’azione suggerito può proseguire per l’intera durata dell’incantesimo. Se l’attività suggerita può essere completata in un tempo più breve, l’incantesimo ha termine quando il soggetto termina di fare ciò che gli è stato chiesto. Puoi anche specificare condizioni che attiveranno un’attività speciale per la durata dell’incantesimo. Per esempio, potresti suggerire a un cavaliere di cedere il suo cavallo da guerra al primo mendicante che incontri. Se la condizione non viene soddisfatta prima del termine dell’incantesimo, l’attività non verrà svolta. Se tu o uno qualsiasi dei tuoi compagni danneggia il bersaglio, l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/suggestione/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('suggestione-di-massa', 'suggestione-di-massa', 'Suggestione di Massa', 6, 'Ammaliamento', '1 azione', '18 metri', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/suggestione-di-massa/', '["bardo","mago","stregone","warlock"]', '{"name":"Suggestione di Massa","level":6,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V, M (la lingua di un serpente e un pezzo di favo o un goccio di olio dolce)","duration":"24 ore","concentration":false,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 7° livello o più alto, la durata è 10 giorni. Quando usi uno slot incantesimo di 9° livello, la durata è un anno e un giorno.","ritual":false,"description":"Suggerisci un corso di attività (limitato a una o due frasi) e influenzi magicamente fino a dodici creature a gittata che puoi vedere e udire e ti possano capire, scelte da te. Le creature che non possono essere affascinate sono immuni a questo effetto. La suggestione deve essere pronunciata in modo che il corso d’azione suoni ragionevole. Chiedere a una creatura di pugnalarsi, gettarsi su di una lancia, darsi fuoco, o fare qualche altro atto palesemente dannoso nega automaticamente gli effetti dell’incantesimo. Ogni bersaglio deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, esso segue il corso d’azione da te descritto al meglio delle sue capacità. Il corso d’azione suggerito può proseguire per l’intera durata dell’incantesimo. Se l’attività suggerita può essere completata in un tempo più breve, l’incantesimo ha termine quando il soggetto termina di fare ciò che gli è stato chiesto. Puoi anche specificare condizioni che attiveranno un’attività speciale per la durata dell’incantesimo. Per esempio, potresti suggerire a un gruppo di soldati di cedere tutti i loro soldi al primo mendicante che incontrino. Se la condizione non viene soddisfatta prima del termine dell’incantesimo, l’attività non verrà svolta. Se tu o uno qualsiasi dei tuoi compagni danneggia una creatura soggetta a questo incantesimo, per quella creatura l’incantesimo ha termine.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/suggestione-di-massa/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('sussurri-dissonanti', 'sussurri-dissonanti', 'Sussurri Dissonanti', 1, 'Ammaliamento', '1 azione', '18 m', 'Istantanea', 0, 0, 'SRD', NULL, '["bardo"]', '{"name":"Sussurri Dissonanti","level":1,"school":"Ammaliamento","casting_time":"1 azione","range":"18 m","components":"V","duration":"Istantanea","concentration":false,"saving_throw":"Saggezza (metà danni, niente fuga)","attack_roll":false,"damage":"3d6 psichici (+1d6 per slot superiore)","scaling":"+1d6 per ogni slot oltre il 1°","ritual":false,"description":"L''incantatore sussurra una melodia dissonante che soltanto una creatura a sua scelta e situata entro gittata è in grado di udire; quella creatura sarà scossa da un dolore lancinante. Il bersaglio deve effettuare un tiro salvezza su Saggezza. Se lo fallisce, subisce 3d6 danni psichici e. se disponibile, deve usare immediatamente la sua reazione per muoversi fin dove la sua velocità glielo consente, allontanandosi dall''incantatore. La creatura non si muove su terreno palesemente pericoloso come un incendio o una fossa. Se invece supera il tiro salvezza, il bersaglio subisce soltanto la metà di quei danni e non deve muoversi per allontanarsi. Una creatura assordata supera automaticamente il tiro salvezza. Ai Livelli Superiori. Quando l''incantatore lancia questo incantesimo usando uno slot incantesimo di 2° livello o superiore, i danni aumentano di ld6 per ogni slot di livello superiore al 1°.","usage":"Forzare disimpegno, rompere concentrazione, togliere nemici dal corpo a corpo.","rest":null,"_source":null,"classes":["bardo"]}', '2026-03-31T13:13:41.272Z', '2026-03-31T13:13:41.272Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('taumaturgia', 'taumaturgia', 'Taumaturgia', 0, 'Trasmutazione', '1 azione', '9 metri', 'Massimo 1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/taumaturgia/', '["chierico"]', '{"name":"Taumaturgia","level":0,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V","duration":"Massimo 1 minuto","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Manifesti a gittata una trucco minore, un segno di potere soprannaturale. Crei a gittata uno dei seguenti effetti magici:\nLa tua voce risuona tre volte più forte del normale per 1 minuto. Fai sì che le fiamme tremolino, si intensifichino, affievoliscano o cambino colore per 1 minuto. Provochi innocui tremori sul terreno per 1 minuto. Crei un rumore istantaneo, come un rombo di tuono, il verso di un corvo, o un sussurro inquietante, che origina da un punto a gittata scelto da te. Fai sì che una porta o una finestra non chiusa a chiave si spalanchi o si chiuda di colpo. Modifichi l’aspetto dei tuoi occhi per 1 minuto.\nSe lanci questo incantesimo più volte, puoi tenere attivi fino a tre effetti da un minuto alla volta, e puoi interrompere questi effetti con un’azione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/taumaturgia/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('telecinesi', 'telecinesi', 'Telecinesi', 5, 'Trasmutazione', '1 azione', '18 metri', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/telecinesi/', '["mago","stregone"]', '{"name":"Telecinesi","level":5,"school":"Trasmutazione","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Ottieni la capacità di muovere o manipolare creature o oggetti tramite il pensiero. Quando lanci questo incantesimo, e come tua azione durante ciascun round, puoi esercitare la tua volontà su di una creatura od oggetto a gittata e che puoi vedere, provocando l’effetto appropriato tra quelli seguenti. Puoi agire round dopo round sempre sullo stesso bersaglio, o sceglierne uno nuovo ogni volta. Se cambi bersaglio, il bersaglio precedente non è più soggetto all’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/telecinesi/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.276Z', '2026-03-31T13:13:41.276Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('teletrasporto', 'teletrasporto', 'Teletrasporto', 7, 'Evocazione', '1 azione', '3 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/teletrasporto/', '["bardo","mago","stregone"]', '{"name":"Teletrasporto","level":7,"school":"Evocazione","casting_time":"1 azione","range":"3 metri","components":"V","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo teletrasporta istantaneamente te e altre otto creature consenzienti (oppure un singolo oggetto) a gittata e che puoi vedere, scelte da te, in una destinazione di tua scelta. Se il bersaglio è un oggetto, deve poter entrare in un cubo di 3 metri di spigolo, e non può essere tenuto o trasportato da una creatura non consenziente. La destinazione che scegli ti deve essere nota, e deve essere sullo stesso piano di esistenza in cui ti trovi. La tua familiarità con la destinazione determina se vi riesce ad arrivare. Il GM tira il d100 e consulta la tabella.\nFamiliarità Errore Area Simile Fuori Bersaglio Sul Bersaglio Cerchio permanente – – – 01-100 Oggetto associato – – – 01-100 Molto familiare 01-05 06-13 14-24 25-100 Visto per caso 01-33 34-43 44-53 54- 100 Visto una volta 01-43 44-53 54-73 74-100 Descrizione 01-43 44-53 54-73 74-100 Falsa destinazione 01-50 51-100 – –","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/teletrasporto/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('tempesta-di-fuoco', 'tempesta-di-fuoco', 'Tempesta di Fuoco', 7, 'Invocazione', '1 azione', '45 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-fuoco/', '["chierico","druido","stregone"]', '{"name":"Tempesta di Fuoco","level":7,"school":"Invocazione","casting_time":"1 azione","range":"45 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"7d10","scaling":null,"ritual":false,"description":"Una tempesta composta di fiamme ruggenti compare in un punto a gittata, scelto da te. L’area della tempesta consiste di un massimo di dieci cubi di 3 metri di spigolo, che puoi disporre come preferisci. Ogni cubo deve avere almeno una faccia adiacente a quella di un altro cubo. Ogni creatura nell’area deve effettuare un tiro salvezza su Destrezza. Se lo fallisce subisce 7d10 danni da fuoco, o la metà di questi danni se lo supera. Il fuoco danneggia gli oggetti nell’area e incendia gli oggetti infiammabili che non sono indossati o trasportati. Se lo desideri, la vita vegetale nell’area resta illesa dagli effetti di questo incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-fuoco/","classes":["chierico","druido","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('tempesta-di-ghiaccio', 'tempesta-di-ghiaccio', 'Tempesta di Ghiaccio', 4, 'Invocazione', '1 azione', '90 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-ghiaccio/', '["druido","mago","stregone"]', '{"name":"Tempesta di Ghiaccio","level":4,"school":"Invocazione","casting_time":"1 azione","range":"90 metri","components":"V, S, M (un pizzico di polvere e alcune gocce d’acqua)","duration":"Istantanea","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":"2d8","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 5° livello o più alto, il danno contundente aumenta di 1d8 per ogni livello dello slot sopra il 4°.","ritual":false,"description":"Una grandinata di ghiaccio si abbatte a terra in un cilindro di 6 metri di raggio e 12 metri di altezza centrato su di un punto a gittata. Ogni creatura nel cilindro deve effettuare un tiro salvezza su Destrezza. La creatura subisce 2d8 danni contundenti e 4d6 danni da freddo se fallisce il tiro salvezza, o la metà se lo supera. La grandine trasforma l’area di effetto della tempesta in terreno difficile fino al termine del tuo prossimo turno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-ghiaccio/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('tempesta-di-nevischio', 'tempesta-di-nevischio', 'Tempesta di Nevischio', 3, 'Evocazione', '1 azione', '45 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-nevischio/', '["druido","mago","stregone"]', '{"name":"Tempesta di Nevischio","level":3,"school":"Evocazione","casting_time":"1 azione","range":"45 metri","components":"V, S, M (un pizzico di polvere e qualche goccia d’acqua)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fino al termine dell’incantesimo, pioggia gelida e nevischio si abbattono in un cilindro alto 6 metri e del raggio di 12 metri centrato in un punto da te scelto a gittata. L’area è oscurata pesantemente, mentre le fiamme esposte vengono spente. Il terreno nell’area è coperto di ghiaccio scivoloso, rendendolo terreno difficile. Quando una creatura entra nell’area dell’incantesimo per la prima volta durante un turno o inizia il suo turno lì, deve effettuare un tiro salvezza su Destrezza. Se lo fallisce, cade prona. Se una creatura nell’area dell’incantesimo si sta concentrando, deve superare un tiro salvezza su Costituzione contro la CD del tiro salvezzadell’incantesimo o perdere la concentrazione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-nevischio/","classes":["druido","mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('tempesta-di-vendetta', 'tempesta-di-vendetta', 'Tempesta di Vendetta', 9, 'Evocazione', '1 azione', 'Vista', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-vendetta/', '["druido"]', '{"name":"Tempesta di Vendetta","level":9,"school":"Evocazione","casting_time":"1 azione","range":"Vista","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":"2d6","scaling":null,"ritual":false,"description":"Si forma una ribollente nube di tempesta, centrata in un punto che puoi vedere e che si propaga in un raggio di 110 metri. L’area è illuminata da fulmini, vi riecheggiano tuoni e venti forti la spazzano. Quando la nube compare, ogni creatura sotto di essa (ovvero non più di 1.500 metri sotto la nube) deve effettuare un tiro salvezza su Costituzione. Se fallisce il tiro salvezza, la creatura subisce 2d6 danni da tuono e resta assordata per 5 minuti. Ogni round in cui mantieni la concentrazione su questo incantesimo, la tempesta, durante il tuo turno, produce ulteriori effetti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/tempesta-di-vendetta/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('tentacoli-neri', 'tentacoli-neri', 'Tentacoli Neri', 4, 'Evocazione', '1 azione', '27 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/tentacoli-neri/', '["mago"]', '{"name":"Tentacoli Neri","level":4,"school":"Evocazione","casting_time":"1 azione","range":"27 metri","components":"V, S, M (un pezzo di tentacolo di una piovra gigante o di un calamaro gigante)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Destrezza","attack_roll":false,"damage":"3d6","scaling":null,"ritual":false,"description":"Viscidi tentacoli d’ebano riempiono un quadrato di 6 metri di lato sul terreno, a gittata e che puoi vedere. Per la durata dell’incantesimo, questi tentacoli trasformano l’area in terreno difficile. Quando una creatura entra nell’area soggetta per la prima volta in un turno o comincia qui il suo turno, la creatura deve superare un tiro salvezza su Destrezza o subire 3d6 danni contundenti e rimanere intralciata dai tentacoli fino al termine dell’incantesimo. Una creatura che inizia il suo turno nell’area ed è già intralciata dai tentacoli, subisce 3d6 danni contundenti. Una creatura intralciata dai tentacoli può usare la sua azione per effettuare una prova di Forza o Destrezza (a sua scelta) contro la CD del tiro salvezza dell’incantesimo. Se la supera, si libera.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/tentacoli-neri/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('terremoto', 'terremoto', 'Terremoto', 8, 'Invocazione', '1 azione', '150 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/terremoto/', '["chierico","druido","stregone"]', '{"name":"Terremoto","level":8,"school":"Invocazione","casting_time":"1 azione","range":"150 metri","components":"V, S, M (un pizzico di terriccio, un pezzo di pietra e un grumo di argilla)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Costituzione","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Provochi un disturbo sismico in un punto sul terreno a gittata e che puoi vedere. Per la durata, un intenso tremore scuote il terreno in un cerchio di 30 metri di raggio centrato su quel punto e scuote le creature e le strutture in quell’area che sono a contatto del terreno. Il terreno nell’area diventa terreno difficile. Ogni creatura a terra che si sta concentrando deve effettuare un tiro salvezza su Costituzione. Se lo fallisce, la sua concentrazione è infranta. Quando lanci questo incantesimo e alla fine di ogni turno che hai speso a concentrarti su di esso, ogni creatura nell’area che si trovi a terra deve effettuare un tiro salvezza su Destrezza. Se lo fallisce, la creatura cade prona. Questo incantesimo ha effetti aggiuntivi a seconda del tipo di terreno nell’area, a discrezione del GM.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/terremoto/","classes":["chierico","druido","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('terreno-illusorio', 'terreno-illusorio', 'Terreno Illusorio', 4, 'Illusione', '10 minuti', '90 metri', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/terreno-illusorio/', '["bardo","druido","mago","warlock"]', '{"name":"Terreno Illusorio","level":4,"school":"Illusione","casting_time":"10 minuti","range":"90 metri","components":"V, S, M (una pietra, un rametto e un pezzo di pianta verde)","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fai sì che un pezzo di terreno naturale a gittata, in un cubo di 45 metri di spigolo, appaia, risuoni e odori come qualche altro tipo di terreno naturale. Di conseguenza, campi aperti o una strada possono essere trasformati in un acquitrino, colline, un crepaccio o qualche altro tipo di terreno difficile o invalicabile. Un laghetto può essere trasformato in una radura erbosa, un precipizio in una lieve pendenza, un burrone cosparso di rocce in una strada ampia e liscia. Le strutture edificate, l’equipaggiamento e le creature all’interno dell’area non mutano d’aspetto. Le peculiarità tattili del terreno sono immutate, così che le creature che entrano nell’area è probabile che svelino l’illusione. Se al contatto la differenza non è ovvia, una creatura che esamina con cautela l’illusione può tentare una prova di Intelligenza (Indagare) contro la CD del tiro salvezza dei tuoi incantesimi per dubitare di essa. Una creatura che riconosca l’illusione per quello che è, la percepisce come una vaga immagine sovrapposta al terreno.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/terreno-illusorio/","classes":["bardo","druido","mago","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('tocco-gelido', 'tocco-gelido', 'Tocco Gelido', 0, 'Necromanzia', '1 azione', '36 metri', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/tocco-gelido/', '["mago","stregone","warlock"]', '{"name":"Tocco Gelido","level":0,"school":"Necromanzia","casting_time":"1 azione","range":"36 metri","components":"V, S","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":false,"damage":"1d8","scaling":null,"ritual":false,"description":"Crei una scheletrica mano spettrale nello spazio di una creatura a gittata. Effettua un attacco a distanza con incantesimo contro la creatura, per aggredirla con il gelo della morte. Se colpisci, il bersaglio subisce 1d8 danni necrotici, e non può recuperare punti ferita fino all’inizio del tuo prossimo turno. Fino ad allora, la mano resterà serrata sul bersaglio.\nSe colpisci un bersaglio non morto, esso avrà anche svantaggio ai tiri per colpire contro di te fino alla fine del suo prossimo turno. Il danno dell’incantesimo aumenta di 1d8 quando raggiungi il 5° livello (2d8), l’11° livello (3d8) e il 17° livello (4d8).","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/tocco-gelido/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('tocco-vampirico', 'tocco-vampirico', 'Tocco Vampirico', 3, 'Necromanzia', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/tocco-vampirico/', '["mago","warlock"]', '{"name":"Tocco Vampirico","level":3,"school":"Necromanzia","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":"3d6","scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, il danno aumenta di 1d6 per ogni livello dello slot sopra il 3°.","ritual":false,"description":"Il contatto con la tua mano avvolta dall’ombra può risucchiare la forza vitale altrui per curare le tue ferite. Effettua un attacco in mischia con incantesimo contro una creatura a portata. Se colpisci, il bersaglio subisce 3d6 danni necrotici, e tu recuperi un numero di punti ferita pari alla metà del danno necrotico che hai inflitto. Fino al termine dell’incantesimo, puoi effettuare ogni turno di nuovo questo attacco come tua azione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/tocco-vampirico/","classes":["mago","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('trama-ipnotica', 'trama-ipnotica', 'Trama Ipnotica', 3, 'Illusione', '1 azione', '36 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/trama-ipnotica/', '["bardo","mago","stregone","warlock"]', '{"name":"Trama Ipnotica","level":3,"school":"Illusione","casting_time":"1 azione","range":"36 metri","components":"S, M (un bastoncino luminoso di incenso o una fiala di cristallo piena di materiale fosforescente)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":"Saggezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei a gittata una trama contorta di colori che si muove nell’aria all’interno di un cubo di 9 metri di spigolo. La trama appare per un momento e poi svanisce. Ogni creatura nell’area che veda la trama deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, una creatura rimane affascinata per la durata. Mentre è affascinata da questo incantesimo, la creatura è inabile e ha velocità 0.\nL’incantesimo termina per la creatura soggetta, qualora questa subisca danni o se qualcuno usa un’azione per scuoterla dal suo stato confusionale.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/trama-ipnotica/","classes":["bardo","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('trasformazione', 'trasformazione', 'Trasformazione', 9, 'Trasmutazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 ora', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/trasformazione/', '["druido","mago"]', '{"name":"Trasformazione","level":9,"school":"Trasmutazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un cerchietto di giada del valore di almeno 1.500 mo, che devi poggiare sulla tua testa prima di lanciare l’incantesimo)","duration":"Concentrazione, massimo 1 ora","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata assumi la forma di una creatura differente. La nuova forma può essere quella di qualsiasi creatura il cui grado di sfida sia pari o inferiore al tuo livello. La creatura non può essere un costrutto o un non morto, e devi averla vista almeno una volta. Ti trasformi in un esemplare medio di quella creatura, uno senza livelli di classe o il tratto Incantesimi.\nPuoi restare nella forma assunta fino al termine dell’incantesimo. Ti ritrasformi automaticamente se cadi privo di sensi, scendi a 0 punti ferita o muori. Le tue statistiche di gioco sono rimpiazzate dalle statistiche della creatura scelta, fatta accezione del tuo allineamento, e dei tuoi punteggi di Intelligenza, Saggezza e Carisma. Mantieni tutte le tue competenze nelle abilità e i tiri salvezza, oltre a ottenere quelle della creatura. Se la creatura possiede le tue stesse competenze e il bonus indicato nelle sue statistiche è più alto del tuo, usa il bonus della creatura al posto del tuo. Non puoi usare nessuna azione leggendaria o azione da tana della nuova forma. Quando ti trasformi, assumi i punti ferita e i Dadi Vita della creatura. Quando ritorni alla tua forma normale, ritorni al numero di punti ferita che avevi prima di trasformarti. Tuttavia, se ti ritrasformi perché sei stato ridotto a 0 punti ferita, tutto il danno in eccesso viene riportato alla tua forma originale. A meno che il danno in eccesso non riduca la tua forma normale a 0 punti ferita, non cadrai privo di sensi. Mantieni tutti i benefici di qualsiasi privilegio di classe, razza, o altra fonte e puoi usarli se la nuova forma è fisicamente capace di farne uso. Tuttavia, non puoi usare nessuno dei tuoi sensi speciali, come la scurovisione, a meno che la nuova forma non possieda anch’essa lo stesso senso. Puoi parlare solo se la creatura è normalmente in grado di parlare. Quando ti trasformi scegli se il tuo equipaggiamento cade a terra nel tuo spazio, si fonde con la nuova forma o sia indossato da essa. L’equipaggiamento indossato funziona come di norma, ma sta al GM decidere se sia comodo per la nuova forma indossare un simile pezzo di equipaggiamento, in base alla taglia e le dimensioni della creatura. Il tuo equipaggiamento non cambia dimensioni né si adatta alla nuova forma, e qualsiasi equipaggiamento che la nuova forma non può indossare deve essere fatto cadere a terra o fondersi con la nuova forma. L’equipaggiamento che si fonde è inefficace. Nella durata dell’incantesimo, puoi usare la tua azione per assumere una forma diversa seguendo le stesse restrizioni e regole della forma originale, con una eccezione: se la tua nuova forma ha più punti ferita della forma attuale, i tuoi punti ferita restano al livello attuale.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/trasformazione/","classes":["druido","mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('traslazione-arborea', 'traslazione-arborea', 'Traslazione Arborea', 5, 'Evocazione', '1 azione', 'Incantatore', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/traslazione-arborea/', '["druido","ranger"]', '{"name":"Traslazione Arborea","level":5,"school":"Evocazione","casting_time":"1 azione","range":"Incantatore","components":"V, S","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Ottieni la capacità di entrare in un albero e muoverti dal suo interno all’interno di un altro albero della stessa specie entro 150 metri. Entrambi gli alberi devono essere vivi e almeno della tua stessa taglia. Devi usare 1,5 metri di movimento per entrare nell’albero. Apprendi istantaneamente la posizione di tutti gli altri alberi della stessa specie entro 150 metri e, come parte del movimento impiegato per entrare nell’albero, puoi passare in uno degli altri alberi o uscire dall’albero in cui sei entrato. Riappari in un punto a tua scelta entro 1,5 metri dall’albero di destinazione, utilizzando altri 1,5 metri di movimento. Se non ti rimane movimento da usare, riappari entro 1,5 metri dall’albero in cui sei entrato.\nPer la durata dell’incantesimo puoi usare questa capacità di trasporto una volta per round. Devi terminare ogni turno al di fuori di un albero.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/traslazione-arborea/","classes":["druido","ranger"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('trasporto-vegetale', 'trasporto-vegetale', 'Trasporto Vegetale', 6, 'Evocazione', '1 azione', '3 metri', '1 round', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/trasporto-vegetale/', '["druido"]', '{"name":"Trasporto Vegetale","level":6,"school":"Evocazione","casting_time":"1 azione","range":"3 metri","components":"V, S","duration":"1 round","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Questo incantesimo crea un legame magico tra un vegetale inanimato di taglia Grande o maggiore a gittata e un altro vegetale, a qualsiasi distanza, sullo stesso piano di esistenza. Devi aver visto o essere entrato in contatto almeno una volta con il vegetale di destinazione. Per la durata dell’incantesimo, qualsiasi creatura può entrare nel vegetale bersaglio e uscire dal vegetale di destinazione usando 1,5 metri di movimento.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/trasporto-vegetale/","classes":["druido"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('trova-cavalcatura', 'trova-cavalcatura', 'Trova Cavalcatura', 2, 'Evocazione', '10 minuti', '9 metri', 'Istantanea', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/trova-cavalcatura/', '["paladino"]', '{"name":"Trova Cavalcatura","level":2,"school":"Evocazione","casting_time":"10 minuti","range":"9 metri","components":"V, S","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Evochi uno spirito che assume la forma di una cavalcatura insolitamente intelligente, forte e leale, stabilendo un legame duraturo con esso. Apparendo in uno spazio a gittata, non occupato, il destriero assume la forma di tua scelta, come quella di un cavallo da guerra, un pony, un cammello, un alce o un mastino (il GM potrebbe darti la possibilità di evocare come destrieri anche altri tipi di animali). Il destriero ha le statistiche della forma scelta, sebbene sia di tipo celestiale, fatato o immondo (a tua scelta) invece del suo normale tipo. Inoltre, se il tuo destriero ha Intelligenza 5 o meno, la sua Intelligenza diventa 6, e ottiene la capacità di comprendere un linguaggio a tua scelta tra quelli che sei in grado di parlare. Il tuo destriero serve da cavalcatura, sia in combattimento che fuori da esso, e possiedi un legame istintivo con esso, che vi permette di combattere come foste un unico insieme. Mentre sei in groppa alla tua cavalcatura, puoi far sì che qualsiasi incantesimo che lanci e che prenda come bersaglio solo te, prenda come bersaglio anche il tuo destriero. Quando il destriero scende a 0 punti ferita, scompare, non lasciandosi dietro alcuna forma fisica. Puoi congedare il destriero in qualsiasi momento con un’azione, facendolo sparire. In entrambi i casi, lanciare di nuovo questo incantesimo evoca lo stesso destriero, ripristinato al massimo dei suoi punti ferita. Mentre il tuo destriero si trova entro 1,5 chilometri da te, puoi comunicare telepaticamente con esso. Non puoi avere più di un destriero legato da questo incantesimo alla volta. Con un’azione, puoi liberare il destriero da questo legame in qualsiasi momento, facendolo sparire.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/trova-cavalcatura/","classes":["paladino"]}', '2026-03-31T13:13:41.277Z', '2026-03-31T13:13:41.277Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('trova-famiglio', 'trova-famiglio', 'Trova Famiglio', 1, 'Evocazione', '1 ora', '3 metri', 'Istantanea', 0, 1, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/trova-famiglio/', '["mago"]', '{"name":"Trova Famiglio","level":1,"school":"Evocazione","casting_time":"1 ora","range":"3 metri","components":"V, S, M (10 mo di carbone, incenso e erbe che devono essere consumate dal fuoco in un braciere d’ottone)","duration":"Istantanea","concentration":false,"saving_throw":null,"attack_roll":true,"damage":null,"scaling":null,"ritual":true,"description":"Ottieni il servizio di un famiglio, uno spirito che assume una forma animale di tua scelta: cavalluccio marino, corvo, donnola, falco, gatto, granchio, gufo, lucertola, pesce (frizzo), piovra, pipistrello, ragno, rana (rospo), ratto o serpente velenoso. Apparendo in uno spazio a gittata, non occupato, il famiglio ha le statistiche della forma scelta, sebbene sia di tipo celestiale, fatato o immondo (a tua scelta) invece di una bestia. Il tuo famiglio agisce in maniera indipendente da te, ma ubbidisce sempre ai tuoi comandi. In combattimento, tira la propria iniziativa e agisce durante il proprio turno. Un famiglio non può attaccare, ma può svolgere le altre azioni come di norma. Quando il famiglio scende a 0 punti ferita, scompare, non lasciandosi dietro alcuna forma fisica. Riappare quando lanci di nuovo questo incantesimo. Mentre il tuo famiglio si trova entro 30 metri da te, puoi comunicare telepaticamente con esso. Inoltre, con un’azione puoi vedere attraverso gli occhi del famiglio e ascoltare quello che sente fino all’inizio del tuo prossimo turno, ottenendo i benefici di qualsiasi senso speciale di cui il famiglio sia in possesso. Durante questo periodo, sei cieco e sordo per quel che concerne i tuoi sensi. Con un’azione, puoi congedare temporaneamente il famiglio. Questo scompare in una dimensione tascabile dove aspetta di essere richiamato. In alternativa, lo puoi congedare per sempre. Con un’azione, mentre è temporaneamente congedato, lo puoi far riapparire in uno spazio non occupato entro 9 metri da te. Non puoi avere più di un famiglio alla volta. Se esegui questo incantesimo mentre hai già un famiglio, fai adottare a quello che hai già una nuova forma. Scegli una delle forme dalla lista precedente. Il tuo famiglio si trasforma nella creatura prescelta. Infine, quando lanci un incantesimo con gittata contatto, il tuo famiglio può trasmettere l’incantesimo come se l’avesse lanciato lui. Il famiglio deve trovarsi entro 30 metri da te, e deve usare la propria reazione per trasmettere l’incantesimo nel momento in cui lo lanci. Se l’incantesimo richiede un tiro per colpire, per questo tiro usi il tuo modificatore di attacco.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/trova-famiglio/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('trucco-della-corda', 'trucco-della-corda', 'Trucco della Corda', 2, 'Trasmutazione', '1 minuto', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/trucco-della-corda/', '["mago"]', '{"name":"Trucco della Corda","level":2,"school":"Trasmutazione","casting_time":"1 minuto","range":"Contatto","components":"V, S, M (estratto di grano in polvere e un laccio di pergamena)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Entri a contatto con un pezzo di corda lungo fino a 18 metri. Un’estremità della corda si leva nell’aria finché la corda non pende perpendicolare al terreno. All’estremità opposta della corda, un’entrata invisibile si apre su di uno spazio extradimensionale che resta fino al termine dell’incantesimo. Lo spazio extradimensionale può essere raggiunto arrampicandosi fino alla cima della corda. Lo spazio può contenere fino a otto creature di taglia Media o inferiore. La corda può essere trascinata nello spazio, facendola sparire dalla vista di chi è fuori di esso. Attacchi e incantesimi non possono attraversare l’ingresso in entrata o uscita dallo spazio extradimensionale, ma chi si trova al suo interno può vedere fuori come se vedesse attraverso una finestra di 1 x 1,5 metri centrata sulla corda.\nQualsiasi cosa si trovi nello spazio extradimensionale ne cade fuori al termine dell’incantesimo.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/trucco-della-corda/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('unto', 'unto', 'Unto', 1, 'Evocazione', '1 azione', '18 metri', '1 minuto', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/unto/', '["mago"]', '{"name":"Unto","level":1,"school":"Evocazione","casting_time":"1 azione","range":"18 metri","components":"V, S, M (un pezzo di cotenna di maiale o burro)","duration":"1 minuto","concentration":false,"saving_throw":"Destrezza","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Grasso scivoloso ricopre il terreno in un quadrato di 3 metri di lato, centrato su di un punto a gittata, e lo trasforma in terreno difficile per la durata dell’incantesimo. Quando compare il grasso, ciascun bersaglio che si trova in piedi nell’area deve superare un tiro salvezza su Destrezza o cadere prono. Una creatura che entra nell’area o termina il suo turno lì, deve superare un tiro salvezza su Destrezza o cadere prona.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/unto/","classes":["mago"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('vedere-invisibilita', 'vedere-invisibilita', 'Vedere Invisibilità', 2, 'Divinazione', '1 azione', 'Incantatore', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/vedere-invisibilita/', '["bardo","mago","stregone"]', '{"name":"Vedere Invisibilità","level":2,"school":"Divinazione","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un pizzico di talco e una manciata di polvere d’argento)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Per la durata dell’incantesimo, vedi le creature e gli oggetti invisibili come se fossero visibili, e inoltre puoi vedere nel Piano Etereo. Le creature e gli oggetti eterei ti appaiono spettrali e trasparenti.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/vedere-invisibilita/","classes":["bardo","mago","stregone"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('velocita', 'velocita', 'Velocità', 3, 'Trasmutazione', '1 azione', '9 metri', 'Concentrazione, massimo 1 minuto', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/velocita/', '["mago","stregone"]', '{"name":"Velocità","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"9 metri","components":"V, S, M (una grattata di radice di liquirizia)","duration":"Concentrazione, massimo 1 minuto","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Scegli una creatura consenziente a gittata e che puoi vedere. Fino al termine dell’incantesimo, la velocità del bersaglio è raddoppiata, ottiene un bonus di +2 alla CA, ha vantaggio ai tiri salvezza su Destrezza, e ottiene un’azione aggiuntiva durante ciascun suo turno. Quest’azione può essere impiegata solo per effettuare le azioni Attaccare (un solo attacco con un’arma), Disimpegnarsi, Nascondersi, Scattare o Usare un Oggetto. Quando l’incantesimo termina, il bersaglio non può muoversi o effettuare azioni fino al suo prossimo turno, mentre è pervaso da un’improvvisa sonnolenza.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/velocita/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('vigilanza-e-interdizione', 'vigilanza-e-interdizione', 'Vigilanza e Interdizione', 6, 'Abiurazione', '10 minuti', 'Contatto', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/vigilanza-e-interdizione/', '["bardo","mago"]', '{"name":"Vigilanza e Interdizione","level":6,"school":"Abiurazione","casting_time":"10 minuti","range":"Contatto","components":"V, S, M (incenso bruciato, un piccolo misurino di zolfo e olio, un laccio legato, un piccolo ammontare di sangue di colosso di terra, e una piccola verga d’argento del valore di almeno 10 mo)","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei una interdizione che protegge fino a 225 metri quadri di pavimento (un’area quadrata di 15 metri di lato, o cento quadrati di 1,5 metri di lato o venticinque quadrati di 3 metri di lato). L’area interdetta può essere alta fino a 6 metri, e modellata come preferisci. Puoi interdire diversi piani di una roccaforte dividendo l’area tra di essi, purché tu possa camminare ininterrottamente in ogni area adiacente, mentre lanci l’incantesimo. Quando lanci questo incantesimo, puoi specificare gli individui che ignorano qualcuno o tutti gli effetti di questo incantesimo. Puoi anche specificare una parola d’ordine che, pronunciata ad alta voce, rende chi la proferisce immune a questi effetti. Vigilanza e interdizione crea i seguenti effetti all’interno dell’area interdetta.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/vigilanza-e-interdizione/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('vincolo-di-interdizione', 'vincolo-di-interdizione', 'Vincolo di Interdizione', 2, 'Abiurazione', '1 azione', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/vincolo-di-interdizione/', '["chierico"]', '{"name":"Vincolo di Interdizione","level":2,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (una coppia di anelli di platino del valore di 50 mo l’uno, che tu e il bersaglio dovete indossare per la durata)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura che vuoi proteggere. Crei una connessione mistica tra di te e il bersaglio fino al termine dell’incantesimo. Finché il bersaglio è entro 18 metri da te, ottiene un bonus di +1 alla CA e ai tiri salvezza e ha resistenza a tutti i danni. Inoltre, ogni volta che il bersaglio subisce danni, tu ne subisci la stessa quantità. L’incantesimo ha fine se scendi a 0 punti ferita o tu e il bersaglio vi allontanate più di 18 metri. Ha fine anche se lo lanci di nuovo sulla stessa creatura su cui è già in atto. Puoi interrompere l’incantesimo con un’azione.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/vincolo-di-interdizione/","classes":["chierico"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('visione-del-vero', 'visione-del-vero', 'Visione del Vero', 6, 'Divinazione', '1 azione', 'Contatto', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/visione-del-vero/', '["bardo","chierico","mago","stregone","warlock"]', '{"name":"Visione del Vero","level":6,"school":"Divinazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (un unguento per gli occhi che costa 25 mo; fatto di funghi in polvere, zafferano e grasso; viene consumato dall’incantesimo)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente. Il bersaglio riceve la capacità di vedere le cose come sono realmente. Per la durata dell’incantesimo, la creatura ha visione del vero, nota porte segrete nascoste dalla magia, e può vedere nel Piano Etereo, fino a una gittata di 36 metri.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/visione-del-vero/","classes":["bardo","chierico","mago","stregone","warlock"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('vita-falsata', 'vita-falsata', 'Vita Falsata', 1, 'Necromanzia', '1 azione', 'Incantatore', '1 ora', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/vita-falsata/', '["mago","stregone"]', '{"name":"Vita Falsata","level":1,"school":"Necromanzia","casting_time":"1 azione","range":"Incantatore","components":"V, S, M (un piccolo ammontare di alcool o spirito distillato)","duration":"1 ora","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 2° livello o più alto, ottieni 5 punti ferita temporanei aggiuntivi per ogni livello dello slot sopra il 1°.","ritual":false,"description":"Potenziandoti con una parvenza necromantica di vitalità, ottieni 1d4 + 4 punti ferita temporanei per la durata.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/vita-falsata/","classes":["mago","stregone"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('volare', 'volare', 'Volare', 3, 'Trasmutazione', '1 azione', 'Contatto', 'Concentrazione, massimo 10 minuti', 1, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/volare/', '["mago","stregone","warlock"]', '{"name":"Volare","level":3,"school":"Trasmutazione","casting_time":"1 azione","range":"Contatto","components":"V, S, M (una piuma dell’ala di qualsiasi volatile)","duration":"Concentrazione, massimo 10 minuti","concentration":true,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":"Quando lanci questo incantesimo usando uno slot incantesimo di 4° livello o più alto, puoi prendere come bersaglio un’ulteriore creatura per ognilivello dello slot sopra il 3°.","ritual":false,"description":"Lanci l’incantesimo a contatto di una creatura consenziente. Per la durata dell’incantesimo, il bersaglio ottiene velocità di volo 18 metri. Quando l’incantesimo ha fine, qualora sia ancora in aria, il bersaglio cade, a meno che non riesca a frenare la discesa.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/volare/","classes":["mago","stregone","warlock"]}', '2026-03-31T13:13:41.274Z', '2026-03-31T13:13:41.274Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('vuoto-mentale', 'vuoto-mentale', 'Vuoto Mentale', 8, 'Abiurazione', '1 azione', 'Contatto', '24 ore', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/vuoto-mentale/', '["bardo","mago"]', '{"name":"Vuoto Mentale","level":8,"school":"Abiurazione","casting_time":"1 azione","range":"Contatto","components":"V, S","duration":"24 ore","concentration":false,"saving_throw":null,"attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Fino al termine dell’incantesimo, una creatura consenziente con cui sei in contatto durante il lancio è immune al danno psichico, qualsiasi effetto che ne percepirebbe le emozioni o leggerebbe i pensieri, incantesimi di divinazione e la condizione affascinato. L’incantesimo nega anche gli incantesimi desiderio e altri incantesimi o effetti di simili potenza impiegati per influenzare la mente del bersaglio o per ottenere informazioni su di esso.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/vuoto-mentale/","classes":["bardo","mago"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
INSERT INTO "Spell" ("id", "slug", "name", "level", "school", "castingTime", "range", "duration", "concentration", "ritual", "sourceType", "sourceUrl", "classes", "data", "createdAt", "updatedAt") VALUES ('zona-di-verita', 'zona-di-verita', 'Zona di Verità', 2, 'Ammaliamento', '1 azione', '18 metri', '10 minuti', 0, 0, 'SRD', 'https://dungeonedraghi.it/compendio/incantesimi/zona-di-verita/', '["bardo","chierico","paladino"]', '{"name":"Zona di Verità","level":2,"school":"Ammaliamento","casting_time":"1 azione","range":"18 metri","components":"V, S","duration":"10 minuti","concentration":false,"saving_throw":"Carisma","attack_roll":false,"damage":null,"scaling":null,"ritual":false,"description":"Crei una zona magica che protegge contro i raggiri in una sfera di 4,5 metri di raggio centrata su di un punto a gittata di tua scelta. Fino al termine dell’incantesimo, una creatura che entra nell’area dell’incantesimo per la prima volta durante un turno, o inizia il suo turno al suo interno, deve effettuare un tiro salvezza su Carisma. Se fallisce il tiro salvezza, la creatura non può pronunciare bugie deliberatamente mentre è nel raggiodell’incantesimo. Sei a conoscenza se una creatura ha superato o fallito il tiro salvezza. Una creatura soggetta all’incantesimo ne è consapevole e può quindi evitare di rispondere a domande a cui risponderebbe normalmente con una bugia. Questa creatura può dare risposte elusive purché rimanga entro i confini della verità.","usage":null,"rest":null,"_source":"https://dungeonedraghi.it/compendio/incantesimi/zona-di-verita/","classes":["bardo","chierico","paladino"]}', '2026-03-31T13:13:41.273Z', '2026-03-31T13:13:41.273Z');
